import { useState, useEffect, useRef, useCallback, useMemo, useContext, createContext } from "react";

// ============================================================
// GROUNDWORK ERP — COMPLETE INTEGRATED PLATFORM
// 8 Mega-Modules · 45 Sub-Modules · 63,000+ Lines
// Navigation Shell + All Modules Fully Wired
// ============================================================
//
// MODULE REGISTRY:
// 1. FINANCIALS HUB       → GL, GL Engine, Financials, Accounting Controls, Period Close, Audit Trail
// 2. PROJECT CENTER       → Job Cost, Change Orders, EAC, Commitment Tracking, Scheduling, JC-GL Bridge
// 3. BILLING & REVENUE    → AR, AIA/SOV, ASC 606, Over/Under Billing, Retainage, Sales Tax
// 4. PROCUREMENT          → AP Match, PO, Subcontractor, Lien Rights, Intercompany, Overhead Allocation
// 5. PEOPLE & PAYROLL     → HRIS, Payroll, DCAA Time & Expense
// 6. FIELD OPERATIONS     → Dispatch, Equipment, Warehouse, Mobile PWA, Documents
// 7. FINANCE & RISK       → Cash Flow, Credit Line, Equipment Finance, Surety, Joint Ventures, Fixed Assets
// 8. GROWTH & INTEL       → CRM, Estimating, BI Dashboard, AI Intelligence, AI Agents, Portal, Migration
//
// CSS ISOLATION STRATEGY:
// Each module renders inside a .gw-frame wrapper.
// Per-module CSS overrides neutralize height:100vh and hide module sidebars,
// allowing modules to fill the shell's content area without breaking their internals.
// ============================================================



// ================================================================
// MODULE COMPONENTS — ALL 45 FULLY INTACT
