// -- GROUNDWORK-ACCOUNTING-CONTROLS --------------------------------------
// ============================================================
// GROUNDWORK — Accounting Controls
// Period Management · Budget Builder · Recurring Transactions · Audit Trail
// Closes GL controls gap to 10/10 · Budget gap to 10/10
// ============================================================

const css_gw_accounting_controls = `
  @import url('https://fonts.googleapis.com/css2?family=Bebas+Neue&family=Epilogue:wght@300;400;500;600;700&family=JetBrains+Mono:wght@400;500&display=swap');
  *, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }
  :root {
    --bg:#141210; --surface:#1E1B18; --raised:#262219; --border:#302B24;
    --border2:#3D3730; --muted:#58524A; --dim:#8A8078; --light:#C8BFB0;
    --bright:#EDE5D8; --white:#FAF7F2;
    --gold:#C07A0A; --gold-l:#E09418; --gold-d:#301E02; --gold-dim:rgba(192,122,10,0.13);
    --green:#1E6040; --green-l:#3CA870; --green-dim:rgba(60,168,112,0.12);
    --red:#6E2030; --red-l:#B04050; --red-dim:rgba(176,64,80,0.12);
    --blue:#163862; --blue-l:#2878C0; --blue-dim:rgba(40,120,192,0.12);
    --teal:#126060; --teal-l:#28A8A8; --teal-dim:rgba(40,168,168,0.12);
    --amber:#5A3800; --amber-l:#D08030; --amber-dim:rgba(208,128,48,0.12);
    --purple-l:#8048C0; --purple-dim:rgba(128,72,192,0.12);
    --stone:rgba(88,82,74,0.3);
  }
  body { font-family:'Epilogue',sans-serif; background:var(--bg); color:var(--bright); min-height:100vh; }
  ::-webkit-scrollbar { width:3px; height:3px; }
  ::-webkit-scrollbar-track { background:var(--surface); }
  ::-webkit-scrollbar-thumb { background:var(--muted); border-radius:2px; }
  .app { display:flex; height:100vh; overflow:hidden; }
  /* Sidebar */
  .sb { width:224px; min-width:224px; background:var(--surface); border-right:1px solid var(--border); display:flex; flex-direction:column; position:relative; }
  .sb::before { content:''; position:absolute; top:0; left:0; right:0; height:2px; background:linear-gradient(90deg,var(--gold),var(--gold-l),var(--gold)); }
  .sb-logo { padding:16px 14px 13px; border-bottom:1px solid var(--border); }
  .sb-logo-r { display:flex; align-items:center; gap:9px; }
  .sb-gem { width:30px; height:30px; background:var(--gold); border-radius:5px; display:flex; align-items:center; justify-content:center; flex-shrink:0; }
  .sb-name { font-family:'Bebas Neue',sans-serif; font-size:17px; letter-spacing:2px; color:var(--bright); }
  .sb-mod { font-size:8px; letter-spacing:3px; color:var(--muted); text-transform:uppercase; margin-top:2px; }
  .sb-nav { flex:1; overflow-y:auto; padding:6px 0; }
  .sb-grp { margin-bottom:2px; }
  .sb-grp-label { font-size:8px; font-weight:700; letter-spacing:3px; text-transform:uppercase; color:var(--muted); padding:10px 14px 3px; }
  .sb-item { display:flex; align-items:center; gap:8px; padding:8px 14px; cursor:pointer; font-size:12px; color:var(--dim); border-left:2px solid transparent; transition:all 0.12s; }
  .sb-item:hover { background:var(--raised); color:var(--light); }
  .sb-item.on { background:var(--gold-dim); color:var(--gold-l); border-left-color:var(--gold); font-weight:600; }
  .sb-dot { width:5px; height:5px; border-radius:50%; background:currentColor; opacity:0.5; flex-shrink:0; }
  .sb-pill { margin-left:auto; background:var(--gold); color:var(--bg); font-size:9px; font-weight:700; padding:1px 6px; border-radius:10px; }
  .sb-badge-r { margin-left:auto; background:var(--red-dim); color:var(--red-l); font-size:9px; font-weight:700; padding:1px 6px; border-radius:10px; }
  /* Main */
  .main { flex:1; display:flex; flex-direction:column; overflow:hidden; }
  .topbar { background:var(--surface); border-bottom:1px solid var(--border); height:52px; padding:0 22px; display:flex; align-items:center; justify-content:space-between; flex-shrink:0; }
  .tb-title { font-family:'Bebas Neue',sans-serif; font-size:17px; letter-spacing:2px; color:var(--bright); }
  .tb-crumb { font-size:9px; color:var(--muted); letter-spacing:1.5px; text-transform:uppercase; margin-top:1px; }
  .tb-right { display:flex; gap:8px; align-items:center; }
  .tab-bar { display:flex; background:var(--surface); border-bottom:1px solid var(--border); padding:0 22px; flex-shrink:0; overflow-x:auto; }
  .tab { padding:10px 14px; font-size:11px; font-weight:500; color:var(--muted); cursor:pointer; border-bottom:2px solid transparent; margin-bottom:-1px; transition:all 0.12s; letter-spacing:0.3px; white-space:nowrap; }
  .tab:hover { color:var(--bright); }
  .tab.on { color:var(--gold-l); border-bottom-color:var(--gold); }
  .content { flex:1; overflow-y:auto; padding:20px 24px; }
  /* Buttons */
  .btn { display:inline-flex; align-items:center; gap:6px; padding:7px 14px; border-radius:7px; border:none; font-family:'Epilogue',sans-serif; font-size:12px; font-weight:600; cursor:pointer; transition:all 0.12s; white-space:nowrap; }
  .btn-ghost { background:var(--raised); color:var(--dim); border:1px solid var(--border); }
  .btn-ghost:hover { background:var(--border); color:var(--light); }
  .btn-gold { background:var(--gold); color:var(--bg); }
  .btn-gold:hover { background:var(--gold-l); }
  .btn-green { background:var(--green-dim); color:var(--green-l); border:1px solid rgba(60,168,112,0.2); }
  .btn-green:hover { background:rgba(60,168,112,0.2); }
  .btn-red { background:var(--red-dim); color:var(--red-l); border:1px solid rgba(176,64,80,0.2); }
  .btn-red:hover { background:rgba(176,64,80,0.2); }
  .btn-blue { background:var(--blue-dim); color:var(--blue-l); border:1px solid rgba(40,120,192,0.2); }
  .btn-blue:hover { background:rgba(40,120,192,0.2); }
  .btn-amber { background:var(--amber-dim); color:var(--amber-l); border:1px solid rgba(208,128,48,0.2); }
  .btn-amber:hover { background:rgba(208,128,48,0.25); }
  .btn-sm { padding:4px 10px; font-size:11px; border-radius:5px; }
  .btn-xs { padding:3px 8px; font-size:10px; border-radius:4px; }
  .btn:disabled { opacity:0.4; cursor:not-allowed; }
  /* Panels */
  .panel { background:var(--surface); border:1px solid var(--border); border-radius:10px; overflow:hidden; margin-bottom:14px; }
  .ph { padding:12px 16px; border-bottom:1px solid var(--border); display:flex; align-items:center; justify-content:space-between; }
  .pt { font-family:'Bebas Neue',sans-serif; font-size:13px; letter-spacing:2px; color:var(--light); }
  .ps { font-size:10px; color:var(--muted); margin-top:1px; }
  /* KPIs */
  .krow { display:flex; gap:0; margin-bottom:14px; }
  .kpi { flex:1; background:var(--surface); border:1px solid var(--border); padding:13px 15px; position:relative; overflow:hidden; }
  .kpi:first-child { border-radius:9px 0 0 9px; }
  .kpi:last-child { border-radius:0 9px 9px 0; }
  .kpi+.kpi { border-left:none; }
  .kpi::after { content:''; position:absolute; bottom:0; left:0; right:0; height:2px; }
  .k-gold::after { background:var(--gold); }
  .k-green::after { background:var(--green-l); }
  .k-red::after { background:var(--red-l); }
  .k-blue::after { background:var(--blue-l); }
  .k-amber::after { background:var(--amber-l); }
  .kl { font-size:9px; font-weight:700; letter-spacing:2px; text-transform:uppercase; color:var(--muted); margin-bottom:5px; }
  .kv { font-family:'JetBrains Mono',monospace; font-size:20px; font-weight:500; color:var(--bright); line-height:1; }
  .ks { font-size:10px; color:var(--muted); margin-top:4px; }
  /* Tables */
  .tbl { width:100%; border-collapse:collapse; }
  .tbl th { font-size:9px; font-weight:700; letter-spacing:2px; text-transform:uppercase; color:var(--muted); padding:9px 13px; text-align:left; border-bottom:1px solid var(--border); background:rgba(0,0,0,0.2); white-space:nowrap; }
  .tbl td { padding:10px 13px; font-size:12px; color:var(--light); border-bottom:1px solid rgba(255,255,255,0.03); vertical-align:middle; }
  .tbl tr:last-child td { border-bottom:none; }
  .tbl tr:hover td { background:rgba(255,255,255,0.02); }
  .mono { font-family:'JetBrains Mono',monospace; font-size:11px; }
  /* Badges */
  .badge { display:inline-flex; align-items:center; padding:2px 7px; border-radius:3px; font-size:9px; font-weight:700; letter-spacing:1px; text-transform:uppercase; }
  .b-gold   { background:var(--gold-dim);   color:var(--gold-l); }
  .b-green  { background:var(--green-dim);  color:var(--green-l); }
  .b-red    { background:var(--red-dim);    color:var(--red-l); }
  .b-blue   { background:var(--blue-dim);   color:var(--blue-l); }
  .b-teal   { background:var(--teal-dim);   color:var(--teal-l); }
  .b-amber  { background:var(--amber-dim);  color:var(--amber-l); }
  .b-purple { background:var(--purple-dim); color:var(--purple-l); }
  .b-stone  { background:rgba(88,82,74,0.2); color:var(--muted); }
  /* Forms */
  .fg { display:flex; flex-direction:column; gap:4px; }
  .fl { font-size:9px; font-weight:700; letter-spacing:2px; text-transform:uppercase; color:var(--muted); }
  .fh { font-size:10px; color:var(--dim); margin-top:1px; }
  .fi,.fsel,.fta { background:var(--raised); border:1px solid var(--border); border-radius:6px; color:var(--bright); font-family:'Epilogue',sans-serif; font-size:12px; padding:7px 10px; outline:none; transition:border-color 0.12s; width:100%; }
  .fi:focus,.fsel:focus,.fta:focus { border-color:var(--gold); box-shadow:0 0 0 2px var(--gold-dim); }
  .fsel option { background:var(--surface); }
  .frow { display:grid; gap:12px; }
  .frow-2 { grid-template-columns:1fr 1fr; }
  .frow-3 { grid-template-columns:1fr 1fr 1fr; }
  /* Modal */
  .overlay { position:fixed; inset:0; background:rgba(0,0,0,0.7); display:flex; align-items:center; justify-content:center; z-index:100; padding:20px; }
  .modal { background:var(--surface); border:1px solid var(--border2); border-radius:12px; width:100%; max-width:540px; max-height:90vh; overflow-y:auto; }
  .modal-lg { max-width:720px; }
  .mh { padding:18px 20px 14px; border-bottom:1px solid var(--border); display:flex; align-items:flex-start; justify-content:space-between; }
  .mt { font-family:'Bebas Neue',sans-serif; font-size:15px; letter-spacing:2px; color:var(--light); }
  .ms { font-size:10px; color:var(--muted); margin-top:3px; }
  .mb { padding:18px 20px; display:flex; flex-direction:column; gap:14px; }
  .mf { padding:14px 20px 18px; border-top:1px solid var(--border); display:flex; justify-content:flex-end; gap:8px; }
  .xbtn { background:none; border:none; color:var(--muted); cursor:pointer; padding:2px; border-radius:4px; font-size:16px; line-height:1; }
  .xbtn:hover { color:var(--bright); }
  /* Alert */
  .alert { display:flex; align-items:flex-start; gap:9px; padding:11px 13px; border-radius:7px; font-size:11px; margin-bottom:10px; }
  .a-red  { background:var(--red-dim);   color:var(--red-l);   border:1px solid rgba(176,64,80,0.2); }
  .a-gd   { background:var(--gold-dim);  color:var(--gold-l);  border:1px solid rgba(192,122,10,0.2); }
  .a-gn   { background:var(--green-dim); color:var(--green-l); border:1px solid rgba(60,168,112,0.2); }
  .a-bl   { background:var(--blue-dim);  color:var(--blue-l);  border:1px solid rgba(40,120,192,0.2); }
  /* Period grid */
  .period-grid { display:grid; grid-template-columns:repeat(4,1fr); gap:10px; margin-bottom:14px; }
  .period-card { background:var(--raised); border:1px solid var(--border); border-radius:8px; padding:13px 14px; cursor:pointer; transition:all 0.15s; position:relative; overflow:hidden; }
  .period-card:hover { border-color:var(--border2); }
  .period-card.open { border-color:rgba(60,168,112,0.3); background:rgba(60,168,112,0.04); }
  .period-card.closed { border-color:rgba(208,128,48,0.3); background:rgba(208,128,48,0.04); }
  .period-card.locked { border-color:rgba(176,64,80,0.3); background:rgba(176,64,80,0.04); }
  .period-card.future { opacity:0.4; cursor:default; }
  .period-card::before { content:''; position:absolute; top:0; left:0; right:0; height:2px; }
  .period-card.open::before   { background:var(--green-l); }
  .period-card.closed::before { background:var(--amber-l); }
  .period-card.locked::before { background:var(--red-l); }
  .pc-month { font-family:'Bebas Neue',sans-serif; font-size:16px; letter-spacing:1.5px; color:var(--bright); }
  .pc-year  { font-size:10px; color:var(--muted); margin-bottom:8px; }
  .pc-status { display:flex; align-items:center; gap:5px; font-size:10px; font-weight:600; letter-spacing:1px; text-transform:uppercase; }
  .pc-meta { font-size:9px; color:var(--dim); margin-top:6px; }
  /* Budget grid */
  .budget-table { width:100%; border-collapse:collapse; font-size:11px; }
  .budget-table th { font-size:8px; font-weight:700; letter-spacing:2px; text-transform:uppercase; color:var(--muted); padding:7px 9px; text-align:right; border-bottom:1px solid var(--border); white-space:nowrap; background:rgba(0,0,0,0.25); position:sticky; top:0; z-index:2; }
  .budget-table th:first-child { text-align:left; min-width:180px; }
  .budget-table td { padding:6px 9px; color:var(--light); border-bottom:1px solid rgba(255,255,255,0.03); text-align:right; vertical-align:middle; }
  .budget-table td:first-child { text-align:left; font-size:11px; }
  .budget-table tr:hover td { background:rgba(255,255,255,0.02); }
  .budget-table tr.section-row td { background:rgba(0,0,0,0.2); font-size:9px; font-weight:700; letter-spacing:2px; color:var(--muted); padding:5px 9px; text-transform:uppercase; }
  .budget-table tr.total-row td { border-top:1px solid var(--border); background:rgba(0,0,0,0.25); font-weight:700; color:var(--bright); }
  .budget-input { background:transparent; border:none; border-bottom:1px solid transparent; color:var(--bright); font-family:'JetBrains Mono',monospace; font-size:11px; text-align:right; width:72px; padding:2px 3px; outline:none; transition:border-color 0.12s; }
  .budget-input:focus { border-bottom-color:var(--gold); background:var(--raised); border-radius:3px; }
  .var-pos { color:var(--green-l); }
  .var-neg { color:var(--red-l); }
  /* Recurring rows */
  .rec-row { display:flex; align-items:center; gap:12px; padding:12px 14px; border-bottom:1px solid rgba(255,255,255,0.04); }
  .rec-row:last-child { border-bottom:none; }
  .rec-icon { width:32px; height:32px; border-radius:7px; display:flex; align-items:center; justify-content:center; flex-shrink:0; }
  .rec-body { flex:1; }
  .rec-name { font-size:12px; color:var(--bright); font-weight:500; }
  .rec-detail { font-size:10px; color:var(--dim); margin-top:2px; }
  .rec-meta { display:flex; flex-direction:column; align-items:flex-end; gap:3px; flex-shrink:0; }
  .next-run { font-family:'JetBrains Mono',monospace; font-size:11px; color:var(--gold-l); }
  /* Audit trail */
  .audit-row { display:flex; gap:14px; padding:11px 14px; border-bottom:1px solid rgba(255,255,255,0.04); }
  .audit-dot { width:8px; height:8px; border-radius:50%; flex-shrink:0; margin-top:4px; }
  .audit-body { flex:1; }
  .audit-action { font-size:12px; color:var(--bright); }
  .audit-detail { font-size:10px; color:var(--dim); margin-top:2px; }
  .audit-meta { display:flex; gap:8px; margin-top:4px; }
  .audit-chip { font-size:9px; background:rgba(255,255,255,0.05); color:var(--muted); padding:2px 6px; border-radius:3px; }
  /* checklist */
  .checklist { display:flex; flex-direction:column; gap:6px; }
  .check-item { display:flex; align-items:center; gap:9px; padding:9px 12px; background:var(--raised); border-radius:6px; font-size:11px; }
  .check-icon { width:18px; height:18px; border-radius:50%; display:flex; align-items:center; justify-content:center; flex-shrink:0; font-size:10px; }
  .ci-pass { background:var(--green-dim); color:var(--green-l); }
  .ci-fail { background:var(--red-dim); color:var(--red-l); }
  .ci-warn { background:var(--amber-dim); color:var(--amber-l); }
  /* Progress bar */
  .prog-bar { height:4px; background:var(--border); border-radius:2px; overflow:hidden; }
  .prog-fill { height:100%; border-radius:2px; transition:width 0.4s; }
  /* Section divider */
  .sec-div { font-size:8px; font-weight:700; letter-spacing:3px; text-transform:uppercase; color:var(--muted); margin:16px 0 8px; display:flex; align-items:center; gap:8px; }
  .sec-div::after { content:''; flex:1; height:1px; background:var(--border); }

  /* -- BANK FEED -- */
  .bank-card{background:var(--raised);border:1px solid var(--border);border-radius:9px;padding:14px 16px;margin-bottom:10px;display:flex;align-items:center;gap:14px}
  .bank-logo{width:40px;height:40px;border-radius:9px;display:flex;align-items:center;justify-content:center;font-size:20px;background:var(--clay);border:1px solid var(--gravel);flex-shrink:0}
  .tx-row{display:flex;align-items:center;gap:12px;padding:10px 14px;border-bottom:1px solid rgba(255,255,255,.03)}
  .tx-row:last-child{border-bottom:none}.tx-row:hover{background:rgba(255,255,255,.02)}
  .tx-ico{width:30px;height:30px;border-radius:7px;display:flex;align-items:center;justify-content:center;font-size:13px;flex-shrink:0}
  .tx-info{flex:1}
  .tx-desc{font-size:12px;color:var(--chalk)}
  .tx-meta{font-size:10px;color:var(--stone);margin-top:2px}
  .tx-amt{font-family:'DM Mono',monospace;font-size:12px;font-weight:600;min-width:90px;text-align:right}
  .tx-match{min-width:110px;text-align:right}
  .match-btn{background:var(--green-dim);color:var(--green-l);border:1px solid rgba(69,168,118,.2);border-radius:4px;padding:3px 9px;font-size:9px;font-weight:700;cursor:pointer;letter-spacing:1px}
  .match-btn:hover{background:rgba(69,168,118,.2)}.match-btn:disabled{opacity:.35;cursor:not-allowed}
`;

