const gw_ai_features_dollardollar = n => "$" + Math.abs(n).toLocaleString("en-US", {minimumFractionDigits:2, maximumFractionDigits:2});

// -- Shared API call -------------------------------------------
async function callClaude(messages, system, apiKey) {
  if (!apiKey || !apiKey.startsWith("sk-")) throw new Error("Enter a valid Anthropic API key (sk-...) in the top bar to use AI features.");
  const res = await fetch("https://api.anthropic.com/v1/messages", {
    method: "POST",
    headers: {
      "Content-Type": "application/json",
      "x-api-key": apiKey,
      "anthropic-version": "2023-06-01",
      "anthropic-dangerous-direct-browser-access": "true",
    },
    body: JSON.stringify({
      model: "claude-sonnet-4-20250514",
      max_tokens: 1000,
      system,
      messages,
    }),
  });
  const data = await res.json();
  if (data.error) throw new Error(data.error.message);
  return data.content.map(b => b.text || "").join("");
}

// -- Shared markdown renderer ----------------------------------
function MD({ text, style = {} }) {
  const lines = text.split("\n");
  const nodes = [];
  let listBuf = [];

  function flushList() {
    if (!listBuf.length) return;
    nodes.push(
      <ul key={nodes.length} style={{ paddingLeft: 16, margin: "4px 0 6px" }}>
        {listBuf.map((l, i) => (
 <li key={i} style={{ marginBottom: 3, color: "var(--light)", fontSize: 11 }} dangerouslySetInnerHTML={{ __html: l }} />
        ))}
      </ul>
    );
    listBuf = [];
  }

  lines.forEach((line, i) => {
    const html = line
      .replace(/\*\*(.*?)\*\*/g, "<strong>$1</strong>")
      .replace(/\*(.*?)\*/g, '<em style="color:var(--dim)">$1</em>')
      .replace(/`(.*?)`/g, '<code style="font-family:\'JetBrains Mono\',monospace;font-size:10px;background:rgba(0,0,0,.3);padding:1px 5px;border-radius:3px;color:var(--tl-l)">$1</code>');

    if (!line.trim()) { flushList(); nodes.push(<br key={i} />); return; }

    if (line.match(/^[-•]\s/)) {
      listBuf.push(html.replace(/^[-•]\s/, ""));
      return;
    }

    flushList();

    if (line.match(/^#{1,3}\s/)) {
      nodes.push(
 <div key={i} style={{ fontWeight: 700, color: "var(--white)", marginBottom: 5, marginTop: 8, fontSize: 12 }} dangerouslySetInnerHTML={{ __html: html.replace(/^#+\s/, "") }} />
      );
      return;
    }

    if (line.startsWith("|")) {
      nodes.push(
 <div key={i} className="mono" style={{ fontSize: 10, color: "var(--light)", margin: "1px 0" }} dangerouslySetInnerHTML={{ __html: html }} />
      );
      return;
    }

    nodes.push(
 <p key={i} style={{ marginBottom: 5, ...style }} dangerouslySetInnerHTML={{ __html: html }} />
    );
  });

  flushList();
  return <>{nodes}</>;
}

