function PredictiveMaintTab({ apiKey }) {
  const [selected, setSelected] = useState(null);
  if (!apiKey || !apiKey.startsWith("sk-")) return <NoKeyBanner />;
  const [analyses, setAnalyses] = useState({});
  const [loading, setLoading] = useState({});
  const [createdWOs, setCreatedWOs] = useState([]);

  const hColor = s => s >= 80 ? "var(--gn-l)" : s >= 65 ? "var(--tl-l)" : s >= 50 ? "var(--am-l)" : "var(--rd-l)";

  async function analyze(eq) {
    setSelected(eq);
    if (analyses[eq.id]) return;
    setLoading(prev => ({ ...prev, [eq.id]: true }));
    try {
      const prompt = `Analyze this equipment for Apex MEP Services and generate a predictive maintenance work order recommendation.

Equipment: ${eq.name} (${eq.model})
Age: ${eq.age} years | Runtime: ${eq.runtime.toLocaleString()} hours | Health score: ${eq.health}/100
Location: ${eq.location}
Last service: ${eq.lastService} | Next scheduled: ${eq.nextScheduled}
Active fault codes: ${eq.faults.length ? eq.faults.join(", ") : "None"}
Service history: ${eq.history.map(h => `${h.date}: ${h.work} ($${h.cost})`).join(" | ")}

Provide: risk level, failure mode analysis, specific WO task list, cost estimate, and consequences of deferral at 30/60/90 days.`;
      const reply = await callClaude([{ role: "user", content: prompt }], MAINT_SYSTEM, apiKey);
      setAnalyses(prev => ({ ...prev, [eq.id]: reply }));
    } catch (e) {
      setAnalyses(prev => ({ ...prev, [eq.id]: `**API Error:** ${e.message}` }));
    }
    setLoading(prev => ({ ...prev, [eq.id]: false }));
  }

  const critCount = FLEET.filter(e => e.health < 50).length;
  const faultCount = FLEET.reduce((s, e) => s + e.faults.length, 0);

  return (
    <div>
      <div className="krow">
        <div className="kpi k-rd"><div className="kl">Critical</div><div className="kv">{critCount}</div><div className="ks">Health below 50</div></div>
        <div className="kpi k-am"><div className="kl">Active Faults</div><div className="kv">{faultCount}</div><div className="ks">Across fleet</div></div>
        <div className="kpi k-gn"><div className="kl">WOs Created</div><div className="kv">{createdWOs.length}</div><div className="ks">From AI analysis</div></div>
        <div className="kpi k-tl"><div className="kl">Fleet Units</div><div className="kv">{FLEET.length}</div><div className="ks">Monitored</div></div>
      </div>

      <div style={{ display: "grid", gridTemplateColumns: "310px 1fr", gap: 14 }}>
        <div className="panel">
          <div className="ph"><div><div className="pt">EQUIPMENT FLEET</div><div className="ps">Click to run AI analysis</div></div></div>
          <div style={{ padding: 10 }}>
            {FLEET.map(eq => (
              <div key={eq.id} className={"eq-card "+(selected?.id === eq.id ? "sel" : "")} onClick={() => analyze(eq)}>
                <div className="eq-ico" style={{ background: eq.health < 50 ? "var(--rd-d)" : eq.health < 70 ? "var(--am-d)" : "var(--gn-d)" }}>{eq.icon}</div>
                <div style={{ flex: 1 }}>
                  <div style={{ fontSize: 12, fontWeight: 600, color: "var(--white)" }}>{eq.name}</div>
                  <div style={{ fontSize: 10, color: "var(--dim)", marginTop: 2 }}>{eq.model} · {eq.age}yr · {eq.runtime.toLocaleString()}h</div>
                  {eq.faults.length > 0 && <div style={{ fontSize: 9, color: "var(--rd-l)", fontWeight: 600, marginTop: 3 }}>{eq.faults.length} fault code{eq.faults.length > 1 ? "s" : ""}</div>}
                </div>
                <div style={{ textAlign: "right" }}>
                  <div style={{ fontFamily: "'JetBrains Mono',monospace", fontSize: 14, fontWeight: 700, color: hColor(eq.health) }}>{eq.health}</div>
                  <div style={{ width: 60, height: 4, background: "var(--border)", borderRadius: 2, marginTop: 4 }}>
                    <div className="hbar" style={{ width: `${eq.health}%`, background: hColor(eq.health) }} />
                  </div>
                  {createdWOs.includes(eq.id) && <div style={{ fontSize: 8, color: "var(--gn-l)", fontWeight: 700, marginTop: 3 }}>WO CREATED</div>}
                </div>
              </div>
            ))}
          </div>
        </div>

        {!selected ? (
          <div style={{ display: "flex", alignItems: "center", justifyContent: "center", background: "var(--surf)", border: "1px solid var(--border)", borderRadius: 10, color: "var(--muted)", fontSize: 13, flexDirection: "column", gap: 8 }}>
            {gw_ai_features_I.tool}<span>Select a unit to run predictive analysis</span>
          </div>
        ) : (
          <div className="panel-ai">
            <div className="ph">
              <div>
                <div className="pt">{selected.icon} {selected.name.toUpperCase()}</div>
                <div className="ps">{selected.model} · {selected.location} · Health {selected.health}/100</div>
              </div>
              <div style={{ display: "flex", gap: 8 }}>
                {analyses[selected.id] && !createdWOs.includes(selected.id) && (
                  <button className="btn btn-tl btn-sm" onClick={() => setCreatedWOs(p => [...p, selected.id])}>{gw_ai_features_I.plus} Create WO</button>
                )}
                {createdWOs.includes(selected.id) && <span className="badge b-gn">{gw_ai_features_I.check} WO Created</span>}
                <span className="badge b-pu">Claude Sonnet</span>
              </div>
            </div>
            <div style={{ padding: 16 }}>
              {selected.faults.length > 0 && (
                <div style={{ display: "flex", gap: 6, flexWrap: "wrap", marginBottom: 12 }}>
                  {selected.faults.map(f => <span key={f} className="badge b-rd" style={{ fontSize: 9 }}>{gw_ai_features_I.warn} {f}</span>)}
                </div>
              )}
              {loading[selected.id] && (
                <div style={{ padding: "24px 0", textAlign: "center" }}>
                  <div className="dots" style={{ justifyContent: "center" }}><span /><span /><span /></div>
                  <div style={{ fontSize: 11, color: "var(--muted)", marginTop: 8 }}>Analyzing service history and fault codes...</div>
                </div>
              )}
              {!loading[selected.id] && analyses[selected.id] && (
                <div style={{ fontSize: 12, lineHeight: 1.7, color: "var(--light)" }}>
                  <MD text={analyses[selected.id]} />
                </div>
              )}
              {!loading[selected.id] && !analyses[selected.id] && (
                <div style={{ padding: "24px 0", textAlign: "center", color: "var(--muted)", fontSize: 12 }}>
                  Click the equipment card to start AI analysis
                </div>
              )}
            </div>
          </div>
        )}
      </div>
    </div>
  );
}

