function AnomalyDetectionTab({ apiKey }) {
  if (!apiKey || !apiKey.startsWith("sk-")) return <NoKeyBanner />;
  const [selected, setSelected] = useState(null);
  const [analyses, setAnalyses] = useState({});
  const [loading, setLoading] = useState({});
  const [scanProgress, setScanProgress] = useState(null);
  const [approved, setApproved] = useState([]);
  const [flagged, setFlagged]   = useState([]);

  async function scanOne(inv) {
    setSelected(inv);
    if (analyses[inv.id]) return;
    setLoading(prev => ({ ...prev, [inv.id]: true }));
    try {
      const linesText = inv.lineItems.map(l =>
        `- ${l.desc}: ${l.qty} × $${l.unit} = $${l.total}${l.histAvg ? ` (our avg: $${l.histAvg})` : ""}`
      ).join("\n");
      const prompt = `Analyze this AP invoice for pricing anomalies, billing errors, or irregularities.

Vendor: ${inv.vendor} | Invoice: ${inv.inv} | Date: ${inv.date} | Total: $${inv.amount.toLocaleString()}

LINE ITEMS:
${linesText}

For each issue found, specify: the exact line item, the overcharge amount vs our historical average, severity (CRITICAL/WARNING/INFO), and a specific recommended action (dispute, request credit memo, ask for documentation, etc.).`;
      const reply = await callClaude([{ role: "user", content: prompt }], ANOMALY_SYSTEM, apiKey);
      setAnalyses(prev => ({ ...prev, [inv.id]: reply }));
    } catch (e) {
      setAnalyses(prev => ({ ...prev, [inv.id]: `**API Error:** ${e.message}` }));
    }
    setLoading(prev => ({ ...prev, [inv.id]: false }));
  }

  async function scanAll() {
    setScanProgress(0);
    for (let i = 0; i < AP_INVOICES.length; i++) {
      await scanOne(AP_INVOICES[i]);
      setScanProgress(i + 1);
    }
    setScanProgress(null);
  }

  const scannedCount = Object.keys(analyses).length;
  const totalValue   = AP_INVOICES.reduce((s, i) => s + i.amount, 0);

  return (
    <div>
      <div className="krow">
        <div className="kpi k-pu"><div className="kl">Invoices Queued</div><div className="kv">{AP_INVOICES.length}</div><div className="ks">Pending AP review</div></div>
        <div className="kpi k-gd"><div className="kl">Total Value</div><div className="kv" style={{ fontSize: 16 }}>{gw_ai_features_dollardollar(totalValue)}</div><div className="ks">Under AI audit</div></div>
        <div className="kpi k-tl"><div className="kl">Scanned</div><div className="kv">{scannedCount}</div><div className="ks">AI analysis done</div></div>
        <div className="kpi k-gn"><div className="kl">Approved</div><div className="kv">{approved.length}</div><div className="ks">Ready to pay</div></div>
      </div>

      <div style={{ display: "grid", gridTemplateColumns: "320px 1fr", gap: 14 }}>
        <div className="panel">
          <div className="ph">
            <div><div className="pt">AP INVOICE QUEUE</div><div className="ps">Click to scan · or run all</div></div>
            <button className="btn btn-pu btn-sm" onClick={scanAll} disabled={scanProgress !== null}>
              {gw_ai_features_I.scan} {scanProgress !== null ? `${scanProgress}/${AP_INVOICES.length}` : "Scan All"}
            </button>
          </div>
          {scanProgress !== null && (
            <div style={{ padding: "8px 14px", borderBottom: "1px solid var(--border)" }}>
              <div style={{ height: 3, background: "var(--border)", borderRadius: 2 }}>
                <div style={{ height: 3, background: "var(--pu-l)", borderRadius: 2, width: `${scanProgress / AP_INVOICES.length * 100}%`, transition: "width .3s" }} />
              </div>
            </div>
          )}
          <div style={{ padding: 10 }}>
            {AP_INVOICES.map(inv => (
              <div key={inv.id} style={{ background: selected?.id === inv.id ? "var(--tl-d)" : "var(--raised)", border: `1px solid ${selected?.id === inv.id ? "var(--tl-b)" : "var(--border)"}`, borderRadius: 8, padding: "11px 13px", marginBottom: 7, cursor: "pointer", transition: "all .12s" }} onClick={() => scanOne(inv)}>
                <div style={{ display: "flex", justifyContent: "space-between", marginBottom: 4 }}>
                  <div style={{ fontSize: 12, fontWeight: 600, color: "var(--white)" }}>{inv.vendor}</div>
                  <div style={{ fontFamily: "'JetBrains Mono',monospace", fontSize: 12, fontWeight: 700, color: "var(--gold-l)" }}>{gw_ai_features_dollardollar(inv.amount)}</div>
                </div>
                <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center" }}>
                  <div style={{ fontSize: 10, color: "var(--muted)" }}>{inv.inv} · {inv.date} · {inv.lineItems.length} lines</div>
                  {loading[inv.id] && <span style={{ fontSize: 9, color: "var(--pu-l)", fontWeight: 700 }}>SCANNING...</span>}
                  {analyses[inv.id] && !loading[inv.id] && <span className="badge b-tl" style={{ fontSize: 8 }}>{gw_ai_features_I.check} Scanned</span>}
                  {!analyses[inv.id] && !loading[inv.id] && <span style={{ fontSize: 9, color: "var(--muted)" }}>Click to scan</span>}
                </div>
                <div style={{ display: "flex", gap: 5, marginTop: 5 }}>
                  {approved.includes(inv.id) && <span className="badge b-gn" style={{ fontSize: 8 }}>{gw_ai_features_I.check} Approved</span>}
                  {flagged.includes(inv.id)   && <span className="badge b-rd" style={{ fontSize: 8 }}>{gw_ai_features_I.warn} Flagged</span>}
                </div>
              </div>
            ))}
          </div>
        </div>

        {!selected ? (
          <div style={{ display: "flex", alignItems: "center", justifyContent: "center", background: "var(--surf)", border: "1px solid var(--border)", borderRadius: 10, color: "var(--muted)", fontSize: 13, flexDirection: "column", gap: 8 }}>
            {gw_ai_features_I.scan}<span>Select an invoice to run AI anomaly detection</span>
          </div>
        ) : (
          <div className="panel-ai">
            <div className="ph">
              <div>
                <div className="pt">{selected.vendor.toUpperCase()} — {selected.inv}</div>
                <div className="ps">{selected.date} · {gw_ai_features_dollardollar(selected.amount)} · {selected.lineItems.length} line items</div>
              </div>
              <span className="badge b-pu">Claude Sonnet</span>
            </div>
            <div style={{ padding: 16 }}>
              <div className="panel" style={{ marginBottom: 14 }}>
                <div className="ph" style={{ padding: "9px 14px" }}><div className="pt" style={{ fontSize: 11 }}>LINE ITEMS</div></div>
                <table className="tbl">
                  <thead>
                    <tr><th>Description</th><th>Qty</th><th>Unit</th><th>Hist Avg</th><th>Total</th></tr>
                  </thead>
                  <tbody>
                    {selected.lineItems.map((l, i) => {
                      const over = l.histAvg && l.unit > l.histAvg * 1.10;
                      return (
                        <tr key={i} style={{ background: over ? "rgba(224,128,32,.04)" : "" }}>
                          <td style={{ fontSize: 11 }}>{l.desc}</td>
                          <td className="mono">{l.qty}</td>
                          <td className="mono" style={{ color: over ? "var(--am-l)" : "var(--light)" }}>{gw_ai_features_dollardollar(l.unit)}</td>
                          <td className="mono" style={{ color: "var(--muted)" }}>{l.histAvg ? gw_ai_features_dollardollar(l.histAvg) : "—"}</td>
                          <td className="mono" style={{ fontWeight: 600, color: "var(--gold-l)" }}>{gw_ai_features_dollardollar(l.total)}</td>
                        </tr>
                      );
                    })}
                    <tr className="tot">
                      <td colSpan={4} style={{ textAlign: "right", fontSize: 11 }}>Invoice Total</td>
                      <td className="mono">{gw_ai_features_dollardollar(selected.amount)}</td>
                    </tr>
                  </tbody>
                </table>
              </div>

              {loading[selected.id] && (
                <div style={{ padding: "20px 0", textAlign: "center" }}>
                  <div className="dots" style={{ justifyContent: "center" }}><span /><span /><span /></div>
                  <div style={{ fontSize: 11, color: "var(--muted)", marginTop: 8 }}>Cross-referencing against vendor pricing history...</div>
                </div>
              )}

              {!loading[selected.id] && analyses[selected.id] && (
                <div>
                  <div style={{ fontSize: 9, fontWeight: 700, letterSpacing: 2, color: "var(--muted)", textTransform: "uppercase", marginBottom: 10 }}>AI Audit Results</div>
                  <div style={{ fontSize: 12, lineHeight: 1.75, color: "var(--light)" }}>
                    <MD text={analyses[selected.id]} />
                  </div>
                  <div style={{ display: "flex", gap: 8, marginTop: 14 }}>
                    <button className="btn btn-rd btn-sm" onClick={() => { if (!flagged.includes(selected.id)) setFlagged(p => [...p, selected.id]); }}>{gw_ai_features_I.warn} Flag — Hold Payment</button>
                    <button className="btn btn-ghost btn-sm">{gw_ai_features_I.dl} Export Audit</button>
                    <button className="btn btn-gn btn-sm" onClick={() => { if (!approved.includes(selected.id)) setApproved(p => [...p, selected.id]); }}>{gw_ai_features_I.check} Approve Invoice</button>
                  </div>
                </div>
              )}
            </div>
          </div>
        )}
      </div>
    </div>
  );
}

