const PROPOSAL_SYSTEM = `You are a senior BD writer for Apex MEP Services LLC, a top-tier MEP contractor in Phoenix AZ. Write polished, persuasive client-facing proposals that win contracts. Be specific, professional, and focused on value — not generic. Company: Founded 2010, 42 employees, NATE-certified, licensed AZ/NV/CA, $8M revenue, 200+ completed MEP projects in healthcare, education, commercial real estate. RESPOND with the full proposal body in markdown. Use ## for section headers. Under 600 words. Do NOT include cover page or line-item pricing table — those are handled separately.`;

const EMPHASIS_OPTIONS = [
  {id:"value",label:"Value & ROI"},{id:"timeline",label:"Timeline certainty"},
  {id:"safety",label:"Safety record"},{id:"disruption",label:"Minimal disruption"},
  {id:"warranty",label:"Warranty & support"},{id:"certs",label:"Certifications"},
];

function ProposalWriterTab({ apiKey }) {
  if (!apiKey || !apiKey.startsWith("sk-")) return <NoKeyBanner />;
  const [est, setEst] = useState(null);
  const [tone, setTone] = useState("professional");
  const [emphasis, setEmphasis] = useState(["value","timeline"]);
  const [proposal, setProposal] = useState(null);
  const [loading, setLoading] = useState(false);
  const [copied, setCopied] = useState(false);

  function toggleEmp(id) { setEmphasis(p => p.includes(id) ? p.filter(e=>e!==id) : [...p,id]); }

  async function generate() {
    if (!est) return;
    setLoading(true); setProposal(null);
    try {
      const empStr = emphasis.map(id=>EMPHASIS_OPTIONS.find(o=>o.id===id)?.label).filter(Boolean).join(", ");
      const prompt = `Write a proposal body for this estimate.\nTone: ${tone}\nKey emphasis: ${empStr}\n\nCLIENT: ${est.client}\nCONTACT: ${est.contact}\nPROJECT: ${est.name}\nSCOPE: ${est.scope}\nCONTRACT VALUE: $${est.totalContract.toLocaleString()}\nTIMELINE: ${est.timeline}\nPAYMENT TERMS: ${est.terms}\nWARRANTY: ${est.warranty}\nDIFFERENTIATORS: ${est.differentiators.join(", ")}\n\nCOST SUMMARY:\n- Equipment: $${est.lineItems.filter(l=>l.cat==="Equipment").reduce((s,l)=>s+l.total,0).toLocaleString()}\n- Materials: $${est.lineItems.filter(l=>l.cat==="Materials").reduce((s,l)=>s+l.total,0).toLocaleString()}\n- Labor: $${est.lineItems.filter(l=>l.cat==="Labor").reduce((s,l)=>s+l.total,0).toLocaleString()}\n- Other: $${est.lineItems.filter(l=>l.cat==="Other").reduce((s,l)=>s+l.total,0).toLocaleString()}\n\nSections to include: Project Understanding, Our Approach, Why Apex MEP, Investment Summary, Next Steps. End with a clear call to action.`;
      const reply = await callClaude([{role:"user",content:prompt}], PROPOSAL_SYSTEM, apiKey);
      setProposal(reply);
    } catch(e) { setProposal("Error: "+e.message); }
    setLoading(false);
  }

  function renderProp(text) {
    return text.split("\n").map((line,i)=>{
      if(!line.trim()) return <div key={i} style={{height:7}}/>;
      if(line.startsWith("## ")) return <h3 key={i} style={{fontFamily:"'Bebas Neue',sans-serif",letterSpacing:2,fontSize:14,color:"var(--tl-l)",margin:"16px 0 5px",borderBottom:"1px solid var(--tl-d)",paddingBottom:3}}>{line.slice(3)}</h3>;
      if(line.startsWith("# ")) return <h2 key={i} style={{fontFamily:"'Bebas Neue',sans-serif",letterSpacing:2,fontSize:17,color:"var(--white)",margin:"10px 0 8px"}}>{line.slice(2)}</h2>;
      if(line.startsWith("- ")||line.startsWith("• ")) return <li key={i} style={{fontSize:11,color:"var(--light)",marginBottom:4,marginLeft:16}}>{line.replace(/^[-•]\s/,"")}</li>;
      const bold = line.replace(/\*\*(.*?)\*\*/g,"<strong>$1</strong>").replace(/\*(.*?)\*/g,"<em>$1</em>");
      return <p key={i} style={{fontSize:12,color:"var(--bright)",lineHeight:1.75,marginBottom:4}} dangerouslySetInnerHTML={{__html:bold}}/>;
    });
  }

  const totalOpp = gw_ai_features_ESTIMATES.reduce((s,e)=>s+e.totalContract,0);

  return (
    <div>
      <div className="krow">
        <div className="kpi k-tl"><div className="kl">Estimates Ready</div><div className="kv">{gw_ai_features_ESTIMATES.length}</div><div className="ks">To convert</div></div>
        <div className="kpi k-pu"><div className="kl">Total Opportunity</div><div className="kv" style={{fontSize:14}}>{gw_ai_features_dollardollar(totalOpp)}</div><div className="ks">Combined value</div></div>
        <div className="kpi k-gn"><div className="kl">Generated</div><div className="kv">{proposal?1:0}</div><div className="ks">This session</div></div>
        <div className="kpi k-gd"><div className="kl">Avg Win Rate</div><div className="kv">34%</div><div className="ks">MEP commercial</div></div>
      </div>
      <div style={{display:"grid",gridTemplateColumns:"290px 1fr",gap:14}}>
        <div>
          <div className="panel" style={{marginBottom:10}}>
            <div className="ph"><div className="pt">SELECT ESTIMATE</div></div>
            <div style={{padding:10}}>
              {gw_ai_features_ESTIMATES.map(e=>(
                <div key={e.id} onClick={()=>{setEst(e);setProposal(null);}} style={{background:est?.id===e.id?"var(--tl-d)":"var(--raised)",border:`1px solid ${est?.id===e.id?"var(--tl-b)":"var(--border)"}`,borderRadius:8,padding:"11px 13px",marginBottom:8,cursor:"pointer",transition:"all .12s"}}>
                  <div style={{fontSize:11,fontWeight:700,color:"var(--white)",marginBottom:3}}>{e.name}</div>
                  <div style={{fontSize:10,color:"var(--muted)",marginBottom:5}}>{e.id} · valid thru {e.validThrough}</div>
                  <div style={{display:"flex",justifyContent:"space-between"}}>
                    <span style={{fontSize:10,color:"var(--dim)"}}>{e.client}</span>
                    <span style={{fontFamily:"'JetBrains Mono',monospace",fontSize:12,fontWeight:700,color:"var(--gold-l)"}}>{gw_ai_features_dollardollar(e.totalContract)}</span>
                  </div>
                </div>
              ))}
            </div>
          </div>
          <div className="panel">
            <div className="ph"><div className="pt">PROPOSAL SETTINGS</div></div>
            <div style={{padding:12,display:"flex",flexDirection:"column",gap:10}}>
              <div className="fg">
                <label className="fl">Tone</label>
                <select className="fsel" value={tone} onChange={e=>setTone(e.target.value)}>
                  {["professional","technical","relationship-focused","competitive"].map(t=>(
                    <option key={t} value={t}>{t.charAt(0).toUpperCase()+t.slice(1)}</option>
                  ))}
                </select>
              </div>
              <div className="fg">
                <label className="fl">Emphasize</label>
                <div style={{display:"flex",flexWrap:"wrap",gap:5,marginTop:2}}>
                  {EMPHASIS_OPTIONS.map(o=>(
                    <span key={o.id} onClick={()=>toggleEmp(o.id)} style={{fontSize:10,padding:"3px 9px",borderRadius:12,cursor:"pointer", fontWeight:emphasis.includes(o.id)?700:400, background:emphasis.includes(o.id)?"var(--tl-d)":"var(--raised)", border:`1px solid ${emphasis.includes(o.id)?"var(--tl-b)":"var(--border)"}`, color:emphasis.includes(o.id)?"var(--tl-l)":"var(--muted)",transition:"all .12s"}}>
                      {o.label}
                    </span>
                  ))}
                </div>
              </div>
 <button className="btn btn-pu" style={{width:"100%",justifyContent:"center"}} onClick={generate} disabled={!est||loading}>
                {loading ? "Generating..." : <>{gw_ai_features_I.brain} Generate Proposal</>}
              </button>
            </div>
          </div>
        </div>
        <div>
          {!est && <div style={{display:"flex",flexDirection:"column",alignItems:"center",justifyContent:"center",height:440,color:"var(--muted)",fontSize:13,background:"var(--surf)",border:"1px solid var(--border)",borderRadius:10,gap:8}}>📄 <span>Select an estimate to generate a proposal</span></div>}
          {est && !proposal && !loading && (
            <div style={{display:"flex",flexDirection:"column",alignItems:"center",justifyContent:"center",height:440,color:"var(--muted)",fontSize:12,background:"var(--surf)",border:"1px solid var(--border)",borderRadius:10,gap:10,textAlign:"center",padding:24}}>
              <div style={{fontSize:32}}>📝</div>
              <div style={{fontSize:13,fontWeight:600,color:"var(--light)"}}>Ready to write proposal for</div>
              <div style={{fontSize:12,color:"var(--tl-l)",fontWeight:700}}>{est.name}</div>
              <div style={{fontSize:11,color:"var(--muted)",maxWidth:340,lineHeight:1.7}}>Set tone and emphasis options, then click Generate.</div>
            </div>
          )}
          {loading && (
            <div style={{display:"flex",flexDirection:"column",alignItems:"center",justifyContent:"center",height:440,background:"var(--surf)",border:"1px solid var(--tl-b)",borderRadius:10,gap:10,boxShadow:"var(--ai-glow)"}}>
              <div className="loading-dots"><span/><span/><span/></div>
              <div style={{fontSize:11,color:"var(--tl-l)"}}>Writing proposal for {est?.client}...</div>
            </div>
          )}
          {proposal && !loading && (
            <div className="panel-ai">
              <div className="ph">
                <div>
                  <div className="pt">{est?.client?.toUpperCase()} — PROPOSAL DRAFT</div>
                  <div className="ps">{est?.id} · {gw_ai_features_dollardollar(est?.totalContract)} · Tone: {tone}</div>
                </div>
                <div style={{display:"flex",gap:6}}>
                  <button className="btn btn-ghost btn-sm" onClick={()=>{navigator.clipboard.writeText(proposal);setCopied(true);setTimeout(()=>setCopied(false),2000);}}>{copied?<>{gw_ai_features_I.check} Copied</>:<>{gw_ai_features_I.dl} Copy</>}</button>
                  <button className="btn btn-tl btn-sm" onClick={generate}>{gw_ai_features_I.refresh} Regen</button>
                </div>
              </div>
              <div style={{padding:"16px 20px",maxHeight:540,overflowY:"auto"}}>{renderProp(proposal)}</div>
            </div>
          )}
        </div>
      </div>
    </div>
  );
}

// ╔==================================================================╗
// ║  TAB 6 — JOB COMPLETION FORECASTING  (6.2 P2)                   ║
// ╚==================================================================╝

const ACTIVE_JOBS = [
  {id:"JOB-2026-001",name:"Scottsdale USD — HVAC Replacement",client:"Scottsdale Unified School District",pm:"Tyler Reynolds",type:"HVAC",contract:480000,start:"2025-12-01",plannedEnd:"2026-03-31",pct:67,budHours:1800,actHours:1280,bac:312000,ctd:226400,openCommit:44000,invoiced:321600,pendingCOs:2,coValue:18400,risks:["Crane access restricted to weekends","2 units back-ordered, ETA Mar 15"],milestones:[{n:"Demo complete",planned:"2026-01-15",actual:"2026-01-17",s:"done"},{n:"Units delivered",planned:"2026-02-01",actual:null,s:"delayed"},{n:"Installation complete",planned:"2026-03-01",actual:null,s:"at-risk"},{n:"Commissioning",planned:"2026-03-25",actual:null,s:"pending"},{n:"Final inspection",planned:"2026-03-31",actual:null,s:"pending"}]},
  {id:"JOB-2026-002",name:"Banner Health — Plumbing Retrofit",client:"Banner Health Systems",pm:"Sarah Kim",type:"Plumbing",contract:280000,start:"2026-01-10",plannedEnd:"2026-04-30",pct:45,budHours:1200,actHours:508,bac:182000,ctd:79100,openCommit:22000,invoiced:126000,pendingCOs:1,coValue:8200,risks:["ICRA infection control sign-off required daily"],milestones:[{n:"Floor 3 complete",planned:"2026-02-28",actual:"2026-02-20",s:"done"},{n:"Floor 4 complete",planned:"2026-03-31",actual:null,s:"on-track"},{n:"Floor 5 complete",planned:"2026-04-20",actual:null,s:"pending"},{n:"Pressure test & sign-off",planned:"2026-04-28",actual:null,s:"pending"}]},
  {id:"JOB-2026-003",name:"Maricopa County — Electrical Upgrade",client:"Maricopa County Facilities",pm:"Tyler Reynolds",type:"Electrical",contract:340000,start:"2026-01-20",plannedEnd:"2026-05-15",pct:30,budHours:1600,actHours:510,bac:221000,ctd:68800,openCommit:58000,invoiced:102000,pendingCOs:0,coValue:0,risks:["Owner-supplied switchgear delivery unclear","Prevailing wage — certified payroll required"],milestones:[{n:"Panel demo",planned:"2026-02-15",actual:"2026-02-18",s:"done"},{n:"Rough-in complete",planned:"2026-03-30",actual:null,s:"on-track"},{n:"Gear installed",planned:"2026-04-15",actual:null,s:"at-risk"},{n:"Inspection & close",planned:"2026-05-10",actual:null,s:"pending"}]},
];

const FORECAST_SYSTEM = `You are a construction project controls analyst for Apex MEP Services specializing in earned value management (EVM) for MEP contractors. Be specific with numbers. Format dollar amounts with $ and commas. Under 350 words. Use ## for section headers.`;

function JobForecastTab({ apiKey }) {
  if (!apiKey || !apiKey.startsWith("sk-")) return <NoKeyBanner />;
  const [sel, setSel] = useState(null);
  const [forecasts, setForecasts] = useState({});
  const [loading, setLoading] = useState({});

  async function runForecast(job) {
    setSel(job);
    if (forecasts[job.id]) return;
    setLoading(p=>({...p,[job.id]:true}));
    try {
      const prompt = `Analyze this job and provide EVM completion forecast.\n\nJOB: ${job.name}\nType: ${job.type} | PM: ${job.pm}\nContract (BAC): $${job.contract.toLocaleString()}\nStart: ${job.start} | Planned End: ${job.plannedEnd}\n% Complete: ${job.pct}%\nBudgeted Hours: ${job.budHours} | Actual Hours: ${job.actHours}\nBudget (BAC): $${job.bac.toLocaleString()} | Cost to Date (ACWP): $${job.ctd.toLocaleString()}\nOpen Commitments: $${job.openCommit.toLocaleString()}\nInvoiced: $${job.invoiced.toLocaleString()}\nPending COs: ${job.pendingCOs} valued at $${job.coValue.toLocaleString()}\nRisks: ${job.risks.join("; ")}\nMilestones: ${job.milestones.map(m=>`${m.n}: ${m.s}`).join(", ")}\n\nProvide: 1) EVM Metrics (BCWP, ACWP, BCWS, CPI, SPI with interpretation) 2) Forecast (EAC, ETC, projected completion date, VAC) 3) Billing gap analysis (invoiced vs cost to date) 4) Top 3 risks with dollar/day estimates 5) Recommended PM actions this week`;
      const reply = await callClaude([{role:"user",content:prompt}], FORECAST_SYSTEM, apiKey);
      setForecasts(p=>({...p,[job.id]:reply}));
    } catch(e) { setForecasts(p=>({...p,[job.id]:"Error: "+e.message})); }
    setLoading(p=>({...p,[job.id]:false}));
  }

  const sColor = s => s==="done"?"var(--gn-l)":s==="on-track"?"var(--tl-l)":s==="at-risk"?"var(--am-l)":s==="delayed"?"var(--rd-l)":"var(--muted)";

  function renderFC(text) {
    return text.split("\n").map((line,i)=>{
      if(!line.trim()) return <div key={i} style={{height:5}}/>;
      if(line.match(/^##+ /)) return <h3 key={i} style={{fontFamily:"'Bebas Neue',sans-serif",letterSpacing:2,fontSize:13,color:"var(--tl-l)",margin:"13px 0 4px",borderBottom:"1px solid var(--tl-d)",paddingBottom:3}}>{line.replace(/^#+\s/,"")}</h3>;
      if(line.startsWith("- ")||line.startsWith("• ")) return <li key={i} style={{fontSize:11,color:"var(--light)",marginBottom:3,marginLeft:14}}>{line.replace(/^[-•]\s/,"")}</li>;
      const bold = line.replace(/\*\*(.*?)\*\*/g,"<strong>$1</strong>");
      return <p key={i} style={{fontSize:11,color:"var(--bright)",lineHeight:1.7,marginBottom:3}} dangerouslySetInnerHTML={{__html:bold}}/>;
    });
  }

  const totalContract = ACTIVE_JOBS.reduce((s,j)=>s+j.contract,0);
  const totalInvoiced = ACTIVE_JOBS.reduce((s,j)=>s+j.invoiced,0);
  const atRisk = ACTIVE_JOBS.filter(j=>j.milestones.some(m=>m.s==="at-risk"||m.s==="delayed")).length;

  return (
    <div>
      <div className="krow">
        <div className="kpi k-tl"><div className="kl">Active Jobs</div><div className="kv">{ACTIVE_JOBS.length}</div><div className="ks">Under contract</div></div>
        <div className="kpi k-gd"><div className="kl">Total Backlog</div><div className="kv" style={{fontSize:14}}>{gw_ai_features_dollardollar(totalContract)}</div><div className="ks">Combined contract</div></div>
        <div className="kpi k-sl"><div className="kl">Billed to Date</div><div className="kv" style={{fontSize:14}}>{gw_ai_features_dollardollar(totalInvoiced)}</div><div className="ks">{Math.round(totalInvoiced/totalContract*100)}% of backlog</div></div>
        <div className="kpi k-am"><div className="kl">At-Risk Jobs</div><div className="kv">{atRisk}</div><div className="ks">Milestone slippage</div></div>
      </div>
      <div style={{display:"grid",gridTemplateColumns:"290px 1fr",gap:14}}>
        <div>
          {ACTIVE_JOBS.map(job=>{
            const cpi = (job.pct/100*job.bac)/job.ctd;
            const cc = cpi>=1?"var(--gn-l)":cpi>=0.90?"var(--am-l)":"var(--rd-l)";
            return (
              <div key={job.id} onClick={()=>runForecast(job)} style={{background:sel?.id===job.id?"var(--tl-d)":"var(--raised)",border:`1px solid ${sel?.id===job.id?"var(--tl-b)":"var(--border)"}`,borderRadius:9,padding:"12px 14px",marginBottom:9,cursor:"pointer",transition:"all .12s"}}>
                <div style={{display:"flex",justifyContent:"space-between",alignItems:"flex-start",marginBottom:4}}>
                  <div style={{fontSize:12,fontWeight:700,color:"var(--white)",flex:1,paddingRight:8}}>{job.name}</div>
                  {loading[job.id] && <span style={{fontSize:9,color:"var(--pu-l)",fontWeight:700,flexShrink:0}}>RUNNING...</span>}
                  {forecasts[job.id] && !loading[job.id] && <span className="badge b-tl" style={{fontSize:8,flexShrink:0}}>{gw_ai_features_I.check}</span>}
                </div>
                <div style={{fontSize:10,color:"var(--muted)",marginBottom:7}}>{job.type} · PM: {job.pm}</div>
                <div style={{display:"flex",gap:8,alignItems:"center",marginBottom:5}}>
                  <div style={{flex:1,height:4,background:"var(--border)",borderRadius:2}}>
                    <div style={{height:4,borderRadius:2,background:"var(--tl-l)",width:`${job.pct}%`}}/>
                  </div>
                  <span style={{fontFamily:"'JetBrains Mono',monospace",fontSize:10,color:"var(--tl-l)",fontWeight:700,flexShrink:0}}>{job.pct}%</span>
                </div>
                <div style={{display:"flex",justifyContent:"space-between"}}>
                  <span style={{fontSize:10,color:"var(--muted)"}}>CPI: <span style={{color:cc,fontWeight:700}}>{cpi.toFixed(2)}</span></span>
                  <span style={{fontFamily:"'JetBrains Mono',monospace",fontSize:10,color:"var(--gold-l)"}}>{gw_ai_features_dollardollar(job.contract)}</span>
                </div>
              </div>
            );
          })}
        </div>
        <div>
          {!sel && <div style={{display:"flex",flexDirection:"column",alignItems:"center",justifyContent:"center",height:420,color:"var(--muted)",fontSize:13,background:"var(--surf)",border:"1px solid var(--border)",borderRadius:10,gap:8}}>📊 <span>Select a job to run completion forecast</span></div>}
          {sel && (
            <div className="panel-ai">
              <div className="ph">
                <div><div className="pt">{sel.name.toUpperCase()}</div><div className="ps">{sel.id} · {sel.pct}% complete · {gw_ai_features_dollardollar(sel.contract)}</div></div>
                <span className="badge b-pu">{gw_ai_features_I.brain} EVM</span>
              </div>
              <div style={{padding:14}}>
                <div style={{display:"flex",gap:7,flexWrap:"wrap",marginBottom:12}}>
                  {sel.milestones.map(m=>(
                    <div key={m.n} style={{background:"var(--raised)",border:`1px solid ${m.s==="done"?"rgba(31,190,112,.2)":m.s==="at-risk"||m.s==="delayed"?"rgba(224,48,80,.2)":"var(--border)"}`,borderRadius:7,padding:"6px 9px",minWidth:100}}>
                      <div style={{fontSize:8,fontWeight:700,letterSpacing:1.5,textTransform:"uppercase",color:sColor(m.s),marginBottom:2}}>{m.s}</div>
                      <div style={{fontSize:11,color:"var(--bright)",fontWeight:500}}>{m.n}</div>
                      <div style={{fontSize:9,color:"var(--muted)",marginTop:1}}>{m.actual||m.planned}</div>
                    </div>
                  ))}
                </div>
                {loading[sel.id] && <div style={{padding:"22px 0",textAlign:"center"}}><div className="loading-dots" style={{justifyContent:"center"}}><span/><span/><span/></div><div style={{fontSize:11,color:"var(--muted)",marginTop:8}}>Running EVM calculations...</div></div>}
                {forecasts[sel.id] && !loading[sel.id] && <div>{renderFC(forecasts[sel.id])}</div>}
              </div>
            </div>
          )}
        </div>
      </div>
    </div>
  );
}

// ╔==================================================================╗
// ║  TAB 7 — VOICE-TO-WORK-ORDER  (6.2 P2)                          ║
// ║  Live mic → Web Speech API → Claude structures → WO draft        ║
// ╚==================================================================╝

const DEMO_TRANSCRIPTS = [
  "This is Mike at the Scottsdale USD campus, unit three on the roof. Compressor is making a grinding noise on startup. Checked refrigerant pressure — suction side is only 60 PSI. Looks like a slow leak in the line set. gw_ai_features_I pulled the disconnect and tagged it out. Building still has cooling from units one and two. Going to need a leak check kit and about two pounds of R-410A minimum. Probably four hours to find and repair the leak and recharge. Flagging as high priority.",
  "Hey it's Jenna at Banner Health, third floor mechanical room. Completed the monthly PM on the circulation pumps. Checked belts, lubed the bearings on pump two, verified flow rates. Everything looks good except pump three has a slight vibration — not bad yet but gw_ai_features_I would schedule a bearing inspection before the next PM cycle. gw_ai_features_I used one quart of bearing grease and one drive belt. Total time on site two and a half hours.",
  "Dave here, emergency call at Mesa Industrial. Total loss of power to the east wing panel. Main breaker tripped and will not reset. Smell of something burnt near the switchgear. gw_ai_features_I have locked out the panel — do not energize. This is a live safety issue. Occupants are evacuated. We need an electrician out here within the hour.",
];

const WO_SYSTEM = `You are a field dispatch coordinator for Apex MEP Services. A technician has dictated field notes. Convert to a structured work order. Respond ONLY with valid JSON, no markdown, no explanation:
{"type":"","priority":"","location":"","equipment":"","problem":"","workPerformed":"","partsUsed":"","followUp":"","estHoursRemaining":"","safetyNotes":"","suggestedTitle":""}
Valid types: Service Call, Repair, PM, Install, Emergency. Valid priorities: Emergency, High, Normal, Low.`;

function VoiceToWOTab({ apiKey }) {
  if (!apiKey || !apiKey.startsWith("sk-")) return <NoKeyBanner />;
  const [recording, setRecording] = useState(false);
  const [transcript, setTranscript] = useState("");
  const [interim, setInterim] = useState("");
  const [processing, setProcessing] = useState(false);
  const [wo, setWo] = useState(null);
  const [saved, setSaved] = useState([]);
  const [err, setErr] = useState(null);
  const speechSupported = "webkitSpeechRecognition" in window || "SpeechRecognition" in window;
  const recogRef = useRef(null);

  function startRec() {
    const SR = window.SpeechRecognition || window.webkitSpeechRecognition;
    if (!SR) { setErr("Speech recognition requires Chrome or Edge."); return; }
    const r = new SR();
    r.continuous = true; r.interimResults = true; r.lang = "en-US";
    r.onresult = ev => {
      let fin = "", int = "";
      for (let i=0; i<ev.results.length; i++) {
        if (ev.results[i].isFinal) fin += ev.results[i][0].transcript+" ";
        else int += ev.results[i][0].transcript;
      }
      if (fin) setTranscript(p=>p+fin);
      setInterim(int);
    };
    r.onerror = e => { setErr("Mic error: "+e.error); setRecording(false); };
    r.onend = () => { setRecording(false); setInterim(""); };
    recogRef.current = r;
    r.start();
    setRecording(true); setErr(null); setWo(null);
  }

  function stopRec() { recogRef.current?.stop(); setRecording(false); setInterim(""); }

  async function process() {
    if (!transcript.trim()) return;
    setProcessing(true); setWo(null); setErr(null);
    try {
      const reply = await callClaude([{role:"user",content:`Convert this field dictation to a work order:\n\n${transcript}`}], WO_SYSTEM, apiKey);
      const clean = reply.replace(/```json/g,"").replace(/```/g,"").trim();
      setWo(JSON.parse(clean));
    } catch(e) { setErr("Parse error: "+e.message); }
    setProcessing(false);
  }

  function saveWO() {
    if (!wo) return;
    setSaved(p=>[{id:`WO-${Date.now().toString().slice(-6)}`, ...wo, createdAt:new Date().toLocaleTimeString()},...p]);
    setTranscript(""); setWo(null);
  }

  const pBadge = p => p==="Emergency"?"b-rd":p==="High"?"b-am":p==="Normal"?"b-tl":"b-st";

  return (
    <div>
      <div className="krow">
        <div className="kpi k-tl"><div className="kl">Speech API</div><div className="kv" style={{fontSize:11,paddingTop:5}}>{speechSupported?"Available":"Unavailable"}</div><div className="ks">{speechSupported?"Chrome/Edge":"Browser issue"}</div></div>
        <div className="kpi k-pu"><div className="kl">Words Captured</div><div className="kv">{transcript?transcript.split(" ").filter(Boolean).length:0}</div><div className="ks">In current session</div></div>
        <div className="kpi k-gn"><div className="kl">WOs Saved</div><div className="kv">{saved.length}</div><div className="ks">This session</div></div>
        <div className="kpi k-gd"><div className="kl">Model</div><div className="kv" style={{fontSize:11,paddingTop:5}}>Sonnet</div><div className="ks">Structuring dictation</div></div>
      </div>
      <div style={{display:"grid",gridTemplateColumns:"1fr 360px",gap:14}}>
        <div>
          <div className="panel-ai" style={{marginBottom:12}}>
            <div className="ph"><div><div className="pt">FIELD DICTATION RECORDER</div><div className="ps">Press record, dictate findings, then generate work order</div></div></div>
            <div style={{padding:16}}>
              <div style={{display:"flex",justifyContent:"center",marginBottom:14}}>
                <button onClick={recording?stopRec:startRec} disabled={!speechSupported} style={{width:76,height:76,borderRadius:"50%",border:`3px solid ${recording?"var(--rd-l)":"var(--tl-b)"}`,background:recording?"var(--rd-d)":"var(--tl-d)",cursor:"pointer",display:"flex",alignItems:"center",justifyContent:"center",fontSize:26,transition:"all .2s",boxShadow:recording?"0 0 24px rgba(224,48,80,.4)":"var(--ai-glow)"}}>
                  {recording?"⏹":"🎤"}
                </button>
              </div>
              {recording && (
                <div style={{textAlign:"center",marginBottom:12}}>
                  <div style={{display:"flex",justifyContent:"center",gap:3,marginBottom:5}}>
                    {Array.from({length:8},(_,i)=>(
                      <div key={i} style={{width:3,borderRadius:2,background:"var(--rd-l)",animation:`voiceBar 0.${6+i%3}s infinite alternate`,height:8+Math.sin(i)*8}}/>
                    ))}
                  </div>
                  <div style={{fontSize:11,color:"var(--rd-l)",fontWeight:700,letterSpacing:2}}>● RECORDING</div>
                </div>
              )}
              <div style={{background:"var(--raised)",border:`1px solid ${recording?"var(--rd-d)":"var(--border)"}`,borderRadius:8,padding:12,minHeight:90,fontSize:12,color:"var(--bright)",lineHeight:1.7,marginBottom:10}}>
                {transcript||<span style={{color:"var(--muted)"}}>Dictation appears here as you speak...</span>}
                {interim && <span style={{color:"var(--tl-l)",opacity:.6}}>{interim}</span>}
              </div>
              <textarea className="fta" rows={3} placeholder="Or type/paste field notes..." value={transcript} onChange={e=>setTranscript(e.target.value)} style={{marginBottom:10,resize:"vertical"}}/>
              {err && <div className="alert a-rd" style={{marginBottom:10}}>{gw_ai_features_I.warn} {err}</div>}
              <div style={{display:"flex",gap:8}}>
                <button className="btn btn-ghost btn-sm" onClick={()=>{setTranscript("");setWo(null);}} disabled={!transcript}>Clear</button>
                <button className="btn btn-pu" style={{flex:1,justifyContent:"center"}} onClick={process} disabled={!transcript||processing}>
                  {processing?"Processing...": <>{gw_ai_features_I.brain} Generate Work Order</>}
                </button>
              </div>
            </div>
          </div>
          <div className="panel">
            <div className="ph"><div><div className="pt">DEMO TRANSCRIPTS</div><div className="ps">Click to load a sample field dictation</div></div></div>
            <div style={{padding:10}}>
              {DEMO_TRANSCRIPTS.map((t,i)=>(
                <div key={i} onClick={()=>{setTranscript(t);setWo(null);setErr(null);}}
                  style={{background:"var(--raised)",border:"1px solid var(--border)",borderRadius:7,padding:"9px 12px",marginBottom:7,cursor:"pointer",fontSize:11,color:"var(--dim)",lineHeight:1.6,transition:"border-color .12s"}}
                  onMouseEnter={e=>e.currentTarget.style.borderColor="var(--tl-b)"}
                  onMouseLeave={e=>e.currentTarget.style.borderColor="var(--border)"}>
                  <div style={{fontSize:9,fontWeight:700,letterSpacing:2,color:"var(--muted)",textTransform:"uppercase",marginBottom:3}}>Sample {i+1}</div>
                  {t.substring(0,130)}...
                </div>
              ))}
            </div>
          </div>
        </div>
        <div>
          {!wo && !processing && (
            <div style={{display:"flex",flexDirection:"column",alignItems:"center",justifyContent:"center",height:380,color:"var(--muted)",fontSize:12,background:"var(--surf)",border:"1px solid var(--border)",borderRadius:10,gap:8,textAlign:"center",padding:20}}>
              <div style={{fontSize:32}}>📋</div>
              <div style={{color:"var(--light)"}}>Structured WO appears here</div>
              <div style={{fontSize:11}}>Record or paste notes, then click Generate</div>
            </div>
          )}
          {processing && (
            <div style={{display:"flex",flexDirection:"column",alignItems:"center",justifyContent:"center",height:380,background:"var(--surf)",border:"1px solid var(--tl-b)",borderRadius:10,gap:10,boxShadow:"var(--ai-glow)"}}>
              <div className="loading-dots"><span/><span/><span/></div>
              <div style={{fontSize:11,color:"var(--tl-l)"}}>Structuring field notes...</div>
            </div>
          )}
          {wo && !processing && (
            <div className="panel-ai">
              <div className="ph">
                <div><div className="pt" style={{fontSize:12}}>{wo.suggestedTitle||"WORK ORDER DRAFT"}</div><div className="ps">{wo.type} · {wo.location}</div></div>
                <span className={"badge "+(pBadge(wo.priority))}>{wo.priority}</span>
              </div>
              <div style={{padding:13,display:"flex",flexDirection:"column",gap:9}}>
                {[["Location",wo.location,"var(--bright)"],["Equipment",wo.equipment,"var(--bright)"],["Problem",wo.problem,"var(--bright)"],["Work Performed",wo.workPerformed,"var(--light)"],["Parts Used",wo.partsUsed,"var(--light)"],["Follow-Up",wo.followUp,"var(--am-l)"],["Est Hours Remaining",wo.estHoursRemaining,"var(--tl-l)"],["Safety Notes",wo.safetyNotes,"var(--rd-l)"]].map(([lbl,val,clr])=> val && val!=="N/A" && val!=="" && (
                  <div key={lbl} style={{borderBottom:"1px solid rgba(255,255,255,.04)",paddingBottom:8}}>
                    <div style={{fontSize:8,fontWeight:700,letterSpacing:2,textTransform:"uppercase",color:"var(--muted)",marginBottom:2}}>{lbl}</div>
                    <div style={{fontSize:11,color:clr,lineHeight:1.6}}>{val}</div>
                  </div>
                ))}
                <div style={{display:"flex",gap:8,marginTop:4}}>
                  <button className="btn btn-ghost btn-sm" style={{flex:1,justifyContent:"center"}} onClick={()=>setWo(null)}>Discard</button>
                  <button className="btn btn-tl" style={{flex:2,justifyContent:"center"}} onClick={saveWO}>{gw_ai_features_I.check} Save WO</button>
                </div>
              </div>
            </div>
          )}
          {saved.length > 0 && (
            <div className="panel" style={{marginTop:10}}>
              <div className="ph"><div><div className="pt">SAVED WORK ORDERS</div><div className="ps">{saved.length} created</div></div></div>
              <div style={{padding:10}}>
                {saved.map(w=>(
                  <div key={w.id} style={{background:"var(--raised)",border:"1px solid var(--border)",borderRadius:7,padding:"9px 12px",marginBottom:7}}>
                    <div style={{display:"flex",justifyContent:"space-between",marginBottom:3}}>
                      <span style={{fontFamily:"'JetBrains Mono',monospace",fontSize:10,color:"var(--tl-l)",fontWeight:700}}>{w.id}</span>
                      <span className={"badge "+(pBadge(w.priority))} style={{fontSize:8}}>{w.priority}</span>
                    </div>
                    <div style={{fontSize:11,fontWeight:600,color:"var(--white)",marginBottom:2}}>{w.suggestedTitle}</div>
                    <div style={{fontSize:10,color:"var(--muted)"}}>{w.location} · {w.type} · {w.createdAt}</div>
                  </div>
                ))}
              </div>
            </div>
          )}
        </div>
      </div>
    </div>
  );
}

// ╔==============================================================╗
// ║  ROOT                                                        ║
// ╚==============================================================╝

// ==================================================================
// CUSTOMER CHURN PREDICTION  (6.2 P3)
// MATERIALS PRICE INTELLIGENCE  (6.2 P3)
// Both injected as new tabs into groundwork-ai-features.jsx
