const gw_ap_match_dollardollar = n => `$${(n||0).toLocaleString("en-US",{minimumFractionDigits:2,maximumFractionDigits:2})}`;
const lt = lines => lines.reduce((s,l) => s + (l.qty||l.qtyReceived||0) * (l.unitCost||0), 0);
const gw_ap_match_skuName = id => gw_ap_match_SKUS.find(s=>s.id===id)?.name || id;
const gw_ap_match_skuCode = id => gw_ap_match_SKUS.find(s=>s.id===id)?.sku  || id;
const gw_ap_match_skuUom  = id => gw_ap_match_SKUS.find(s=>s.id===id)?.uom  || "";
const vName   = id => gw_ap_match_VENDORS.find(v=>v.id===id)?.name || id;

const toWords = n => {
  if (!n) return "Zero and 00/100";
  const u=["","One","Two","Three","Four","Five","Six","Seven","Eight","Nine","Ten","Eleven","Twelve","Thirteen","Fourteen","Fifteen","Sixteen","Seventeen","Eighteen","Nineteen"];
  const t=["","","Twenty","Thirty","Forty","Fifty","Sixty","Seventy","Eighty","Ninety"];
  const c=x=>{if(x<20)return u[x];if(x<100)return t[Math.floor(x/10)]+(x%10?" "+u[x%10]:"");return u[Math.floor(x/100)]+" Hundred"+(x%100?" "+c(x%100):"")};
  const d=Math.round(n*100),dol=Math.floor(d/100),cts=d%100;
  const pts=[];
  if(dol>=1000) pts.push(c(Math.floor(dol/1000))+" Thousand");
  if(dol%1000>=100) pts.push(c(Math.floor((dol%1000)/100))+" Hundred");
  if(dol%100>0) pts.push(c(dol%100));
  return (pts.join(" ")||"Zero")+` and ${String(cts).padStart(2,"0")}/100`;
};

function runMatch(po, grn, invLines) {
  const ex=[]; let qm=true, pm=true;
  if (!grn) return {qtyMatch:false,priceMatch:false,overallPass:false,exceptions:[{type:"no_grn",msg:"No GRN on file. Invoice cannot be approved until goods are received."}]};
  invLines.forEach(l => {
    const pl=po?.lines.find(x=>x.skuId===l.skuId);
    const gl=grn?.lines.find(x=>x.skuId===l.skuId);
    if (!gl||l.qty>(gl.qtyReceived||0)) { qm=false; ex.push({skuId:l.skuId,type:"qty",poQty:pl?.qty,grnQty:gl?.qtyReceived||0,invQty:l.qty,msg:`${gw_ap_match_skuCode(l.skuId)}: Invoice qty (${l.qty}) exceeds received qty (${gl?.qtyReceived||0}).`}); }
    if (pl&&Math.abs(l.unitCost-pl.unitCost)>0.01) { pm=false; ex.push({skuId:l.skuId,type:"price",poCost:pl.unitCost,invCost:l.unitCost,diff:l.unitCost-pl.unitCost,msg:`${gw_ap_match_skuCode(l.skuId)}: Invoice price ${gw_ap_match_dollardollar(l.unitCost)} vs PO price ${gw_ap_match_dollardollar(pl.unitCost)} — variance ${gw_ap_match_dollardollar(Math.abs(l.unitCost-pl.unitCost))}/unit.`}); }
  });
  return {qtyMatch:qm, priceMatch:pm, overallPass:qm&&pm, exceptions:ex};
}

