// Compute transaction price = base + included variable consideration
function txPrice(contract) {
  const vc = contract.variableConsideration.filter(v=>v.include).reduce((s,v)=>s+v.amount,0);
  return contract.baseContractValue + vc;
}

// Compute earned revenue = txPrice × (actualCost / estimatedTotalCost) for cost-to-cost
function earnedRevenue(contract) {
  if (contract.pctComplete >= 100) return txPrice(contract);
  const costPct = contract.estimatedTotalCost > 0
    ? contract.actualCost / contract.estimatedTotalCost
    : contract.pctComplete / 100;
  return Math.round(txPrice(contract) * costPct);
}

// Revenue recognized in period (earned - prior billed approximation)
function revenueThisPeriod(contract) {
  return Math.max(0, earnedRevenue(contract) - contract.billedToDate);
}

// Over/under billing
function overbilling(contract) {
  return contract.billedToDate - earnedRevenue(contract);
}

// 5-step completeness check
function step5Status(contract) {
  const steps = [
    contract.customer && contract.baseContractValue > 0,                   // step 1
    contract.obligations.length > 0,                                        // step 2
    contract.variableConsideration !== undefined,                           // step 3
    contract.obligations.every(o=>o.standalone > 0),                       // step 4
    contract.recognitionMethod !== null,                                    // step 5
  ];
  return steps;
}

