// ============================================================
// HELPERS
// ============================================================
const gw_assets_dollardollar = (n) => n == null ? "—" : n.toLocaleString("en-US", { style: "currency", currency: "USD", minimumFractionDigits: 0, maximumFractionDigits: 0 });
const fmt2 = (n) => n == null ? "—" : n.toLocaleString("en-US", { minimumFractionDigits: 2, maximumFractionDigits: 2 });
const gw_assets_pct = (n) => n == null ? "—" : `${Math.round(n * 100)}%`;

function getAccumDepr(asset) {
  const sch = generateSchedule(asset);
  const inService = new Date(asset.inServiceDate);
  let accum = 0;
  for (const row of sch) {
    const rowYear = row.calYear;
    if (rowYear < CURRENT_DATE.getFullYear()) accum += row.depr;
    else if (rowYear === CURRENT_DATE.getFullYear()) {
      // Add partial year through current month
      const monthsInYear = (CURRENT_DATE.getMonth() + 1);
      accum += (row.depr / 12) * monthsInYear;
      break;
    } else break;
  }
  return Math.round(accum);
}

function getBookValue(asset) {
  return Math.max(asset.cost - getAccumDepr(asset), asset.salvage || 0);
}

function getDeprPct(asset) {
  return getAccumDepr(asset) / asset.cost;
}

