// ============================================================
// GROUNDWORK — SOC 1 Type II Audit Trail (P2)
// Immutable Transaction Log · User Attribution · Auditor Export
// ============================================================

const css_gw_audit_trail = `
  @import url('https://fonts.googleapis.com/css2?family=Bebas+Neue&family=IBM+Plex+Sans:wght@300;400;500;600&family=IBM+Plex+Mono:wght@400;500&display=swap');
  *,*::before,*::after{box-sizing:border-box;margin:0;padding:0}
  :root{
    --bg:#0B0C0E;--surf:#111316;--raise:#181B1F;--card:#1D2026;
    --bord:#242830;--bord2:#2E333C;--mute:#4A5568;--dim:#64748B;
    --lite:#94A3B8;--brite:#CBD5E0;--white:#E8EDF5;
    --sl:#3B7DD8;--sl-d:rgba(59,125,216,.12);--sl-b:rgba(59,125,216,.25);
    --tl:#1FA99A;--tl-d:rgba(31,169,154,.12);--tl-b:rgba(31,169,154,.25);
    --gn:#22C55E;--gn-d:rgba(34,197,94,.12);--gn-b:rgba(34,197,94,.25);
    --gd:#D97706;--gd-d:rgba(217,119,6,.12);--gd-b:rgba(217,119,6,.25);
    --rd:#E53E3E;--rd-d:rgba(229,62,62,.12);--rd-b:rgba(229,62,62,.25);
    --pu:#7C3AED;--pu-d:rgba(124,58,237,.12);--pu-b:rgba(124,58,237,.25);
  }
  body{font-family:"IBM Plex Sans",sans-serif;background:var(--bg);color:var(--brite);min-height:100vh}
  ::-webkit-scrollbar{width:4px;height:4px}
  ::-webkit-scrollbar-track{background:transparent}
  ::-webkit-scrollbar-thumb{background:var(--mute);border-radius:2px}
  .app{display:flex;height:100vh;overflow:hidden}
  .sb{width:220px;min-width:220px;background:var(--surf);border-right:1px solid var(--bord);display:flex;flex-direction:column;flex-shrink:0;position:relative}
  .sb::before{content:"";position:absolute;top:0;left:0;right:0;height:3px;background:linear-gradient(90deg,var(--pu),var(--sl),var(--tl))}
  .sb-logo{padding:16px 14px 13px;border-bottom:1px solid var(--bord);display:flex;align-items:center;gap:10px}
  .sb-gem{width:28px;height:28px;background:var(--pu);border-radius:6px;display:grid;place-items:center;flex-shrink:0;font-size:14px}
  .sb-n{font-family:"Bebas Neue",sans-serif;font-size:16px;letter-spacing:2.5px;color:var(--white)}
  .sb-m{font-size:8px;letter-spacing:3px;color:var(--mute);text-transform:uppercase;margin-top:1px}
  .sb-nav{flex:1;overflow-y:auto;padding:8px 0}
  .sb-sec{font-size:8px;font-weight:700;letter-spacing:3px;text-transform:uppercase;color:var(--mute);padding:10px 14px 4px}
  .sb-item{display:flex;align-items:center;gap:8px;padding:8px 14px;cursor:pointer;font-size:12px;color:var(--dim);border-left:2px solid transparent;transition:all .1s}
  .sb-item:hover{background:var(--raise);color:var(--lite)}
  .sb-item.on{background:var(--pu-d);color:var(--pu);border-left-color:var(--pu);font-weight:500}
  .sb-dot{width:4px;height:4px;border-radius:50%;background:currentColor;opacity:.6;flex-shrink:0}
  .main{flex:1;display:flex;flex-direction:column;overflow:hidden;min-width:0}
  .topbar{background:var(--surf);border-bottom:1px solid var(--bord);height:50px;padding:0 22px;display:flex;align-items:center;justify-content:space-between;flex-shrink:0}
  .tb-t{font-family:"Bebas Neue",sans-serif;font-size:16px;letter-spacing:2.5px;color:var(--white)}
  .tb-s{font-size:9px;color:var(--mute);letter-spacing:2px;text-transform:uppercase;margin-top:1px}
  .tab-bar{background:var(--surf);border-bottom:1px solid var(--bord);display:flex;padding:0 22px;flex-shrink:0;overflow-x:auto}
  .tab{padding:10px 15px;font-size:11px;font-weight:500;color:var(--mute);cursor:pointer;border-bottom:2px solid transparent;margin-bottom:-1px;transition:all .1s;white-space:nowrap}
  .tab:hover{color:var(--brite)}.tab.on{color:var(--pu);border-bottom-color:var(--pu)}
  .content{flex:1;overflow-y:auto;padding:20px 22px}
  .btn{display:inline-flex;align-items:center;gap:6px;padding:7px 13px;border-radius:6px;border:none;font-family:"IBM Plex Sans",sans-serif;font-size:12px;font-weight:500;cursor:pointer;transition:all .12s;white-space:nowrap}
  .btn-ghost{background:var(--raise);color:var(--dim);border:1px solid var(--bord)}.btn-ghost:hover{color:var(--lite);background:var(--card)}
  .btn-pu{background:var(--pu);color:#fff}.btn-pu:hover{opacity:.9}
  .btn-sm{padding:4px 10px;font-size:11px}.btn-xs{padding:3px 8px;font-size:10px;border-radius:4px}
  .panel{background:var(--surf);border:1px solid var(--bord);border-radius:9px;overflow:hidden;margin-bottom:14px}
  .ph{padding:12px 16px;border-bottom:1px solid var(--bord);display:flex;align-items:center;justify-content:space-between;flex-wrap:wrap;gap:8px}
  .pt{font-family:"Bebas Neue",sans-serif;font-size:12px;letter-spacing:2px;color:var(--lite)}
  .ps{font-size:10px;color:var(--mute);margin-top:1px}
  .krow{display:flex;gap:0;margin-bottom:16px}
  .kpi{flex:1;background:var(--surf);border:1px solid var(--bord);padding:13px 15px;position:relative;overflow:hidden}
  .kpi:first-child{border-radius:9px 0 0 9px}.kpi:last-child{border-radius:0 9px 9px 0}.kpi+.kpi{border-left:none}
  .kpi::after{content:"";position:absolute;bottom:0;left:0;right:0;height:2px}
  .k-sl::after{background:var(--sl)}.k-tl::after{background:var(--tl)}.k-gd::after{background:var(--gd)}
  .k-gn::after{background:var(--gn)}.k-rd::after{background:var(--rd)}.k-pu::after{background:var(--pu)}
  .kl{font-size:9px;font-weight:600;letter-spacing:2px;text-transform:uppercase;color:var(--mute);margin-bottom:5px}
  .kv{font-family:"IBM Plex Mono",monospace;font-size:20px;font-weight:500;color:var(--white);line-height:1}
  .ks{font-size:10px;color:var(--mute);margin-top:4px}
  .tbl{width:100%;border-collapse:collapse}
  .tbl th{font-size:9px;font-weight:600;letter-spacing:2px;text-transform:uppercase;color:var(--mute);padding:8px 12px;text-align:left;border-bottom:1px solid var(--bord);background:rgba(0,0,0,.15);white-space:nowrap}
  .tbl td{padding:8px 12px;font-size:11px;color:var(--lite);border-bottom:1px solid rgba(255,255,255,.03);vertical-align:middle}
  .tbl tr:last-child td{border-bottom:none}
  .tbl tr:hover td{background:rgba(255,255,255,.015)}
  .mono{font-family:"IBM Plex Mono",monospace;font-size:11px}
  .badge{display:inline-flex;align-items:center;gap:4px;padding:2px 7px;border-radius:3px;font-size:9px;font-weight:600;letter-spacing:1px;text-transform:uppercase}
  .b-sl{background:var(--sl-d);color:var(--sl)}.b-tl{background:var(--tl-d);color:var(--tl)}
  .b-gn{background:var(--gn-d);color:var(--gn)}.b-gd{background:var(--gd-d);color:var(--gd)}
  .b-rd{background:var(--rd-d);color:var(--rd)}.b-pu{background:var(--pu-d);color:var(--pu)}
  .b-st{background:rgba(74,85,104,.2);color:var(--mute)}
  .fg{display:flex;flex-direction:column;gap:4px}
  .fl{font-size:9px;font-weight:600;letter-spacing:2px;text-transform:uppercase;color:var(--mute)}
  .fi,.fsel{background:var(--raise);border:1px solid var(--bord);border-radius:6px;color:var(--white);font-family:"IBM Plex Sans",sans-serif;font-size:12px;padding:7px 10px;outline:none;transition:border-color .12s;width:100%}
  .fi:focus,.fsel:focus{border-color:var(--pu);box-shadow:0 0 0 2px var(--pu-d)}
  .fsel option{background:var(--surf)}
  .fh{font-size:10px;color:var(--mute);margin-top:2px}
  .g2{display:grid;grid-template-columns:1fr 1fr;gap:14px}
  .g3{display:grid;grid-template-columns:1fr 1fr 1fr;gap:12px}
  .sdiv{font-family:"Bebas Neue",sans-serif;font-size:11px;letter-spacing:2px;color:var(--pu);margin:18px 0 10px;display:flex;align-items:center;gap:10px}
  .sdiv::after{content:"";flex:1;height:1px;background:var(--bord)}
  .alert-banner{display:flex;align-items:flex-start;gap:10px;padding:10px 14px;border-radius:7px;margin-bottom:10px;font-size:11px}
  .alert-good{background:var(--gn-d);border:1px solid var(--gn-b);color:var(--gn)}
  .alert-info{background:var(--pu-d);border:1px solid var(--pu-b);color:var(--pu)}
  .alert-warn{background:var(--gd-d);border:1px solid var(--gd-b);color:var(--gd)}

  /* Audit Specific */
  .log-entry{display:flex;gap:0;border-bottom:1px solid rgba(255,255,255,.03);transition:background .1s}
  .log-entry:hover{background:rgba(255,255,255,.015)}
  .log-entry:last-child{border-bottom:none}
  .log-ts{padding:8px 12px;font-family:"IBM Plex Mono",monospace;font-size:10px;color:var(--mute);flex-shrink:0;width:140px;border-right:1px solid rgba(255,255,255,.04)}
  .log-user{padding:8px 10px;font-size:11px;font-weight:500;color:var(--brite);flex-shrink:0;width:130px;border-right:1px solid rgba(255,255,255,.04)}
  .log-action{padding:8px 10px;flex:1;font-size:11px}
  .log-module{padding:8px 10px;flex-shrink:0;width:110px}
  .log-hash{padding:8px 12px;font-family:"IBM Plex Mono",monospace;font-size:9px;color:var(--mute);flex-shrink:0;width:90px;text-align:right}

  .immutable-badge{display:flex;align-items:center;gap:6px;background:var(--gn-d);border:1px solid var(--gn-b);border-radius:6px;padding:5px 10px;font-size:10px;color:var(--gn);font-weight:600}

  .filter-bar{display:flex;gap:8px;margin-bottom:14px;flex-wrap:wrap;align-items:center}
  .search-fi{background:var(--raise);border:1px solid var(--bord);border-radius:6px;color:var(--white);font-family:"IBM Plex Sans",sans-serif;font-size:12px;padding:7px 10px;outline:none;width:240px}
  .search-fi:focus{border-color:var(--pu);box-shadow:0 0 0 2px var(--pu-d)}

  .hash-verify{background:var(--card);border:1px solid var(--bord);border-radius:6px;padding:8px 12px;font-family:"IBM Plex Mono",monospace;font-size:10px;color:var(--mute);display:flex;align-items:center;gap:8px}
  .hash-verify .dot{width:6px;height:6px;border-radius:50%;background:var(--gn);flex-shrink:0}

  .export-card{background:var(--raise);border:1px solid var(--bord);border-radius:8px;padding:14px;cursor:pointer;transition:all .12s}
  .export-card:hover{border-color:var(--pu-b);background:var(--pu-d)}
  .export-icon{font-size:24px;margin-bottom:8px}
  .export-title{font-size:12px;font-weight:600;color:var(--white);margin-bottom:3px}
  .export-desc{font-size:10px;color:var(--mute);line-height:1.5}

  .user-activity-row{display:flex;align-items:center;gap:12px;padding:8px 16px;border-bottom:1px solid rgba(255,255,255,.03);font-size:11px}
  .user-avatar{width:28px;height:28px;border-radius:50%;display:grid;place-items:center;font-size:11px;font-weight:600;flex-shrink:0}
  .activity-bar-wrap{flex:1;background:var(--card);border-radius:3px;height:6px;overflow:hidden}
  .activity-bar-fill{height:100%;background:var(--pu);border-radius:3px;opacity:.7}
`;

