const ACTION_COLORS = {
  post:"pu", approve:"gn", unlock:"rd", void:"rd", create:"sl", authorize:"gd", system:"mute", close:"tl", update:"gd", receive:"gn", reconcile:"tl", submit:"sl"
};

function AuditTrailModule() {
  const [tab, setTab] = useState("log");
  const [search, setSearch] = useState("");
  const [moduleFilter, setModuleFilter] = useState("all");
  const [actionFilter, setActionFilter] = useState("all");
  const [expandedId, setExpandedId] = useState(null);

  const modules = [...new Set(gw_audit_trail_AUDIT_LOG.map(l=>l.module))];
  const filtered = gw_audit_trail_AUDIT_LOG.filter(l=>{
    const matchSearch = !search || l.action.toLowerCase().includes(search.toLowerCase()) || l.user.toLowerCase().includes(search.toLowerCase());
    const matchModule = moduleFilter==="all" || l.module===moduleFilter;
    const matchAction = actionFilter==="all" || l.type===actionFilter;
    return matchSearch && matchModule && matchAction;
  });

  const TABS = [
    {id:"log",label:"Audit Log"},
    {id:"search",label:"Search & Filter"},
    {id:"users",label:"User Activity"},
    {id:"controls",label:"Control Points"},
    {id:"export",label:"Auditor Export"},
    {id:"integrity",label:"Data Integrity"},
  ];

  const NAV = [
    {sec:"Audit",items:["Audit Trail","SOC 1 Controls","User Access Log","Data Integrity"]},
    {sec:"Compliance",items:["Auditor Package","Control Matrix","Exception Report"]},
  ];

  const userStats = [...new Set(gw_audit_trail_AUDIT_LOG.map(l=>l.user))].map(u=>{
    const actions = gw_audit_trail_AUDIT_LOG.filter(l=>l.user===u);
    return {user:u,role:actions[0].role,count:actions.length};
  }).sort((a,b)=>b.count-a.count);

  const userColors = ["#3B7DD8","#1FA99A","#D97706","#7C3AED","#22C55E","#E53E3E"];

  return (
    <div className="app">
      <style>{css_gw_audit_trail}</style>
      <div className="sb">
        <div className="sb-logo">
          <div className="sb-gem">🔒</div>
          <div>
            <div className="sb-n">GROUNDWORK</div>
            <div className="sb-m">Audit Trail</div>
          </div>
        </div>
        <div className="sb-nav">
          {NAV.map(s=>(
            <div key={s.sec}>
              <div className="sb-sec">{s.sec}</div>
              {s.items.map(i=>(
                <div key={i} className={"sb-item "+(i==="Audit Trail"?"on":"")}>
                  <span className="sb-dot"/>{i}
                </div>
              ))}
            </div>
          ))}
        </div>
      </div>

      <div className="main">
        <div className="topbar">
          <div>
            <div className="tb-t">SOC 1 TYPE II AUDIT TRAIL</div>
            <div className="tb-s">Immutable Log · User Attribution · Auditor-Ready Export</div>
          </div>
          <div style={{display:"flex",gap:8,alignItems:"center"}}>
            <div className="immutable-badge">🔒 Tamper-Proof Log</div>
            <button className="btn btn-ghost btn-sm">📋 Attestation Letter</button>
            <button className="btn btn-pu btn-sm">Export for Auditor</button>
          </div>
        </div>

        <div className="tab-bar">
          {TABS.map(t=>(
            <div key={t.id} className={"tab"+(tab===t.id?" on":"")} onClick={()=>setTab(t.id)}>{t.label}</div>
          ))}
        </div>

        <div className="content">
          {(tab==="log"||tab==="search") && (
            <>
              <div className="krow">
                <div className="kpi k-pu"><div className="kl">Events Today</div><div className="kv">47</div><div className="ks">All modules captured</div></div>
                <div className="kpi k-sl"><div className="kl">Events This Month</div><div className="kv">1,284</div><div className="ks">Feb 2026 MTD</div></div>
                <div className="kpi k-gn"><div className="kl">Data Integrity</div><div className="kv">100%</div><div className="ks">All hashes verified</div></div>
                <div className="kpi k-rd"><div className="kl">Exceptions Today</div><div className="kv">2</div><div className="ks">Period unlock, void</div></div>
                <div className="kpi k-gd"><div className="kl">Active Users</div><div className="kv">4</div><div className="ks">Users logged in today</div></div>
              </div>

              <div className="panel">
                <div className="ph">
                  <div><div className="pt">IMMUTABLE AUDIT LOG</div><div className="ps">Every system event — cryptographically hashed, user-attributed, timestamped to the second</div></div>
                  <div style={{display:"flex",gap:8,alignItems:"center"}}>
                    <div className="hash-verify"><span className="dot"/>Chain integrity: VALID</div>
                  </div>
                </div>

                {tab==="search" && (
                  <div style={{padding:"12px 16px",borderBottom:"1px solid var(--bord)",display:"flex",gap:10,flexWrap:"wrap"}}>
                    <input className="search-fi" placeholder="Search by user, action, module..." value={search} onChange={e=>setSearch(e.target.value)}/>
                    <select className="fsel" style={{width:180}} value={moduleFilter} onChange={e=>setModuleFilter(e.target.value)}>
                      <option value="all">All Modules</option>
                      {modules.map(m=><option key={m} value={m}>{m}</option>)}
                    </select>
                    <select className="fsel" style={{width:150}} value={actionFilter} onChange={e=>setActionFilter(e.target.value)}>
                      <option value="all">All Actions</option>
                      {[...new Set(gw_audit_trail_AUDIT_LOG.map(l=>l.type))].map(t=><option key={t} value={t}>{t}</option>)}
                    </select>
                    {(search||moduleFilter!=="all"||actionFilter!=="all") && (
                      <button className="btn btn-ghost btn-sm" onClick={()=>{setSearch("");setModuleFilter("all");setActionFilter("all")}}>Clear Filters</button>
                    )}
                    <span style={{fontSize:10,color:"var(--mute)",alignSelf:"center"}}>{filtered.length} of {gw_audit_trail_AUDIT_LOG.length} events</span>
                  </div>
                )}

                {/* Column headers */}
                <div style={{display:"flex",gap:0,borderBottom:"1px solid var(--bord)",background:"rgba(0,0,0,.15)"}}>
                  {[["TIMESTAMP",140],["USER",130],["ACTION / DESCRIPTION","flex"],["MODULE",110],["HASH",90]].map(([h,w])=>(
                    <div key={h} style={{padding:"7px 12px",fontSize:"9px",fontWeight:700,letterSpacing:2,textTransform:"uppercase",color:"var(--mute)",width:w==="flex"?"auto":w,flex:w==="flex"?1:"none",borderRight:w===90?"none":"1px solid rgba(255,255,255,.04)"}}>{h}</div>
                  ))}
                </div>

                <div style={{maxHeight:440,overflowY:"auto"}}>
                  {filtered.map((entry,i)=>{
                    const color = ACTION_COLORS[entry.type]||"mute";
                    return (
                      <div key={i} className="log-entry" style={{cursor:"pointer"}} onClick={()=>setExpandedId(expandedId===i?null:i)}>
                        <div className="log-ts">{entry.ts}</div>
                        <div className="log-user">
                          <div style={{fontWeight:600,color:"var(--brite)"}}>{entry.user}</div>
                          <div style={{fontSize:9,color:"var(--mute)"}}>{entry.role}</div>
                        </div>
                        <div className="log-action">
                          <div style={{color:"var(--brite)",marginBottom:expandedId===i?4:0}}>{entry.action.slice(0,80)}{entry.action.length>80?"...":""}</div>
                          {expandedId===i && (
                            <div style={{fontSize:10,color:"var(--lite)",background:"var(--card)",borderRadius:5,padding:"8px 10px",marginTop:4,lineHeight:1.6}}>
                              <strong>Full event:</strong> {entry.action}
                              <div style={{marginTop:6,display:"flex",gap:12}}>
                                <span style={{color:"var(--mute)"}}>Hash chain: {entry.hash}→{gw_audit_trail_AUDIT_LOG[i+1]?.hash||"HEAD"}</span>
                                <span style={{color:"var(--gn)"}}>✓ Integrity verified</span>
                              </div>
                            </div>
                          )}
                        </div>
                        <div className="log-module"><span className={"badge b-"+(color)}>{entry.module.split("/")[0].trim()}</span></div>
                        <div className="log-hash">{entry.hash}</div>
                      </div>
                    );
                  })}
                </div>
              </div>
            </>
          )}

          {tab==="users" && (
            <div className="panel">
              <div className="ph"><div><div className="pt">USER ACTIVITY — FEBRUARY 2026</div><div className="ps">Actions by user, role-based breakdown</div></div></div>
              {userStats.map((u,i)=>(
                <div key={u.user} className="user-activity-row">
                  <div className="user-avatar" style={{background:`${userColors[i]}22`,color:userColors[i]}}>
                    {u.user.split(" ").map(n=>n[0]).join("")}
                  </div>
                  <div style={{width:130,flexShrink:0}}>
                    <div style={{fontSize:11,fontWeight:600,color:"var(--white)"}}>{u.user}</div>
                    <div style={{fontSize:9,color:"var(--mute)"}}>{u.role}</div>
                  </div>
                  <div className="activity-bar-wrap">
                    <div className="activity-bar-fill" style={{width:`${(u.count/userStats[0].count)*100}%`,background:userColors[i]}}/>
                  </div>
                  <div className="mono" style={{width:30,textAlign:"right",color:userColors[i]}}>{u.count}</div>
                  <div style={{width:120,textAlign:"right",fontSize:10,color:"var(--mute)"}}>actions this month</div>
                </div>
              ))}
              <div style={{padding:"12px 16px",borderTop:"1px solid var(--bord)"}}>
                <div className="sdiv">Access Control Summary</div>
                <div className="g2">
                  {[
                    {role:"CFO",perms:["GL Post","Period Open/Close","Wire Auth","Covenant Approve"],color:"var(--gd)"},
                    {role:"Controller",perms:["GL Post","Period Close","Bank Recon","Journal Reverse"],color:"var(--sl)"},
                    {role:"Project Manager",perms:["Job Cost View","CO Approve","EAC Submit","Lien Submit"],color:"var(--tl)"},
                    {role:"AP/AR Clerk",perms:["Invoice Create","Payment Record","Void (supervised)","AR Apply"],color:"var(--pu)"},
                  ].map(r=>(
                    <div key={r.role} style={{background:"var(--raise)",border:"1px solid var(--bord)",borderRadius:8,padding:"12px 14px"}}>
                      <div style={{fontFamily:"Bebas Neue,sans-serif",fontSize:12,letterSpacing:2,color:r.color,marginBottom:8}}>{r.role}</div>
                      {r.perms.map(p=>(
                        <div key={p} style={{display:"flex",alignItems:"center",gap:6,fontSize:11,padding:"3px 0",color:"var(--lite)"}}>
                          <span style={{color:"var(--gn)"}}>✓</span>{p}
                        </div>
                      ))}
                    </div>
                  ))}
                </div>
              </div>
            </div>
          )}

          {tab==="controls" && (
            <div className="panel">
              <div className="ph"><div><div className="pt">SOC 1 CONTROL POINTS</div><div className="ps">Financial reporting controls relevant to SOC 1 Type II examination</div></div><span className="badge b-gn">All Controls Active</span></div>
              <table className="tbl">
                <thead>
                  <tr><th>Control ID</th><th>Description</th><th>Category</th><th>Frequency</th><th>Evidence Captured</th><th>Status</th></tr>
                </thead>
                <tbody>
                  {[
                    {id:"GC-01",desc:"All GL journal entries require dual authorization above $10K",cat:"Authorization",freq:"Per Transaction",evidence:"Approver ID + Timestamp in audit log",status:"Active"},
                    {id:"GC-02",desc:"Period lock prevents backdated entries without CFO approval",cat:"Period Control",freq:"Monthly",evidence:"Unlock event logged with CFO auth code",status:"Active"},
                    {id:"GC-03",desc:"Bank reconciliation required before period close sign-off",cat:"Reconciliation",freq:"Monthly",evidence:"Recon sign-off captured in close log",status:"Active"},
                    {id:"GC-04",desc:"AP invoice creation requires 3-way match: PO + Receipt + Invoice",cat:"Payables Control",freq:"Per Invoice",evidence:"Match result logged with document refs",status:"Active"},
                    {id:"GC-05",desc:"Payroll changes require HR + Controller approval before processing",cat:"Payroll Control",freq:"Per Pay Period",evidence:"Dual approval captured in HRIS log",status:"Active"},
                    {id:"GC-06",desc:"Wire transfers above $50K require CFO digital authorization",cat:"Treasury Control",freq:"Per Transaction",evidence:"CFO auth code + IP address logged",status:"Active"},
                    {id:"GC-07",desc:"User access provisioning/deprovisioning logged and reviewed quarterly",cat:"Access Control",freq:"Quarterly",evidence:"User role change events in audit log",status:"Active"},
                    {id:"GC-08",desc:"Audit log hash chain verified nightly — alerts on integrity failure",cat:"Data Integrity",freq:"Daily",evidence:"Automated hash verification report",status:"Active"},
                    {id:"GC-09",desc:"Revenue recognition calculations reviewed before billing application",cat:"Revenue Control",freq:"Per Billing",evidence:"ASC 606 calc stored with each billing run",status:"Active"},
                    {id:"GC-10",desc:"Change orders above $50K require PM + Controller + CFO approval",cat:"Project Control",freq:"Per CO",evidence:"3-level approval chain in CO module",status:"Active"},
                  ].map(c=>(
                    <tr key={c.id}>
                      <td className="mono" style={{color:"var(--pu)",fontWeight:600}}>{c.id}</td>
                      <td style={{maxWidth:280}}>{c.desc}</td>
                      <td><span className="badge b-pu">{c.cat}</span></td>
                      <td style={{fontSize:10,color:"var(--mute)"}}>{c.freq}</td>
                      <td style={{fontSize:10,color:"var(--mute)",maxWidth:200}}>{c.evidence}</td>
                      <td><span className="badge b-gn">Active</span></td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          )}

          {tab==="export" && (
            <div>
              <div className="alert-banner alert-info">
                🔒 All exports are cryptographically signed and include the immutable audit chain. Exports cannot be retroactively modified. Each export generates a unique export certificate stored in the audit log.
              </div>
              <div className="g3" style={{display:"grid",gridTemplateColumns:"1fr 1fr 1fr",gap:14}}>
                {[
                  {icon:"📋",title:"Full Audit Log",desc:"Complete transaction history with hash chain. CSV/JSON format. Includes all users, timestamps, actions, and module references.",badge:"SOC 1 Standard"},
                  {icon:"👤",title:"User Activity Report",desc:"Actions grouped by user with role context, authorization events, and access pattern analysis.",badge:"Access Control"},
                  {icon:"⚠️",title:"Exception Report",desc:"High-risk events only: period unlocks, voids, overrides, failed authentications, and out-of-policy transactions.",badge:"Risk Focus"},
                  {icon:"🏛️",title:"GL Audit Package",desc:"Journal entries with full approver chain, period lock events, and balance reconciliation confirmations.",badge:"Financial Controls"},
                  {icon:"💳",title:"Payables Audit",desc:"AP invoices, 3-way match results, payment authorizations, and void/adjustment history.",badge:"AP Controls"},
                  {icon:"🔐",title:"Access Control Log",desc:"User provisioning, role changes, login events, and permission override requests.",badge:"IT Controls"},
                ].map(e=>(
                  <div key={e.title} className="export-card">
                    <div className="export-icon">{e.icon}</div>
                    <div className="export-title">{e.title}</div>
                    <div className="export-desc">{e.desc}</div>
                    <div style={{marginTop:10,display:"flex",gap:8,alignItems:"center",justifyContent:"space-between"}}>
                      <span className="badge b-pu">{e.badge}</span>
                      <button className="btn btn-ghost btn-xs">Export</button>
                    </div>
                  </div>
                ))}
              </div>
              <div className="panel" style={{marginTop:14}}>
                <div className="ph"><div className="pt">GENERATE CUSTOM EXPORT</div></div>
                <div style={{padding:"14px 16px"}}>
                  <div style={{display:"grid",gridTemplateColumns:"1fr 1fr 1fr 1fr",gap:12,marginBottom:12}}>
                    <div className="fg"><label className="fl">Date From</label><input className="fi" type="date" defaultValue="2026-01-01"/></div>
                    <div className="fg"><label className="fl">Date To</label><input className="fi" type="date" defaultValue="2026-02-19"/></div>
                    <div className="fg"><label className="fl">Module Filter</label><select className="fsel"><option>All Modules</option>{modules.map(m=><option key={m}>{m}</option>)}</select></div>
                    <div className="fg"><label className="fl">User Filter</label><select className="fsel"><option>All Users</option>{[...new Set(gw_audit_trail_AUDIT_LOG.map(l=>l.user))].map(u=><option key={u}>{u}</option>)}</select></div>
                  </div>
                  <div style={{display:"flex",gap:8}}>
                    <button className="btn btn-pu btn-sm">Generate Export Package</button>
                    <button className="btn btn-ghost btn-sm">Preview Results</button>
                  </div>
                </div>
              </div>
            </div>
          )}

          {tab==="integrity" && (
            <div>
              <div className="alert-banner alert-good">
                ✓ <strong>Full chain integrity verified.</strong> All {gw_audit_trail_AUDIT_LOG.length} records in current view pass hash chain validation. Last full verification: 2026-02-19 03:00:02 UTC (nightly automated run).
              </div>
              <div className="g2">
                <div className="panel">
                  <div className="ph"><div className="pt">HASH CHAIN STATUS</div></div>
                  <div style={{padding:"14px 16px",display:"flex",flexDirection:"column",gap:10}}>
                    {[
                      ["Current Block Height","1,284,041","var(--pu)"],
                      ["Genesis Block Date","2022-01-15","var(--mute)"],
                      ["Chain Integrity","VALID ✓","var(--gn)"],
                      ["Last Verification","2026-02-19 03:00 UTC","var(--lite)"],
                      ["Hash Algorithm","SHA-256","var(--mute)"],
                      ["Storage","Immutable append-only log","var(--mute)"],
                      ["Backup Copies","3 geographically distributed","var(--mute)"],
                      ["Tamper Attempts","0 detected","var(--gn)"],
                    ].map(([k,v,c])=>(
                      <div key={k} style={{display:"flex",justifyContent:"space-between",fontSize:11,borderBottom:"1px solid rgba(255,255,255,.03)",paddingBottom:8}}>
                        <span style={{color:"var(--mute)"}}>{k}</span>
                        <span style={{fontFamily:"IBM Plex Mono,monospace",color:c,fontWeight:500}}>{v}</span>
                      </div>
                    ))}
                  </div>
                </div>
                <div className="panel">
                  <div className="ph"><div className="pt">VERIFY SPECIFIC RECORD</div><div className="ps">Enter a hash to verify record authenticity</div></div>
                  <div style={{padding:"14px 16px"}}>
                    <div className="fg" style={{marginBottom:12}}>
                      <label className="fl">Record Hash</label>
                      <input className="fi" placeholder="e.g. a4f2c1b" defaultValue="a4f2c1b"/>
                      <div className="fh">Hash from audit log or auditor export</div>
                    </div>
                    <button className="btn btn-pu btn-sm" style={{marginBottom:14}}>Verify Record</button>
                    <div style={{background:"var(--card)",border:"1px solid var(--gn-b)",borderRadius:8,padding:"12px 14px"}}>
                      <div style={{display:"flex",alignItems:"center",gap:8,marginBottom:8}}>
                        <span style={{color:"var(--gn)",fontSize:16}}>✓</span>
                        <span style={{fontSize:12,fontWeight:600,color:"var(--gn)"}}>Record Verified — Hash Valid</span>
                      </div>
                      <div style={{fontSize:11,color:"var(--lite)",lineHeight:1.6}}>
                        <div>Record: GL Journal Entry #2026-0482</div>
                        <div>User: Sarah Chen (sarah.chen@groundworkco.com)</div>
                        <div>Timestamp: 2026-02-19 14:32:07 UTC</div>
                        <div>Previous hash: f3c7b9e · Next hash: b7e3d9a</div>
                        <div style={{color:"var(--gn)",marginTop:4}}>Chain position: Block 1,284,034 — Unmodified</div>
                      </div>
                    </div>
                  </div>
                </div>
              </div>
            </div>
          )}
        </div>
      </div>
    </div>
  );
}


