// Compute weekly totals
function sumRows(rowObj) {
  return Array.from({length:13}, (_, w) =>
    Object.values(rowObj).reduce((s, arr) => s + (arr[w] || 0), 0)
  );
}

function buildWeeklyTotals() {
  const inflow_ar = sumRows(CF_DATA.ar_collections);
  const inflow_other = sumRows(CF_DATA.other_inflows);
  const total_inflows = inflow_ar.map((v,i) => v + inflow_other[i]);

  const out_payroll = sumRows(CF_DATA.payroll);
  const out_subs = sumRows(CF_DATA.subcontractors);
  const out_materials = sumRows(CF_DATA.material_po);
  const out_equip = sumRows(CF_DATA.equipment);
  const out_overhead = sumRows(CF_DATA.overhead);
  const total_outflows = out_payroll.map((v,i) => v + out_subs[i] + out_materials[i] + out_equip[i] + out_overhead[i]);

  const net_cf = total_inflows.map((v,i) => v - total_outflows[i]);

  // LOC separate
  const loc_draws = sumRows({ loc: CF_DATA.loc.LOC_Draw ? [CF_DATA.loc["LOC Draw"]] : [CF_DATA.loc["LOC Draw"]] });
  const loc_repay = sumRows({ loc: [CF_DATA.loc["LOC Repayment"]] });

  const opening_cash = 6_420_000;
  let running = opening_cash;
  const ending_cash = net_cf.map((v, i) => {
    const locNet = (CF_DATA.loc["LOC Draw"][i] || 0) - (CF_DATA.loc["LOC Repayment"][i] || 0);
    running += v + locNet;
    return running;
  });

  return { inflow_ar, inflow_other, total_inflows, out_payroll, out_subs, out_materials, out_equip, out_overhead, total_outflows, net_cf, ending_cash };
}

// Cash waterfall chart
function WaterfallChart({ weeks, totals }) {
  const { ending_cash, total_inflows, total_outflows } = totals;
  const maxVal = Math.max(...ending_cash) * 1.1;
  const minVal = Math.min(...ending_cash) * 0.9;
  const range = maxVal - minVal;
  const w = 720, h = 140, padL = 40, padR = 20, padT = 14, padB = 28;
  const chartW = w - padL - padR;
  const chartH = h - padT - padB;
  const barW = (chartW / 13) - 4;

  const xPos = (i) => padL + (i / 13) * chartW + 2;
  const yPos = (v) => padT + chartH - ((v - minVal) / range) * chartH;

  // Line for cash balance
  const linePts = ending_cash.map((v, i) => `${xPos(i) + barW/2},${yPos(v)}`).join(" ");
  // Zero/covenant line
  const covenantMin = 2_000_000;
  const yZero = yPos(covenantMin);

  return (
    <svg viewBox={"0 0 "+(w)+" "+(h)} style={{ width: "100%", height: 140 }}>
      <defs>
        <linearGradient id="cashGrad" x1="0" y1="0" x2="0" y2="1">
          <stop offset="0%" stopColor="var(--sl)" stopOpacity=".3" />
          <stop offset="100%" stopColor="var(--sl)" stopOpacity="0" />
        </linearGradient>
      </defs>
      {/* Grid */}
      {[0, 0.25, 0.5, 0.75, 1].map(r => (
 <line key={r} x1={padL} y1={padT + chartH * r} x2={w - padR} y2={padT + chartH * r} stroke="rgba(255,255,255,.04)" strokeWidth="1" />
      ))}
      {/* Covenant min line */}
      <line x1={padL} y1={yZero} x2={w - padR} y2={yZero} stroke="rgba(229,62,62,.4)" strokeWidth="1" strokeDasharray="5 4" />
      <text x={padL + 4} y={yZero - 4} fill="rgba(229,62,62,.6)" fontSize="8" fontFamily="IBM Plex Mono">Min Cash $2M</text>

      {/* Bars — weekly net */}
      {ending_cash.map((v, i) => {
        const net = totals.net_cf[i];
        const color = net >= 0 ? "rgba(34,197,94,.35)" : "rgba(229,62,62,.35)";
        const barH = Math.abs(net) / range * chartH;
        const barY = net >= 0 ? yPos(v) : yPos(v - net);
        return <rect key={i} x={xPos(i)} y={barY} width={barW} height={Math.max(barH, 1)} fill={color} rx="1" />;
      })}

      {/* Area fill */}
      <polyline points={linePts} fill="none" stroke="transparent" />
      {(() => {
        const areaPath = ending_cash.map((v, i) => `${i === 0 ? "M" : "L"} ${xPos(i) + barW/2} ${yPos(v)}`).join(" ") +
          ` L ${xPos(12) + barW/2} ${padT + chartH} L ${xPos(0) + barW/2} ${padT + chartH} Z`;
        return <path d={areaPath} fill="url(#cashGrad)" />;
      })()}

      {/* Cash balance line */}
      <polyline points={linePts} fill="none" stroke="var(--sl)" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" />
      {ending_cash.map((v, i) => (
 <circle key={i} cx={xPos(i) + barW/2} cy={yPos(v)} r={i === 0 ? 4 : 3} fill={i === 0 ? "var(--sl)" : v < covenantMin ? "var(--rd)" : "var(--gn)"} stroke="var(--surf)" strokeWidth="2" />
      ))}

      {/* Y axis labels */}
      {[minVal, (minVal + maxVal) / 2, maxVal].map((v, i) => (
        <text key={i} x={padL - 4} y={yPos(v) + 3} textAnchor="end" fill="var(--mute)" fontSize="8" fontFamily="IBM Plex Mono">
          {gw_cashflow_fmtM(v)}
        </text>
      ))}

      {/* X labels */}
      {weeks.map((wk, i) => (
        <text key={i} x={xPos(i) + barW/2} y={h - 4} textAnchor="middle" fill={wk.isCurrent ? "var(--sl)" : "var(--mute)"} fontSize="8" fontFamily="IBM Plex Sans">{wk.label}</text>
      ))}
    </svg>
  );
}

// Inline sparkline for row
function Sparkline_CashFlow({ values, color = "var(--sl)" }) {
  const valid = values.filter(v => v !== 0);
  if (valid.length === 0) return <span style={{ color: "var(--mute)", fontSize: 9 }}>—</span>;
  const max = Math.max(...values); const pts = values.map((v, i) => `${i * 8},${12 - (v / max) * 10}`).join(" ");
  return (
    <svg viewBox={"0 0 "+(values.length * 8)+" 14"} width={values.length * 8} height={14} style={{ display: "inline-block", verticalAlign: "middle", marginLeft: 6 }}>
      <polyline points={pts} fill="none" stroke={color} strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round" opacity="0.7" />
    </svg>
  );
}

