function GroundworkCRM() {
  const [activeTab, setActiveTab] = useState("dashboard");
  const [contacts,  setContacts]  = useState(CONTACTS);
  const [opps,      setOpps]      = useState(OPPORTUNITIES);
  const [calls,     setCalls]     = useState(CALLS);
  const [campaigns, setCampaigns] = useState(gw_crm_CAMPAIGNS);
  const [agreements,setAgreements]= useState(SERVICE_AGREEMENTS);
  const [aiConfig,  setAiConfig]  = useState(AI_AGENT_DEFAULT);
  const [selectedContact, setSelectedContact] = useState(null);

  const sectionLabels = [...new Set(NAV.filter(n=>n.section).map(n=>n.section))];

  return (
    <>
      <style>{css_gw_crm}</style>
      <div className="crm-root">
        {/* Sidebar */}
        <div className="crm-sidebar">
          <div className="crm-sidebar-logo">
            GROUNDWORK
            <span>CRM · Customer Platform</span>
          </div>
          <nav className="crm-nav">
            {sectionLabels.map(sec=>(
              <div key={sec}>
                <div className="crm-nav-section">{sec}</div>
                {NAV.filter(n=>n.section===sec).map(n=>(
 <div key={n.id} className={"crm-nav-item"+(activeTab===n.id?" active":"")} onClick={()=>setActiveTab(n.id)}>
                    <span className="nav-icon">{n.icon}</span>
                    <span>{n.label}</span>
                    {n.badge&&<span className="nav-badge">{n.badge}</span>}
                  </div>
                ))}
              </div>
            ))}
          </nav>
          <div style={{padding:"10px 14px",borderTop:"1px solid var(--gravel)"}}>
            <div style={{fontSize:10.5,color:"var(--stone)"}}>Apex MEP Services LLC</div>
            <div style={{fontSize:10,color:"var(--gravel)",marginTop:2}}>CRM v2.0</div>
          </div>
        </div>

        {/* Main */}
        <div className="crm-main">
          <div className="crm-topbar">
            <div>
              <div className="crm-topbar-title">{TITLES[activeTab]}</div>
              <div className="crm-topbar-sub">Groundwork · CRM</div>
            </div>
            <div className="crm-topbar-spacer"/>
            {activeTab==="contacts"&&(
              <button className="crm-topbar-btn ghost" style={{fontSize:11}}>📥 Import</button>
            )}
            {activeTab==="contacts"&&(
              <button className="crm-topbar-btn primary">+ Add Contact</button>
            )}
            {activeTab==="calls"&&(
              <button className="crm-topbar-btn teal">📞 New Call Log</button>
            )}
            {activeTab==="analytics"&&(
              <button className="crm-topbar-btn ghost" style={{fontSize:11}}>📥 Export Report</button>
            )}
          </div>

          <div className="crm-body">
            {activeTab==="dashboard"&&(
              <DashboardView_Crm contacts={contacts} opps={opps} calls={calls} campaigns={campaigns}/>
            )}
            {activeTab==="contacts"&&(
              <ContactsView contacts={contacts} onSelect={setSelectedContact}/>
            )}
            {activeTab==="pipeline"&&(
              <PipelineView opps={opps} contacts={contacts}/>
            )}
            {activeTab==="calls"&&(
              <CallCenterView calls={calls} contacts={contacts} aiConfig={aiConfig}/>
            )}
            {activeTab==="ai-agent"&&(
              <AIAgentView config={aiConfig}/>
            )}
            {activeTab==="campaigns"&&(
              <CampaignsView campaigns={campaigns}/>
            )}
            {activeTab==="analytics"&&(
              <MarketingView metrics={MARKETING_METRICS}/>
            )}
            {activeTab==="agreements"&&(
              <AgreementsView agreements={agreements} contacts={contacts}/>
            )}
          </div>
        </div>

        {/* Contact detail drawer */}
        {selectedContact&&(
          <ContactDetail contact={selectedContact} onClose={()=>setSelectedContact(null)}/>
        )}
      </div>
    </>
  );
}


