// -- WO Status helpers -----------------------------------------
const WO_STATUSES = ["unassigned","scheduled","en-route","on-site","complete","invoiced"];

const gw_dispatch_statusLabel = s => ({
  unassigned:"Unassigned",scheduled:"Scheduled","en-route":"En Route",
  "on-site":"On Site",complete:"Complete",invoiced:"Invoiced"
}[s] || s);

const gw_dispatch_statusBadge = s => ({
  unassigned:"b-mute",scheduled:"b-sl","en-route":"b-gd",
  "on-site":"b-tl",complete:"b-gn",invoiced:"b-pu"
}[s] || "b-mute");

const gw_dispatch_statusColor = s => ({
  unassigned:"var(--mute)",scheduled:"var(--sl)","en-route":"var(--gd)",
  "on-site":"var(--tl)",complete:"var(--gn)",invoiced:"var(--pu)"
}[s] || "var(--mute)");

const priorityBadge = p => ({
  emergency:"b-rd",urgent:"b-gd",routine:"b-sl",planned:"b-mute"
}[p] || "b-mute");

const tradeBadge = t => ({
  HVAC:"b-tl",Plumbing:"b-sl",Electrical:"b-gd"
}[t] || "b-mute");

const calcWOTotal = (wo) => {
  const labor = wo.laborHours.reduce((s,l) => s + l.hours * l.rate * 1.65, 0); // billing rate ~65% markup
  const parts = wo.partsUsed.reduce((s,p) => {
    const sku = PARTS_CATALOG.find(x => x.id === p.skuId);
    return s + (sku ? sku.price * p.qty : 0);
  }, 0);
  return {labor, parts, total: labor + parts};
};

