// -- Helpers ---------------------------------------------------
const gw_documents_fmt = n => {
  if (!n) return "—";
  const num = parseFloat(n.replace(/[^0-9.]/g,""));
  if (n.includes("MB")) return n;
  if (n.includes("KB")) return n;
  return n;
};

function docsByJob() {
  const map = {};
  DOCUMENTS.filter(d => d.jobId).forEach(d => {
    if (!map[d.jobId]) map[d.jobId] = { name: d.jobName, docs: [] };
    map[d.jobId].docs.push(d);
  });
  return map;
}

// -- CSS -------------------------------------------------------
const css_gw_documents = `
  @import url('https://fonts.googleapis.com/css2?family=Bebas+Neue&family=DM+Sans:ital,opsz,wght@0,9..40,300;0,9..40,400;0,9..40,500;0,9..40,600;0,9..40,700;1,9..40,400&family=DM+Mono:wght@400;500&display=swap');
  *, *::before, *::after { box-sizing:border-box; margin:0; padding:0; }
  :root {
    --soil:#15130F; --clay:#1E1B16; --raise:#252118; --gravel:#302C24;
    --stone:#5C5448; --sand:#9C8E7A; --bone:#D8CFBF; --chalk:#EDE8DF;
    --amber:#C8780A; --amber-l:#E89420; --amber-b:rgba(200,120,10,.18);
    --teal:#0E8C72;  --teal-l:#12A887;  --teal-b:rgba(14,140,114,.18);
    --green:#1A7A3C; --green-l:#22A050; --green-b:rgba(26,122,60,.18);
    --blue:#1B5A8A;  --blue-l:#2478B8;  --blue-b:rgba(27,90,138,.18);
    --red:#8B2020;   --red-l:#C03030;   --red-b:rgba(139,32,32,.18);
    --purple:#5C2D8A;--purple-l:#7C44B8;--purple-b:rgba(92,45,138,.18);
    --font:'DM Sans',sans-serif; --mono:'DM Mono',monospace; --display:'Bebas Neue',sans-serif;
  }
  html,body,#root { height:100%; background:var(--soil); color:var(--chalk); font-family:var(--font); font-size:13px; }
  @keyframes fadeUp  { from{opacity:0;transform:translateY(8px)} to{opacity:1;transform:translateY(0)} }
  @keyframes fadeIn  { from{opacity:0} to{opacity:1} }
  @keyframes slideR  { from{opacity:0;transform:translateX(20px)} to{opacity:1;transform:translateX(0)} }
  @keyframes popIn   { from{opacity:0;transform:scale(.96)} to{opacity:1;transform:scale(1)} }

  /* Shell */
  .dm-root { display:flex; height:100vh; overflow:hidden; }
  .dm-sidebar { width:210px; flex-shrink:0; background:var(--clay); border-right:1px solid var(--gravel); display:flex; flex-direction:column; }
  .dm-logo { padding:16px 14px 12px; border-bottom:1px solid var(--gravel); font-family:var(--display); font-size:18px; letter-spacing:.04em; color:var(--amber-l); }
  .dm-logo span { display:block; font-family:var(--font); font-size:10px; font-weight:500; letter-spacing:.08em; text-transform:uppercase; color:var(--stone); margin-top:2px; }
  .dm-nav { flex:1; padding:8px 0; overflow-y:auto; }
  .dm-nav-section { padding:10px 14px 3px; font-size:9.5px; font-weight:700; letter-spacing:.1em; text-transform:uppercase; color:var(--stone); }
  .dm-nav-item { display:flex; align-items:center; gap:9px; padding:8px 14px; cursor:pointer; font-size:12.5px; font-weight:500; color:var(--sand); transition:all .15s; border-left:2px solid transparent; }
  .dm-nav-item:hover { background:var(--raise); color:var(--bone); }
  .dm-nav-item.active { background:var(--amber-b); color:var(--amber-l); border-left-color:var(--amber); }
  .dm-nav-badge { margin-left:auto; background:var(--amber); color:#fff; font-size:9px; font-weight:700; padding:1px 5px; border-radius:8px; font-family:var(--mono); }
  .dm-nav-count { margin-left:auto; font-size:10px; color:var(--stone); font-family:var(--mono); }
  .dm-main { flex:1; display:flex; flex-direction:column; overflow:hidden; }
  .dm-topbar { height:52px; background:var(--clay); border-bottom:1px solid var(--gravel); display:flex; align-items:center; padding:0 20px; gap:12px; flex-shrink:0; }
  .dm-topbar-title { font-family:var(--display); font-size:20px; letter-spacing:.04em; }
  .dm-body { flex:1; overflow-y:auto; padding:18px 20px; }

  /* Buttons */
  .btn { padding:6px 14px; border-radius:5px; border:none; cursor:pointer; font-size:12px; font-family:var(--font); font-weight:600; transition:all .15s; display:inline-flex; align-items:center; gap:5px; }
  .btn-primary { background:var(--amber); color:#fff; }
  .btn-primary:hover { background:var(--amber-l); }
  .btn-ghost { background:var(--gravel); color:var(--bone); }
  .btn-ghost:hover { background:var(--stone); }
  .btn-danger { background:var(--red-b); color:var(--red-l); border:1px solid var(--red); }
  .btn-sm { padding:4px 10px; font-size:11px; }
  .btn-xs { padding:2px 7px; font-size:10px; }

  /* Panel */
  .panel { background:var(--clay); border:1px solid var(--gravel); border-radius:8px; overflow:hidden; margin-bottom:14px; animation:fadeUp .22s ease both; }
  .panel-head { padding:11px 16px; border-bottom:1px solid var(--gravel); display:flex; align-items:center; gap:10px; }
  .panel-title { font-size:12px; font-weight:700; letter-spacing:.06em; text-transform:uppercase; color:var(--bone); }
  .panel-sub { font-size:11px; color:var(--stone); margin-left:auto; }
  .panel-body { padding:14px 16px; }

  /* KPI */
  .kpi-row { display:grid; grid-template-columns:repeat(5,1fr); gap:10px; margin-bottom:16px; }
  .kpi { background:var(--clay); border:1px solid var(--gravel); border-radius:8px; padding:14px 16px 12px; position:relative; overflow:hidden; animation:fadeUp .2s ease both; }
  .kpi::after { content:''; position:absolute; bottom:0; left:0; right:0; height:3px; }
  .kpi.amber::after { background:linear-gradient(90deg,var(--amber),var(--amber-l)); }
  .kpi.green::after { background:linear-gradient(90deg,var(--green),var(--green-l)); }
  .kpi.blue::after  { background:linear-gradient(90deg,var(--blue),var(--blue-l)); }
  .kpi.teal::after  { background:linear-gradient(90deg,var(--teal),var(--teal-l)); }
  .kpi.red::after   { background:linear-gradient(90deg,var(--red),var(--red-l)); }
  .kpi-label { font-size:10px; font-weight:600; letter-spacing:.08em; text-transform:uppercase; color:var(--stone); margin-bottom:4px; }
  .kpi-val { font-family:var(--display); font-size:26px; line-height:1.1; }
  .kpi-sub { font-size:10.5px; color:var(--sand); margin-top:3px; }

  /* Badge */
  .badge { display:inline-flex; align-items:center; padding:2px 7px; border-radius:3px; font-size:10px; font-weight:700; letter-spacing:.04em; text-transform:uppercase; }
  .b-amber  { background:var(--amber-b);  color:var(--amber-l);  }
  .b-teal   { background:var(--teal-b);   color:var(--teal-l);   }
  .b-green  { background:var(--green-b);  color:var(--green-l);  }
  .b-blue   { background:var(--blue-b);   color:var(--blue-l);   }
  .b-red    { background:var(--red-b);    color:var(--red-l);    }
  .b-purple { background:var(--purple-b); color:var(--purple-l); }
  .b-stone  { background:var(--gravel);   color:var(--sand);     }

  /* Table */
  .tbl { width:100%; border-collapse:collapse; }
  .tbl th { padding:7px 12px; text-align:left; font-size:10px; font-weight:700; letter-spacing:.08em; text-transform:uppercase; color:var(--stone); border-bottom:1px solid var(--gravel); white-space:nowrap; }
  .tbl td { padding:10px 12px; border-bottom:1px solid rgba(48,44,36,.4); font-size:12.5px; vertical-align:middle; }
  .tbl tr:last-child td { border-bottom:none; }
  .tbl tr.clickable:hover td { background:var(--raise); cursor:pointer; }
  .mono { font-family:var(--mono); font-size:11px; color:var(--amber-l); }

  /* Doc card */
  .doc-card { background:var(--clay); border:1px solid var(--gravel); border-radius:8px; padding:14px 16px; cursor:pointer; transition:all .15s; animation:fadeUp .2s ease both; display:flex; gap:14px; align-items:flex-start; margin-bottom:8px; }
  .doc-card:hover { border-color:var(--stone); transform:translateY(-1px); box-shadow:0 4px 12px rgba(0,0,0,.2); }
  .doc-card-icon { font-size:28px; flex-shrink:0; width:40px; text-align:center; margin-top:2px; }
  .doc-card-id { font-family:var(--mono); font-size:10px; color:var(--amber-l); margin-bottom:2px; }
  .doc-card-name { font-size:13px; font-weight:700; color:var(--chalk); line-height:1.3; margin-bottom:4px; }
  .doc-card-desc { font-size:11.5px; color:var(--sand); line-height:1.5; margin-bottom:6px; }
  .doc-card-meta { display:flex; gap:8px; align-items:center; flex-wrap:wrap; }
  .doc-card-size { font-family:var(--mono); font-size:10px; color:var(--stone); }
  .doc-card-actions { margin-left:auto; display:flex; gap:6px; flex-shrink:0; }

  /* Tags */
  .tag { display:inline-flex; padding:1px 6px; border-radius:3px; font-size:10px; font-weight:500; background:var(--raise); color:var(--sand); border:1px solid var(--gravel); }

  /* Tree view */
  .tree-job { background:var(--clay); border:1px solid var(--gravel); border-radius:8px; overflow:hidden; margin-bottom:10px; }
  .tree-job-head { padding:12px 16px; cursor:pointer; display:flex; align-items:center; gap:10px; background:var(--raise); transition:background .15s; }
  .tree-job-head:hover { background:var(--gravel); }
  .tree-job-name { font-size:13px; font-weight:700; color:var(--chalk); flex:1; }
  .tree-job-count { font-family:var(--mono); font-size:11px; color:var(--stone); }
  .tree-cat-head { padding:8px 16px 6px; display:flex; align-items:center; gap:8px; border-top:1px solid var(--gravel); background:var(--clay); }
  .tree-cat-label { font-size:11px; font-weight:700; color:var(--bone); flex:1; text-transform:uppercase; letter-spacing:.06em; }
  .tree-doc-row { padding:8px 16px 8px 32px; display:flex; align-items:center; gap:10px; border-top:1px solid rgba(48,44,36,.3); cursor:pointer; transition:background .12s; }
  .tree-doc-row:hover { background:var(--raise); }
  .tree-doc-name { font-size:12.5px; color:var(--chalk); flex:1; }
  .tree-doc-size { font-family:var(--mono); font-size:10px; color:var(--stone); }

  /* Upload drop zone */
  .dropzone { border:2px dashed var(--stone); border-radius:8px; padding:32px; text-align:center; transition:all .15s; cursor:pointer; }
  .dropzone:hover, .dropzone.drag { border-color:var(--amber-l); background:var(--amber-b); }
  .dropzone-icon { font-size:32px; margin-bottom:8px; }
  .dropzone-text { font-size:13.5px; color:var(--bone); font-weight:600; }
  .dropzone-sub { font-size:11.5px; color:var(--stone); margin-top:4px; }

  /* Detail drawer */
  .detail-overlay { position:fixed; inset:0; background:rgba(0,0,0,.5); z-index:400; display:flex; justify-content:flex-end; animation:fadeIn .18s ease; }
  .detail-drawer { width:480px; background:var(--clay); height:100%; overflow-y:auto; animation:slideR .2s ease; border-left:1px solid var(--gravel); display:flex; flex-direction:column; }
  .detail-head { padding:16px 20px; border-bottom:1px solid var(--gravel); display:flex; align-items:flex-start; gap:12px; flex-shrink:0; position:sticky; top:0; background:var(--clay); z-index:2; }
  .detail-close { width:28px; height:28px; border-radius:50%; background:var(--gravel); border:none; cursor:pointer; color:var(--sand); font-size:14px; display:flex; align-items:center; justify-content:center; flex-shrink:0; }
  .detail-close:hover { background:var(--stone); }
  .detail-body { padding:16px 20px; flex:1; }
  .detail-section { margin-bottom:18px; }
  .detail-section-title { font-size:10px; font-weight:700; letter-spacing:.1em; text-transform:uppercase; color:var(--stone); margin-bottom:8px; padding-bottom:5px; border-bottom:1px solid var(--gravel); }
  .detail-row { display:flex; gap:12px; padding:6px 0; border-bottom:1px solid rgba(48,44,36,.3); font-size:12.5px; }
  .detail-row:last-child { border-bottom:none; }
  .detail-row-label { color:var(--sand); min-width:110px; flex-shrink:0; }
  .detail-row-val { color:var(--chalk); flex:1; }

  /* Upload modal */
  .modal-overlay { position:fixed; inset:0; background:rgba(0,0,0,.6); z-index:500; display:flex; align-items:center; justify-content:center; animation:fadeIn .18s ease; }
  .modal { background:var(--clay); border:1px solid var(--gravel); border-radius:10px; width:520px; max-height:85vh; display:flex; flex-direction:column; animation:popIn .18s ease; }
  .modal-head { padding:14px 18px; border-bottom:1px solid var(--gravel); display:flex; align-items:center; gap:10px; }
  .modal-title { font-size:13px; font-weight:700; color:var(--chalk); flex:1; }
  .modal-close { width:26px; height:26px; border-radius:50%; background:var(--gravel); border:none; cursor:pointer; color:var(--sand); font-size:13px; display:flex; align-items:center; justify-content:center; }
  .modal-close:hover { background:var(--stone); }
  .modal-body { flex:1; overflow-y:auto; padding:16px 18px; }

  /* Inputs */
  .field-label { font-size:10px; font-weight:600; letter-spacing:.06em; text-transform:uppercase; color:var(--stone); margin-bottom:4px; }
  .field-input { width:100%; background:var(--gravel); border:1px solid var(--stone); border-radius:5px; padding:8px 10px; font-size:12.5px; color:var(--chalk); font-family:var(--font); outline:none; transition:border-color .15s; }
  .field-input:focus { border-color:var(--amber); }
  .field-select { width:100%; background:var(--gravel); border:1px solid var(--stone); border-radius:5px; padding:8px 10px; font-size:12.5px; color:var(--chalk); font-family:var(--font); outline:none; cursor:pointer; appearance:none; }
  .field-select:focus { border-color:var(--amber); }

  /* Progress */
  .prog { height:4px; background:var(--gravel); border-radius:2px; overflow:hidden; }
  .prog-fill { height:100%; border-radius:2px; }

  /* View toggle */
  .view-toggle { display:inline-flex; background:var(--gravel); border-radius:5px; padding:2px; }
  .view-btn { width:28px; height:26px; border-radius:4px; border:none; cursor:pointer; background:transparent; color:var(--stone); font-size:14px; display:flex; align-items:center; justify-content:center; transition:all .15s; }
  .view-btn.active { background:var(--clay); color:var(--chalk); }

  /* Retention table */
  .retention-row { display:flex; align-items:center; gap:12px; padding:10px 14px; border-bottom:1px solid rgba(48,44,36,.4); }
  .retention-row:last-child { border-bottom:none; }
  .retention-cat { font-size:13px; color:var(--chalk); min-width:140px; font-weight:600; }
  .retention-years { font-family:var(--display); font-size:22px; color:var(--amber-l); min-width:60px; }
  .retention-reason { font-size:11.5px; color:var(--sand); flex:1; }

  ::-webkit-scrollbar { width:5px; height:5px; }
  ::-webkit-scrollbar-track { background:transparent; }
  ::-webkit-scrollbar-thumb { background:var(--gravel); border-radius:3px; }
  ::-webkit-scrollbar-thumb:hover { background:var(--stone); }

  @media (max-width:1100px) { .kpi-row { grid-template-columns:repeat(3,1fr); } }
  @media (max-width:768px)  { .dm-sidebar { width:52px; } .kpi-row { grid-template-columns:repeat(2,1fr); } }
`;

// -- Document detail drawer ------------------------------------
function DocDetailDrawer({ doc, onClose }) {
  const cat = gw_documents_CATEGORIES[doc.cat] || gw_documents_CATEGORIES.Other;
  const sm  = gw_documents_STATUS_META[doc.status] || gw_documents_STATUS_META.current;

  return (
    <div className="detail-overlay" onClick={onClose}>
      <div className="detail-drawer" onClick={e => e.stopPropagation()}>
        <div className="detail-head">
          <span style={{ fontSize:28 }}>{cat.icon}</span>
          <div style={{ flex:1, minWidth:0 }}>
            <div className="mono">{doc.id}</div>
            <div style={{ fontSize:13.5, fontWeight:700, color:"var(--chalk)", lineHeight:1.3, marginTop:2 }}>
              {doc.name}
            </div>
          </div>
          <button className="detail-close" onClick={onClose}>✕</button>
        </div>

        <div className="detail-body">
          {/* Actions */}
          <div style={{ display:"flex", gap:8, marginBottom:18, flexWrap:"wrap" }}>
            <button className="btn btn-primary btn-sm">⬇ Download</button>
            <button className="btn btn-ghost btn-sm">👁 Preview</button>
            <button className="btn btn-ghost btn-sm">📤 Share</button>
            <button className="btn btn-ghost btn-sm">➕ New Rev</button>
          </div>

          <div className="detail-section">
            <div className="detail-section-title">Document Info</div>
            {[
              { label:"Category", val:<span className={"badge "+(cat.badge)}>{doc.cat}</span> },
              { label:"Status",   val:<span className={"badge "+(sm.cls)}>{sm.label}</span> },
              { label:"Revision", val:doc.rev || "—" },
              { label:"Pages",    val:doc.pages },
              { label:"File Size",val:doc.size },
              { label:"Uploaded", val:doc.uploadedBy+" · "+doc.uploaded },
              doc.expiresAt && { label:"Expires", val:<span style={{color:"var(--red-l)"}}>{doc.expiresAt}</span> },
            ].filter(Boolean).map(r => (
              <div key={r.label} className="detail-row">
                <span className="detail-row-label">{r.label}</span>
                <span className="detail-row-val">{r.val}</span>
              </div>
            ))}
          </div>
          {doc.jobId && (
            <div className="detail-section">
              <div className="detail-section-title">Project Reference</div>
              <div className="detail-row">
                <span className="detail-row-label">Job</span>
                <span className="detail-row-val mono">{doc.jobId}</span>
              </div>
              <div className="detail-row">
                <span className="detail-row-label">Project</span>
                <span className="detail-row-val">{doc.jobName}</span>
              </div>
            </div>
          )}

          {doc.linkedTo && (
            <div className="detail-section">
              <div className="detail-section-title">Linked Record</div>
              <div className="detail-row">
                <span className="detail-row-label">Module</span>
                <span className="detail-row-val">{doc.linkedTo.module}</span>
              </div>
              <div className="detail-row">
                <span className="detail-row-label">Record ID</span>
                <span className="detail-row-val mono">{doc.linkedTo.id}</span>
              </div>
            </div>
          )}

          {doc.description && (
            <div className="detail-section">
              <div className="detail-section-title">Description</div>
              <div style={{ fontSize:12.5, color:"var(--sand)", lineHeight:1.6, background:"var(--raise)", borderRadius:6, padding:"10px 12px" }}>
                {doc.description}
              </div>
            </div>
          )}

          {doc.tags?.length > 0 && (
            <div className="detail-section">
              <div className="detail-section-title">Tags</div>
              <div style={{ display:"flex", gap:5, flexWrap:"wrap" }}>
                {doc.tags.map(t => <span key={t} className="tag">{t}</span>)}
              </div>
            </div>
          )}

          {/* Version history stub */}
          <div className="detail-section">
            <div className="detail-section-title">Version History</div>
            <div style={{ background:"var(--raise)", borderRadius:6, padding:"10px 12px" }}>
              {[
                { rev:doc.rev||"v1", date:doc.uploaded, user:doc.uploadedBy, note:"Current" },
                doc.rev && doc.rev !== "v1" && { rev:"Rev 1", date:"Earlier", user:doc.uploadedBy, note:"Previous" },
              ].filter(Boolean).map((v, i) => (
 <div key={i} style={{ display:"flex", gap:10, padding:"6px 0", borderBottom:i===0?"1px solid var(--gravel)":"none", fontSize:12 }}>
                  <span className="mono" style={{ minWidth:50 }}>{v.rev}</span>
                  <span style={{ color:"var(--sand)", flex:1 }}>{v.date} · {v.user}</span>
                  <span className={"badge "+(i===0?"b-green":"b-stone")}>{v.note}</span>
                </div>
              ))}
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}

// -- Upload modal ----------------------------------------------
function UploadModal({ onClose }) {
  const [drag, setDrag] = useState(false);

  return (
    <div className="modal-overlay" onClick={onClose}>
      <div className="modal" onClick={e => e.stopPropagation()}>
        <div className="modal-head">
          <span className="modal-title">⬆ Upload Document</span>
          <button className="modal-close" onClick={onClose}>✕</button>
        </div>
        <div className="modal-body">
 <div className={"dropzone"+(drag?" drag":"")} onDragOver={e=>{e.preventDefault();setDrag(true);}}
            onDragLeave={()=>setDrag(false)}
            onDrop={e=>{e.preventDefault();setDrag(false);}}>
            <div className="dropzone-icon">📂</div>
            <div className="dropzone-text">Drop files here or click to browse</div>
            <div className="dropzone-sub">PDF, DOCX, DWG, XLSX — up to 100 MB per file</div>
          </div>
          <div style={{ display:"grid", gridTemplateColumns:"1fr 1fr", gap:10, marginTop:14 }}>
            <div>
              <div className="field-label">Category</div>
              <select className="field-select">
                {Object.keys(gw_documents_CATEGORIES).map(c => <option key={c}>{c}</option>)}
              </select>
            </div>
            <div>
              <div className="field-label">Linked Job</div>
              <select className="field-select">
                <option value="">— Not job-specific —</option>
                {[...new Set(DOCUMENTS.filter(d=>d.jobId).map(d=>d.jobId))].map(j => (
                  <option key={j} value={j}>{j}</option>
                ))}
              </select>
            </div>
            <div>
              <div className="field-label">Revision / Version</div>
              <input className="field-input" placeholder="e.g. Rev 1, v2, Final…" />
            </div>
            <div>
              <div className="field-label">Status</div>
              <select className="field-select">
                {Object.entries(gw_documents_STATUS_META).map(([k,v]) => <option key={k} value={k}>{v.label}</option>)}
              </select>
            </div>
          </div>
          <div style={{ marginTop:10 }}>
            <div className="field-label">Description</div>
            <textarea className="field-input" rows={3} placeholder="Brief description of this document…" style={{ resize:"vertical" }} />
          </div>
          <div style={{ marginTop:10 }}>
            <div className="field-label">Tags (comma-separated)</div>
            <input className="field-input" placeholder="e.g. submittal, hvac, approved" />
          </div>
          <div style={{ display:"flex", gap:8, marginTop:14 }}>
            <button className="btn btn-primary" style={{ flex:1, justifyContent:"center" }}>
              ⬆ Upload Document
            </button>
            <button className="btn btn-ghost" onClick={onClose}>Cancel</button>
          </div>
        </div>
      </div>
    </div>
  );
}

// -- All Documents view ----------------------------------------
function AllDocumentsView() {
  const [search,     setSearch]     = useState("");
  const [catFilter,  setCatFilter]  = useState("all");
  const [statusFilter,setStatusFilter] = useState("all");
  const [jobFilter,  setJobFilter]  = useState("all");
  const [viewMode,   setViewMode]   = useState("list"); // list | grid
  const [selectedDoc,setSelectedDoc]= useState(null);
  const [showUpload, setShowUpload] = useState(false);

  const jobs = [{ id:"all", name:"All Jobs" }, ...Object.entries(docsByJob()).map(([k,v])=>({ id:k, name:v.name }))];

  const filtered = DOCUMENTS.filter(d => {
    const ms = !search || (d.name + d.description + d.tags?.join(" ")).toLowerCase().includes(search.toLowerCase());
    const mc = catFilter    === "all" || d.cat     === catFilter;
    const mst= statusFilter === "all" || d.status  === statusFilter;
    const mj = jobFilter    === "all" || d.jobId   === jobFilter || (!d.jobId && jobFilter === "templates");
    return ms && mc && mst && mj;
  });

  return (
    <div>
      {/* Filters */}
      <div style={{ display:"flex", gap:8, marginBottom:14, flexWrap:"wrap", alignItems:"center" }}>
 <input className="field-input" placeholder="🔍 Search documents…" value={search} onChange={e=>setSearch(e.target.value)}
          style={{ flex:"1", minWidth:200, maxWidth:300 }} />
        <select className="field-select" value={catFilter} onChange={e=>setCatFilter(e.target.value)}
          style={{ width:150 }}>
          <option value="all">All Categories</option>
          {Object.keys(gw_documents_CATEGORIES).map(c => <option key={c}>{c}</option>)}
        </select>
        <select className="field-select" value={statusFilter} onChange={e=>setStatusFilter(e.target.value)}
          style={{ width:150 }}>
          <option value="all">All Statuses</option>
          {Object.entries(gw_documents_STATUS_META).map(([k,v]) => <option key={k} value={k}>{v.label}</option>)}
        </select>
        <select className="field-select" value={jobFilter} onChange={e=>setJobFilter(e.target.value)}
          style={{ width:180 }}>
          {jobs.map(j => <option key={j.id} value={j.id}>{j.name}</option>)}
          <option value="templates">Templates only</option>
        </select>
        <div className="view-toggle">
          <button className={"view-btn"+(viewMode==="list"?" active":"")} onClick={()=>setViewMode("list")}>☰</button>
          <button className={"view-btn"+(viewMode==="grid"?" active":"")} onClick={()=>setViewMode("grid")}>⊞</button>
        </div>
        <button className="btn btn-primary btn-sm" onClick={()=>setShowUpload(true)}>⬆ Upload</button>
        <span style={{ fontSize:11, color:"var(--stone)" }}>{filtered.length} docs</span>
      </div>

      {viewMode === "list" ? (
        <table className="tbl">
          <thead><tr>
            <th></th><th>Document</th><th>Category</th>
            <th>Job</th><th>Rev</th><th>Status</th>
            <th>Uploaded</th><th>Size</th><th></th>
          </tr></thead>
          <tbody>
            {filtered.map((doc, i) => {
              const cat = gw_documents_CATEGORIES[doc.cat] || gw_documents_CATEGORIES.Other;
              const sm  = gw_documents_STATUS_META[doc.status] || gw_documents_STATUS_META.current;
              return (
                <tr key={doc.id} className="clickable" onClick={()=>setSelectedDoc(doc)}>
                  <td style={{ width:32, textAlign:"center", fontSize:18 }}>{cat.icon}</td>
                  <td style={{ maxWidth:280 }}>
                    <div style={{ fontSize:12.5, fontWeight:600, color:"var(--chalk)", lineHeight:1.3 }}>{doc.name}</div>
                    <div style={{ fontSize:11, color:"var(--stone)", marginTop:2 }}>{doc.description?.slice(0,60)}…</div>
                  </td>
                  <td><span className={"badge "+(cat.badge)}>{doc.cat}</span></td>
                  <td style={{ fontSize:11 }}>
                    {doc.jobId
                      ? <><div className="mono">{doc.jobId}</div><div style={{ fontSize:10.5, color:"var(--stone)" }}>{doc.jobName?.slice(0,28)}</div></>
                      : <span style={{ color:"var(--stone)" }}>Template</span>
                    }
                  </td>
                  <td style={{ fontFamily:"var(--mono)", fontSize:11, color:"var(--stone)" }}>{doc.rev||"—"}</td>
                  <td><span className={"badge "+(sm.cls)}>{sm.label}</span></td>
                  <td style={{ fontSize:11.5, color:"var(--stone)" }}>
                    <div>{doc.uploaded}</div>
                    <div style={{ fontSize:10.5 }}>{doc.uploadedBy}</div>
                  </td>
                  <td style={{ fontFamily:"var(--mono)", fontSize:11, color:"var(--stone)" }}>{doc.size}</td>
                  <td>
                    <div style={{ display:"flex", gap:4 }}>
                      <button className="btn btn-ghost btn-xs" onClick={e=>{e.stopPropagation();}}>⬇</button>
                      <button className="btn btn-ghost btn-xs" onClick={e=>{e.stopPropagation();setSelectedDoc(doc);}}>👁</button>
                    </div>
                  </td>
                </tr>
              );
            })}
          </tbody>
        </table>
      ) : (
        <div style={{ display:"grid", gridTemplateColumns:"repeat(auto-fill,minmax(320px,1fr))", gap:10 }}>
          {filtered.map((doc, i) => {
            const cat = gw_documents_CATEGORIES[doc.cat] || gw_documents_CATEGORIES.Other;
            const sm  = gw_documents_STATUS_META[doc.status] || gw_documents_STATUS_META.current;
            return (
 <div key={doc.id} className="doc-card" style={{ animationDelay:`${i*.03}s` }} onClick={()=>setSelectedDoc(doc)}>
                <div className="doc-card-icon">{cat.icon}</div>
                <div style={{ flex:1, minWidth:0 }}>
                  <div className="doc-card-id">{doc.id}</div>
                  <div className="doc-card-name">{doc.name}</div>
                  <div className="doc-card-desc">{doc.description?.slice(0,80)}…</div>
                  <div className="doc-card-meta">
                    <span className={"badge "+(cat.badge)}>{doc.cat}</span>
                    <span className={"badge "+(sm.cls)}>{sm.label}</span>
                    {doc.rev && <span style={{ fontFamily:"var(--mono)", fontSize:10, color:"var(--stone)" }}>{doc.rev}</span>}
                    <span className="doc-card-size">{doc.size}</span>
                  </div>
                  {doc.tags?.length > 0 && (
                    <div style={{ display:"flex", gap:4, flexWrap:"wrap", marginTop:6 }}>
                      {doc.tags.slice(0,3).map(t => <span key={t} className="tag">{t}</span>)}
                    </div>
                  )}
                </div>
              </div>
            );
          })}
        </div>
      )}

      {selectedDoc && <DocDetailDrawer doc={selectedDoc} onClose={()=>setSelectedDoc(null)} />}
      {showUpload   && <UploadModal onClose={()=>setShowUpload(false)} />}
    </div>
  );
}

// -- By Project view -------------------------------------------
function ByProjectView() {
  const [openJobs, setOpenJobs] = useState({});
  const [selectedDoc, setSelectedDoc] = useState(null);
  const byJob = docsByJob();

  function toggleJob(id) {
    setOpenJobs(prev => ({ ...prev, [id]: !prev[id] }));
  }

  function groupByCategory(docs) {
    const map = {};
    docs.forEach(d => {
      if (!map[d.cat]) map[d.cat] = [];
      map[d.cat].push(d);
    });
    return map;
  }

  return (
    <div>
      {Object.entries(byJob).map(([jobId, { name, docs }]) => {
        const isOpen  = openJobs[jobId] !== false; // default open
        const byCat   = groupByCategory(docs);
        const pending = docs.filter(d => d.status === "pending").length;

        return (
          <div key={jobId} className="tree-job">
            <div className="tree-job-head" onClick={()=>toggleJob(jobId)}>
 <span style={{ fontSize:12, color:"var(--stone)", transition:"transform .2s", display:"inline-block", transform:isOpen?"rotate(0deg)":"rotate(-90deg)" }}>▾</span>
              <div style={{ flex:1 }}>
                <div className="mono">{jobId}</div>
                <div className="tree-job-name">{name}</div>
              </div>
              {pending > 0 && <span className="dm-nav-badge">{pending} pending</span>}
              <span className="tree-job-count">{docs.length} docs</span>
            </div>
            {isOpen && Object.entries(byCat).map(([cat, catDocs]) => {
              const catMeta = gw_documents_CATEGORIES[cat] || gw_documents_CATEGORIES.Other;
              return (
                <div key={cat}>
                  <div className="tree-cat-head">
                    <span style={{ fontSize:14 }}>{catMeta.icon}</span>
                    <span className="tree-cat-label">{cat}</span>
                    <span style={{ fontFamily:"var(--mono)", fontSize:10, color:"var(--stone)" }}>{catDocs.length}</span>
                  </div>
                  {catDocs.map(doc => {
                    const sm = gw_documents_STATUS_META[doc.status] || gw_documents_STATUS_META.current;
                    return (
                      <div key={doc.id} className="tree-doc-row" onClick={()=>setSelectedDoc(doc)}>
                        <div className="tree-doc-name">{doc.name}</div>
                        {doc.rev && <span style={{ fontFamily:"var(--mono)", fontSize:10, color:"var(--stone)" }}>{doc.rev}</span>}
                        <span className={"badge "+(sm.cls)} style={{ fontSize:9 }}>{sm.label}</span>
                        <span className="tree-doc-size">{doc.size}</span>
                        <button className="btn btn-ghost btn-xs" onClick={e=>{e.stopPropagation();}}>⬇</button>
                      </div>
                    );
                  })}
                </div>
              );
            })}
          </div>
        );
      })}
      {selectedDoc && <DocDetailDrawer doc={selectedDoc} onClose={()=>setSelectedDoc(null)} />}
    </div>
  );
}

// -- Templates view --------------------------------------------
function TemplatesView() {
  const templates = DOCUMENTS.filter(d => !d.jobId);
  const [selectedDoc, setSelectedDoc] = useState(null);

  return (
    <div>
      <div style={{ marginBottom:14, display:"flex", justifyContent:"space-between", alignItems:"center" }}>
        <div style={{ fontSize:13, color:"var(--sand)" }}>
          {templates.length} document templates — reusable forms, contracts, and standard documents
        </div>
        <button className="btn btn-primary btn-sm">⬆ Add Template</button>
      </div>

      <div style={{ display:"grid", gridTemplateColumns:"repeat(auto-fill,minmax(320px,1fr))", gap:10 }}>
        {templates.map((doc, i) => {
          const cat = gw_documents_CATEGORIES[doc.cat] || gw_documents_CATEGORIES.Other;
          return (
            <div key={doc.id} className="doc-card" style={{ animationDelay:`${i*.05}s` }}>
              <div className="doc-card-icon">{cat.icon}</div>
              <div style={{ flex:1, minWidth:0 }}>
                <div className="doc-card-name">{doc.name.replace("TEMPLATE – ","")}</div>
                <div className="doc-card-desc">{doc.description}</div>
                <div className="doc-card-meta">
                  <span className={"badge "+(cat.badge)}>{doc.cat}</span>
                  <span style={{ fontFamily:"var(--mono)", fontSize:10, color:"var(--stone)" }}>{doc.rev}</span>
                  <span className="doc-card-size">{doc.size}</span>
                </div>
              </div>
              <div className="doc-card-actions" style={{ flexDirection:"column", gap:5 }}>
                <button className="btn btn-primary btn-xs" style={{ whiteSpace:"nowrap" }}>
                  Use Template
                </button>
                <button className="btn btn-ghost btn-xs" onClick={()=>setSelectedDoc(doc)}>Details</button>
              </div>
            </div>
          );
        })}
      </div>
      {selectedDoc && <DocDetailDrawer doc={selectedDoc} onClose={()=>setSelectedDoc(null)} />}
    </div>
  );
}

// -- Pending Review view ---------------------------------------
function PendingView() {
  const pending = DOCUMENTS.filter(d => d.status === "pending");

  return (
    <div>
      {PENDING_REVIEWS.map(item => {
        const doc = DOCUMENTS.find(d => d.id === item.docId);
        if (!doc) return null;
        const cat = gw_documents_CATEGORIES[doc.cat] || gw_documents_CATEGORIES.Other;
        const daysLeft = Math.ceil((new Date(item.dueDate) - new Date()) / 86400000);

        return (
 <div key={item.docId} style={{ background:"var(--clay)", border:`1px solid ${item.urgent?"var(--red)":"var(--gravel)"}`, borderRadius:8, padding:"16px 18px", marginBottom:12, animation:"fadeUp .2s ease both" }}>
            <div style={{ display:"flex", alignItems:"flex-start", gap:14 }}>
              <span style={{ fontSize:26 }}>{cat.icon}</span>
              <div style={{ flex:1 }}>
                <div style={{ display:"flex", gap:8, alignItems:"center", marginBottom:4 }}>
                  {item.urgent && <span className="badge b-red">🔴 Urgent</span>}
                  <span className="badge b-amber">{item.type}</span>
                  <span style={{ fontFamily:"var(--mono)", fontSize:10, color:"var(--stone)" }}>Due {item.dueDate}</span>
                  <span style={{ fontFamily:"var(--mono)", fontSize:10, color:daysLeft <= 3 ? "var(--red-l)" : "var(--amber-l)" }}>
                    {daysLeft > 0 ? `${daysLeft}d left` : "Overdue"}
                  </span>
                </div>
                <div style={{ fontSize:14, fontWeight:700, color:"var(--chalk)", marginBottom:2 }}>{doc.name}</div>
                <div style={{ fontSize:12, color:"var(--sand)", marginBottom:8 }}>
                  {item.jobName} · Assigned to {item.assignedTo}
                </div>
                <div style={{ fontSize:12, color:"var(--sand)" }}>{doc.description}</div>
              </div>
              <div style={{ display:"flex", flexDirection:"column", gap:6, flexShrink:0 }}>
                <button className="btn btn-primary btn-sm">✅ Approve</button>
                <button className="btn btn-ghost btn-sm">🔄 Request Changes</button>
                <button className="btn btn-ghost btn-sm">👁 Review</button>
              </div>
            </div>
          </div>
        );
      })}
      {pending.length === 0 && PENDING_REVIEWS.length === 0 && (
        <div style={{ textAlign:"center", padding:"48px", color:"var(--stone)" }}>
          <div style={{ fontSize:32, marginBottom:8 }}>✅</div>
          No documents pending review
        </div>
      )}
    </div>
  );
}

// -- Retention view --------------------------------------------
function RetentionView() {
  return (
    <div>
      <div style={{ marginBottom:14 }}>
 <div style={{ background:"var(--amber-b)", border:"1px solid var(--amber)", borderRadius:6, padding:"10px 14px", fontSize:12.5, color:"var(--amber-l)", marginBottom:10 }}>
          ⚠ Document retention policies are set by AZ statute and federal regulations. Review with legal counsel annually.
        </div>
      </div>

      <div className="panel" style={{ marginBottom:14 }}>
        <div className="panel-head"><span className="panel-title">Retention Schedule by Category</span></div>
        {RETENTION_RULES.map((r, i) => {
          const cat = gw_documents_CATEGORIES[r.cat] || gw_documents_CATEGORIES.Other;
          return (
            <div key={r.cat} className="retention-row">
              <span style={{ fontSize:18, minWidth:24 }}>{cat.icon}</span>
              <span className="retention-cat">{r.cat}</span>
              <span className="retention-years">{r.years}Y</span>
              <span className="retention-reason">{r.reason}</span>
            </div>
          );
        })}
      </div>

      <div className="panel">
        <div className="panel-head">
          <span className="panel-title">Expiring Documents</span>
          <span className="panel-sub">Next 12 months</span>
        </div>
        <table className="tbl">
          <thead><tr>
            <th>Document</th><th>Category</th><th>Job</th><th>Expires</th><th>Days</th><th></th>
          </tr></thead>
          <tbody>
            {DOCUMENTS.filter(d => d.expiresAt).map(doc => {
              const daysLeft = Math.ceil((new Date(doc.expiresAt) - new Date()) / 86400000);
              const urgency  = daysLeft < 30 ? "var(--red-l)" : daysLeft < 90 ? "var(--amber-l)" : "var(--sand)";
              const cat = gw_documents_CATEGORIES[doc.cat] || gw_documents_CATEGORIES.Other;
              return (
                <tr key={doc.id}>
                  <td>
                    <div style={{ fontSize:12.5, fontWeight:600, color:"var(--chalk)" }}>{doc.name}</div>
                  </td>
                  <td><span className={"badge "+(cat.badge)}>{doc.cat}</span></td>
                  <td style={{ fontFamily:"var(--mono)", fontSize:11, color:"var(--stone)" }}>{doc.jobId||"—"}</td>
                  <td style={{ fontFamily:"var(--mono)", fontSize:12, color:urgency }}>{doc.expiresAt}</td>
                  <td style={{ fontFamily:"var(--mono)", fontSize:12, color:urgency }}>{daysLeft}d</td>
                  <td><button className="btn btn-ghost btn-xs">Renew</button></td>
                </tr>
              );
            })}
          </tbody>
        </table>
      </div>
    </div>
  );
}

// -- Root component --------------------------------------------
function GroundworkDocuments() {
  const [activeTab, setActiveTab] = useState("all");

  const pending = DOCUMENTS.filter(d => d.status === "pending").length;
  const expiring = DOCUMENTS.filter(d => {
    if (!d.expiresAt) return false;
    const days = Math.ceil((new Date(d.expiresAt) - new Date()) / 86400000);
    return days > 0 && days < 90;
  }).length;

  const NAV = [
    { id:"all",       icon:"📁", label:"All Documents",  section:"LIBRARY",  count:DOCUMENTS.length },
    { id:"project",   icon:"🔧", label:"By Project",     section:"LIBRARY",  count:null },
    { id:"templates", icon:"📄", label:"Templates",      section:"LIBRARY",  count:DOCUMENTS.filter(d=>!d.jobId).length },
    { id:"pending",   icon:"🔄", label:"Pending Review", section:"WORKFLOW", badge:pending||null },
    { id:"retention", icon:"🗃", label:"Retention",      section:"COMPLIANCE",badge:expiring||null },
  ];

  const TITLES = {
    all:"All Documents", project:"By Project", templates:"Templates",
    pending:"Pending Review", retention:"Retention Policy",
  };

  // Summary KPIs
  const totalDocs   = DOCUMENTS.length;
  const byJobDocs   = DOCUMENTS.filter(d => d.jobId).length;
  const templateDocs= DOCUMENTS.filter(d => !d.jobId).length;
  const totalSizeMB = 112.4; // sum of all sizes

  return (
    <>
      <style>{css_gw_documents}</style>
      <div className="dm-root">
        <div className="dm-sidebar">
          <div className="dm-logo">GROUNDWORK<span>Document Management</span></div>
          <nav className="dm-nav">
            {["LIBRARY","WORKFLOW","COMPLIANCE"].map(sec => (
              <div key={sec}>
                <div className="dm-nav-section">{sec}</div>
                {NAV.filter(n => n.section === sec).map(n => (
                  <div key={n.id} className={"dm-nav-item"+(activeTab===n.id?" active":"")} onClick={()=>setActiveTab(n.id)}>
                    <span style={{ fontSize:15 }}>{n.icon}</span>
                    <span>{n.label}</span>
                    {n.badge ? <span className="dm-nav-badge">{n.badge}</span>
                              : n.count ? <span className="dm-nav-count">{n.count}</span> : null}
                  </div>
                ))}
              </div>
            ))}
          </nav>
          <div style={{ padding:"10px 14px", borderTop:"1px solid var(--gravel)" }}>
            <div style={{ fontSize:10, color:"var(--stone)", marginBottom:2 }}>STORAGE</div>
            <div style={{ fontFamily:"var(--mono)", fontSize:11, color:"var(--amber-l)" }}>{totalSizeMB} MB used</div>
            <div className="prog" style={{ marginTop:6 }}>
              <div className="prog-fill" style={{ width:"23%", background:"linear-gradient(90deg,var(--amber),var(--amber-l))" }}/>
            </div>
            <div style={{ fontSize:10, color:"var(--stone)", marginTop:3 }}>23% of 500 MB plan</div>
          </div>
        </div>

        <div className="dm-main">
          <div className="dm-topbar">
            <div className="dm-topbar-title">{TITLES[activeTab]}</div>
            <div style={{ marginLeft:"auto", display:"flex", gap:8 }}>
              <button className="btn btn-ghost btn-sm">⬇ Export List</button>
            </div>
          </div>
          <div className="dm-body">
            {activeTab === "all" && (
              <>
                <div className="kpi-row">
                  {[
                    { label:"Total Documents",  val:totalDocs,    sub:"In repository",          cls:"amber", delay:".04s" },
                    { label:"Job Documents",    val:byJobDocs,    sub:"Linked to active jobs",  cls:"blue",  delay:".07s" },
                    { label:"Templates",        val:templateDocs, sub:"Reusable forms",          cls:"teal",  delay:".10s" },
                    { label:"Pending Review",   val:pending,      sub:"Awaiting approval",       cls:pending>0?"red":"green",delay:".13s" },
                    { label:"Storage Used",     val:`${totalSizeMB}MB`, sub:"23% of plan",       cls:"stone", delay:".16s" },
                  ].map(k => (
                    <div key={k.label} className={"kpi "+(k.cls)} style={{ animationDelay:k.delay }}>
                      <div className="kpi-label">{k.label}</div>
                      <div className="kpi-val">{k.val}</div>
                      <div className="kpi-sub">{k.sub}</div>
                    </div>
                  ))}
                </div>
                <AllDocumentsView />
              </>
            )}
            {activeTab === "project"   && <ByProjectView />}
            {activeTab === "templates" && <TemplatesView />}
            {activeTab === "pending"   && <PendingView />}
            {activeTab === "retention" && <RetentionView />}
          </div>
        </div>
      </div>
    </>
  );
}


// -- GROUNDWORK-EAC --------------------------------------
// ============================================================
// GROUNDWORK — EAC / Earned Value Management Module
// Estimate-at-Completion · Earned Value · Forecast · Bonding
// ============================================================

const css_gw_eac = `
  @import url('https://fonts.googleapis.com/css2?family=Bebas+Neue&family=IBM+Plex+Sans:wght@300;400;500;600&family=IBM+Plex+Mono:wght@400;500&display=swap');
  *,*::before,*::after{box-sizing:border-box;margin:0;padding:0}
  :root{
    --bg:#0B0C0E;--surf:#111316;--raise:#181B1F;--card:#1D2026;
    --bord:#242830;--bord2:#2E333C;--mute:#4A5568;--dim:#64748B;
    --lite:#94A3B8;--brite:#CBD5E0;--white:#E8EDF5;
    --sl:#3B7DD8;--sl-d:rgba(59,125,216,.12);--sl-b:rgba(59,125,216,.25);
    --tl:#1FA99A;--tl-d:rgba(31,169,154,.12);
    --gn:#22C55E;--gn-d:rgba(34,197,94,.12);--gn-b:rgba(34,197,94,.25);
    --gd:#D97706;--gd-d:rgba(217,119,6,.12);--gd-b:rgba(217,119,6,.25);
    --rd:#E53E3E;--rd-d:rgba(229,62,62,.12);--rd-b:rgba(229,62,62,.25);
    --og:#EA580C;--og-d:rgba(234,88,12,.12);
    --pu:#7C3AED;--pu-d:rgba(124,58,237,.12);
    --amber:#F59E0B;
  }
  body{font-family:"IBM Plex Sans",sans-serif;background:var(--bg);color:var(--brite);min-height:100vh}
  ::-webkit-scrollbar{width:4px;height:4px}
  ::-webkit-scrollbar-track{background:transparent}
  ::-webkit-scrollbar-thumb{background:var(--mute);border-radius:2px}
  .app{display:flex;height:100vh;overflow:hidden}

  .sb{width:220px;min-width:220px;background:var(--surf);border-right:1px solid var(--bord);display:flex;flex-direction:column;flex-shrink:0;position:relative}
  .sb::before{content:"";position:absolute;top:0;left:0;right:0;height:3px;background:linear-gradient(90deg,var(--sl),var(--tl),var(--gn))}
  .sb-logo{padding:16px 14px 13px;border-bottom:1px solid var(--bord)}
  .sb-gem{width:28px;height:28px;background:var(--sl);border-radius:6px;display:grid;place-items:center;flex-shrink:0}
  .sb-n{font-family:"Bebas Neue",sans-serif;font-size:16px;letter-spacing:2.5px;color:var(--white)}
  .sb-m{font-size:8px;letter-spacing:3px;color:var(--mute);text-transform:uppercase;margin-top:1px}
  .sb-nav{flex:1;overflow-y:auto;padding:8px 0}
  .sb-sec{font-size:8px;font-weight:700;letter-spacing:3px;text-transform:uppercase;color:var(--mute);padding:10px 14px 4px}
  .sb-item{display:flex;align-items:center;gap:8px;padding:8px 14px;cursor:pointer;font-size:12px;color:var(--dim);border-left:2px solid transparent;transition:all .1s}
  .sb-item:hover{background:var(--raise);color:var(--lite)}
  .sb-item.on{background:var(--sl-d);color:var(--sl);border-left-color:var(--sl);font-weight:500}
  .sb-dot{width:4px;height:4px;border-radius:50%;background:currentColor;opacity:.6;flex-shrink:0}

  .main{flex:1;display:flex;flex-direction:column;overflow:hidden;min-width:0}
  .topbar{background:var(--surf);border-bottom:1px solid var(--bord);height:50px;padding:0 22px;display:flex;align-items:center;justify-content:space-between;flex-shrink:0}
  .tb-t{font-family:"Bebas Neue",sans-serif;font-size:16px;letter-spacing:2.5px;color:var(--white)}
  .tb-s{font-size:9px;color:var(--mute);letter-spacing:2px;text-transform:uppercase;margin-top:1px}
  .tab-bar{background:var(--surf);border-bottom:1px solid var(--bord);display:flex;padding:0 22px;flex-shrink:0;overflow-x:auto}
  .tab{padding:10px 15px;font-size:11px;font-weight:500;color:var(--mute);cursor:pointer;border-bottom:2px solid transparent;margin-bottom:-1px;transition:all .1s;white-space:nowrap}
  .tab:hover{color:var(--brite)}.tab.on{color:var(--sl);border-bottom-color:var(--sl)}
  .content{flex:1;overflow-y:auto;padding:20px 22px}

  .btn{display:inline-flex;align-items:center;gap:6px;padding:7px 13px;border-radius:6px;border:none;font-family:"IBM Plex Sans",sans-serif;font-size:12px;font-weight:500;cursor:pointer;transition:all .12s;white-space:nowrap}
  .btn-ghost{background:var(--raise);color:var(--dim);border:1px solid var(--bord)}.btn-ghost:hover{color:var(--lite);background:var(--card)}
  .btn-sl{background:var(--sl);color:#fff}.btn-sl:hover{background:#4A8BE0}
  .btn-gn{background:var(--gn-d);color:var(--gn);border:1px solid var(--gn-b)}.btn-gn:hover{background:rgba(34,197,94,.18)}
  .btn-rd{background:var(--rd-d);color:var(--rd);border:1px solid var(--rd-b)}.btn-rd:hover{background:rgba(229,62,62,.18)}
  .btn-gd{background:var(--gd-d);color:var(--gd);border:1px solid var(--gd-b)}.btn-gd:hover{background:rgba(217,119,6,.18)}
  .btn-tl{background:var(--tl-d);color:var(--tl);border:1px solid rgba(31,169,154,.25)}.btn-tl:hover{background:rgba(31,169,154,.18)}
  .btn-sm{padding:4px 10px;font-size:11px}.btn-xs{padding:3px 8px;font-size:10px;border-radius:4px}

  .panel{background:var(--surf);border:1px solid var(--bord);border-radius:9px;overflow:hidden;margin-bottom:14px}
  .ph{padding:12px 16px;border-bottom:1px solid var(--bord);display:flex;align-items:center;justify-content:space-between;flex-wrap:wrap;gap:8px}
  .pt{font-family:"Bebas Neue",sans-serif;font-size:12px;letter-spacing:2px;color:var(--lite)}
  .ps{font-size:10px;color:var(--mute);margin-top:1px}

  .krow{display:flex;gap:0;margin-bottom:16px}
  .kpi{flex:1;background:var(--surf);border:1px solid var(--bord);padding:13px 15px;position:relative;overflow:hidden}
  .kpi:first-child{border-radius:9px 0 0 9px}.kpi:last-child{border-radius:0 9px 9px 0}.kpi+.kpi{border-left:none}
  .kpi::after{content:"";position:absolute;bottom:0;left:0;right:0;height:2px}
  .k-sl::after{background:var(--sl)}.k-tl::after{background:var(--tl)}.k-gd::after{background:var(--gd)}
  .k-gn::after{background:var(--gn)}.k-rd::after{background:var(--rd)}.k-pu::after{background:var(--pu)}
  .kl{font-size:9px;font-weight:600;letter-spacing:2px;text-transform:uppercase;color:var(--mute);margin-bottom:5px}
  .kv{font-family:"IBM Plex Mono",monospace;font-size:20px;font-weight:500;color:var(--white);line-height:1}
  .ks{font-size:10px;color:var(--mute);margin-top:4px}

  .tbl{width:100%;border-collapse:collapse}
  .tbl th{font-size:9px;font-weight:600;letter-spacing:2px;text-transform:uppercase;color:var(--mute);padding:9px 14px;text-align:left;border-bottom:1px solid var(--bord);background:rgba(0,0,0,.15);white-space:nowrap}
  .tbl td{padding:10px 14px;font-size:12px;color:var(--lite);border-bottom:1px solid rgba(255,255,255,.03);vertical-align:middle}
  .tbl tr:last-child td{border-bottom:none}
  .tbl tr:hover td{background:rgba(255,255,255,.02);cursor:pointer}
  .mono{font-family:"IBM Plex Mono",monospace;font-size:11px}

  .badge{display:inline-flex;align-items:center;gap:4px;padding:2px 7px;border-radius:3px;font-size:9px;font-weight:600;letter-spacing:1px;text-transform:uppercase}
  .b-sl{background:var(--sl-d);color:var(--sl)}.b-tl{background:var(--tl-d);color:var(--tl)}
  .b-gn{background:var(--gn-d);color:var(--gn)}.b-gd{background:var(--gd-d);color:var(--gd)}
  .b-rd{background:var(--rd-d);color:var(--rd)}.b-pu{background:var(--pu-d);color:var(--pu)}

  .fg{display:flex;flex-direction:column;gap:4px}
  .fl{font-size:9px;font-weight:600;letter-spacing:2px;text-transform:uppercase;color:var(--mute)}
  .fi,.fsel{background:var(--raise);border:1px solid var(--bord);border-radius:6px;color:var(--white);font-family:"IBM Plex Sans",sans-serif;font-size:12px;padding:7px 10px;outline:none;transition:border-color .12s;width:100%}
  .fi:focus,.fsel:focus{border-color:var(--sl);box-shadow:0 0 0 2px var(--sl-d)}
  .fsel option{background:var(--surf)}
  .fh{font-size:10px;color:var(--mute);margin-top:2px}
  .g2{display:grid;grid-template-columns:1fr 1fr;gap:14px}
  .g3{display:grid;grid-template-columns:1fr 1fr 1fr;gap:12px}
  .sdiv{font-family:"Bebas Neue",sans-serif;font-size:11px;letter-spacing:2px;color:var(--sl);margin:18px 0 10px;display:flex;align-items:center;gap:10px}
  .sdiv::after{content:"";flex:1;height:1px;background:var(--bord)}

  .modal-bg{position:fixed;inset:0;background:rgba(0,0,0,.85);display:flex;align-items:center;justify-content:center;z-index:200;backdrop-filter:blur(4px)}
  .modal{background:var(--surf);border:1px solid var(--bord2);border-radius:12px;width:900px;max-width:96vw;max-height:93vh;overflow-y:auto;box-shadow:0 40px 100px rgba(0,0,0,.8)}
  .modal.lg{width:1060px}.modal.sm{width:560px}
  .mh{padding:15px 20px;border-bottom:1px solid var(--bord);display:flex;align-items:flex-start;justify-content:space-between;position:sticky;top:0;background:var(--surf);z-index:5}
  .mt{font-family:"Bebas Neue",sans-serif;font-size:15px;letter-spacing:2px;color:var(--white)}
  .msub{font-size:11px;color:var(--mute);margin-top:2px}
  .mbd{padding:20px}
  .mft{padding:14px 20px;border-top:1px solid var(--bord);display:flex;justify-content:flex-end;gap:8px;position:sticky;bottom:0;background:var(--surf)}

  .eac-grid{display:grid;grid-template-columns:1fr 1fr 1fr;gap:12px;margin-bottom:16px}
  .eac-card{background:var(--surf);border:1px solid var(--bord);border-radius:9px;padding:14px 16px;position:relative;overflow:hidden}
  .eac-card-header{display:flex;align-items:flex-start;justify-content:space-between;margin-bottom:10px}
  .eac-card-title{font-size:10px;font-weight:600;letter-spacing:2px;text-transform:uppercase;color:var(--mute)}
  .eac-bar{height:4px;background:var(--raise);border-radius:2px;margin-top:10px;overflow:hidden}
  .eac-bar-fill{height:100%;border-radius:2px;transition:width .3s}

  .perf-pill{display:inline-flex;align-items:center;gap:5px;padding:3px 8px;border-radius:12px;font-size:10px;font-weight:600}
  .perf-good{background:var(--gn-d);color:var(--gn)}
  .perf-warn{background:var(--gd-d);color:var(--gd)}
  .perf-bad{background:var(--rd-d);color:var(--rd)}

  .idx-box{display:flex;flex-direction:column;align-items:center;padding:10px;background:var(--raise);border-radius:7px;min-width:68px}
  .idx-val{font-family:"IBM Plex Mono",monospace;font-size:18px;font-weight:500}
  .idx-lbl{font-size:8px;font-weight:700;letter-spacing:2px;text-transform:uppercase;color:var(--mute);margin-top:2px}
  .idx-good{color:var(--gn)}.idx-warn{color:var(--gd)}.idx-bad{color:var(--rd)}

  .vbar-wrap{display:flex;align-items:center;gap:8px}
  .vbar{height:6px;flex:1;background:var(--raise);border-radius:3px;overflow:hidden;position:relative}
  .vbar-center{position:absolute;left:50%;top:0;bottom:0;width:1px;background:var(--bord2)}
  .vbar-fill{height:100%;position:absolute;border-radius:3px}
  .vbar-pos{background:var(--gn);left:50%}
  .vbar-neg{background:var(--rd);right:50%}

  .alert-banner{display:flex;align-items:flex-start;gap:10px;padding:10px 14px;border-radius:7px;margin-bottom:10px;font-size:11px}
  .alert-warn{background:var(--gd-d);border:1px solid var(--gd-b);color:var(--gd)}
  .alert-danger{background:var(--rd-d);border:1px solid var(--rd-b);color:var(--rd)}
  .alert-good{background:var(--gn-d);border:1px solid var(--gn-b);color:var(--gn)}
  .alert-info{background:var(--sl-d);border:1px solid var(--sl-b);color:var(--sl)}

  .surety-row{display:grid;grid-template-columns:1fr 1fr;gap:12px;margin-bottom:14px}
  .ratio-card{background:var(--surf);border:1px solid var(--bord);border-radius:8px;padding:14px 16px}
  .ratio-title{font-size:9px;font-weight:700;letter-spacing:2px;text-transform:uppercase;color:var(--mute);margin-bottom:10px}
  .ratio-row{display:flex;justify-content:space-between;align-items:center;padding:6px 0;border-bottom:1px solid rgba(255,255,255,.03);font-size:11px}
  .ratio-row:last-child{border-bottom:none}
  .ratio-name{color:var(--lite)}
  .ratio-val{font-family:"IBM Plex Mono",monospace;font-size:11px}

  .fc-row{display:grid;grid-template-columns:2fr 1fr 1fr 1fr 1fr 1fr;gap:8px;align-items:end;padding:8px 0;border-bottom:1px solid rgba(255,255,255,.03)}
  .fc-row:last-child{border-bottom:none}
  .fc-lbl{font-size:11px;color:var(--brite);font-weight:500}
  .fc-sub{font-size:10px;color:var(--mute);margin-top:1px}
  .fi-sm{background:var(--raise);border:1px solid var(--bord);border-radius:5px;color:var(--white);font-family:"IBM Plex Mono",sans-serif;font-size:11px;padding:5px 8px;outline:none;width:100%;text-align:right}
  .fi-sm:focus{border-color:var(--sl)}
`;

const gw_eac_fmt$ = (n, dec = 0) => n == null ? "—" : "$" + Math.abs(n).toLocaleString("en-US", { minimumFractionDigits: dec, maximumFractionDigits: dec });
const fmtN = (n, dec = 2) => n == null ? "—" : n.toLocaleString("en-US", { minimumFractionDigits: dec, maximumFractionDigits: dec });
const gw_eac_fmtPct = (n) => n == null ? "—" : (n * 100).toFixed(1) + "%";
const fmtIdx = (n) => n == null ? "—" : n.toFixed(2);

function cpiClass(v) { if (v >= 1.0) return "idx-good"; if (v >= 0.9) return "idx-warn"; return "idx-bad"; }
function spiClass(v) { if (v >= 0.95) return "idx-good"; if (v >= 0.85) return "idx-warn"; return "idx-bad"; }
function vacClass(v) { if (v >= 0) return "idx-good"; if (v >= -0.05) return "idx-warn"; return "idx-bad"; }

