function buildAmortization(asset) {
  // simplified — build monthly schedule
  const rows = [];
  let bal = asset.financed;
  const monthlyRate = asset.rate/100/12;
  const pmt = asset.monthly_payment;
  const start = new Date(asset.start);
  for(let i=0;i<asset.term;i++){
    const int = bal * monthlyRate;
    const prin = pmt - int;
    const d = new Date(start);
    d.setMonth(d.getMonth()+i);
    rows.push({
      n:i+1,
      date:`${d.getFullYear()}-${String(d.getMonth()+1).padStart(2,"0")}`,
      payment:pmt, interest:int, principal:prin,
      balance: Math.max(bal - prin, 0),
    });
    bal = Math.max(bal-prin,0);
    if(bal<=0) break;
  }
  return rows;
}

