// ============================================================
// HELPERS
// ============================================================
const gw_gl_engine_dollarc = n => n == null ? "" : (n < 0 ? `(${Math.abs(n).toLocaleString("en-US", { minimumFractionDigits: 2 })})` : n.toLocaleString("en-US", { minimumFractionDigits: 2 }));
const $s = n => n == null ? "" : (n >= 0 ? `+$${n.toLocaleString("en-US", { minimumFractionDigits: 2 })}` : `-$${Math.abs(n).toLocaleString("en-US", { minimumFractionDigits: 2 })}`);
const $a = n => n == null ? "" : `$${Math.abs(n).toLocaleString("en-US", { minimumFractionDigits: 2 })}`;

const totalDebit  = lines => lines.reduce((s, l) => s + (parseFloat(l.debit)  || 0), 0);
const totalCredit = lines => lines.reduce((s, l) => s + (parseFloat(l.credit) || 0), 0);
const isBalanced  = lines => Math.abs(totalDebit(lines) - totalCredit(lines)) < 0.01;

