// ============================================================
// NEW JE MODAL
// ============================================================
function NewJEModal({ open, onClose, onSave, prefill = null }) {
  const blank = () => ({ id: Date.now(), acct: "", memo: "", division: "", location: "", debit: "", credit: "" });
  const [form, setForm] = useState({
    date: "2026-02-17",
    ref: "",
    memo: "",
    lines: prefill?.lines?.map((l, i) => ({ ...l, id: i })) || [blank(), blank()],
  });
  const [showDims, setShowDims] = useState(false);

  if (!open) return null;

  const setField = (k, v) => setForm(f => ({ ...f, [k]: v }));
  const setLine  = (id, k, v) => setForm(f => ({ ...f, lines: f.lines.map(l => l.id === id ? { ...l, [k]: v } : l) }));
  const addLine  = () => setForm(f => ({ ...f, lines: [...f.lines, blank()] }));
  const delLine  = (id) => setForm(f => ({ ...f, lines: f.lines.filter(l => l.id !== id) }));

  const dr = totalDebit(form.lines);
  const cr = totalCredit(form.lines);
  const diff = Math.abs(dr - cr);
  const balanced = diff < 0.01;

  return (
    <div className="modal-bg" onClick={onClose}>
      <div className="modal" onClick={e => e.stopPropagation()}>
        <div className="mh">
          <div>
            <div className="mt">NEW JOURNAL ENTRY</div>
            <div className="msub">All entries require balanced debits and credits before posting</div>
          </div>
          <button className="mx" onClick={onClose}>{gw_gl_engine_I.x}</button>
        </div>
        <div className="mb">
          {/* Header fields */}
          <div style={{ display: "grid", gridTemplateColumns: "140px 1fr 1fr", gap: 12, marginBottom: 16 }}>
            <div className="fg">
              <label className="fl">Date</label>
              <input className="fi" type="date" value={form.date} onChange={e => setField("date", e.target.value)} />
            </div>
            <div className="fg">
              <label className="fl">Reference / #</label>
              <input className="fi mono-in" placeholder="ADJ-0022" value={form.ref} onChange={e => setField("ref", e.target.value)} />
            </div>
            <div className="fg">
              <label className="fl">Memo / Description</label>
              <input className="fi" placeholder="e.g. Accrue February health insurance" value={form.memo} onChange={e => setField("memo", e.target.value)} />
            </div>
          </div>

          {/* Lines */}
          <div style={{ display: "flex", alignItems: "center", justifyContent: "space-between", marginBottom: 8 }}>
            <div style={{ fontSize: 10, fontWeight: 700, letterSpacing: 2, textTransform: "uppercase", color: "var(--muted)" }}>Entry Lines</div>
            <div style={{ display: "flex", gap: 8 }}>
              <button className="btn btn-ghost btn-sm" onClick={() => setShowDims(v => !v)}>
                {gw_gl_engine_I.filter} {showDims ? "Hide" : "Show"} Dimensions
              </button>
              <button className="btn btn-ghost btn-sm" onClick={addLine}>{gw_gl_engine_I.plus} Add Line</button>
            </div>
          </div>

          <div style={{ overflow: "auto" }}>
            <table className="je-lines">
              <thead>
                <tr>
                  <th className="line-acct">Account</th>
                  <th>Memo</th>
                  {showDims && <th className="line-dim">Division</th>}
                  {showDims && <th className="line-dim">Location</th>}
                  <th className="line-amt r">Debit</th>
                  <th className="line-amt r">Credit</th>
                  <th className="line-del"></th>
                </tr>
              </thead>
              <tbody>
                {form.lines.map((line, idx) => (
                  <tr key={line.id}>
                    <td className="line-acct">
 <select className="fsel" style={{ fontSize: 11, padding: "5px 8px" }} value={line.acct} onChange={e => setLine(line.id, "acct", e.target.value)}>
                        <option value="">— Select account —</option>
                        {gw_gl_engine_GL_ACCOUNTS.map(a => (
                          <option key={a.num} value={a.num}>{a.num} · {a.name}</option>
                        ))}
                      </select>
                    </td>
                    <td>
 <input className="fi" style={{ fontSize: 11, padding: "5px 8px" }} placeholder="Line memo..." value={line.memo || ""} onChange={e => setLine(line.id, "memo", e.target.value)} />
                    </td>
                    {showDims && (
                      <td className="line-dim">
 <select className="fsel" style={{ fontSize: 11, padding: "5px 8px" }} value={line.division || ""} onChange={e => setLine(line.id, "division", e.target.value)}>
                          <option value="">—</option>
                          {DIMS.division.map(d => <option key={d}>{d}</option>)}
                        </select>
                      </td>
                    )}
                    {showDims && (
                      <td className="line-dim">
 <select className="fsel" style={{ fontSize: 11, padding: "5px 8px" }} value={line.location || ""} onChange={e => setLine(line.id, "location", e.target.value)}>
                          <option value="">—</option>
                          {DIMS.location.map(l => <option key={l}>{l}</option>)}
                        </select>
                      </td>
                    )}
                    <td className="line-amt">
 <input className="fi mono-in" style={{ fontSize: 12, padding: "5px 8px", textAlign: "right" }} placeholder="0.00" value={line.debit} onChange={e => { setLine(line.id, "debit", e.target.value); if (e.target.value) setLine(line.id, "credit", ""); }} />
                    </td>
                    <td className="line-amt">
 <input className="fi mono-in" style={{ fontSize: 12, padding: "5px 8px", textAlign: "right" }} placeholder="0.00" value={line.credit} onChange={e => { setLine(line.id, "credit", e.target.value); if (e.target.value) setLine(line.id, "debit", ""); }} />
                    </td>
                    <td className="line-del">
                      {form.lines.length > 2 && (
                        <button className="btn btn-ghost btn-icon btn-sm" onClick={() => delLine(line.id)} style={{ color: "var(--red-l)" }}>{gw_gl_engine_I.trash}</button>
                      )}
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>

          {/* Totals */}
          <div className="je-totals">
            <div className="je-total-item">
              <div className="je-total-label">Total Debits</div>
              <div className="je-total-val" style={{ color: "var(--bright)" }}>${dr.toLocaleString("en-US", { minimumFractionDigits: 2 })}</div>
            </div>
            <div className="je-total-item">
              <div className="je-total-label">Total Credits</div>
              <div className="je-total-val" style={{ color: "var(--bright)" }}>${cr.toLocaleString("en-US", { minimumFractionDigits: 2 })}</div>
            </div>
            <div className="je-total-item">
              <div className="je-total-label">Difference</div>
              <div className={"je-total-val "+(balanced ? "bal-ok" : diff > 0 ? "bal-off" : "bal-zero")}>
                {balanced ? "✓ Balanced" : `$${diff.toLocaleString("en-US", { minimumFractionDigits: 2 })} off`}
              </div>
            </div>
          </div>

          {!balanced && dr > 0 && cr > 0 && (
            <div className="alert a-red" style={{ marginTop: 12, marginBottom: 0 }}>
              ⚠️ <span>Entry is out of balance by <strong>${diff.toLocaleString("en-US", { minimumFractionDigits: 2 })}</strong>. Debits must equal credits before you can post.</span>
            </div>
          )}
        </div>
        <div className="mf">
          <button className="btn btn-ghost" onClick={onClose}>Cancel</button>
          <button className="btn btn-ghost" onClick={() => { onSave({ ...form, status: "draft" }); onClose(); }}>Save as Draft</button>
          <button className="btn btn-gold" disabled={!balanced || dr === 0} onClick={() => { onSave({ ...form, status: "posted" }); onClose(); }}>
            {gw_gl_engine_I.bolt} Post to GL
          </button>
        </div>
      </div>
    </div>
  );
}

// ============================================================
// REVERSE JE CONFIRM
// ============================================================
function ReverseModal({ je, open, onClose, onConfirm }) {
  if (!open || !je) return null;
  return (
    <div className="modal-bg" onClick={onClose}>
      <div className="modal sm" onClick={e => e.stopPropagation()}>
        <div className="mh">
          <div>
            <div className="mt">REVERSE ENTRY — {je.id}</div>
            <div className="msub">Creates an equal and opposite entry. Original entry is preserved.</div>
          </div>
          <button className="mx" onClick={onClose}>{gw_gl_engine_I.x}</button>
        </div>
        <div className="mb">
          <div className="alert a-gold">
            {gw_gl_engine_I.undo} <div>A reversal entry dated <strong>2026-02-28</strong> will be created that flips all debits and credits. The original entry <strong>{je.id}</strong> remains in the GL as a permanent record.</div>
          </div>
          <div style={{ background: "var(--raised)", borderRadius: 8, padding: 14 }}>
            <div style={{ fontSize: 10, fontWeight: 700, letterSpacing: 2, textTransform: "uppercase", color: "var(--muted)", marginBottom: 8 }}>Original: {je.memo}</div>
            {je.lines.map((l, i) => (
              <div key={i} style={{ display: "flex", justifyContent: "space-between", padding: "4px 0", fontSize: 11, borderBottom: "1px solid var(--border)", color: "var(--dim)" }}>
                <span style={{ fontFamily: "'JetBrains Mono', monospace", color: "var(--gold-l)" }}>{l.acct}</span>
                <span style={{ flex: 1, marginLeft: 10, color: "var(--light)" }}>{l.name}</span>
                {l.debit  > 0 && <span style={{ color: "var(--bright)", fontFamily: "'JetBrains Mono', monospace" }}>Dr {$a(l.debit)}</span>}
                {l.credit > 0 && <span style={{ color: "var(--dim)",    fontFamily: "'JetBrains Mono', monospace" }}>Cr {$a(l.credit)}</span>}
              </div>
            ))}
          </div>
        </div>
        <div className="mf">
          <button className="btn btn-ghost" onClick={onClose}>Cancel</button>
          <button className="btn btn-gold" onClick={() => { onConfirm(je); onClose(); }}>{gw_gl_engine_I.undo} Create Reversal</button>
        </div>
      </div>
    </div>
  );
}

// ============================================================
// JOURNAL ENTRIES TAB
// ============================================================
function JETab() {
  const [jes, setJes] = useState(INIT_JES);
  const [newOpen, setNewOpen] = useState(false);
  const [reverseTarget, setReverseTarget] = useState(null);
  const [expanded, setExpanded] = useState({});
  const [filter, setFilter] = useState("all");
  const [search, setSearch] = useState("");

  const toggle = id => setExpanded(e => ({ ...e, [id]: !e[id] }));

  const filtered = useMemo(() => jes.filter(je => {
    const matchFilter = filter === "all" || je.status === filter || (filter === "system" && je.source === "system") || (filter === "manual" && je.source === "manual");
    const matchSearch = !search || je.memo.toLowerCase().includes(search.toLowerCase()) || je.id.toLowerCase().includes(search.toLowerCase()) || je.ref?.toLowerCase().includes(search.toLowerCase());
    return matchFilter && matchSearch;
  }), [jes, filter, search]);

  const addJE = (form) => {
    const id = `JE-${String(jes.length + 1).padStart(4, "0")}`;
    setJes(prev => [{ ...form, id, source: "manual", createdBy: "Tyler H." }, ...prev]);
  };

  const reverseJE = (je) => {
    const revId = `JE-${String(jes.length + 1).padStart(4, "0")}-REV`;
    const reversed = {
      id: revId,
      date: "2026-02-28",
      ref: `REV-${je.id}`,
      memo: `REVERSAL: ${je.memo}`,
      status: "posted",
      source: "manual",
      createdBy: "Tyler H.",
      lines: je.lines.map(l => ({ ...l, debit: l.credit, credit: l.debit })),
    };
    setJes(prev => [reversed, ...prev]);
  };

  const postDraft = (id) => setJes(prev => prev.map(je => je.id === id ? { ...je, status: "posted" } : je));

  const totalPosted = jes.filter(j => j.status === "posted").length;
  const totalDraft  = jes.filter(j => j.status === "draft").length;
  const totalDebits = jes.filter(j => j.status === "posted").reduce((s, j) => s + totalDebit(j.lines), 0);

  return (
    <div className="fade">
      <div className="krow">
        <div className="kpi k-gold"><div className="kl">Total Entries</div><div className="kv">{jes.length}</div><div className="ks">This period</div></div>
        <div className="kpi k-green"><div className="kl">Posted</div><div className="kv">{totalPosted}</div><div className="ks">In GL</div></div>
        <div className="kpi k-gold"><div className="kl">Draft</div><div className="kv">{totalDraft}</div><div className="ks">Awaiting review</div></div>
        <div className="kpi k-blue"><div className="kl">Total Debit Volume</div><div className="kv">${(totalDebits / 1000).toFixed(1)}K</div><div className="ks">Posted entries</div></div>
        <div className="kpi k-teal"><div className="kl">System Entries</div><div className="kv">{jes.filter(j => j.source === "system").length}</div><div className="ks">Auto-generated</div></div>
      </div>

      <div className="search-row">
        <div className="search-w">
          {gw_gl_engine_I.search}
          <input className="search-in" placeholder="Search by memo, reference, or JE number..." value={search} onChange={e => setSearch(e.target.value)} />
        </div>
        <button className="btn btn-ghost btn-sm">Import CSV</button>
        <button className="btn btn-gold" onClick={() => setNewOpen(true)}>{gw_gl_engine_I.plus} New Entry</button>
      </div>

      <div className="frow">
        {[
          { id: "all",    label: "All Entries" },
          { id: "posted", label: "Posted" },
          { id: "draft",  label: "Draft" },
          { id: "system", label: "System" },
          { id: "manual", label: "Manual" },
        ].map(f => <div key={f.id} className={"fc "+(filter === f.id ? "on" : "")} onClick={() => setFilter(f.id)}>{f.label}</div>)}
      </div>

      <div className="panel">
        <div className="ph">
          <div><div className="pt">JOURNAL ENTRY REGISTER</div><div className="ps">Click any row to expand line details · Hover to see actions</div></div>
        </div>
        <table className="tbl">
          <thead>
            <tr>
              <th style={{ width: 28 }}></th>
              <th>JE #</th>
              <th>Date</th>
              <th>Reference</th>
              <th>Memo</th>
              <th>Source</th>
              <th style={{ textAlign: "right" }}>Debits</th>
              <th style={{ textAlign: "right" }}>Credits</th>
              <th>Status</th>
              <th>Actions</th>
            </tr>
          </thead>
          <tbody>
            {filtered.map(je => {
              const dr = totalDebit(je.lines);
              const cr = totalCredit(je.lines);
              const isOpen = expanded[je.id];
              return (
                <>
                  <tr key={je.id} className={isOpen ? "sel" : ""} onClick={() => toggle(je.id)}>
                    <td style={{ color: "var(--muted)", textAlign: "center" }}>{isOpen ? gw_gl_engine_I.down : gw_gl_engine_I.right}</td>
                    <td className="mono" style={{ color: "var(--gold-l)" }}>{je.id}</td>
                    <td className="mono" style={{ color: "var(--dim)", fontSize: 11 }}>{je.date}</td>
                    <td className="mono" style={{ color: "var(--muted)", fontSize: 11 }}>{je.ref}</td>
                    <td style={{ maxWidth: 260 }}>
                      <div style={{ fontSize: 12, fontWeight: 500 }}>{je.memo}</div>
                      <div style={{ fontSize: 10, color: "var(--muted)", marginTop: 1 }}>{je.createdBy}</div>
                    </td>
                    <td><span className={"badge "+(je.source === "system" ? "b-teal" : "b-stone")}>{je.source}</span></td>
                    <td className="mono" style={{ textAlign: "right", color: "var(--bright)" }}>${dr.toLocaleString("en-US", { minimumFractionDigits: 2 })}</td>
                    <td className="mono" style={{ textAlign: "right", color: "var(--dim)" }}>${cr.toLocaleString("en-US", { minimumFractionDigits: 2 })}</td>
                    <td onClick={e => e.stopPropagation()}>
                      <span className={"badge "+(je.status === "posted" ? "b-green" : je.status === "draft" ? "b-gold" : "b-stone")}>{je.status}</span>
                    </td>
                    <td onClick={e => e.stopPropagation()}>
                      <div style={{ display: "flex", gap: 5 }}>
                        {je.status === "draft" && (
                          <button className="btn btn-green btn-xs" onClick={() => postDraft(je.id)}>{gw_gl_engine_I.bolt} Post</button>
                        )}
                        {je.status === "posted" && (
                          <button className="btn btn-ghost btn-xs" onClick={() => setReverseTarget(je)}>{gw_gl_engine_I.undo} Reverse</button>
                        )}
                      </div>
                    </td>
                  </tr>
                  {isOpen && (
                    <tr key={(je.id)+"-exp"}>
                      <td colSpan={10} style={{ padding: 0 }}>
                        <div className="je-expand">
                          <table style={{ width: "100%", borderCollapse: "collapse" }}>
                            <thead>
                              <tr style={{ background: "rgba(0,0,0,0.1)" }}>
                                <th style={{ padding: "6px 40px", fontSize: 9, letterSpacing: 2, textTransform: "uppercase", color: "var(--muted)", textAlign: "left", width: 50 }}>Acct</th>
                                <th style={{ padding: "6px 8px", fontSize: 9, letterSpacing: 2, textTransform: "uppercase", color: "var(--muted)", textAlign: "left" }}>Account Name</th>
                                <th style={{ padding: "6px 8px", fontSize: 9, letterSpacing: 2, textTransform: "uppercase", color: "var(--muted)", textAlign: "left" }}>Memo</th>
                                <th style={{ padding: "6px 8px", fontSize: 9, letterSpacing: 2, textTransform: "uppercase", color: "var(--muted)", textAlign: "left" }}>Dimensions</th>
                                <th style={{ padding: "6px 8px", fontSize: 9, letterSpacing: 2, textTransform: "uppercase", color: "var(--muted)", textAlign: "right", width: 110 }}>Debit</th>
                                <th style={{ padding: "6px 8px", fontSize: 9, letterSpacing: 2, textTransform: "uppercase", color: "var(--muted)", textAlign: "right", width: 110 }}>Credit</th>
                              </tr>
                            </thead>
                            <tbody>
                              {je.lines.map((l, i) => (
                                <tr key={i} className="jel-row" style={{ display: "table-row" }}>
                                  <td style={{ padding: "7px 8px 7px 40px", fontFamily: "'JetBrains Mono', monospace", fontSize: 11, color: "var(--gold-l)", borderBottom: "1px solid rgba(255,255,255,0.025)", width: 50 }}>{l.acct}</td>
                                  <td style={{ padding: "7px 8px", fontSize: 12, color: "var(--light)", borderBottom: "1px solid rgba(255,255,255,0.025)" }}>{l.name}</td>
                                  <td style={{ padding: "7px 8px", fontSize: 11, color: "var(--muted)", borderBottom: "1px solid rgba(255,255,255,0.025)" }}>{l.memo || "—"}</td>
                                  <td style={{ padding: "7px 8px", fontSize: 10, color: "var(--muted)", borderBottom: "1px solid rgba(255,255,255,0.025)" }}>
                                    {[l.division, l.location, l.class].filter(Boolean).join(" · ") || "—"}
                                  </td>
                                  <td style={{ padding: "7px 8px", fontFamily: "'JetBrains Mono', monospace", fontSize: 11, textAlign: "right", color: l.debit > 0 ? "var(--bright)" : "var(--muted)", borderBottom: "1px solid rgba(255,255,255,0.025)" }}>
                                    {l.debit > 0 ? `$${l.debit.toLocaleString("en-US", { minimumFractionDigits: 2 })}` : "—"}
                                  </td>
                                  <td style={{ padding: "7px 8px", fontFamily: "'JetBrains Mono', monospace", fontSize: 11, textAlign: "right", color: l.credit > 0 ? "var(--dim)" : "var(--muted)", borderBottom: "1px solid rgba(255,255,255,0.025)" }}>
                                    {l.credit > 0 ? `$${l.credit.toLocaleString("en-US", { minimumFractionDigits: 2 })}` : "—"}
                                  </td>
                                </tr>
                              ))}
                              <tr style={{ background: "rgba(0,0,0,0.15)" }}>
                                <td colSpan={4} style={{ padding: "8px 8px 8px 40px", fontSize: 11, fontWeight: 700, color: "var(--light)" }}>TOTALS</td>
                                <td style={{ padding: "8px", fontFamily: "'JetBrains Mono', monospace", fontSize: 12, fontWeight: 700, textAlign: "right", color: "var(--bright)" }}>${dr.toLocaleString("en-US", { minimumFractionDigits: 2 })}</td>
                                <td style={{ padding: "8px", fontFamily: "'JetBrains Mono', monospace", fontSize: 12, fontWeight: 700, textAlign: "right", color: "var(--bright)" }}>${cr.toLocaleString("en-US", { minimumFractionDigits: 2 })}</td>
                              </tr>
                            </tbody>
                          </table>
                        </div>
                      </td>
                    </tr>
                  )}
                </>
              );
            })}
          </tbody>
        </table>
      </div>

      <NewJEModal open={newOpen} onClose={() => setNewOpen(false)} onSave={addJE} />
      <ReverseModal je={reverseTarget} open={!!reverseTarget} onClose={() => setReverseTarget(null)} onConfirm={reverseJE} />
    </div>
  );
}

// ============================================================
// BANK RECONCILIATION TAB
// ============================================================
function ReconTab() {
  const [bankTxns, setBankTxns]   = useState(BANK_TXN);
  const [glTxns,   setGlTxns]     = useState(GL_TXN);
  const [matched,  setMatched]    = useState({});   // bankId -> glId
  const [selBank,  setSelBank]    = useState(null);
  const [selGL,    setSelGL]      = useState(null);
  const [cleared,  setCleared]    = useState({});
  const [posted,   setPosted]     = useState(false);

  const stmtBalance   =  284320;
  const glBalance     =  284320;
  const stmtEndDate   = "2026-02-17";

  const matchedBankIds = new Set(Object.keys(matched));
  const matchedGlIds   = new Set(Object.values(matched));

  const clearedDeposits   = bankTxns.filter(t => t.amount > 0 && matchedBankIds.has(t.id)).reduce((s, t) => s + t.amount, 0);
  const clearedPayments   = bankTxns.filter(t => t.amount < 0 && matchedBankIds.has(t.id)).reduce((s, t) => s + Math.abs(t.amount), 0);
  const outstandingCount  = bankTxns.filter(t => !matchedBankIds.has(t.id)).length;
  const difference        = bankTxns.filter(t => matchedBankIds.has(t.id)).reduce((s, t) => s + t.amount, 0)
                          - glTxns.filter(t => matchedGlIds.has(t.id)).reduce((s, t) => s + t.amount, 0);
  const isDone            = Math.abs(difference) < 0.01 && outstandingCount === 0;

  const tryMatch = () => {
    if (selBank && selGL) {
      const bank = bankTxns.find(t => t.id === selBank);
      const gl   = glTxns.find(t => t.id === selGL);
      if (bank && gl && Math.abs(Math.abs(bank.amount) - Math.abs(gl.amount)) < 0.01) {
        setMatched(m => ({ ...m, [selBank]: selGL }));
        setSelBank(null); setSelGL(null);
      }
    }
  };

  const autoMatch = () => {
    const newMatches = {};
    bankTxns.forEach(b => {
      if (matchedBankIds.has(b.id)) return;
      const match = glTxns.find(g =>
        !matchedGlIds.has(g.id) &&
        !Object.values(newMatches).includes(g.id) &&
        Math.abs(Math.abs(b.amount) - Math.abs(g.amount)) < 0.01
      );
      if (match) newMatches[b.id] = match.id;
    });
    setMatched(m => ({ ...m, ...newMatches }));
  };

  const unmatch = (bankId) => setMatched(m => { const n = { ...m }; delete n[bankId]; return n; });

  return (
    <div className="fade">
      {/* Summary bar */}
      <div className="recon-sum">
        <div className="rs-item">
          <div className="rs-label">Bank Statement Balance</div>
          <div className="rs-val">${stmtBalance.toLocaleString("en-US", { minimumFractionDigits: 2 })}</div>
          <div style={{ fontSize: 10, color: "var(--muted)", marginTop: 2 }}>As of {stmtEndDate}</div>
        </div>
        <div className="rs-divider" />
        <div className="rs-item">
          <div className="rs-label">GL Book Balance</div>
          <div className="rs-val">${glBalance.toLocaleString("en-US", { minimumFractionDigits: 2 })}</div>
          <div style={{ fontSize: 10, color: "var(--muted)", marginTop: 2 }}>1010 · Checking — Operating</div>
        </div>
        <div className="rs-divider" />
        <div className="rs-item">
          <div className="rs-label">Matched</div>
          <div className="rs-val" style={{ color: "var(--green-l)" }}>{matchedBankIds.size} / {bankTxns.length}</div>
          <div style={{ fontSize: 10, color: "var(--muted)", marginTop: 2 }}>{outstandingCount} unmatched</div>
        </div>
        <div className="rs-divider" />
        <div style={{ flex: 1 }} />
        <div className="rs-item" style={{ alignItems: "flex-end" }}>
          <div className="rs-label">Difference</div>
          <div className={"rs-diff "+(isDone ? "ok" : "off")}>
            {isDone ? "✓ $0.00" : `$${Math.abs(difference).toLocaleString("en-US", { minimumFractionDigits: 2 })}`}
          </div>
        </div>
        <div style={{ display: "flex", flexDirection: "column", gap: 6, marginLeft: 20 }}>
          <button className="btn btn-gold btn-sm" onClick={autoMatch}>{gw_gl_engine_I.bolt} Auto-Match</button>
          <button className="btn btn-green btn-sm" disabled={!isDone} onClick={() => setPosted(true)}>{gw_gl_engine_I.check} Post Reconciliation</button>
        </div>
      </div>

      {posted && (
        <div className="alert a-green" style={{ marginBottom: 14 }}>
          {gw_gl_engine_I.check} <div><strong>Reconciliation Complete — Feb 2026</strong><br />All matched transactions cleared. GL period balance confirmed: ${stmtBalance.toLocaleString("en-US", { minimumFractionDigits: 2 })}.</div>
        </div>
      )}

      {selBank && selGL && (
        <div className="alert a-gold" style={{ marginBottom: 14 }}>
          {gw_gl_engine_I.link} <div>
            <strong>Ready to match:</strong> Selected bank txn + GL entry. 
            {Math.abs(Math.abs(bankTxns.find(t => t.id === selBank)?.amount || 0) - Math.abs(glTxns.find(t => t.id === selGL)?.amount || 0)) < 0.01
              ? " ✓ Amounts match — " : " ⚠ Amounts differ — "}
            <button className="btn btn-gold btn-xs" onClick={tryMatch} style={{ marginLeft: 6 }}>{gw_gl_engine_I.link} Confirm Match</button>
            <button className="btn btn-ghost btn-xs" onClick={() => { setSelBank(null); setSelGL(null); }} style={{ marginLeft: 4 }}>Cancel</button>
          </div>
        </div>
      )}

      <div className="alert a-blue" style={{ marginBottom: 14 }}>
        {gw_gl_engine_I.bolt} <div><strong>Auto-Match available</strong> — Groundwork found {bankTxns.filter(b => b.suggested && !matchedBankIds.has(b.id)).length} high-confidence matches based on amount and date proximity. Click <strong>Auto-Match</strong> to apply them, or manually select one bank item and one GL item to match them together.</div>
      </div>

      {/* Two-column layout */}
      <div className="recon-grid">
        {/* Bank Statement */}
        <div className="panel" style={{ marginBottom: 0 }}>
          <div className="col-hd">
            <span>BANK STATEMENT — 1010 OPERATING</span>
            <button className="btn btn-ghost btn-xs">{gw_gl_engine_I.import} Import OFX</button>
          </div>
          {bankTxns.map(txn => {
            const isMatched   = matchedBankIds.has(txn.id);
            const isSuggested = txn.suggested && !isMatched;
            const isSelected  = selBank === txn.id;
            const matchedGL   = isMatched ? glTxns.find(g => g.id === matched[txn.id]) : null;
            return (
              <div key={txn.id} className={"recon-row "+(isMatched ? "matched" : isSuggested ? "suggested" : "")+" "+(isSelected ? "selected" : "")} onClick={() => !isMatched && setSelBank(id => id === txn.id ? null : txn.id)}
              >
                <div className={"rr-check "+(isMatched ? "on" : "")} onClick={e => { e.stopPropagation(); if (isMatched) unmatch(txn.id); }}>
                  {isMatched && gw_gl_engine_I.check}
                </div>
                <div className="rr-date">{txn.date.slice(5)}</div>
                <div style={{ flex: 1 }}>
                  <div className="rr-desc">{txn.desc}</div>
                  {isMatched && matchedGL && (
                    <div style={{ marginTop: 3 }}>
                      <span className="match-badge">{gw_gl_engine_I.link} Matched · {matchedGL.account} · {matchedGL.desc.slice(0, 30)}{matchedGL.desc.length > 30 ? "…" : ""}</span>
                    </div>
                  )}
                  {isSuggested && (
                    <div style={{ marginTop: 3 }}>
                      <span className="match-badge suggest-badge">{gw_gl_engine_I.bolt} Suggested match available</span>
                    </div>
                  )}
                </div>
                <div className={"rr-amt "+(txn.amount > 0 ? "bal-ok" : "")} style={{ color: txn.amount > 0 ? "var(--green-l)" : "var(--red-l)" }}>
                  {$s(txn.amount)}
                </div>
              </div>
            );
          })}
          {/* Bank totals */}
          <div style={{ padding: "10px 14px", borderTop: "1px solid var(--border)", display: "flex", justifyContent: "space-between", background: "rgba(0,0,0,0.15)" }}>
            <span style={{ fontSize: 11, color: "var(--muted)" }}>Unmatched: {bankTxns.filter(t => !matchedBankIds.has(t.id)).length} items</span>
            <span className="mono" style={{ color: "var(--bright)", fontSize: 12 }}>
              Net: {$s(bankTxns.reduce((s, t) => s + t.amount, 0))}
            </span>
          </div>
        </div>

        {/* GL Entries */}
        <div className="panel" style={{ marginBottom: 0 }}>
          <div className="col-hd">
            <span>GL ENTRIES — UNCLEARED</span>
            <span style={{ fontSize: 10, color: "var(--muted)" }}>{glTxns.filter(t => !matchedGlIds.has(t.id)).length} unmatched</span>
          </div>
          {glTxns.map(txn => {
            const isMatched  = matchedGlIds.has(txn.id);
            const isSelected = selGL === txn.id;
            const matchedBank = isMatched ? bankTxns.find(b => matched[b.id] === txn.id) : null;
            return (
              <div key={txn.id} className={"recon-row "+(isMatched ? "matched" : "")+" "+(isSelected ? "selected" : "")} onClick={() => !isMatched && setSelGL(id => id === txn.id ? null : txn.id)}
              >
                <div className={"rr-check "+(isMatched ? "on" : "")}>
                  {isMatched && gw_gl_engine_I.check}
                </div>
                <div className="rr-date">{txn.date.slice(5)}</div>
                <div style={{ flex: 1 }}>
                  <div className="rr-desc">{txn.desc}</div>
                  <div className="rr-sub">{txn.account} · {gw_gl_engine_GL_ACCOUNTS.find(a => a.num === txn.account)?.name}</div>
                  {isMatched && matchedBank && (
                    <div style={{ marginTop: 3 }}>
                      <span className="match-badge">{gw_gl_engine_I.link} Matched · {matchedBank.desc.slice(0, 30)}{matchedBank.desc.length > 30 ? "…" : ""}</span>
                    </div>
                  )}
                </div>
                <div style={{ color: txn.amount > 0 ? "var(--green-l)" : "var(--red-l)" }} className="rr-amt">
                  {$s(txn.amount)}
                </div>
              </div>
            );
          })}
          {/* GL totals */}
          <div style={{ padding: "10px 14px", borderTop: "1px solid var(--border)", display: "flex", justifyContent: "space-between", background: "rgba(0,0,0,0.15)" }}>
            <span style={{ fontSize: 11, color: "var(--muted)" }}>
              {glTxns.filter(t => !matchedGlIds.has(t.id)).length} GL entries not yet matched to bank
            </span>
            <span className="mono" style={{ color: "var(--bright)", fontSize: 12 }}>
              Net: {$s(glTxns.reduce((s, t) => s + t.amount, 0))}
            </span>
          </div>
        </div>
      </div>

      <div style={{ marginTop: 14 }}>
        <div className="panel">
          <div className="ph">
            <div><div className="pt">OUTSTANDING ITEMS — NEEDS REVIEW</div><div className="ps">Unmatched transactions that must be resolved before close</div></div>
          </div>
          <table className="tbl">
            <thead>
              <tr><th>Side</th><th>Date</th><th>Description</th><th style={{ textAlign: "right" }}>Amount</th><th>Action</th></tr>
            </thead>
            <tbody>
              {[
                ...bankTxns.filter(t => !matchedBankIds.has(t.id)).map(t => ({ side: "bank", ...t, desc: t.desc })),
                ...glTxns.filter(t => !matchedGlIds.has(t.id)).map(t => ({ side: "gl", ...t })),
              ].map((item, i) => (
                <tr key={i}>
                  <td><span className={"badge "+(item.side === "bank" ? "b-teal" : "b-blue")}>{item.side === "bank" ? "Bank" : "GL"}</span></td>
                  <td className="mono" style={{ color: "var(--muted)", fontSize: 11 }}>{item.date}</td>
                  <td style={{ fontSize: 12 }}>{item.desc || item.description || item.desc}</td>
                  <td className="mono" style={{ textAlign: "right", color: item.amount > 0 ? "var(--green-l)" : "var(--red-l)" }}>{$s(item.amount)}</td>
                  <td>
                    <div style={{ display: "flex", gap: 6 }}>
                      <button className="btn btn-ghost btn-xs">Create JE</button>
                      <button className="btn btn-ghost btn-xs">Mark Cleared</button>
                    </div>
                  </td>
                </tr>
              ))}
              {bankTxns.filter(t => !matchedBankIds.has(t.id)).length + glTxns.filter(t => !matchedGlIds.has(t.id)).length === 0 && (
                <tr><td colSpan={5} className="empty">All transactions matched — ready to close ✓</td></tr>
              )}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
}

