// --- Cash Flow Classification -------------------------------------------------
const CF_CLASSES = [
  { id: "operating",  label: "Operating",  color: "badge-green",  desc: "Day-to-day operations — A/R, A/P, inventory, revenue, expenses" },
  { id: "investing",  label: "Investing",  color: "badge-blue",   desc: "Capital expenditures, asset purchases/sales, long-term investments" },
  { id: "financing",  label: "Financing",  color: "badge-amber",  desc: "Debt proceeds/repayments, equity contributions, owner draws" },
  { id: "na",         label: "N/A (Cash)", color: "badge-stone",  desc: "Cash and cash equivalents — these ARE the cash being tracked" },
];

const CF_COLOR = { operating: "badge-green", investing: "badge-blue", financing: "badge-amber", na: "badge-stone" };

const cfBadge = (cfClass) => {
  const c = CF_CLASSES.find(x => x.id === cfClass);
  if (!c) return null;
  return <span className={"badge "+(CF_COLOR[cfClass] || "badge-stone")} style={{ fontSize: 8 }}>{c.label}</span>;
};

