// -- Helpers --------------------------------------------------
const gw_hris_dollarc = n => n < 0 ? `-$${Math.abs(n).toLocaleString()}` : `$${n.toLocaleString()}`;
const $h = n => `$${n.toFixed(2)}/hr`;
const gw_hris_pct = (a,b) => b ? +(a/b*100).toFixed(1) : 0;
const gw_hris_fmtDate = d => d ? new Date(d+"T12:00:00").toLocaleDateString("en-US",{month:"short",day:"numeric",year:"numeric"}) : "—";
const gw_hris_fmtShort = d => d ? new Date(d+"T12:00:00").toLocaleDateString("en-US",{month:"short",day:"numeric"}) : "—";
const gw_hris_daysDiff = (a,b) => Math.round((new Date(b+"T12:00:00")-new Date(a+"T12:00:00"))/86400000);
const gw_hris_TODAY = "2026-02-18";
const gw_hris_addDays = (d,n) => { const dt=new Date(d+"T12:00:00"); dt.setDate(dt.getDate()+n); return dt.toISOString().slice(0,10); };

