// -- Section 7(i) Analysis Engine -----------------------------

const AZ_MIN_WAGE_2026 = 14.35;
const SEC7I_MIN_RATE_MULTIPLIER = 1.5;
const SEC7I_COMMISSION_THRESHOLD = 0.50; // >50% must be commission

function analyze7i(empId, weeks) {
  const records = COMMISSION_RECORDS.filter(r =>
    r.empId === empId && weeks.includes(r.week)
  );

  if (!records.length) return null;

  const emp = gw_hris_EMPLOYEES.find(e => e.id === empId);

  // Aggregate over period
  let totalHours        = 0;
  let totalRegularHrs   = 0;
  let totalOtHrs        = 0;
  let totalHourlyEarnings    = 0;
  let totalFlatRate     = 0;
  let totalSpiff        = 0;
  let totalInvoicePct   = 0;
  let allJobs           = [];

  for (const r of records) {
    totalHours      += r.regularHrs + r.otHrs;
    totalRegularHrs += r.regularHrs;
    totalOtHrs      += r.otHrs;
    totalHourlyEarnings  += r.hourlyEarnings;
    totalFlatRate   += r.flatRateEarnings;
    totalSpiff      += r.spiffEarnings;
    totalInvoicePct += r.invoicePctEarnings;
    allJobs.push(...r.jobs);
  }

  const totalCommissions   = totalFlatRate + totalSpiff + totalInvoicePct;
  const totalCompensation  = totalHourlyEarnings + totalCommissions;
  const commissionPct      = totalCompensation > 0 ? totalCommissions / totalCompensation : 0;

  // Regular rate of pay = total compensation / total hours worked
  const regularRate        = totalHours > 0 ? totalCompensation / totalHours : 0;

  // 7(i) threshold = 1.5 × applicable minimum wage
  const minWageThreshold   = AZ_MIN_WAGE_2026 * SEC7I_COMMISSION_THRESHOLD; // wait — this is wrong
  // Correct: regular rate must exceed 1.5× min wage
  const rateThreshold      = AZ_MIN_WAGE_2026 * SEC7I_MIN_RATE_MULTIPLIER;

  // Three-part test
  const test1_retail       = true; // MEP service = retail/service establishment ✓
  const test2_rate         = regularRate > rateThreshold;
  const test3_commission   = commissionPct > SEC7I_COMMISSION_THRESHOLD;

  const exempt             = test1_retail && test2_rate && test3_commission;
  const weekCount          = records.length;

  // OT liability if NOT exempt
  // FLSA OT = 0.5 × regular rate × OT hours (since straight time already paid)
  const otLiability        = exempt ? 0 : Math.round(0.5 * regularRate * totalOtHrs);

  // Week-by-week breakdown
  const weeklyBreakdown = records.map(r => {
    const wkCommissions  = r.flatRateEarnings + r.spiffEarnings + r.invoicePctEarnings;
    const wkTotal        = r.hourlyEarnings + wkCommissions;
    const wkHours        = r.regularHrs + r.otHrs;
    const wkRegRate      = wkHours > 0 ? wkTotal / wkHours : 0;
    const wkCommPct      = wkTotal > 0 ? wkCommissions / wkTotal : 0;
    const wkTest2        = wkRegRate > rateThreshold;
    const wkTest3        = wkCommPct > SEC7I_COMMISSION_THRESHOLD;
    const wkOtLiability  = (!wkTest2 || !wkTest3) ? Math.round(0.5 * wkRegRate * r.otHrs) : 0;
    return {
      week: r.week, regularHrs: r.regularHrs, otHrs: r.otHrs,
      hourlyEarnings: r.hourlyEarnings, flatRate: r.flatRateEarnings,
      spiff: r.spiffEarnings, invoicePct: r.invoicePctEarnings,
      commissions: wkCommissions, total: wkTotal,
      regularRate: wkRegRate, commPct: wkCommPct,
      test2: wkTest2, test3: wkTest3,
      exempt: wkTest2 && wkTest3, otLiability: wkOtLiability,
      jobs: r.jobs,
    };
  });

  return {
    emp, empId, weeks, weekCount,
    totalHours, totalRegularHrs, totalOtHrs,
    totalHourlyEarnings, totalFlatRate, totalSpiff, totalInvoicePct,
    totalCommissions, totalCompensation, commissionPct,
    regularRate, rateThreshold,
    test1_retail, test2_rate, test3_commission, exempt,
    otLiability, allJobs, weeklyBreakdown,
    // For report
    periodStart: weeks[0], periodEnd: weeks[weeks.length - 1],
    analysisDate: gw_hris_TODAY,
  };
}

// Generate all weeks in a date range
function getWeeksInRange(startDate, endDate) {
  const weeks = [];
  let cur = startDate;
  while (cur <= endDate) {
    // round to nearest Monday
    const d = new Date(cur + "T12:00:00");
    const day = d.getDay();
    const monday = new Date(d);
    monday.setDate(d.getDate() - (day === 0 ? 6 : day - 1));
    const wk = monday.toISOString().slice(0, 10);
    if (!weeks.includes(wk)) weeks.push(wk);
    const next = new Date(cur + "T12:00:00");
    next.setDate(next.getDate() + 7);
    cur = next.toISOString().slice(0, 10);
  }
  return weeks;
}

