// -- Computed helpers -----------------------------------------

function calcPaycheck_Hris(emp, hours = null) {
  const regular = hours?.regular ?? 40;
  const overtime = hours?.overtime ?? 0;
  const doubletime = hours?.doubletime ?? 0;

  let grossPay = 0;
  if (emp.payType === "salary") {
    const perPeriod = emp.payRate / (emp.payFreq === "semimonthly" ? 24 : emp.payFreq === "biweekly" ? 26 : 52);
    grossPay = perPeriod;
  } else {
    grossPay = (emp.payRate * regular) + (emp.payRate * gw_hris_COMPANY.overtime * overtime) + (emp.payRate * gw_hris_COMPANY.doubleTime * doubletime);
  }

  // Union fringes (employer cost, not deducted from employee)
  let unionFringes = 0;
  if (emp.union && gw_hris_UNIONS[emp.union]) {
    const u = gw_hris_UNIONS[emp.union];
    const totalHours = regular + overtime + doubletime;
    unionFringes = u.fringes.total * totalHours;
  }

  // Deductions
  const fedRate = grossPay > 3000 ? 0.22 : grossPay > 1500 ? 0.12 : 0.10;
  const fedTax = Math.round(grossPay * fedRate);
  const stateTax = Math.round(grossPay * 0.0259); // AZ flat 2.5%
  const ss = Math.round(grossPay * 0.062);
  const medicare = Math.round(grossPay * 0.0145);

  // Benefits deductions
  let benefitDeductions = 0;
  if (emp.benefits?.medical) {
    const plan = gw_hris_BENEFIT_PLANS.medical.find(p => p.id === emp.benefits.medical);
    if (plan) benefitDeductions += Math.round(plan.employeeOnly / (emp.payFreq === "semimonthly" ? 24 : emp.payFreq === "biweekly" ? 26 : 52));
  }
  if (emp.benefits?.dental) {
    const plan = gw_hris_BENEFIT_PLANS.dental.find(p => p.id === emp.benefits.dental);
    if (plan) benefitDeductions += Math.round(plan.employeeOnly / (emp.payFreq === "semimonthly" ? 24 : emp.payFreq === "biweekly" ? 26 : 52));
  }
  if (emp.benefits?.vision) {
    const plan = gw_hris_BENEFIT_PLANS.vision.find(p => p.id === emp.benefits.vision);
    if (plan) benefitDeductions += Math.round(plan.employeeOnly / (emp.payFreq === "semimonthly" ? 24 : emp.payFreq === "biweekly" ? 26 : 52));
  }
  const retirement401k = emp.benefits?.retirement ? Math.round(grossPay * (emp.benefits.retirementPct / 100)) : 0;

  const totalDeductions = fedTax + stateTax + ss + medicare + benefitDeductions + retirement401k;
  const netPay = grossPay - totalDeductions;

  return { grossPay: Math.round(grossPay), fedTax, stateTax, ss, medicare,
           benefitDeductions, retirement401k, totalDeductions: Math.round(totalDeductions),
           netPay: Math.round(netPay), unionFringes: Math.round(unionFringes),
           totalLaborCost: Math.round(grossPay + unionFringes) };
}

function getExpiredCerts() {
  return gw_hris_EMPLOYEES.flatMap(emp =>
    emp.certs.filter(c => {
      if (!c.expires) return false;
      const days = gw_hris_daysDiff(gw_hris_TODAY, c.expires);
      return days < 60;
    }).map(c => {
      const cat = CERT_CATALOG.find(x => x.id === c.id);
      return { emp, cert: cat, expires: c.expires, daysLeft: gw_hris_daysDiff(gw_hris_TODAY, c.expires) };
    })
  ).sort((a,b) => a.daysLeft - b.daysLeft);
}

function avatarColor(emp) {
  const colors = ["var(--sl)","var(--tl)","var(--pu)","var(--gn)","var(--pk)","var(--gd)"];
  const idx = (emp.first.charCodeAt(0) + emp.last.charCodeAt(0)) % colors.length;
  return colors[idx];
}

function initials(emp) { return emp.first[0] + emp.last[0]; }

function statusBadge(status) {
  const map = {
    active:    ["b-gn","Active"],
    onleave:   ["b-gd","On Leave"],
    terminated:["b-rd","Terminated"],
    pending:   ["b-sl","Pending"],
  };
  const [cls, lbl] = map[status] || ["b-mute", status];
  return <span className={"badge "+(cls)}>{lbl}</span>;
}

function appStatusBadge(status) {
  const map = {
    applied:       ["b-mute","Applied"],
    phone_screen:  ["b-sl","Phone Screen"],
    interview_1:   ["b-sl","Interview 1"],
    interview_2:   ["b-pu","Interview 2"],
    offer_pending: ["b-gd","Offer Pending"],
    hired:         ["b-gn","Hired"],
    rejected:      ["b-rd","Rejected"],
    withdrawn:     ["b-mute","Withdrawn"],
  };
  const [cls, lbl] = map[status] || ["b-mute", status];
  return <span className={"badge "+(cls)}>{lbl}</span>;
}

function reqStatusBadge(status) {
  const map = {
    draft:     ["b-mute","Draft"],
    pending:   ["b-gd","Pending Approval"],
    posted:    ["b-sl","Posted"],
    interview: ["b-pu","In Interviews"],
    offer:     ["b-gd","Offer Extended"],
    filled:    ["b-gn","Filled"],
    cancelled: ["b-rd","Cancelled"],
  };
  const [cls, lbl] = map[status] || ["b-mute", status];
  return <span className={"badge "+(cls)}>{lbl}</span>;
}

