function GroundworkJobCost() {
  const [tab, setTab]   = useState("dash");
  const [jobs, setJobs] = useState(gw_jobcost_SEED_JOBS);

  const updateJob = updated => setJobs(prev => prev.map(j => j.id === updated.id ? updated : j));

  const tabs = [
    {id:"dash",  icon:"📊", label:"Dashboard"},
    {id:"jobs",  icon:"📋", label:"Jobs"},
    {id:"labor", icon:"⏱",  label:"Labor Tracker"},
    {id:"wip",   icon:"📈", label:"WIP Schedule"},
    {id:"rel",   icon:"🔗", label:"Relationships"},
  ];

  const totalActiveJobs = jobs.filter(j => j.status === "Active").length;
  const billingAlerts   = jobs.filter(j => {
    const earned = j.contractValue * (j.pctComplete / 100);
    return (earned - j.billedToDate) > 10000 && j.status === "Active";
  });

  return (
    <>
      <style>{css_gw_jobcost}</style>
      <div className="app">
        <aside className="sb">
          <div style={{position:"absolute",top:0,left:0,right:0,height:3,background:"linear-gradient(90deg,var(--sl),var(--tl),var(--gn))"}}/>
          <div className="sb-logo">
            <div style={{display:"flex",alignItems:"center",gap:9}}>
              <div className="sb-gem">
                <svg width="14" height="14" viewBox="0 0 24 24" fill="none">
                  <path d="M12 2L2 7l10 5 10-5-10-5z" fill="#0B0C0E"/>
                  <path d="M2 17l10 5 10-5M2 12l10 5 10-5" stroke="#0B0C0E" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"/>
                </svg>
              </div>
              <div>
                <div className="sb-n">GROUNDWORK</div>
                <div className="sb-m">Job Costing</div>
              </div>
            </div>
          </div>

          <nav className="sb-nav">
            <div className="sb-sec">Job Costing</div>
            {tabs.map(t => (
              <div key={t.id} className={"sb-item "+(tab===t.id?"on":"")} onClick={()=>setTab(t.id)}>
                <span style={{fontSize:13,width:18,flexShrink:0}}>{t.icon}</span>
                {t.label}
                {t.id==="jobs" && totalActiveJobs > 0 && <span className="sb-badge">{totalActiveJobs}</span>}
              </div>
            ))}

            {billingAlerts.length > 0 && (
              <div onClick={()=>setTab("jobs")} style={{margin:"10px 8px",padding:"10px 12px",
                background:"rgba(220,38,38,.1)",border:"1px solid rgba(220,38,38,.3)",
                borderRadius:8,cursor:"pointer"}}>
                <div style={{fontSize:9,fontWeight:700,letterSpacing:1.5,color:"#F87171",marginBottom:4}}>
                  ⚠ BILLING ALERT
                </div>
                {billingAlerts.map(j => {
                  const unbilled = Math.round(j.contractValue * j.pctComplete/100) - j.billedToDate;
                  return (
                    <div key={j.id} style={{fontSize:10,color:"#FCA5A5",marginBottom:2}}>
                      {j.num} — ${Math.round(unbilled/1000)}k unbilled
                    </div>
                  );
                })}
              </div>
            )}

            <div className="sb-sec" style={{marginTop:12}}>Reports</div>
            {[["Job P&L","📊"],["Cost-to-Complete","📉"],["Certified Payroll","🏗"],["Invoice Register","🧾"]].map(([s,ic]) => (
              <div key={s} className="sb-item" style={{opacity:.4}}>
                <span style={{fontSize:12}}>{ic}</span>
                <span dangerouslySetInnerHTML={{__html:s}}/>
                <span className="sb-soon">SOON</span>
              </div>
            ))}
          </nav>
        </aside>

        <div className="main">
          <div className="topbar">
            <div>
              <div className="tb-t">JOB COSTING</div>
              <div className="tb-s">Groundwork · Apex MEP Services LLC · {jobs.length} jobs</div>
            </div>
            <div style={{display:"flex",gap:8,alignItems:"center"}}>
              {billingAlerts.length > 0 && (
                <div onClick={()=>setTab("jobs")} style={{padding:"5px 10px",background:"rgba(220,38,38,.15)",border:"1px solid rgba(220,38,38,.4)",
                  borderRadius:6,fontSize:11,color:"#F87171",cursor:"pointer",fontWeight:600}}>
                  ⚠ {billingAlerts.length} job{billingAlerts.length>1?"s":""} need billing
                </div>
              )}
              <button className="btn btn-ghost btn-sm">Export</button>
              <button className="btn btn-sl btn-sm" onClick={()=>setTab("jobs")}>{gw_jobcost_Ic.plus} New Job</button>
            </div>
          </div>

          <div className="tab-bar">
            {tabs.map(t => (
              <div key={t.id} className={"tab "+(tab===t.id?"on":"")} onClick={()=>setTab(t.id)}>{t.icon} {t.label}</div>
            ))}
          </div>

          <div className="content">
            {tab==="dash"  && <DashboardTab_JobCost jobs={jobs}/>}
            {tab==="jobs"  && <JobsTab jobs={jobs} setJobs={setJobs}/>}
            {tab==="labor" && <LaborTab jobs={jobs}/>}
            {tab==="wip"   && <WIPTab_JobCost jobs={jobs}/>}
            {tab==="rel"   && <RelationshipsTab jobs={jobs}/>}
          </div>
        </div>
      </div>
    </>
  );
}



