// -- CSS ------------------------------------------------------
const css_gw_payroll = `
  @import url('https://fonts.googleapis.com/css2?family=Bebas+Neue&family=IBM+Plex+Sans:wght@300;400;500;600;700&family=IBM+Plex+Mono:wght@400;500;600&display=swap');
  *,*::before,*::after{box-sizing:border-box;margin:0;padding:0}
  :root{
    --bg:#09090B;--surf:#111114;--raise:#18181C;--card:#1E1E23;
    --bord:#27272D;--bord2:#323238;--mute:#52525B;--dim:#71717A;
    --lite:#A1A1AA;--brite:#D4D4D8;--white:#F4F4F5;
    --sl:#4F7ADB;--sl-d:rgba(79,122,219,.12);--sl-b:rgba(79,122,219,.28);
    --tl:#10A57E;--tl-d:rgba(16,165,126,.12);--tl-b:rgba(16,165,126,.28);
    --gn:#16A34A;--gn-d:rgba(22,163,74,.12);--gn-b:rgba(22,163,74,.28);
    --gd:#D97706;--gd-d:rgba(217,119,6,.12);--gd-b:rgba(217,119,6,.28);
    --rd:#DC2626;--rd-d:rgba(220,38,38,.12);--rd-b:rgba(220,38,38,.28);
    --pu:#7C3AED;--pu-d:rgba(124,58,237,.12);--pu-b:rgba(124,58,237,.28);
    --pk:#BE185D;--pk-d:rgba(190,24,93,.12);--pk-b:rgba(190,24,93,.28);
    --font:'IBM Plex Sans',sans-serif;
    --mono:'IBM Plex Mono',monospace;
    --display:'Bebas Neue',sans-serif;
  }
  html,body,#root{height:100%;background:var(--bg);color:var(--white);font-family:var(--font);font-size:13px}
  @keyframes fi{from{opacity:0;transform:translateY(6px)}to{opacity:1;transform:translateY(0)}}
  @keyframes spin{to{transform:rotate(360deg)}}
  @keyframes pulse{0%,100%{opacity:1}50%{opacity:.5}}
  .fade{animation:fi .2s ease}

  /* Layout */
  .shell{display:flex;height:100vh;overflow:hidden}
  .pay-sb{width:220px;flex-shrink:0;background:var(--surf);border-right:1px solid var(--bord);display:flex;flex-direction:column;overflow-y:auto}
  .main{flex:1;display:flex;flex-direction:column;overflow:hidden}
  .topbar{height:52px;background:var(--surf);border-bottom:1px solid var(--bord);display:flex;align-items:center;padding:0 20px;gap:12px;flex-shrink:0}
  .content{flex:1;overflow-y:auto;padding:20px}

  /* Sidebar */
  .sb-logo{padding:16px 14px 12px;border-bottom:1px solid var(--bord)}
  .sb-section{padding:8px 10px 4px;font-size:9px;font-weight:700;letter-spacing:2px;text-transform:uppercase;color:var(--mute)}
  .sb-item{display:flex;align-items:center;gap:9px;padding:8px 12px;margin:1px 6px;border-radius:7px;cursor:pointer;font-size:12px;color:var(--lite);transition:all .12s;user-select:none}
  .sb-item:hover{background:var(--raise);color:var(--white)}
  .sb-item.on{background:var(--sl-d);color:var(--sl);border:1px solid var(--sl-b)}
  .sb-badge{margin-left:auto;background:var(--rd);color:#fff;border-radius:10px;padding:1px 6px;font-size:9px;font-weight:700}

  /* Panels */
  .panel{background:var(--surf);border:1px solid var(--bord);border-radius:10px;overflow:hidden}
  .ph{padding:14px 16px;border-bottom:1px solid var(--bord);display:flex;justify-content:space-between;align-items:center;gap:10}
  .pt{font-family:var(--display);letter-spacing:2px;font-size:12px;color:var(--white)}
  .ps{font-size:10px;color:var(--mute);margin-top:2px}

  /* KPIs */
  .krow{display:grid;grid-template-columns:repeat(auto-fit,minmax(140px,1fr));gap:10px}
  .kpi{background:var(--surf);border:1px solid var(--bord);border-radius:10px;padding:14px 16px}
  .kl{font-size:10px;color:var(--mute);margin-bottom:5px;text-transform:uppercase;letter-spacing:.5px}
  .kv{font-family:var(--mono);font-size:18px;font-weight:600;color:var(--white);line-height:1}
  .ks{font-size:9px;color:var(--mute);margin-top:4px}
  .k-sl{border-color:var(--sl-b)}.k-sl .kv{color:var(--sl)}
  .k-tl{border-color:var(--tl-b)}.k-tl .kv{color:var(--tl)}
  .k-gn{border-color:var(--gn-b)}.k-gn .kv{color:var(--gn)}
  .k-gd{border-color:var(--gd-b)}.k-gd .kv{color:var(--gd)}
  .k-rd{border-color:var(--rd-b)}.k-rd .kv{color:var(--rd)}
  .k-pu{border-color:var(--pu-b)}.k-pu .kv{color:var(--pu)}

  /* Tables */
  .tbl{width:100%;border-collapse:collapse;font-size:12px}
  .tbl th{padding:9px 12px;text-align:left;font-size:9px;font-weight:700;letter-spacing:1.5px;text-transform:uppercase;color:var(--mute);border-bottom:1px solid var(--bord);white-space:nowrap}
  .tbl td{padding:9px 12px;border-bottom:1px solid rgba(255,255,255,.04);vertical-align:middle}
  .tbl tr:last-child td{border-bottom:none}
  .tbl tr:hover td{background:rgba(255,255,255,.02)}
  .mono{font-family:var(--mono);font-size:11px}

  /* Badges */
  .badge{display:inline-flex;align-items:center;gap:4px;padding:2px 8px;border-radius:20px;font-size:10px;font-weight:600;white-space:nowrap}
  .b-sl{background:var(--sl-d);color:var(--sl);border:1px solid var(--sl-b)}
  .b-tl{background:var(--tl-d);color:var(--tl);border:1px solid var(--tl-b)}
  .b-gn{background:var(--gn-d);color:var(--gn);border:1px solid var(--gn-b)}
  .b-gd{background:var(--gd-d);color:var(--gd);border:1px solid var(--gd-b)}
  .b-rd{background:var(--rd-d);color:var(--rd);border:1px solid var(--rd-b)}
  .b-pu{background:var(--pu-d);color:var(--pu);border:1px solid var(--pu-b)}
  .b-mute{background:rgba(82,82,91,.2);color:var(--lite);border:1px solid var(--bord)}

  /* Buttons */
  .btn{display:inline-flex;align-items:center;gap:6px;padding:7px 14px;border-radius:7px;border:none;font-family:var(--font);font-size:12px;font-weight:500;cursor:pointer;transition:all .12s;white-space:nowrap}
  .btn:disabled{opacity:.4;cursor:not-allowed}
  .btn-primary{background:var(--sl);color:#fff}.btn-primary:hover:not(:disabled){background:#5F8AEB}
  .btn-tl{background:var(--tl);color:#fff}.btn-tl:hover:not(:disabled){background:#12B88E}
  .btn-gn{background:var(--gn);color:#fff}.btn-gn:hover:not(:disabled){background:#18B854}
  .btn-rd{background:var(--rd);color:#fff}.btn-rd:hover:not(:disabled){background:#EF3535}
  .btn-pu{background:var(--pu);color:#fff}.btn-pu:hover:not(:disabled){background:#8B45FF}
  .btn-ghost{background:transparent;color:var(--lite);border:1px solid var(--bord)}.btn-ghost:hover:not(:disabled){border-color:var(--bord2);color:var(--white)}
  .btn-sm{padding:5px 10px;font-size:11px}

  /* Inputs */
  .inp{background:var(--raise);border:1px solid var(--bord);border-radius:7px;color:var(--white);font-family:var(--font);font-size:12px;padding:8px 11px;outline:none;width:100%;transition:border .12s}
  .inp:focus{border-color:var(--sl)}
  select.inp option{background:var(--raise)}
  .lbl{font-size:10px;font-weight:600;color:var(--lite);letter-spacing:.5px;margin-bottom:4px;display:block}

  /* Grids */
  .g2{display:grid;grid-template-columns:1fr 1fr;gap:14px}
  .g3{display:grid;grid-template-columns:1fr 1fr 1fr;gap:14px}
  .g4{display:grid;grid-template-columns:repeat(4,1fr);gap:12px}

  /* Alerts */
  .alert{display:flex;align-items:flex-start;gap:10px;padding:10px 14px;border-radius:8px;font-size:11px;line-height:1.6}
  .a-rd{background:var(--rd-d);border:1px solid var(--rd-b);color:var(--rd)}
  .a-gd{background:var(--gd-d);border:1px solid var(--gd-b);color:var(--gd)}
  .a-gn{background:var(--gn-d);border:1px solid var(--gn-b);color:var(--gn)}
  .a-sl{background:var(--sl-d);border:1px solid var(--sl-b);color:var(--sl)}
  .a-pu{background:var(--pu-d);border:1px solid var(--pu-b);color:var(--pu)}

  /* Filters */
  .frow{display:flex;align-items:center;gap:8px;flex-wrap:wrap;margin-bottom:14px}
  .fc{padding:5px 12px;border-radius:6px;border:1px solid var(--bord);font-size:11px;color:var(--mute);cursor:pointer;transition:all .12s;white-space:nowrap}
  .fc:hover{border-color:var(--bord2);color:var(--lite)}
  .fc.on{border-color:var(--sl-b);color:var(--sl);background:var(--sl-d)}

  /* Modal */
  .overlay{position:fixed;inset:0;background:rgba(0,0,0,.65);z-index:100;display:flex;align-items:center;justify-content:center;padding:20px}
  .modal{background:var(--surf);border:1px solid var(--bord);border-radius:12px;width:100%;max-width:720px;max-height:90vh;overflow-y:auto;animation:fi .18s ease}
  .modal-lg{max-width:900px}
  .modal-head{padding:16px 20px;border-bottom:1px solid var(--bord);display:flex;justify-content:space-between;align-items:center;position:sticky;top:0;background:var(--surf);z-index:1}
  .modal-body{padding:20px}
  .modal-foot{padding:14px 20px;border-top:1px solid var(--bord);display:flex;justify-content:flex-end;gap:8px;position:sticky;bottom:0;background:var(--surf)}

  /* Pay stub */
  .stub{border:1px solid var(--bord);border-radius:8px;overflow:hidden;font-size:12px}
  .stub-head{background:var(--sl-d);padding:12px 16px;border-bottom:1px solid var(--sl-b)}
  .stub-section{padding:6px 16px;border-bottom:1px solid var(--bord);background:rgba(255,255,255,.01)}
  .stub-row{display:flex;justify-content:space-between;padding:5px 16px;border-bottom:1px solid rgba(255,255,255,.04)}
  .stub-total{display:flex;justify-content:space-between;padding:10px 16px;background:var(--raise);font-weight:700;border-top:1px solid var(--bord)}
  .stub-net{display:flex;justify-content:space-between;padding:12px 16px;background:var(--sl-d);font-weight:700;font-size:14px;border-top:1px solid var(--sl-b)}

  /* Flag pills */
  .flag-rd{background:var(--rd-d);border:1px solid var(--rd-b);color:var(--rd);border-radius:5px;padding:3px 8px;font-size:10px;font-weight:600;display:inline-flex;align-items:center;gap:4px}
  .flag-gd{background:var(--gd-d);border:1px solid var(--gd-b);color:var(--gd);border-radius:5px;padding:3px 8px;font-size:10px;font-weight:600;display:inline-flex;align-items:center;gap:4px}
  .flag-sl{background:var(--sl-d);border:1px solid var(--sl-b);color:var(--sl);border-radius:5px;padding:3px 8px;font-size:10px;font-weight:600;display:inline-flex;align-items:center;gap:4px}

  /* Check print */
  .check{background:#fff;color:#111;border:2px solid #c8a800;border-radius:6px;padding:0;overflow:hidden;font-family:'IBM Plex Mono',monospace;font-size:11px;width:680px;max-width:100%}
  .check-head{background:linear-gradient(135deg,#1a3a6e,#1e4d8c);color:#fff;padding:10px 18px;display:flex;justify-content:space-between;align-items:center}
  .check-body{padding:14px 18px;display:grid;grid-template-columns:1fr 1fr;gap:8px}
  .check-amount{background:#f8f4e8;border:1px solid #c8a800;border-radius:4px;padding:8px 14px;text-align:center;font-size:16px;font-weight:700;color:#1a3a6e;margin:8px 18px;letter-spacing:1px}
  .check-words{padding:4px 18px 10px;font-size:10px;color:#444;border-bottom:1px dashed #c8a800}
  .check-memo{padding:8px 18px 12px;display:grid;grid-template-columns:1fr 1fr;gap:8px;font-size:10px;color:#333}
  .check-void{font-family:'Bebas Neue',sans-serif;letter-spacing:4px;font-size:42px;color:rgba(220,38,38,.12);position:absolute;top:50%;left:50%;transform:translate(-50%,-50%) rotate(-20deg);pointer-events:none;width:100%;text-align:center}

  /* Progress */
  .prog-wrap{height:6px;background:var(--raise);border-radius:3px;overflow:hidden}
  .prog-fill{height:100%;border-radius:3px;transition:width .5s ease}

  /* Scrollbar */
  ::-webkit-scrollbar{width:5px;height:5px}
  ::-webkit-scrollbar-track{background:transparent}
  ::-webkit-scrollbar-thumb{background:var(--bord2);border-radius:3px}
`;

// -- Constants ------------------------------------------------
const gw_payroll_TODAY      = "2026-02-18";
const PAY_PERIOD = { start: "2026-02-09", end: "2026-02-13", label: "Feb 9–13, 2026" };

const gw_payroll_dollarc  = n => n < 0 ? `-$${Math.abs(n).toLocaleString("en-US",{minimumFractionDigits:2,maximumFractionDigits:2})}` : `$${n.toLocaleString("en-US",{minimumFractionDigits:2,maximumFractionDigits:2})}`;
const $r  = n => `$${parseFloat(n).toFixed(2)}`;
const gw_payroll_fmtDate = d => d ? new Date(d+"T12:00:00").toLocaleDateString("en-US",{month:"short",day:"numeric",year:"numeric"}) : "—";
const numWords = n => {
  const ones=["","One","Two","Three","Four","Five","Six","Seven","Eight","Nine","Ten","Eleven","Twelve","Thirteen","Fourteen","Fifteen","Sixteen","Seventeen","Eighteen","Nineteen"];
  const tens=["","","Twenty","Thirty","Forty","Fifty","Sixty","Seventy","Eighty","Ninety"];
  if(n===0) return "Zero";
  const dollars = Math.floor(n);
  const cents = Math.round((n-dollars)*100);
  const toW = x => {
    if(x===0) return "";
    if(x<20) return ones[x];
    if(x<100) return tens[Math.floor(x/10)]+(x%10?" "+ones[x%10]:"");
    return ones[Math.floor(x/100)]+" Hundred"+(x%100?" "+toW(x%100):"");
  };
  const parts=[];
  if(dollars>=1000) parts.push(toW(Math.floor(dollars/1000))+" Thousand");
  if(dollars%1000>=100) parts.push(toW(Math.floor((dollars%1000)/100))+" Hundred");
  if(dollars%100) parts.push(toW(dollars%100));
  return parts.join(" ")+" and "+cents+"/100";
};

