// -- Tax calculation engine ------------------------------------
function calcFedTax(annualizedGross, filingStatus) {
  const brackets = FED_TAX_2026[filingStatus] || FED_TAX_2026.single;
  // Weekly → annualized bracket lookup
  const weekly = annualizedGross / 52;
  const bracket = brackets.findLast(b => weekly >= b.min) || brackets[0];
  const tax = bracket.base + (weekly - bracket.min) * bracket.rate;
  return Math.max(0, Math.round(tax));
}

function calcPaycheck_Payroll(emp) {
  const ts     = gw_payroll_TIMESHEETS[emp.id];
  const w4     = emp.w4;
  const u      = emp.union ? gw_payroll_UNIONS[emp.union] : null;

  // -- Hours & gross ------------------------------------------
  let regularHrs = 0, otHrs = 0, gross = 0, unionFringes = 0;

  if (emp.payType === "hourly") {
    ts.entries.forEach(e => { regularHrs += e.hrs - e.ot; otHrs += e.ot; });
    const regPay = regularHrs * emp.payRate;
    const otPay  = otHrs * emp.payRate * 1.5;
    gross = regPay + otPay;
    if (u) {
      const totalHrs = regularHrs + otHrs;
      unionFringes = u.fringes.total * totalHrs;
    }
  } else {
    // Salary: divide annual by pay periods
    const periods = emp.payFreq === "semimonthly" ? 24 : emp.payFreq === "biweekly" ? 26 : 52;
    gross = emp.payRate / periods;
  }

  // -- Federal income tax (2026 brackets) --------------------
  const annualized = gross * (emp.payFreq === "weekly" ? 52 : emp.payFreq === "biweekly" ? 26 : 24);
  let fedTax = calcFedTax(annualized, w4.filingStatus);
  fedTax = Math.max(0, fedTax - (w4.allowances * 88)); // $88/allowance/week 2026
  fedTax += (w4.extraWithholding || 0);
  if (w4.exemptFed) fedTax = 0;

  // -- AZ state tax -------------------------------------------
  let stateTax = w4.exemptState ? 0 : Math.round(gross * AZ_FLAT_RATE);

  // -- FICA ---------------------------------------------------
  const ytdGross = emp.ytd.gross;
  const ssWages  = Math.max(0, Math.min(gross, FICA_SS_WAGE_BASE - ytdGross));
  const ss       = Math.round(ssWages * FICA_SS);
  const medicare = Math.round(gross * FICA_MEDICARE);
  // Additional Medicare for high earners
  const addMedicare = (ytdGross + gross) > 200000 ? Math.round(gross * FICA_ADD_MEDICARE) : 0;

  // -- Benefits deductions (employee share, pre-tax where applicable) --
  const periods = emp.payFreq === "semimonthly" ? 24 : emp.payFreq === "biweekly" ? 26 : 52;
  let benefitDed = 0;
  let medicalDed = 0, dentalDed = 0, visionDed = 0;
  if (emp.benefits.medical) {
    const plan = gw_payroll_BENEFIT_PLANS.medical.find(p => p.id === emp.benefits.medical);
    if (plan) { medicalDed = Math.round(plan.eeOnly / periods); benefitDed += medicalDed; }
  }
  if (emp.benefits.dental) {
    const plan = gw_payroll_BENEFIT_PLANS.dental.find(p => p.id === emp.benefits.dental);
    if (plan) { dentalDed = Math.round(plan.eeOnly / periods); benefitDed += dentalDed; }
  }
  if (emp.benefits.vision) {
    const plan = gw_payroll_BENEFIT_PLANS.vision.find(p => p.id === emp.benefits.vision);
    if (plan) { visionDed = Math.round(plan.eeOnly / periods); benefitDed += visionDed; }
  }

  // -- 401(k) ------------------------------------------------
  const retirement401k = emp.benefits.retirement ? Math.round(gross * (emp.benefits.retirementPct / 100)) : 0;

  // -- Union working dues (employee deduction) ---------------
  const unionDues = u ? Math.round(gross * u.workingDues) : 0;

  // -- Net pay -----------------------------------------------
  const totalDed = fedTax + stateTax + ss + medicare + addMedicare + benefitDed + retirement401k + unionDues;
  const net      = Math.max(0, Math.round(gross - totalDed));

  // -- Employer-side taxes -----------------------------------
  const employerSS       = Math.round(ssWages * FICA_SS);
  const employerMedicare = Math.round(gross * FICA_MEDICARE);
  const futa             = gross <= 7000 ? Math.round(gross * 0.006) : 0;
  const suta             = Math.round(gross * 0.027); // AZ SUTA avg rate

  // -- Flags (red-flag pre-review checks) -------------------
  const flags = [];
  if (!ts.approved)               flags.push({type:"error",  msg:"Timesheet not approved"});
  if (gross > emp.ytd.gross / 7)  flags.push({type:"warn",   msg:"Gross pay significantly above YTD average"});
  if (net < 0)                    flags.push({type:"error",  msg:"Net pay is negative — check deductions"});
  if (fedTax === 0 && !w4.exemptFed && gross > 500) flags.push({type:"warn", msg:"Federal withholding is $0 — verify W-4"});
  if (otHrs > 12)                 flags.push({type:"warn",   msg:"Overtime >12 hrs — confirm hours"});
  if (emp.payMethod === "check" && emp.directDeposit.length > 0) flags.push({type:"info", msg:"Has DD on file but method is check"});
  if (retirement401k > 0 && (ytdGross + gross) * (emp.benefits.retirementPct/100) > 23500)
    flags.push({type:"warn", msg:"Approaching 401(k) contribution limit ($23,500)"});

  return {
    empId:emp.id, emp,
    regularHrs, otHrs, totalHrs: regularHrs+otHrs,
    gross:Math.round(gross), gross_raw:gross,
    fedTax, stateTax, ss, medicare, addMedicare,
    benefitDed, medicalDed, dentalDed, visionDed,
    retirement401k, unionDues,
    totalDed: Math.round(totalDed),
    net,
    // Employer-side
    employerSS, employerMedicare, futa, suta,
    unionFringes: Math.round(unionFringes),
    totalLaborCost: Math.round(gross + unionFringes + employerSS + employerMedicare + futa + suta),
    // Meta
    flags, ts, approved: ts.approved,
    payMethod: emp.payMethod,
    checkNumber: null, // assigned on print
  };
}

// -- Compute all paychecks -------------------------------------
function buildPayroll() {
  return gw_payroll_EMPLOYEES
    .filter(e => {
      if (e.payFreq === "weekly") return true;
      if (e.payFreq === "biweekly") return true; // assume this is a biweekly pay week
      if (e.payFreq === "semimonthly") return true;
      return false;
    })
    .map(e => calcPaycheck_Payroll(e));
}

// -- Department rollup -----------------------------------------
function deptRollup(paychecks) {
  const rollup = {};
  paychecks.forEach(pc => {
    const dept = pc.emp.dept;
    if (!rollup[dept]) rollup[dept] = { dept, count:0, gross:0, fedTax:0, stateTax:0, fica:0, benefits:0, retirement:0, unionFringes:0, employerTax:0, net:0, totalLaborCost:0 };
    const r = rollup[dept];
    r.count++;
    r.gross        += pc.gross;
    r.fedTax       += pc.fedTax;
    r.stateTax     += pc.stateTax;
    r.fica         += pc.ss + pc.medicare;
    r.benefits     += pc.benefitDed;
    r.retirement   += pc.retirement401k;
    r.unionFringes += pc.unionFringes;
    r.employerTax  += pc.employerSS + pc.employerMedicare + pc.futa + pc.suta;
    r.net          += pc.net;
    r.totalLaborCost += pc.totalLaborCost;
  });
  return Object.values(rollup).sort((a,b) => b.gross - a.gross);
}

// -- GL Entry builder ------------------------------------------
function buildGLEntries_Payroll(paychecks) {
  const totals = {
    fieldGross:0, officeGross:0, execGross:0,
    fedTax:0, stateTax:0, ss:0, medicare:0,
    employerSS:0, employerMedicare:0, futa:0, suta:0,
    medicalBen:0, dentalBen:0, visionBen:0,
    retirement:0, unionHealth:0, unionPension:0, unionAnnuity:0, unionTraining:0,
    ddNet:0, checkNet:0,
  };
  paychecks.forEach(pc => {
    if (pc.emp.type === "field")  totals.fieldGross  += pc.gross;
    else if (pc.emp.type === "office") totals.officeGross += pc.gross;
    else totals.execGross += pc.gross;
    totals.fedTax          += pc.fedTax;
    totals.stateTax        += pc.stateTax;
    totals.ss              += pc.ss;
    totals.medicare        += pc.medicare;
    totals.employerSS      += pc.employerSS;
    totals.employerMedicare += pc.employerMedicare;
    totals.futa            += pc.futa;
    totals.suta            += pc.suta;
    totals.medicalBen      += pc.medicalDed;
    totals.dentalBen       += pc.dentalDed;
    totals.visionBen       += pc.visionDed;
    totals.retirement      += pc.retirement401k;
    if (pc.emp.union && gw_payroll_UNIONS[pc.emp.union]) {
      const u = gw_payroll_UNIONS[pc.emp.union];
      const hrs = pc.totalHrs;
      totals.unionHealth   += Math.round(u.fringes.health   * hrs);
      totals.unionPension  += Math.round(u.fringes.pension  * hrs);
      totals.unionAnnuity  += Math.round(u.fringes.annuity  * hrs);
      totals.unionTraining += Math.round(u.fringes.training * hrs);
    }
    if (pc.payMethod === "direct_deposit") totals.ddNet += pc.net;
    else totals.checkNet += pc.net;
  });

  const entries = [];
  const debit  = (acctKey, amount, memo) => { if (amount > 0) entries.push({type:"Dr",acct:gw_payroll_GL_ACCOUNTS[acctKey].acct,name:gw_payroll_GL_ACCOUNTS[acctKey].name,amount,memo}); };
  const credit = (acctKey, amount, memo) => { if (amount > 0) entries.push({type:"Cr",acct:gw_payroll_GL_ACCOUNTS[acctKey].acct,name:gw_payroll_GL_ACCOUNTS[acctKey].name,amount,memo}); };

  // Gross wages — debits
  debit("grossWages",    totals.fieldGross,  "Field labor gross wages");
  debit("grossSalaries", totals.officeGross, "Office/admin gross wages");
  debit("grossExec",     totals.execGross,   "Executive gross wages");
  // Employer taxes — debits
  debit("employerSS",       totals.employerSS,      "Employer FICA — SS 6.2%");
  debit("employerMedicare", totals.employerMedicare,"Employer FICA — Medicare 1.45%");
  debit("futa",             totals.futa,             "FUTA 0.6%");
  debit("suta",             totals.suta,             "AZ SUTA 2.7%");
  // Union fringes — debits
  debit("unionHealth",   totals.unionHealth,   "Union H&W contributions");
  debit("unionPension",  totals.unionPension,  "Union pension contributions");
  debit("unionAnnuity",  totals.unionAnnuity,  "Union annuity contributions");
  debit("unionTraining", totals.unionTraining, "Union training contributions");

  // Credits — liabilities
  credit("fedTaxLiability",   totals.fedTax,          "Federal income tax withheld");
  credit("stateTaxLiability", totals.stateTax,         "AZ income tax withheld");
  credit("ssLiability",       totals.ss + totals.employerSS,       "SS — employee + employer");
  credit("medicareLiability", totals.medicare + totals.medicare, "Medicare — employee + employer");
  credit("benefitMedical",    totals.medicalBen,       "Employee medical premiums");
  credit("benefitDental",     totals.dentalBen,        "Employee dental premiums");
  credit("benefitVision",     totals.visionBen,        "Employee vision premiums");
  credit("retirement401k",    totals.retirement,       "401(k) contributions");
  credit("ddLiability",       totals.ddNet,            "Direct deposit net pay — ACH");
  credit("checkLiability",    totals.checkNet,         "Payroll checks net pay");

  return { entries, totals };
}

