// -- Direct Deposit Setup Modal --------------------------------
function DDSetupModal({emp, onClose}) {
  const [accounts, setAccounts] = useState(emp.directDeposit || []);
  const [newAcct, setNewAcct] = useState({bank:"",routing:"",account:"",type:"checking",pct:100});

  const totalPct = accounts.filter(a=>a.active).reduce((s,a)=>s+a.pct,0);

  return (
    <div className="overlay">
      <div className="modal">
        <div className="modal-head">
          <div>
            <div className="pt">DIRECT DEPOSIT — {emp.first} {emp.last}</div>
            <div className="ps">Manage ACH deposit accounts</div>
          </div>
          <button className="btn btn-ghost btn-sm" onClick={onClose}>✕</button>
        </div>
        <div className="modal-body" style={{display:"flex",flexDirection:"column",gap:14}}>
          {/* Existing accounts */}
          {accounts.length > 0 && (
            <div>
              <div className="lbl" style={{marginBottom:8}}>Current Accounts</div>
              {accounts.map((a,i) => (
 <div key={i} style={{display:"flex",alignItems:"center",gap:8,padding:"10px 12px", background:"var(--raise)",border:"1px solid var(--bord)",borderRadius:7,marginBottom:6}}>
                  <div style={{width:8,height:8,borderRadius:"50%",background:a.active?"var(--tl)":"var(--mute)",flexShrink:0}}/>
                  <div style={{flex:1}}>
                    <div style={{fontSize:11,fontWeight:600}}>{a.bank}</div>
                    <div style={{fontSize:10,color:"var(--mute)"}}>ABA {a.routing} · {a.type} {a.account}</div>
                  </div>
                  <div style={{fontFamily:"var(--mono)",fontSize:12,fontWeight:700,color:"var(--tl)",minWidth:40,textAlign:"right"}}>{a.pct}%</div>
 <button className="btn btn-ghost btn-sm" style={{padding:"3px 8px",fontSize:10}} onClick={()=>setAccounts(prev=>prev.filter((_,j)=>j!==i))}>
                    ✕
                  </button>
                </div>
              ))}
 <div style={{padding:"6px 12px",background:totalPct===100?"var(--tl-d)":"var(--rd-d)",borderRadius:5, border:"1px solid "+(totalPct===100?"var(--tl-b)":"var(--rd-b)"), fontSize:10,color:totalPct===100?"var(--tl)":"var(--rd)",fontWeight:600}}>
                Total allocation: {totalPct}% {totalPct!==100 && "— must equal 100%"}
              </div>
            </div>
          )}

          {/* Add new */}
          <div style={{borderTop:"1px solid var(--bord)",paddingTop:14}}>
            <div className="lbl" style={{marginBottom:10}}>Add Account</div>
            <div className="g2" style={{marginBottom:8}}>
              <div><label className="lbl">Bank Name</label><input className="inp" placeholder="Chase Bank" value={newAcct.bank} onChange={e=>setNewAcct(p=>({...p,bank:e.target.value}))}/></div>
              <div><label className="lbl">ABA Routing</label><input className="inp" placeholder="9-digit routing" value={newAcct.routing} onChange={e=>setNewAcct(p=>({...p,routing:e.target.value}))}/></div>
            </div>
            <div className="g3" style={{marginBottom:12}}>
              <div><label className="lbl">Account #</label><input className="inp" placeholder="Account number" value={newAcct.account} onChange={e=>setNewAcct(p=>({...p,account:e.target.value}))}/></div>
              <div><label className="lbl">Type</label>
                <select className="inp" value={newAcct.type} onChange={e=>setNewAcct(p=>({...p,type:e.target.value}))}>
                  <option value="checking">Checking</option>
                  <option value="savings">Savings</option>
                </select>
              </div>
              <div><label className="lbl">% of Net Pay</label><input type="number" className="inp" min="1" max="100" value={newAcct.pct} onChange={e=>setNewAcct(p=>({...p,pct:+e.target.value}))}/></div>
            </div>
            <button className="btn btn-tl btn-sm" onClick={()=>{
              if(!newAcct.bank||!newAcct.routing||!newAcct.account) return;
              setAccounts(prev=>[...prev,{...newAcct,active:true}]);
              setNewAcct({bank:"",routing:"",account:"",type:"checking",pct:0});
            }}>+ Add Account</button>
          </div>
        </div>
        <div className="modal-foot">
          <button className="btn btn-ghost" onClick={onClose}>Cancel</button>
          <button className="btn btn-primary" onClick={onClose}>Save Direct Deposit</button>
        </div>
      </div>
    </div>
  );
}

