            <div className="g3">
              {[["Gross Pay",gw_payroll_dollarc(preview.gross),"var(--tl)"],["Fed Tax",gw_payroll_dollarc(preview.fedTax),"var(--rd)"],["State Tax",gw_payroll_dollarc(preview.stateTax),"var(--rd)"],["FICA",gw_payroll_dollarc(preview.ss+preview.medicare),"var(--rd)"],["Total Ded.",gw_payroll_dollarc(preview.totalDed),"var(--rd)"],["Net Pay",gw_payroll_dollarc(preview.net),"var(--tl)"]].map(([l,v,c])=>(
                <div key={l} style={{textAlign:"center",padding:"8px 4px",background:"var(--card)",borderRadius:5}}>
                  <div style={{fontSize:9,color:"var(--mute)",marginBottom:3}}>{l}</div>
                  <div className="mono" style={{fontSize:12,fontWeight:700,color:c}}>{v}</div>
                </div>
              ))}
            </div>
