    const blob = new Blob([nacha.file], {type:"text/plain"});
    const url  = URL.createObjectURL(blob);
    const a    = document.createElement("a");
    a.href     = url;
    a.download = `APEX_ACH_PAYROLL_${effectiveDate.replace(/-/g,"")}.ach`;
    a.click();
