// Sign-off panel
function SignOffModal({ checklist, onClose }) {
  const allDone = checklist.every(i => i.status === "done");
  const openItems = checklist.filter(i => i.status !== "done");
  return (
    <div className="modal-bg" onClick={e => e.target === e.currentTarget && onClose()}>
      <div className="modal">
        <div className="mh">
          <div>
            <div className="mt">CFO PERIOD SIGN-OFF — JANUARY 2026</div>
            <div className="msub">Digital signature creates immutable audit timestamp</div>
          </div>
          <button className="btn btn-ghost btn-sm" onClick={onClose}>✕</button>
        </div>
        <div className="mbd">
          {!allDone && (
            <div className="alert-banner alert-danger">
              ✗ {openItems.length} checklist item{openItems.length > 1 ? "s" : ""} not complete. All items must be done before CFO sign-off.
              <ul style={{ marginTop: 6, paddingLeft: 16 }}>
                {openItems.slice(0,4).map(i => <li key={i.id} style={{ fontSize: 10, marginTop: 2 }}>{i.title}</li>)}
                {openItems.length > 4 && <li style={{ fontSize: 10, marginTop: 2 }}>+ {openItems.length - 4} more…</li>}
              </ul>
            </div>
          )}
          {allDone && (
            <div className="alert-banner alert-good">✓ All {checklist.length} checklist items complete. Period is ready for CFO sign-off.</div>
          )}
          <div className="sdiv">Period Lock Attestation</div>
          <div style={{ background: "var(--raise)", borderRadius: 8, padding: "16px", border: "1px solid var(--bord)", fontSize: 11, lineHeight: 1.8, color: "var(--brite)", marginBottom: 16 }}>
            By signing below, I, the Chief Financial Officer, certify that:<br/>
            <span style={{ color: "var(--mute)" }}>
              (1) All financial transactions for the period ending January 31, 2026 have been properly recorded;<br/>
              (2) The accounts receivable, accounts payable, job cost, and general ledger have been reconciled and agree;<br/>
              (3) Revenue has been recognized in accordance with ASC 606 based on updated project completion data;<br/>
              (4) All known accruals and adjustments have been posted;<br/>
              (5) The financial statements fairly present the financial position of the company for the period.
            </span>
          </div>
          <div className="g2" style={{ marginBottom: 16 }}>
            <div className="fg">
              <label className="fl">CFO Name</label>
              <input className="fi" defaultValue="Sarah Chen" />
            </div>
            <div className="fg">
              <label className="fl">Date</label>
              <input className="fi" defaultValue="2026-02-05" />
            </div>
            <div className="fg">
              <label className="fl">Period Being Closed</label>
              <input className="fi" defaultValue="January 2026 (2026-01-01 through 2026-01-31)" readOnly style={{ color: "var(--mute)" }} />
            </div>
            <div className="fg">
              <label className="fl">Audit Timestamp</label>
              <input className="fi" defaultValue="Auto-generated on submission" readOnly style={{ color: "var(--mute)" }} />
            </div>
          </div>
          <div className="fg">
            <label className="fl">CFO Notes / Exceptions</label>
            <textarea className="fi" rows={3} placeholder="Note any exceptions, unusual items, or items deferred to next period…" style={{ resize: "vertical" }} />
          </div>
        </div>
        <div className="mft">
          <button className="btn btn-ghost" onClick={onClose}>Cancel</button>
          <button className={"btn "+(allDone ? "btn-gn" : "btn-ghost")} disabled={!allDone}>
            {allDone ? "🔒 Sign & Lock Period" : "✗ Complete All Items First"}
          </button>
        </div>
      </div>
    </div>
  );
}

function GroundworkPeriodClose() {
  const [activeTab, setActiveTab] = useState("close");
  const [checklist, setChecklist] = useState(INIT_CHECKLIST);
  const [expandedPhases, setExpandedPhases] = useState({ 1: true, 2: true, 3: true, 4: true, 5: true });
  const [showSignOff, setShowSignOff] = useState(false);
  const [selectedAccrual, setSelectedAccrual] = useState(null);

  const phases = useMemo(() => {
    const map = {};
    checklist.forEach(item => {
      if (!map[item.phase]) map[item.phase] = { name: item.phaseName, items: [] };
      map[item.phase].items.push(item);
    });
    return map;
  }, [checklist]);

  const done = checklist.filter(i => i.status === "done").length;
  const inProgress = checklist.filter(i => i.status === "in-progress").length;
  const pending = checklist.filter(i => i.status === "pending").length;
  const total = checklist.length;
  const pct = Math.round((done / total) * 100);

  const toggleItem = (id) => {
    setChecklist(cl => cl.map(item => {
      if (item.id !== id) return item;
      if (item.status === "done") return { ...item, status: "pending" };
      // Check blockers
      const blockedBy = cl.filter(other => other.blocking?.includes(id) || false);
      if (item.status === "pending") return { ...item, status: "done" };
      return { ...item, status: "done" };
    }));
  };

  const reconIssues = RECONCILIATIONS.filter(r => Math.abs(r.gl - r.sub) > 100);
  const accrualsPending = ACCRUALS.filter(a => a.status === "pending").length;

  const tabs = [
    { id: "close", label: "Close Checklist" },
    { id: "wip", label: "WIP Cutoff" },
    { id: "recon", label: "Tie-Out Dashboard" },
    { id: "accruals", label: "Accruals & Reversals" },
    { id: "signoff", label: "Sign-Off & Lock" },
    { id: "history", label: "Period History" },
  ];

  return (
    <>
      <style>{css_gw_periodclose}</style>
      <div className="app">
        <div className="sb">
          <div className="sb-logo">
            <div style={{ display: "flex", alignItems: "center", gap: 8 }}>
              <div className="sb-gem">
                <svg width="14" height="14" viewBox="0 0 14 14" fill="none">
                  <path d="M7 1L13 5V9L7 13L1 9V5L7 1Z" fill="white" fillOpacity=".9" />
                </svg>
              </div>
              <div>
                <div className="sb-n">Groundwork</div>
                <div className="sb-m">ERP Platform</div>
              </div>
            </div>
          </div>
          <div className="sb-nav">
            <div className="sb-sec">Financial</div>
            {["AR Billing","AP & Matching","General Ledger","ASC 606","13-Week Cash Forecast","Period Close"].map(l => (
              <div key={l} className={"sb-item "+(l === "Period Close" ? "on" : "")}><span className="sb-dot" />{l}</div>
            ))}
            <div className="sb-sec">Project Controls</div>
            {["EAC / Earned Value","WIP Schedule","Lien Management","Bonding & Surety"].map(l => (
              <div key={l} className="sb-item"><span className="sb-dot" />{l}</div>
            ))}
            <div className="sb-sec">Operations</div>
            {["Dispatch","Job Costing","Change Orders","Subcontractor"].map(l => (
              <div key={l} className="sb-item"><span className="sb-dot" />{l}</div>
            ))}
          </div>
        </div>

        <div className="main">
          <div className="topbar">
            <div>
              <div className="tb-t">Period-End Close Workflow</div>
              <div className="tb-s">January 2026 · Close Target: February 5, 2026 · {done}/{total} Items Complete</div>
            </div>
            <div style={{ display: "flex", gap: 8, alignItems: "center" }}>
              {reconIssues.length > 0 && <span className="badge b-rd">⚠ {reconIssues.length} Recon Issue{reconIssues.length > 1 ? "s" : ""}</span>}
              {accrualsPending > 0 && <span className="badge b-gd">{accrualsPending} Accruals Pending</span>}
              <button className="btn btn-ghost btn-sm">📅 Prior Period</button>
              <button className="btn btn-sl btn-sm" onClick={() => setShowSignOff(true)}>🔒 CFO Sign-Off</button>
            </div>
          </div>

          <div className="tab-bar">
            {tabs.map(t => (
              <div key={t.id} className={"tab "+(activeTab === t.id ? "on" : "")} onClick={() => setActiveTab(t.id)}>{t.label}</div>
            ))}
          </div>

          <div className="content">

            {/* -- CLOSE CHECKLIST -- */}
            {activeTab === "close" && (
              <>
                <div className="krow">
                  {[
                    { l: "Complete", v: done, s: "Items checked off", c: "k-gn" },
                    { l: "In Progress", v: inProgress, s: "Currently being worked", c: "k-gd" },
                    { l: "Pending", v: pending, s: "Not yet started", c: "k-sl" },
                    { l: "Overall Progress", v: pct + "%", s: `${done} of ${total} items`, c: pct >= 80 ? "k-gn" : pct >= 50 ? "k-gd" : "k-sl" },
                    { l: "Close Target", v: "Feb 5", s: "3 business days remaining", c: "k-tl" },
                    { l: "Phase", v: `${Math.min(...checklist.filter(i=>i.status!=="done").map(i=>i.phase))} of 5`, s: "Current active phase", c: "k-pu" },
                  ].map(k => (
                    <div key={k.l} className={"kpi "+(k.c)}>
                      <div className="kl">{k.l}</div>
                      <div className="kv" style={{ fontSize: 18 }}>{k.v}</div>
                      <div className="ks">{k.s}</div>
                    </div>
                  ))}
                </div>

                {/* Overall progress bar */}
                <div style={{ background: "var(--surf)", border: "1px solid var(--bord)", borderRadius: 9, padding: "14px 16px", marginBottom: 14, display: "flex", gap: 16, alignItems: "center" }}>
                  <Ring pct={pct} size={60} stroke={5} color={pct >= 80 ? "var(--gn)" : pct >= 50 ? "var(--gd)" : "var(--sl)"} />
                  <div style={{ flex: 1 }}>
                    <div style={{ display: "flex", gap: 0, height: 10, borderRadius: 5, overflow: "hidden", marginBottom: 6 }}>
                      <div style={{ width: (done/total*100)+"%", background: "var(--gn)" }} />
                      <div style={{ width: (inProgress/total*100)+"%", background: "var(--gd)" }} />
                      <div style={{ width: (pending/total*100)+"%", background: "var(--raise)" }} />
                    </div>
                    <div style={{ display: "flex", gap: 20, fontSize: 10 }}>
                      <span style={{ color: "var(--gn)" }}>● {done} Done</span>
                      <span style={{ color: "var(--gd)" }}>● {inProgress} In Progress</span>
                      <span style={{ color: "var(--mute)" }}>● {pending} Pending</span>
                    </div>
                  </div>
                  <div style={{ textAlign: "right" }}>
                    <div style={{ fontSize: 10, color: "var(--mute)" }}>Estimated Close</div>
                    <div style={{ fontFamily: "IBM Plex Mono", fontSize: 13, color: "var(--brite)" }}>Feb 5, 2026</div>
                  </div>
                </div>

                {/* Phase groups */}
                {Object.entries(phases).map(([phaseNum, { name, items }]) => {
                  const phaseDone = items.filter(i => i.status === "done").length;
                  const phaseTotal = items.length;
                  const phaseComplete = phaseDone === phaseTotal;
                  const expanded = expandedPhases[phaseNum];
                  return (
                    <div key={phaseNum} className="panel">
                      <div className="phase-header" onClick={() => setExpandedPhases(p => ({ ...p, [phaseNum]: !p[phaseNum] }))}>
                        <div style={{ display: "flex", alignItems: "center", gap: 10 }}>
                          <div style={{ width: 24, height: 24, borderRadius: "50%", background: phaseComplete ? "var(--gn-d)" : "var(--raise)", border: `2px solid ${phaseComplete ? "var(--gn)" : "var(--bord2)"}`, display: "grid", placeItems: "center", fontSize: 10, fontWeight: 700, color: phaseComplete ? "var(--gn)" : "var(--mute)" }}>
                            {phaseComplete ? "✓" : phaseNum}
                          </div>
                          <div className="phase-title">Phase {phaseNum} — {name}</div>
                          {phaseComplete && <span className="badge b-gn" style={{ fontSize: 8 }}>Complete</span>}
                        </div>
                        <div style={{ display: "flex", gap: 10, alignItems: "center" }}>
                          <div style={{ display: "flex", gap: 0, width: 80, height: 6, borderRadius: 3, overflow: "hidden", background: "var(--card)" }}>
                            <div style={{ width: (phaseDone/phaseTotal*100)+"%", background: phaseComplete ? "var(--gn)" : "var(--gd)" }} />
                          </div>
                          <span className="phase-progress">{phaseDone}/{phaseTotal}</span>
                          <span style={{ color: "var(--mute)", fontSize: 10 }}>{expanded ? "▲" : "▼"}</span>
                        </div>
                      </div>
                      {expanded && items.map(item => (
 <div key={item.id} className={"checklist-item "+(item.status === "done" ? "done" : "")} onClick={() => toggleItem(item.id)}>
                          <div className={"check-box "+(item.status === "done" ? "checked" : "")}>
                            {item.status === "done" && <span style={{ color: "#fff", fontSize: 11, fontWeight: 700 }}>✓</span>}
                          </div>
                          <div style={{ flex: 1 }}>
                            <div className={"check-title "+(item.status === "done" ? "done" : "")}>{item.title}</div>
                            <div className="check-meta">{item.meta}</div>
                            {item.notes && <div style={{ fontSize: 10, color: "var(--gd)", marginTop: 3 }}>⚠ {item.notes}</div>}
                            <div style={{ marginTop: 4 }}>
                              <span className="check-owner">👤 {item.owner}</span>
                              {item.blocking?.length > 0 && (
                                <span style={{ fontSize: 9, color: "var(--mute)", marginLeft: 8 }}>
                                  blocks: {item.blocking.map(b => checklist.find(i => i.id === b)?.title?.slice(0, 30)).join(", ")}
                                </span>
                              )}
                            </div>
                          </div>
                          <div className="check-actions">
                            <span className={"badge "+(item.status === "done" ? "b-gn" : item.status === "in-progress" ? "b-gd" : "b-st")}>
                              {item.status === "done" ? "✓ Done" : item.status === "in-progress" ? "In Progress" : "Pending"}
                            </span>
                          </div>
                        </div>
                      ))}
                    </div>
                  );
                })}
              </>
            )}

            {/* -- WIP CUTOFF -- */}
            {activeTab === "wip" && (
              <>
                <div className="alert-banner alert-info" style={{ marginBottom: 14 }}>
                  ℹ WIP cutoff reconciliation ties the job cost ledger to billing and the WIP schedule. Overbillings become deferred revenue; underbillings become contract assets under ASC 606.
                </div>
                <div className="panel">
                  <div className="ph">
                    <div><div className="pt">WIP CUTOFF — JANUARY 31, 2026</div><div className="ps">From PM EAC inputs — pending finalization</div></div>
                    <span className="badge b-gd">Pending Finalization</span>
                  </div>
                  <div style={{ overflowX: "auto" }}>
                    <table className="tbl">
                      <thead>
                        <tr>
                          <th>Project</th>
                          <th style={{ textAlign: "right" }}>Contract Value</th>
                          <th style={{ textAlign: "right" }}>% Complete</th>
                          <th style={{ textAlign: "right" }}>Rev Earned</th>
                          <th style={{ textAlign: "right" }}>Billed to Date</th>
                          <th style={{ textAlign: "right" }}>Over / (Under) Billed</th>
                          <th style={{ textAlign: "right" }}>Cost to Date</th>
                          <th style={{ textAlign: "right" }}>Gross Profit</th>
                          <th>Status</th>
                        </tr>
                      </thead>
                      <tbody>
                        {[
                          { name: "Banner Health Scottsdale — HVAC/Plumbing", contract: 5_162_000, pct: 0.492, billed: 1_980_000, cost: 2_671_450 },
                          { name: "Desert Ridge Data Center — Electrical", contract: 9_565_000, pct: 0.607, billed: 5_809_440, cost: 5_432_100 },
                          { name: "Sky Harbor Terminal 4 — Plumbing", contract: 3_328_500, pct: 0.717, billed: 2_388_200, cost: 2_831_200 },
                          { name: "ASU Student Union — MEP", contract: 6_774_000, pct: 0.359, billed: 2_050_000, cost: 2_245_000 },
                          { name: "Gilbert Civic Center — HVAC", contract: 1_933_200, pct: 0.970, billed: 1_924_800, cost: 1_942_000 },
                        ].map(p => {
                          const revEarned = p.contract * p.pct;
                          const overUnder = p.billed - revEarned;
                          const gp = revEarned - p.cost;
                          const gpPct = gp / revEarned;
                          return (
                            <tr key={p.name}>
                              <td>
                                <div style={{ fontSize: 11, color: "var(--white)", fontWeight: 500 }}>{p.name.length > 40 ? p.name.slice(0,40)+"…" : p.name}</div>
                              </td>
                              <td style={{ textAlign: "right" }} className="mono">{gw_periodclose_fmt$(p.contract)}</td>
                              <td style={{ textAlign: "right" }}>
                                <div style={{ display: "flex", alignItems: "center", gap: 5, justifyContent: "flex-end" }}>
                                  <div style={{ width: 32, height: 4, background: "var(--raise)", borderRadius: 2, overflow: "hidden" }}>
                                    <div style={{ width: (p.pct*100)+"%", height: "100%", background: "var(--sl)", borderRadius: 2 }} />
                                  </div>
                                  <span className="mono">{(p.pct*100).toFixed(1)}%</span>
                                </div>
                              </td>
                              <td style={{ textAlign: "right" }} className="mono">{gw_periodclose_fmt$(revEarned)}</td>
                              <td style={{ textAlign: "right" }} className="mono">{gw_periodclose_fmt$(p.billed)}</td>
                              <td style={{ textAlign: "right" }}>
                                <span className={"mono "+(overUnder > 0 ? "recon-warn" : "recon-bad")}>
                                  {overUnder > 0 ? "+" : ""}{gw_periodclose_fmt$(overUnder)}
                                </span>
                              </td>
                              <td style={{ textAlign: "right" }} className="mono">{gw_periodclose_fmt$(p.cost)}</td>
                              <td style={{ textAlign: "right" }}>
                                <span className={"mono "+(gp >= 0 ? "recon-ok" : "recon-bad")}>{gw_periodclose_fmt$(gp)}</span>
                                <span style={{ fontSize: 9, color: "var(--mute)", marginLeft: 4 }}>({(gpPct*100).toFixed(1)}%)</span>
                              </td>
                              <td><span className="badge b-gd">Draft</span></td>
                            </tr>
                          );
                        })}
                      </tbody>
                      <tfoot>
                        <tr style={{ borderTop: "2px solid var(--bord2)" }}>
                          <td style={{ fontFamily: "Bebas Neue", fontSize: 11, letterSpacing: 2, color: "var(--lite)" }}>TOTALS</td>
                          <td style={{ textAlign: "right" }} className="mono" style={{ color: "var(--white)" }}>{gw_periodclose_fmt$(26_762_700)}</td>
                          <td />
                          <td style={{ textAlign: "right" }} className="mono" style={{ color: "var(--white)" }}>{gw_periodclose_fmt$(16_188_510)}</td>
                          <td style={{ textAlign: "right" }} className="mono" style={{ color: "var(--white)" }}>{gw_periodclose_fmt$(14_152_440)}</td>
                          <td style={{ textAlign: "right" }}>
                            <span className="mono recon-bad">{gw_periodclose_fmt$(14_152_440 - 16_188_510)}</span>
                          </td>
                          <td style={{ textAlign: "right" }} className="mono" style={{ color: "var(--white)" }}>{gw_periodclose_fmt$(15_121_750)}</td>
                          <td style={{ textAlign: "right" }}><span className="mono recon-ok">{gw_periodclose_fmt$(16_188_510 - 15_121_750)}</span></td>
                          <td />
                        </tr>
                      </tfoot>
                    </table>
                  </div>
                </div>
              </>
            )}

            {/* -- TIE-OUT DASHBOARD -- */}
            {activeTab === "recon" && (
              <>
                <div className="krow">
                  {[
                    { l: "Reconciled", v: RECONCILIATIONS.filter(r=>Math.abs(r.gl-r.sub)===0).length, s: "Perfect tie-out", c: "k-gn" },
                    { l: "Differences", v: reconIssues.length, s: "Require resolution", c: reconIssues.length > 0 ? "k-rd" : "k-gn" },
                    { l: "Largest Diff", v: reconIssues.length > 0 ? gw_periodclose_fmt$(Math.max(...reconIssues.map(r=>Math.abs(r.gl-r.sub)))) : "$0", s: "Needs investigation", c: reconIssues.length > 0 ? "k-gd" : "k-gn" },
                    { l: "Close Status", v: reconIssues.length > 0 ? "Blocked" : "Ready", s: "For CFO sign-off", c: reconIssues.length > 0 ? "k-rd" : "k-gn" },
                  ].map(k => (
                    <div key={k.l} className={"kpi "+(k.c)}>
                      <div className="kl">{k.l}</div>
                      <div className="kv" style={{ fontSize: 18 }}>{k.v}</div>
                      <div className="ks">{k.s}</div>
                    </div>
                  ))}
                </div>

                <div className="panel">
                  <div className="ph">
                    <div><div className="pt">RECONCILIATION TIE-OUT — AR · AP · JOB COST · GL</div><div className="ps">All schedules must agree before period lock</div></div>
                  </div>
                  <div style={{ padding: "0 16px" }}>
                    {/* Column headers */}
                    <div style={{ display: "flex", gap: 0, padding: "8px 0", borderBottom: "1px solid var(--bord)", marginBottom: 4 }}>
                      <div style={{ flex: 1, fontSize: 9, fontWeight: 700, letterSpacing: "2px", textTransform: "uppercase", color: "var(--mute)" }}>Account / Schedule</div>
                      <div style={{ width: 110, textAlign: "right", fontSize: 9, fontWeight: 700, letterSpacing: "2px", textTransform: "uppercase", color: "var(--mute)" }}>GL Balance</div>
                      <div style={{ width: 110, textAlign: "right", fontSize: 9, fontWeight: 700, letterSpacing: "2px", textTransform: "uppercase", color: "var(--mute)" }}>Sub-Ledger</div>
                      <div style={{ width: 90, textAlign: "right", fontSize: 9, fontWeight: 700, letterSpacing: "2px", textTransform: "uppercase", color: "var(--mute)" }}>Difference</div>
                      <div style={{ width: 70, textAlign: "center", fontSize: 9, fontWeight: 700, letterSpacing: "2px", textTransform: "uppercase", color: "var(--mute)" }}>Status</div>
                    </div>
                    {RECONCILIATIONS.map((r, i) => {
                      const diff = r.gl - r.sub;
                      const ok = Math.abs(diff) < 1;
                      const cls = ok ? "recon-ok" : Math.abs(diff) < 5000 ? "recon-warn" : "recon-bad";
                      return (
                        <div key={i} className="recon-row">
                          <div className="recon-label">
                            <div style={{ fontWeight: 500, color: "var(--white)" }}>{r.label}</div>
                            <div style={{ fontSize: 10, color: "var(--mute)", marginTop: 1 }}>{r.note}</div>
                          </div>
                          <div className="recon-gl">{gw_periodclose_fmt$(r.gl)}</div>
                          <div className="recon-sub">{gw_periodclose_fmt$(r.sub)}</div>
                          <div className={"recon-diff "+(cls)}>{ok ? "—" : (diff > 0 ? "+" : "") + gw_periodclose_fmt$(diff)}</div>
                          <div className="recon-status">
                            <span className={"badge "+(ok ? "b-gn" : "b-rd")} style={{ fontSize: 8 }}>{ok ? "✓ Tie" : "✗ Diff"}</span>
                          </div>
                        </div>
                      );
                    })}
                  </div>
                </div>

                {reconIssues.length > 0 && (
                  <div className="alert-banner alert-warn">
                    ⚠ {reconIssues.length} reconciliation difference{reconIssues.length > 1 ? "s" : ""} detected. These must be resolved before the period can be locked. WIP schedule finalization will resolve the overbilling/underbilling differences.
                  </div>
                )}
              </>
            )}

            {/* -- ACCRUALS -- */}
            {activeTab === "accruals" && (
              <>
                <div className="krow">
                  {[
                    { l: "Accruals Posted", v: ACCRUALS.filter(a=>a.status==="posted").length, s: "This period", c: "k-gn" },
                    { l: "Accruals Pending", v: ACCRUALS.filter(a=>a.status==="pending").length, s: "Need posting", c: accrualsPending > 0 ? "k-gd" : "k-gn" },
                    { l: "Total Accrued", v: gw_periodclose_fmt$(ACCRUALS.filter(a=>a.status==="posted").reduce((s,a)=>s+Math.abs(a.amount),0)), s: "Gross accrual balance", c: "k-sl" },
                    { l: "Auto-Reversals Set", v: ACCRUALS.filter(a=>a.reverses!=="N/A" && !a.reverses.startsWith("N/A")).length, s: "Will reverse Feb 1", c: "k-tl" },
                  ].map(k => (
                    <div key={k.l} className={"kpi "+(k.c)}>
                      <div className="kl">{k.l}</div>
                      <div className="kv" style={{ fontSize: 18 }}>{k.v}</div>
                      <div className="ks">{k.s}</div>
                    </div>
                  ))}
                </div>

                <div className="panel">
                  <div className="ph">
                    <div><div className="pt">ACCRUAL SCHEDULE — JANUARY 2026</div></div>
                    <button className="btn btn-tl btn-sm">+ New Accrual</button>
                  </div>
                  <div style={{ overflowX: "auto" }}>
                    <table className="tbl">
                      <thead>
                        <tr>
                          <th>ID</th>
                          <th>Description</th>
                          <th>GL Account</th>
                          <th style={{ textAlign: "right" }}>Amount</th>
                          <th>Type</th>
                          <th>Auto-Reversal</th>
                          <th>Status</th>
                          <th></th>
                        </tr>
                      </thead>
                      <tbody>
                        {ACCRUALS.map(a => (
                          <tr key={a.id}>
                            <td className="mono" style={{ fontSize: 10, color: "var(--mute)" }}>{a.id}</td>
                            <td style={{ fontSize: 11, color: "var(--white)", fontWeight: 500 }}>{a.desc}</td>
                            <td style={{ fontSize: 10, color: "var(--mute)" }}>{a.account}</td>
                            <td style={{ textAlign: "right" }}>
                              <span className={"mono "+(a.amount >= 0 ? "" : "recon-bad")}>{gw_periodclose_fmt$(Math.abs(a.amount))}</span>
                            </td>
                            <td><span className={"badge "+(a.type === "Recurring" ? "b-tl" : "b-pu")}>{a.type}</span></td>
                            <td style={{ fontSize: 10, color: a.reverses.startsWith("N/A") ? "var(--mute)" : "var(--gd)" }}>{a.reverses}</td>
                            <td>
                              <span className={"badge "+(a.status === "posted" ? "b-gn" : "b-gd")}>
                                {a.status === "posted" ? "✓ Posted" : "Pending"}
                              </span>
                            </td>
                            <td>
                              {a.status === "pending" && (
                                <button className="btn btn-gn btn-xs">Post</button>
                              )}
                            </td>
                          </tr>
                        ))}
                      </tbody>
                    </table>
                  </div>
                </div>
              </>
            )}

            {/* -- SIGN-OFF -- */}
            {activeTab === "signoff" && (
              <>
                {/* Period lock status */}
                <div className="period-lock">
                  <div className={"lock-icon lock-open"}>🔓</div>
                  <div style={{ flex: 1 }}>
                    <div style={{ fontSize: 13, color: "var(--white)", fontWeight: 500 }}>January 2026 — Open</div>
                    <div style={{ fontSize: 10, color: "var(--mute)", marginTop: 2 }}>Transactions may still be posted. Lock requires all checklist items complete and CFO digital signature.</div>
                  </div>
                  <button className="btn btn-gn btn-sm" onClick={() => setShowSignOff(true)}>🔒 Lock Period</button>
                </div>

                {/* Sign-off cards */}
                <div className="sdiv">Required Approvals</div>
                <div style={{ display: "flex", flexDirection: "column", gap: 10 }}>
                  {[
                    { name: "Marcus Torres", title: "Controller", initials: "MT", color: "#3B7DD8", task: "Complete tie-out dashboard and close memo", status: inProgress > 0 || pending > 2 ? "pending" : "done", completedAt: null },
                    { name: "Sarah Chen", title: "Chief Financial Officer", initials: "SC", color: "#1FA99A", task: "Review financials and issue digital sign-off to lock period", status: "pending", completedAt: null },
                  ].map((s, i) => (
                    <div key={i} className="signoff-card">
 <div className={"signoff-avatar "+(s.status === "done" ? "signoff-done" : "signoff-pending")} style={{ background: s.color }}>{s.initials}</div>
                      <div style={{ flex: 1 }}>
                        <div style={{ fontSize: 12, color: "var(--white)", fontWeight: 500 }}>{s.name} — {s.title}</div>
                        <div style={{ fontSize: 10, color: "var(--mute)", marginTop: 2 }}>{s.task}</div>
                        {s.completedAt && <div style={{ fontSize: 10, color: "var(--gn)", marginTop: 4 }}>✓ Signed {s.completedAt}</div>}
                      </div>
                      <div style={{ display: "flex", gap: 8, alignItems: "center" }}>
                        <span className={"badge "+(s.status === "done" ? "b-gn" : "b-gd")}>{s.status === "done" ? "✓ Complete" : "Awaiting"}</span>
                        {s.title === "Chief Financial Officer" && s.status !== "done" && (
                          <button className="btn btn-sl btn-sm" onClick={() => setShowSignOff(true)}>Sign Now →</button>
                        )}
                      </div>
                    </div>
                  ))}
                </div>

                <div className="sdiv">Checklist Summary for Sign-Off</div>
                <div style={{ display: "grid", gridTemplateColumns: "repeat(5,1fr)", gap: 10 }}>
                  {Object.entries(phases).map(([num, { name, items }]) => {
                    const pd = items.filter(i => i.status === "done").length;
                    const pt = items.length;
                    const complete = pd === pt;
                    return (
                      <div key={num} style={{ background: "var(--raise)", borderRadius: 8, padding: "12px 14px", border: `1px solid ${complete ? "var(--gn-b)" : "var(--bord)"}`, textAlign: "center" }}>
                        <Ring pct={Math.round(pd/pt*100)} size={44} stroke={4} color={complete ? "var(--gn)" : "var(--gd)"} />
                        <div style={{ fontSize: 9, fontWeight: 700, letterSpacing: "1px", textTransform: "uppercase", color: "var(--mute)", marginTop: 6 }}>Phase {num}</div>
                        <div style={{ fontSize: 10, color: complete ? "var(--gn)" : "var(--brite)", marginTop: 2 }}>{pd}/{pt}</div>
                      </div>
                    );
                  })}
                </div>
              </>
            )}

            {/* -- PERIOD HISTORY -- */}
            {activeTab === "history" && (
              <>
                <div className="panel">
                  <div className="ph"><div className="pt">PERIOD CLOSE HISTORY</div></div>
                  <div style={{ overflowX: "auto" }}>
                    <table className="tbl">
                      <thead>
                        <tr>
                          <th>Period</th>
                          <th>Closed Date</th>
                          <th>Signed By</th>
                          <th style={{ textAlign: "right" }}>Checklist Items</th>
                          <th style={{ textAlign: "right" }}>Issues at Close</th>
                          <th>Status</th>
                          <th></th>
                        </tr>
                      </thead>
                      <tbody>
                        {/* Current open period */}
                        <tr>
                          <td>
                            <div style={{ fontSize: 11, color: "var(--sl)", fontWeight: 600 }}>February 2026</div>
                            <div style={{ fontSize: 9, color: "var(--mute)" }}>Current period</div>
                          </td>
                          <td style={{ fontSize: 10, color: "var(--mute)" }}>—</td>
                          <td style={{ fontSize: 10, color: "var(--mute)" }}>—</td>
                          <td style={{ textAlign: "right" }} className="mono">{total}</td>
                          <td style={{ textAlign: "right" }} className="mono">{reconIssues.length}</td>
                          <td><span className="badge b-sl">Open</span></td>
                          <td><button className="btn btn-ghost btn-xs" onClick={() => setActiveTab("close")}>View →</button></td>
                        </tr>
                        {PERIOD_HISTORY.map((p, i) => (
                          <tr key={i}>
                            <td style={{ fontSize: 11, color: "var(--white)", fontWeight: 500 }}>{p.period}</td>
                            <td style={{ fontSize: 10 }}>{p.closedDate}</td>
                            <td style={{ fontSize: 10 }}>{p.closedBy}</td>
                            <td style={{ textAlign: "right" }} className="mono">{p.items}</td>
                            <td style={{ textAlign: "right" }}>
                              <span className={"mono "+(p.issues > 0 ? "recon-warn" : "recon-ok")}>{p.issues}</span>
                            </td>
                            <td><span className="badge b-st">🔒 {p.status}</span></td>
                            <td>
                              <div style={{ display: "flex", gap: 4 }}>
                                <button className="btn btn-ghost btn-xs">View</button>
                                <button className="btn btn-rd btn-xs">Unlock</button>
                              </div>
                            </td>
                          </tr>
                        ))}
                      </tbody>
                    </table>
                  </div>
                </div>
                <div className="alert-banner alert-info">
                  ℹ Unlocking a closed period requires CFO authorization and creates an audit log entry. All adjustments made to a locked period are separately tracked for auditor review.
                </div>
              </>
            )}

          </div>
        </div>
      </div>

      {showSignOff && (
        <SignOffModal checklist={checklist} onClose={() => setShowSignOff(false)} />
      )}
    </>
  );
}


// -- GROUNDWORK-PO --------------------------------------
// ============================================================
// GROUNDWORK — Purchase Order Module
// Draft → Submit → Receive → Close · GL auto-post · 3-way match foundation
// ============================================================

const css_gw_po = `
  @import url('https://fonts.googleapis.com/css2?family=Bebas+Neue&family=Outfit:wght@300;400;500;600;700&family=JetBrains+Mono:wght@400;500&display=swap');

  *, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }

  :root {
    --bg:        #0F1014;
    --surface:   #171A1F;
    --raised:    #1E2128;
    --border:    #272B34;
    --border2:   #333840;
    --muted:     #505A6A;
    --dim:       #788090;
    --light:     #B0BCC8;
    --bright:    #D8E2EC;
    --white:     #EEF4F8;
    --indigo:    #2040A0;
    --indigo-l:  #4070D8;
    --indigo-dim:rgba(64,112,216,0.13);
    --amber:     #B87820;
    --amber-l:   #D89A2C;
    --amber-dim: rgba(184,120,32,0.13);
    --green:     #1A5A38;
    --green-l:   #34A868;
    --green-dim: rgba(52,168,104,0.13);
    --red:       #601828;
    --red-l:     #B04050;
    --red-dim:   rgba(176,64,80,0.13);
    --teal:      #105858;
    --teal-l:    #24A0A0;
    --teal-dim:  rgba(36,160,160,0.13);
    --orange-l:  #D06820;
    --orange-dim:rgba(208,104,32,0.13);
    --purple-l:  #8050C0;
    --purple-dim:rgba(128,80,192,0.13);
  }

  body { font-family: 'Outfit', sans-serif; background: var(--bg); color: var(--bright); min-height: 100vh; }
  ::-webkit-scrollbar { width: 3px; height: 3px; }
  ::-webkit-scrollbar-track { background: var(--surface); }
  ::-webkit-scrollbar-thumb { background: var(--muted); border-radius: 2px; }

  .app { display: flex; height: 100vh; overflow: hidden; }

  /* SIDEBAR */
  .sb { width: 230px; min-width: 230px; background: var(--surface); border-right: 1px solid var(--border); display: flex; flex-direction: column; position: relative; flex-shrink: 0; }
  .sb::before { content:''; position:absolute; top:0; left:0; right:0; height:2px; background:linear-gradient(90deg,var(--indigo),var(--indigo-l),var(--amber-l)); }
  .sb-logo { padding: 15px 14px 12px; border-bottom: 1px solid var(--border); }
  .sb-lr { display: flex; align-items: center; gap: 9px; }
  .sb-gem { width: 30px; height: 30px; background: var(--indigo-l); border-radius: 5px; display: flex; align-items: center; justify-content: center; flex-shrink: 0; }
  .sb-name { font-family: 'Bebas Neue', sans-serif; font-size: 17px; letter-spacing: 2px; color: var(--bright); }
  .sb-mod { font-size: 8px; letter-spacing: 3px; color: var(--muted); text-transform: uppercase; margin-top: 2px; }
  .sb-nav { flex: 1; overflow-y: auto; padding: 6px 0; }
  .sb-grp-label { font-size: 8px; font-weight: 700; letter-spacing: 3px; text-transform: uppercase; color: var(--muted); padding: 10px 14px 3px; }
  .sb-item { display: flex; align-items: center; gap: 8px; padding: 8px 14px; cursor: pointer; font-size: 12px; color: var(--dim); border-left: 2px solid transparent; transition: all 0.12s; }
  .sb-item:hover { background: var(--raised); color: var(--light); }
  .sb-item.on { background: var(--indigo-dim); color: var(--indigo-l); border-left-color: var(--indigo-l); font-weight: 600; }
  .sb-dot { width: 5px; height: 5px; border-radius: 50%; background: currentColor; opacity: 0.5; flex-shrink: 0; }
  .sb-pill { margin-left: auto; background: var(--amber-l); color: var(--bg); font-size: 9px; font-weight: 700; padding: 1px 6px; border-radius: 10px; }
  .sb-soon { margin-left: auto; font-size: 8px; color: var(--muted); letter-spacing: 1px; }

  /* MAIN */
  .main { flex: 1; display: flex; flex-direction: column; overflow: hidden; min-width: 0; }
  .topbar { background: var(--surface); border-bottom: 1px solid var(--border); height: 52px; padding: 0 22px; display: flex; align-items: center; justify-content: space-between; flex-shrink: 0; }
  .tb-title { font-family: 'Bebas Neue', sans-serif; font-size: 17px; letter-spacing: 2px; color: var(--bright); }
  .tb-crumb { font-size: 9px; color: var(--muted); letter-spacing: 1.5px; text-transform: uppercase; margin-top: 1px; }

  /* gw_po_TABS */
  .tab-bar { display: flex; background: var(--surface); border-bottom: 1px solid var(--border); padding: 0 22px; flex-shrink: 0; }
  .tab { padding: 10px 14px; font-size: 11px; font-weight: 600; color: var(--muted); cursor: pointer; border-bottom: 2px solid transparent; margin-bottom: -1px; transition: all 0.12s; white-space: nowrap; letter-spacing: 0.3px; }
  .tab:hover { color: var(--bright); }
  .tab.on { color: var(--indigo-l); border-bottom-color: var(--indigo-l); }

  /* CONTENT */
  .content { flex: 1; overflow-y: auto; padding: 18px 22px; }

  /* BUTTONS */
  .btn { display: inline-flex; align-items: center; gap: 6px; padding: 7px 14px; border-radius: 7px; border: none; font-family: 'Outfit', sans-serif; font-size: 12px; font-weight: 600; cursor: pointer; transition: all 0.12s; white-space: nowrap; }
  .btn-ghost  { background: var(--raised); color: var(--dim); border: 1px solid var(--border); }
  .btn-ghost:hover { background: var(--border); color: var(--light); }
  .btn-indigo { background: var(--indigo-l); color: #fff; }
  .btn-indigo:hover { background: #5080E0; }
  .btn-green  { background: var(--green-dim); color: var(--green-l); border: 1px solid rgba(52,168,104,0.2); }
  .btn-green:hover { background: rgba(52,168,104,0.22); }
  .btn-amber  { background: var(--amber-dim); color: var(--amber-l); border: 1px solid rgba(184,120,32,0.2); }
  .btn-amber:hover { background: rgba(184,120,32,0.22); }
  .btn-red    { background: var(--red-dim);   color: var(--red-l);   border: 1px solid rgba(176,64,80,0.2); }
  .btn-red:hover { background: rgba(176,64,80,0.22); }
  .btn-teal   { background: var(--teal-dim);  color: var(--teal-l);  border: 1px solid rgba(36,160,160,0.2); }
  .btn-teal:hover { background: rgba(36,160,160,0.22); }
  .btn-sm  { padding: 4px 10px; font-size: 11px; border-radius: 5px; }
  .btn-xs  { padding: 3px 8px;  font-size: 10px; border-radius: 4px; }
  .btn-icon{ padding: 5px; border-radius: 6px; }
  .btn:disabled { opacity: 0.35; cursor: not-allowed; }

  /* PANELS */
  .panel { background: var(--surface); border: 1px solid var(--border); border-radius: 10px; overflow: hidden; margin-bottom: 14px; }
  .ph { padding: 12px 16px; border-bottom: 1px solid var(--border); display: flex; align-items: center; justify-content: space-between; flex-wrap: wrap; gap: 8px; }
  .pt { font-family: 'Bebas Neue', sans-serif; font-size: 13px; letter-spacing: 2px; color: var(--light); }
  .ps { font-size: 10px; color: var(--muted); margin-top: 1px; }

  /* KPI ROW */
  .krow { display: flex; gap: 0; margin-bottom: 14px; }
  .kpi { flex: 1; background: var(--surface); border: 1px solid var(--border); padding: 13px 15px; position: relative; overflow: hidden; }
  .kpi:first-child { border-radius: 9px 0 0 9px; }
  .kpi:last-child  { border-radius: 0 9px 9px 0; }
  .kpi + .kpi { border-left: none; }
  .kpi::after { content:''; position:absolute; bottom:0; left:0; right:0; height:2px; }
  .k-indigo::after { background: var(--indigo-l); }
  .k-amber::after  { background: var(--amber-l); }
  .k-green::after  { background: var(--green-l); }
  .k-red::after    { background: var(--red-l); }
  .k-teal::after   { background: var(--teal-l); }
  .k-orange::after { background: var(--orange-l); }
  .kl { font-size: 9px; font-weight: 700; letter-spacing: 2px; text-transform: uppercase; color: var(--muted); margin-bottom: 5px; }
  .kv { font-family: 'JetBrains Mono', monospace; font-size: 19px; font-weight: 500; color: var(--bright); line-height: 1; }
  .ks { font-size: 10px; color: var(--muted); margin-top: 4px; }

  /* TABLE */
  .tbl { width: 100%; border-collapse: collapse; }
  .tbl th { font-size: 9px; font-weight: 700; letter-spacing: 2px; text-transform: uppercase; color: var(--muted); padding: 9px 13px; text-align: left; border-bottom: 1px solid var(--border); background: rgba(0,0,0,0.2); white-space: nowrap; }
  .tbl td { padding: 10px 13px; font-size: 12px; color: var(--light); border-bottom: 1px solid rgba(255,255,255,0.03); vertical-align: middle; }
  .tbl tr:last-child td { border-bottom: none; }
  .tbl tr:hover td { background: rgba(255,255,255,0.02); cursor: pointer; }
  .tbl tr.sel td { background: var(--indigo-dim); }
  .mono { font-family: 'JetBrains Mono', monospace; font-size: 11px; }

  /* BADGE */
  .badge { display: inline-flex; align-items: center; gap: 4px; padding: 2px 7px; border-radius: 3px; font-size: 9px; font-weight: 700; letter-spacing: 1px; text-transform: uppercase; }
  .b-indigo { background: var(--indigo-dim);  color: var(--indigo-l); }
  .b-amber  { background: var(--amber-dim);   color: var(--amber-l); }
  .b-green  { background: var(--green-dim);   color: var(--green-l); }
  .b-red    { background: var(--red-dim);     color: var(--red-l); }
  .b-teal   { background: var(--teal-dim);    color: var(--teal-l); }
  .b-orange { background: var(--orange-dim);  color: var(--orange-l); }
  .b-purple { background: var(--purple-dim);  color: var(--purple-l); }
  .b-stone  { background: rgba(80,90,106,0.2); color: var(--muted); }

  /* STATUS STEPPER */
  .stepper { display: flex; align-items: center; gap: 0; margin-bottom: 20px; }
  .step { display: flex; flex-direction: column; align-items: center; flex: 1; position: relative; }
  .step-dot { width: 28px; height: 28px; border-radius: 50%; display: flex; align-items: center; justify-content: center; font-size: 11px; font-weight: 700; z-index: 1; transition: all 0.2s; }
  .step-dot.done   { background: var(--green-l); color: #fff; }
  .step-dot.active { background: var(--indigo-l); color: #fff; box-shadow: 0 0 0 4px var(--indigo-dim); }
  .step-dot.future { background: var(--raised); color: var(--muted); border: 2px solid var(--border); }
  .step-label { font-size: 9px; font-weight: 700; letter-spacing: 1.5px; text-transform: uppercase; color: var(--muted); margin-top: 5px; text-align: center; }
  .step-label.active { color: var(--indigo-l); }
  .step-label.done   { color: var(--green-l); }
  .step-connector { flex: 1; height: 2px; background: var(--border); margin-top: -14px; }
  .step-connector.done { background: var(--green-l); }

  /* FORMS */
  .fg   { display: flex; flex-direction: column; gap: 4px; }
  .fl   { font-size: 9px; font-weight: 700; letter-spacing: 2px; text-transform: uppercase; color: var(--muted); }
  .fi, .fsel { background: var(--raised); border: 1px solid var(--border); border-radius: 6px; color: var(--bright); font-family: 'Outfit', sans-serif; font-size: 12px; padding: 7px 10px; outline: none; transition: border-color 0.12s; width: 100%; }
  .fi:focus, .fsel:focus { border-color: var(--indigo-l); box-shadow: 0 0 0 2px var(--indigo-dim); }
  .fsel option { background: var(--surface); }
  .fh { font-size: 10px; color: var(--muted); margin-top: 2px; }
  .fi.mono-in { font-family: 'JetBrains Mono', monospace; }

  /* MODAL */
  .modal-bg { position: fixed; inset: 0; background: rgba(0,0,0,0.82); display: flex; align-items: center; justify-content: center; z-index: 200; backdrop-filter: blur(4px); animation: fi 0.15s; }
  .modal { background: var(--surface); border: 1px solid var(--border2); border-radius: 12px; width: 860px; max-width: 96vw; max-height: 94vh; overflow-y: auto; box-shadow: 0 32px 80px rgba(0,0,0,0.7); animation: su 0.2s cubic-bezier(0.34,1.56,0.64,1); }
  .modal.sm  { width: 480px; }
  .modal.md  { width: 620px; }
  .modal.xl  { width: 1000px; }
  .mh { padding: 16px 20px; border-bottom: 1px solid var(--border); display: flex; align-items: flex-start; justify-content: space-between; position: sticky; top: 0; background: var(--surface); z-index: 10; }
  .mt { font-family: 'Bebas Neue', sans-serif; font-size: 15px; letter-spacing: 2px; color: var(--bright); }
  .msub { font-size: 11px; color: var(--muted); margin-top: 2px; }
  .mb { padding: 20px; }
  .mf { padding: 13px 20px; border-top: 1px solid var(--border); display: flex; align-items: center; justify-content: flex-end; gap: 9px; position: sticky; bottom: 0; background: var(--surface); }
  .mx { background: var(--raised); border: none; color: var(--muted); width: 26px; height: 26px; border-radius: 5px; cursor: pointer; display: flex; align-items: center; justify-content: center; transition: all 0.12s; }
  .mx:hover { background: var(--red-dim); color: var(--red-l); }

  /* PO LINE TABLE */
  .po-lines { width: 100%; border-collapse: collapse; }
  .po-lines th { font-size: 9px; font-weight: 700; letter-spacing: 2px; text-transform: uppercase; color: var(--muted); padding: 8px 10px; text-align: left; border-bottom: 1px solid var(--border); background: rgba(0,0,0,0.2); white-space: nowrap; }
  .po-lines td { padding: 6px 4px; border-bottom: 1px solid rgba(255,255,255,0.03); vertical-align: middle; }
  .po-lines tr:last-child td { border-bottom: none; }

  /* PO STATUS PILL COLORS */
  .status-draft    { background: rgba(80,90,106,0.2);   color: var(--muted); }
  .status-sent     { background: var(--indigo-dim);     color: var(--indigo-l); }
  .status-partial  { background: var(--amber-dim);      color: var(--amber-l); }
  .status-received { background: var(--green-dim);      color: var(--green-l); }
  .status-closed   { background: rgba(52,168,104,0.08); color: var(--muted); }
  .status-cancelled{ background: var(--red-dim);        color: var(--red-l); }

  /* RECEIVE PANEL */
  .recv-line { display: flex; align-items: center; gap: 12px; padding: 11px 16px; border-bottom: 1px solid rgba(255,255,255,0.03); }
  .recv-line:last-child { border-bottom: none; }
  .recv-progress { height: 4px; background: var(--raised); border-radius: 2px; overflow: hidden; margin-top: 5px; width: 100%; }
  .recv-progress-fill { height: 100%; border-radius: 2px; transition: width 0.4s; }

  /* ALERTS */
  .alert { border-radius: 8px; padding: 10px 14px; display: flex; gap: 10px; margin-bottom: 13px; font-size: 11px; line-height: 1.6; align-items: flex-start; }
  .a-indigo { background: var(--indigo-dim); border: 1px solid rgba(64,112,216,0.2);  color: var(--light); }
  .a-amber  { background: var(--amber-dim);  border: 1px solid rgba(184,120,32,0.25); color: var(--light); }
  .a-green  { background: var(--green-dim);  border: 1px solid rgba(52,168,104,0.25); color: var(--light); }
  .a-red    { background: var(--red-dim);    border: 1px solid rgba(176,64,80,0.25);  color: var(--light); }

  /* SEARCH */
  .srow { display: flex; gap: 8px; margin-bottom: 12px; }
  .sw   { display: flex; align-items: center; gap: 8px; background: var(--raised); border: 1px solid var(--border); border-radius: 7px; padding: 6px 11px; flex: 1; }
  .si   { background: none; border: none; outline: none; color: var(--bright); font-family: 'Outfit', sans-serif; font-size: 12px; flex: 1; }
  .si::placeholder { color: var(--muted); }

  /* FILTER CHIPS */
  .frow { display: flex; gap: 6px; margin-bottom: 12px; flex-wrap: wrap; }
  .fc   { display: inline-flex; align-items: center; gap: 5px; padding: 4px 10px; border-radius: 5px; font-size: 11px; font-weight: 600; cursor: pointer; border: 1px solid var(--border); background: var(--raised); color: var(--dim); transition: all 0.12s; }
  .fc:hover { color: var(--light); border-color: var(--muted); }
  .fc.on { background: var(--indigo-dim); border-color: var(--indigo-l); color: var(--indigo-l); }

  /* GRID */
  .grid-2 { display: grid; grid-template-columns: 1fr 1fr; gap: 14px; }
  .grid-3 { display: grid; grid-template-columns: 1fr 1fr 1fr; gap: 12px; }
  .grid-4 { display: grid; grid-template-columns: 1fr 1fr 1fr 1fr; gap: 12px; }

  /* SECTION DIVIDER */
  .sdiv { font-family: 'Bebas Neue', sans-serif; font-size: 11px; letter-spacing: 2px; color: var(--indigo-l); margin: 18px 0 10px; display: flex; align-items: center; gap: 10px; }
  .sdiv::after { content:''; flex:1; height:1px; background: var(--border); }

  /* PO DETAIL SPLIT VIEW */
  .po-detail-wrap { display: grid; grid-template-columns: 340px 1fr; gap: 14px; height: calc(100vh - 160px); overflow: hidden; }
  .po-list-col { overflow-y: auto; display: flex; flex-direction: column; gap: 8px; padding-right: 4px; }
  .po-detail-col { overflow-y: auto; }

  /* PO LIST CARD */
  .po-card { background: var(--surface); border: 1px solid var(--border); border-radius: 9px; padding: 13px 14px; cursor: pointer; transition: all 0.13s; }
  .po-card:hover { border-color: var(--border2); }
  .po-card.selected { border-color: var(--indigo-l); background: var(--indigo-dim); }
  .po-card-top { display: flex; align-items: flex-start; justify-content: space-between; margin-bottom: 8px; }
  .po-num { font-family: 'JetBrains Mono', monospace; font-size: 11px; color: var(--indigo-l); }
  .po-vendor { font-size: 12px; font-weight: 600; color: var(--bright); margin-top: 2px; }
  .po-date { font-size: 10px; color: var(--muted); margin-top: 1px; }
  .po-card-bottom { display: flex; justify-content: space-between; align-items: center; margin-top: 10px; padding-top: 8px; border-top: 1px solid rgba(255,255,255,0.05); }
  .po-total { font-family: 'JetBrains Mono', monospace; font-size: 14px; color: var(--bright); }
  .po-sub { font-size: 10px; color: var(--muted); }

  /* PO DETAIL CARD */
  .po-detail-card { background: var(--surface); border: 1px solid var(--border); border-radius: 10px; overflow: hidden; margin-bottom: 14px; }
  .po-detail-header { padding: 20px; border-bottom: 1px solid var(--border); background: linear-gradient(180deg, rgba(64,112,216,0.05) 0%, transparent 100%); }

  /* RECEIVE QTY INPUT */
  .qty-input { background: var(--raised); border: 1px solid var(--border); border-radius: 5px; color: var(--bright); font-family: 'JetBrains Mono', monospace; font-size: 13px; padding: 5px 8px; outline: none; width: 70px; text-align: center; }
  .qty-input:focus { border-color: var(--indigo-l); }

  /* GL ENTRY PREVIEW */
  .je-preview { background: rgba(0,0,0,0.2); border-radius: 8px; padding: 12px 14px; font-family: 'JetBrains Mono', monospace; font-size: 11px; }
  .je-preview-row { display: flex; gap: 12px; padding: 4px 0; border-bottom: 1px solid rgba(255,255,255,0.04); }
  .je-preview-row:last-child { border-bottom: none; }

  /* 3-WAY MATCH INDICATOR */
  .match-row { display: flex; align-items: center; gap: 0; }
  .match-step { flex: 1; text-align: center; padding: 8px 6px; font-size: 10px; font-weight: 600; border-bottom: 3px solid; }
  .match-step.complete { border-color: var(--green-l); color: var(--green-l); }
  .match-step.pending  { border-color: var(--amber-l); color: var(--amber-l); }
  .match-step.missing  { border-color: var(--border);  color: var(--muted); }
  .match-arrow { color: var(--muted); font-size: 14px; padding: 0 2px; }

  /* VARIANCE BADGE */
  .var-ok  { color: var(--green-l); font-family: 'JetBrains Mono', monospace; font-size: 11px; }
  .var-off { color: var(--red-l);   font-family: 'JetBrains Mono', monospace; font-size: 11px; }

  /* ANIMATIONS */
  @keyframes fi { from { opacity:0 } to { opacity:1 } }
  @keyframes su { from { opacity:0; transform:translateY(10px) } to { opacity:1; transform:translateY(0) } }
  .fade { animation: fi 0.22s ease; }

  /* PROGRESS */
  .prog { height: 4px; background: var(--raised); border-radius: 2px; overflow: hidden; }
  .prog-f { height: 100%; border-radius: 2px; }

  /* EMPTY STATE */
  .empty { padding: 40px; text-align: center; color: var(--muted); font-size: 13px; }
  .empty-icon { font-size: 36px; margin-bottom: 10px; }

  /* RECEIPT HISTORY */
  .receipt-row { display: flex; align-items: center; gap: 12px; padding: 9px 16px; border-bottom: 1px solid rgba(255,255,255,0.03); font-size: 11px; }
  .receipt-row:last-child { border-bottom: none; }
`;

