const gw_po_dollardollar = n => `$${(n||0).toLocaleString("en-US", { minimumFractionDigits: 2, maximumFractionDigits: 2 })}`;
const poTotal      = po  => po.lines.reduce((s, l) => s + l.qty * l.unitCost, 0);
const poReceived   = po  => po.lines.reduce((s, l) => s + l.receivedQty * l.unitCost, 0);
const poOutstanding= po  => po.lines.reduce((s, l) => s + (l.qty - l.receivedQty) * l.unitCost, 0);
const lineOutstanding = l => l.qty - l.receivedQty;
const gw_po_skuName = id => gw_po_SKUS.find(s => s.id === id)?.name || id;
const gw_po_skuCode = id => gw_po_SKUS.find(s => s.id === id)?.sku  || id;
const gw_po_skuUom  = id => gw_po_SKUS.find(s => s.id === id)?.uom  || "";
const vendorName = id => gw_po_VENDORS.find(v => v.id === id)?.name || id;

const STATUS_STEPS = ["draft", "sent", "partial", "received", "closed"];
const stepIndex = s => STATUS_STEPS.indexOf(s);

