// -- Rate Tables Tab -------------------------------------------
function RatesTab() {
  const [search, setSearch] = useState("");
  const [showAdd, setShowAdd] = useState(false);
  const [rates, setRates] = useState(TAX_RATES);

  const filtered = rates.filter(r =>
    !search || r.name.toLowerCase().includes(search.toLowerCase()) ||
    r.county.toLowerCase().includes(search.toLowerCase())
  );

  return (
    <div>
      <div className="krow">
        <div className="kpi k-gold">
          <div className="kl">Jurisdictions</div>
          <div className="kv">{rates.filter(r=>r.active).length}</div>
          <div className="ks">Active tax rates</div>
        </div>
        <div className="kpi k-blue">
          <div className="kl">Avg Combined Rate</div>
          <div className="kv">{(rates.filter(r=>r.active).reduce((s,r)=>s+r.totalRate,0)/rates.filter(r=>r.active).length).toFixed(2)}%</div>
          <div className="ks">AZ jurisdictions</div>
        </div>
        <div className="kpi k-green">
          <div className="kl">Materials Taxable</div>
          <div className="kv">Yes</div>
          <div className="ks">All AZ jurisdictions</div>
        </div>
        <div className="kpi k-amber">
          <div className="kl">Labor Taxable</div>
          <div className="kv">No</div>
          <div className="ks">AZ: labor is exempt</div>
        </div>
      </div>

      <div className="alert a-bl">
        {gw_sales_tax_Ic.info} <div><strong>Arizona TPT — Prime Contracting Class 15:</strong> Under AZ TPT, contractors pay tax on 65% of the gross contract amount (the materials portion). Labor is exempt. Tax is calculated on materials only and must be collected from the customer. Rate varies by city where the project is located.</div>
      </div>

      <div className="panel">
        <div className="ph">
          <div>
            <div className="pt">TAX RATE TABLE</div>
            <div className="ps">Rate by jurisdiction · Effective dates · Applies-to rules</div>
          </div>
          <div style={{display:"flex",gap:8}}>
            <input className="fi" style={{width:200,padding:"4px 10px",fontSize:11}} placeholder="Search jurisdiction..." value={search} onChange={e=>setSearch(e.target.value)} />
            <button className="btn btn-gold btn-sm" onClick={()=>setShowAdd(true)}>{gw_sales_tax_Ic.plus} Add Jurisdiction</button>
          </div>
        </div>
        <div style={{padding:16}}>
          {filtered.map(r => (
            <div className="rate-card" key={r.id} style={{opacity:r.active?1:0.5}}>
              <div className="rate-header">
                <div>
                  <div className="rate-name">{r.name}</div>
                  <div style={{fontSize:10,color:"var(--dim)",marginTop:2}}>{r.category} · Effective {r.effectiveDate}</div>
                </div>
                <div style={{textAlign:"right"}}>
                  <div className="rate-total">{r.totalRate.toFixed(3)}%</div>
                  <div style={{fontSize:9,color:"var(--muted)",marginTop:1}}>Combined rate</div>
                </div>
              </div>
              <div style={{display:"flex",alignItems:"center",gap:8,marginBottom:10}}>
                <div className="rate-breakdown">
                  <div className="rate-chip">
                    <div className="rate-chip-label">State</div>
                    <div className="rate-chip-val">{r.stateRate.toFixed(1)}%</div>
                  </div>
                  <div className="rate-chip">
                    <div className="rate-chip-label">County</div>
                    <div className="rate-chip-val">{r.countyRate.toFixed(1)}%</div>
                  </div>
                  <div className="rate-chip">
                    <div className="rate-chip-label">City</div>
                    <div className="rate-chip-val">{r.cityRate.toFixed(2)}%</div>
                  </div>
                </div>
                <div style={{marginLeft:"auto",display:"flex",gap:6,alignItems:"center"}}>
                  <span style={{fontSize:9,color:"var(--muted)",fontWeight:700,letterSpacing:1}}>APPLIES TO:</span>
                  {r.appliesMat  && <span className="ap ap-mat">Materials</span>}
                  {r.appliesLab  && <span className="ap ap-lab">Labor</span>}
                  {r.appliesEquip && <span className="ap ap-equip">Equipment</span>}
                  {!r.appliesLab && <span className="ap" style={{background:"rgba(88,82,74,0.15)",color:"var(--muted)"}}>Labor Exempt</span>}
                  <span className={"badge "+(r.active?"b-green":"b-stone")}>{r.active?"Active":"Inactive"}</span>
                </div>
              </div>
              {r.notes && <div style={{fontSize:10,color:"var(--dim)",borderTop:"1px solid var(--border)",paddingTop:8}}>{r.notes}</div>}
            </div>
          ))}
        </div>
      </div>

      {showAdd && (
        <div className="overlay" onClick={e=>{if(e.target===e.currentTarget)setShowAdd(false);}}>
          <div className="modal">
            <div className="mh">
              <div><div className="mt">ADD TAX JURISDICTION</div><div className="ms">Define rates for a new city or jurisdiction</div></div>
              <button className="xbtn" onClick={()=>setShowAdd(false)}>{gw_sales_tax_Ic.close}</button>
            </div>
            <div className="mb">
              <div className="frow frow-2">
                <div className="fg"><label className="fl">State</label><input className="fi" placeholder="AZ" /></div>
                <div className="fg"><label className="fl">County</label><input className="fi" placeholder="Maricopa" /></div>
              </div>
              <div className="fg"><label className="fl">City / Jurisdiction Name</label><input className="fi" placeholder="e.g. Peoria, AZ" /></div>
              <div className="frow frow-3">
                <div className="fg"><label className="fl">State Rate (%)</label><input className="fi" placeholder="5.6" /></div>
                <div className="fg"><label className="fl">County Rate (%)</label><input className="fi" placeholder="0.7" /></div>
                <div className="fg"><label className="fl">City Rate (%)</label><input className="fi" placeholder="1.8" /></div>
              </div>
              <div className="sec-div">Applies To</div>
              <div style={{display:"flex",gap:12}}>
                {["Materials","Labor","Equipment"].map(item => (
                  <label key={item} style={{display:"flex",alignItems:"center",gap:6,fontSize:12,color:"var(--light)",cursor:"pointer"}}>
                    <input type="checkbox" defaultChecked={item==="Materials"} style={{accentColor:"var(--gold)"}} /> {item}
                  </label>
                ))}
              </div>
              <div className="fg"><label className="fl">Effective Date</label><input className="fi" type="date" defaultValue="2026-01-01" /></div>
              <div className="fg"><label className="fl">Notes</label><input className="fi" placeholder="Optional rate notes or source" /></div>
            </div>
            <div className="mf">
              <button className="btn btn-ghost" onClick={()=>setShowAdd(false)}>Cancel</button>
              <button className="btn btn-gold" onClick={()=>setShowAdd(false)}>{gw_sales_tax_Ic.plus} Add Jurisdiction</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

