// --- 14-day capacity data -------------------------------------
const CAPACITY_DATA = Array.from({ length: 14 }, (_, i) => {
  const date = new Date("2025-02-20");
  date.setDate(date.getDate() + i);
  const isWeekend = date.getDay() === 0 || date.getDay() === 6;
  const booked    = isWeekend ? 0 : Math.floor(Math.random() * 18) + 4;
  const capacity  = isWeekend ? 0 : gw_scheduling_TECHS.filter(t=>t.available).length * 8;
  return {
    date:       date.toISOString().slice(0, 10),
    label:      date.toLocaleDateString("en-US", { weekday:"short", month:"numeric", day:"numeric" }),
    isWeekend,
    booked,
    capacity,
    utilPct:    capacity > 0 ? booked / capacity : 0,
  };
});

// --- Skill matrix ---------------------------------------------
const ALL_SKILLS = [
  "HVAC Install","HVAC Service","DDC Controls","Refrigerant 410A","Sheet Metal","Ductwork","Preventive Maintenance",
  "Plumbing Rough","Plumbing Finish","Gas Piping","Backflow","Water Heater","Drain Cleaning",
  "Panel Upgrade","EV Charger","Commercial Wiring","Low Voltage","Generator",
];

// --- Smart assign scoring engine (local — mirrors Claude API logic) ---
function scoreCandidate(tech, wo) {
  let score = 0;
  const reasons = [];

  // Skill match (40 pts max)
  const skillMatches = wo.requiredSkills.filter(s => tech.skills.includes(s)).length;
  const skillScore   = Math.round((skillMatches / wo.requiredSkills.length) * 40);
  score += skillScore;
  if (skillScore === 40) reasons.push("✅ Full skill match");
  else if (skillScore > 0) reasons.push(`⚠ Partial skill match (${skillMatches}/${wo.requiredSkills.length})`);
  else reasons.push("❌ Skill gap");

  // Cert match (20 pts max)
  if (wo.requiredCerts.length > 0) {
    const certMatches = wo.requiredCerts.filter(c => tech.certs.includes(c)).length;
    const certScore   = Math.round((certMatches / wo.requiredCerts.length) * 20);
    score += certScore;
    if (certScore === 20) reasons.push("✅ All certifications held");
    else reasons.push("⚠ Missing required cert");
  }

  // Availability (15 pts)
  if (tech.available && tech.nextAvailable === "Now") {
    score += 15; reasons.push("✅ Available now");
  } else if (tech.available) {
    score += 8;  reasons.push(`⏱ Available ${tech.nextAvailable}`);
  } else {
    score += 0;  reasons.push("❌ Not available today");
  }

  // Workload balance (10 pts)
  const loadRatio = tech.hoursThisWeek / tech.maxHours;
  if (loadRatio < 0.6)       { score += 10; reasons.push("✅ Lightly loaded"); }
  else if (loadRatio < 0.85) { score +=  6; reasons.push("◎ Moderate load"); }
  else                       { score +=  2; reasons.push("⚠ Near capacity"); }

  // OT risk (5 pts)
  const projectedHours = tech.hoursThisWeek + wo.estimatedHours;
  if (projectedHours <= tech.maxHours) {
    score += 5; reasons.push("✅ No OT risk");
  } else if (tech.otApproved) {
    score += 3; reasons.push("◎ OT approved");
  } else {
    score += 0; reasons.push("⚠ Would cause OT");
  }

  // Customer history (5 pts)
  if (wo.contactId && tech.customerHistory.includes(wo.contactId)) {
    score += 5; reasons.push("⭐ Prior customer relationship");
  }

  // Preferred tech (5 pts bonus)
  if (wo.preferredTech === tech.id) {
    score += 5; reasons.push("⭐ Customer preferred");
  }

  // Geographic proximity (rough — same zone area bonus)
  const latDiff = Math.abs(tech.lat - wo.lat);
  const lngDiff = Math.abs(tech.lng - wo.lng);
  const dist    = Math.sqrt(latDiff**2 + lngDiff**2) * 69; // approx miles
  const travelMins = Math.round(dist * 2.2); // rough city driving
  if (dist < 3)       { score += 5; reasons.push(`✅ ${Math.round(dist*10)/10} mi away (~${travelMins} min)`); }
  else if (dist < 8)  { score += 3; reasons.push(`◎ ${Math.round(dist*10)/10} mi away (~${travelMins} min)`); }
  else                { score += 1; reasons.push(`⚠ ${Math.round(dist*10)/10} mi away (~${travelMins} min)`); }

  return { tech, score: Math.min(score, 100), reasons, travelMins };
}

function rankCandidates(wo) {
  return gw_scheduling_TECHS
    .map(t => scoreCandidate(t, wo))
    .sort((a, b) => b.score - a.score);
}

// --- Helpers --------------------------------------------------
const scoreColor = s => s >= 80 ? "var(--green-l)" : s >= 55 ? "var(--amber-l)" : "var(--red-l)";
const scoreLabel = s => s >= 80 ? "Excellent" : s >= 65 ? "Good" : s >= 50 ? "Fair" : "Poor";

// -- CSS -------------------------------------------------------
const css_gw_scheduling = `
  @import url('https://fonts.googleapis.com/css2?family=Bebas+Neue&family=DM+Sans:ital,opsz,wght@0,9..40,300;0,9..40,400;0,9..40,500;0,9..40,600;0,9..40,700;1,9..40,400&family=DM+Mono:wght@400;500&display=swap');
  *, *::before, *::after { box-sizing:border-box; margin:0; padding:0; }
  :root {
    --soil:#15130F; --clay:#1E1B16; --raise:#252118; --gravel:#302C24;
    --stone:#5C5448; --sand:#9C8E7A; --bone:#D8CFBF; --chalk:#EDE8DF;
    --amber:#C8780A; --amber-l:#E89420; --amber-b:rgba(200,120,10,.18);
    --teal:#0E8C72;  --teal-l:#12A887;  --teal-b:rgba(14,140,114,.18);
    --green:#1A7A3C; --green-l:#22A050; --green-b:rgba(26,122,60,.18);
    --blue:#1B5A8A;  --blue-l:#2478B8;  --blue-b:rgba(27,90,138,.18);
    --red:#8B2020;   --red-l:#C03030;   --red-b:rgba(139,32,32,.18);
    --purple:#5C2D8A;--purple-l:#7C44B8;--purple-b:rgba(92,45,138,.18);
    --font:'DM Sans',sans-serif; --mono:'DM Mono',monospace; --display:'Bebas Neue',sans-serif;
  }
  html,body,#root { height:100%; background:var(--soil); color:var(--chalk); font-family:var(--font); font-size:13px; -webkit-font-smoothing:antialiased; }
  @keyframes fadeUp  { from{opacity:0;transform:translateY(8px)} to{opacity:1;transform:translateY(0)} }
  @keyframes fadeIn  { from{opacity:0} to{opacity:1} }
  @keyframes slideR  { from{opacity:0;transform:translateX(16px)} to{opacity:1;transform:translateX(0)} }
  @keyframes spin    { to{transform:rotate(360deg)} }

  /* Shell */
  .so-root { display:flex; height:100vh; overflow:hidden; }
  .so-sidebar { width:210px; flex-shrink:0; background:var(--clay); border-right:1px solid var(--gravel); display:flex; flex-direction:column; }
  .so-logo { padding:16px 14px 12px; border-bottom:1px solid var(--gravel); font-family:var(--display); font-size:18px; letter-spacing:.04em; color:var(--amber-l); }
  .so-logo span { display:block; font-family:var(--font); font-size:10px; font-weight:500; letter-spacing:.08em; text-transform:uppercase; color:var(--stone); margin-top:2px; }
  .so-nav { flex:1; padding:8px 0; }
  .so-nav-item { display:flex; align-items:center; gap:9px; padding:9px 14px; cursor:pointer; font-size:12.5px; font-weight:500; color:var(--sand); transition:all .15s; border-left:2px solid transparent; }
  .so-nav-item:hover { background:var(--raise); color:var(--bone); }
  .so-nav-item.active { background:var(--amber-b); color:var(--amber-l); border-left-color:var(--amber); }
  .so-main { flex:1; display:flex; flex-direction:column; overflow:hidden; }
  .so-topbar { height:52px; background:var(--clay); border-bottom:1px solid var(--gravel); display:flex; align-items:center; padding:0 20px; gap:12px; flex-shrink:0; }
  .so-title { font-family:var(--display); font-size:20px; letter-spacing:.04em; }
  .so-body { flex:1; overflow-y:auto; padding:18px 20px; }

  /* Buttons */
  .btn { padding:6px 14px; border-radius:5px; border:none; cursor:pointer; font-size:12px; font-family:var(--font); font-weight:600; transition:all .15s; display:inline-flex; align-items:center; gap:5px; }
  .btn-primary { background:var(--amber); color:#fff; }
  .btn-primary:hover { background:var(--amber-l); }
  .btn-ghost { background:var(--gravel); color:var(--bone); }
  .btn-ghost:hover { background:var(--stone); }
  .btn-green { background:var(--green); color:#fff; }
  .btn-green:hover { background:var(--green-l); }
  .btn-sm { padding:4px 10px; font-size:11px; }
  .btn-xs { padding:2px 7px; font-size:10px; }

  /* KPIs */
  .kpi-row { display:grid; grid-template-columns:repeat(5,1fr); gap:10px; margin-bottom:16px; }
  .kpi { background:var(--clay); border:1px solid var(--gravel); border-radius:8px; padding:14px 16px 12px; position:relative; overflow:hidden; animation:fadeUp .2s ease both; }
  .kpi::after { content:''; position:absolute; bottom:0; left:0; right:0; height:3px; }
  .kpi.amber::after  { background:linear-gradient(90deg,var(--amber),var(--amber-l)); }
  .kpi.green::after  { background:linear-gradient(90deg,var(--green),var(--green-l)); }
  .kpi.blue::after   { background:linear-gradient(90deg,var(--blue),var(--blue-l)); }
  .kpi.teal::after   { background:linear-gradient(90deg,var(--teal),var(--teal-l)); }
  .kpi.red::after    { background:linear-gradient(90deg,var(--red),var(--red-l)); }
  .kpi-label { font-size:10px; font-weight:600; letter-spacing:.08em; text-transform:uppercase; color:var(--stone); margin-bottom:4px; }
  .kpi-val { font-family:var(--display); font-size:26px; line-height:1.1; }
  .kpi-sub { font-size:10.5px; color:var(--sand); margin-top:3px; }

  /* Panel */
  .panel { background:var(--clay); border:1px solid var(--gravel); border-radius:8px; overflow:hidden; margin-bottom:14px; animation:fadeUp .22s ease both; }
  .panel-head { padding:11px 16px; border-bottom:1px solid var(--gravel); display:flex; align-items:center; gap:10px; }
  .panel-title { font-size:12px; font-weight:700; letter-spacing:.06em; text-transform:uppercase; color:var(--bone); }
  .panel-sub { font-size:11px; color:var(--stone); margin-left:auto; }
  .panel-body { padding:14px 16px; }

  /* WO card */
  .wo-card { background:var(--raise); border:1px solid var(--gravel); border-radius:7px; padding:13px 15px; margin-bottom:10px; cursor:pointer; transition:all .15s; animation:fadeUp .2s ease both; }
  .wo-card:hover { border-color:var(--stone); }
  .wo-card.selected { border-color:var(--amber); background:var(--amber-b); }
  .wo-id { font-family:var(--mono); font-size:10px; color:var(--amber-l); margin-bottom:2px; }
  .wo-type { font-size:13px; font-weight:700; color:var(--chalk); }
  .wo-customer { font-size:11.5px; color:var(--sand); margin-top:2px; }
  .wo-addr { font-size:11px; color:var(--stone); margin-top:1px; }
  .wo-meta { display:flex; gap:8px; align-items:center; flex-wrap:wrap; margin-top:7px; }

  /* Badge */
  .badge { display:inline-flex; align-items:center; padding:2px 7px; border-radius:3px; font-size:10px; font-weight:700; letter-spacing:.04em; text-transform:uppercase; }
  .b-amber  { background:var(--amber-b);  color:var(--amber-l);  }
  .b-green  { background:var(--green-b);  color:var(--green-l);  }
  .b-blue   { background:var(--blue-b);   color:var(--blue-l);   }
  .b-red    { background:var(--red-b);    color:var(--red-l);    }
  .b-teal   { background:var(--teal-b);   color:var(--teal-l);   }
  .b-purple { background:var(--purple-b); color:var(--purple-l); }
  .b-stone  { background:var(--gravel);   color:var(--sand);     }

  /* Candidate card */
  .candidate { background:var(--clay); border:1px solid var(--gravel); border-radius:7px; padding:12px 14px; margin-bottom:8px; animation:slideR .18s ease both; transition:border-color .15s; }
  .candidate:hover { border-color:var(--stone); }
  .candidate.rank1 { border-color:var(--amber); background:var(--amber-b); }
  .cand-header { display:flex; align-items:center; gap:12px; margin-bottom:8px; }
  .cand-avatar { width:36px; height:36px; border-radius:50%; display:flex; align-items:center; justify-content:center; font-size:12px; font-weight:700; font-family:var(--mono); flex-shrink:0; }
  .cand-name { font-size:13.5px; font-weight:700; color:var(--chalk); }
  .cand-div  { font-size:11px; color:var(--stone); }
  .score-ring { width:42px; height:42px; border-radius:50%; display:flex; align-items:center; justify-content:center; font-family:var(--display); font-size:16px; flex-shrink:0; margin-left:auto; }
  .reason-list { display:flex; flex-direction:column; gap:3px; }
  .reason-item { font-size:11.5px; color:var(--sand); line-height:1.4; }

  /* Progress */
  .prog { height:4px; background:var(--gravel); border-radius:2px; overflow:hidden; }
  .prog-fill { height:100%; border-radius:2px; }

  /* Skill pill */
  .skill-pill { display:inline-flex; padding:2px 6px; border-radius:3px; font-size:10px; font-weight:500; margin:2px; }
  .skill-has  { background:var(--green-b);  color:var(--green-l);  border:1px solid var(--green); }
  .skill-miss { background:var(--red-b);    color:var(--red-l);    border:1px solid var(--red); }
  .skill-na   { background:var(--gravel);   color:var(--stone);    }

  /* Skill matrix */
  .skill-matrix-table { border-collapse:collapse; width:100%; font-size:11px; }
  .skill-matrix-table th { padding:6px 8px; text-align:left; font-size:9.5px; font-weight:700; letter-spacing:.07em; text-transform:uppercase; color:var(--stone); border-bottom:1px solid var(--gravel); white-space:nowrap; }
  .skill-matrix-table td { padding:7px 8px; border-bottom:1px solid rgba(48,44,36,.3); vertical-align:middle; }
  .skill-matrix-table tr:last-child td { border-bottom:none; }
  .skill-check { width:20px; height:20px; border-radius:4px; display:flex; align-items:center; justify-content:center; font-size:11px; margin:0 auto; }
  .skill-check.yes { background:var(--green-b); color:var(--green-l); }
  .skill-check.no  { background:var(--gravel);  color:var(--stone); }

  /* Capacity chart */
  .cap-bar-wrap { display:flex; gap:4px; height:80px; align-items:flex-end; margin-bottom:8px; }
  .cap-bar-col  { flex:1; display:flex; flex-direction:column; align-items:center; gap:2px; }
  .cap-bar      { width:100%; border-radius:2px 2px 0 0; transition:opacity .15s; cursor:pointer; min-height:3px; }
  .cap-bar:hover { opacity:.8; }
  .cap-bar-label { font-size:8.5px; color:var(--stone); white-space:nowrap; transform:rotate(-45deg); transform-origin:center; margin-top:2px; width:28px; overflow:hidden; text-overflow:ellipsis; }

  /* Route stop */
  .route-stop { display:flex; gap:12px; align-items:flex-start; position:relative; padding-bottom:14px; }
  .route-stop:not(:last-child)::after { content:''; position:absolute; left:14px; top:30px; bottom:0; width:2px; background:var(--gravel); }
  .route-dot { width:28px; height:28px; border-radius:50%; flex-shrink:0; display:flex; align-items:center; justify-content:center; font-size:11px; font-weight:700; font-family:var(--mono); z-index:1; }
  .route-content { flex:1; padding-top:4px; }
  .route-wo-id  { font-family:var(--mono); font-size:10px; color:var(--amber-l); }
  .route-wo-type{ font-size:12.5px; font-weight:700; color:var(--chalk); }
  .route-addr   { font-size:11.5px; color:var(--sand); margin-top:1px; }
  .route-drive  { font-size:11px; color:var(--stone); margin-top:3px; }

  /* AI indicator */
  .ai-tag { display:inline-flex; align-items:center; gap:4px; padding:2px 8px; border-radius:4px; background:var(--purple-b); border:1px solid var(--purple); color:var(--purple-l); font-size:10px; font-weight:700; letter-spacing:.06em; }
  .ai-spin { display:inline-block; animation:spin .8s linear infinite; }

  /* Load bar */
  .load-bar-row { display:flex; gap:10px; align-items:center; padding:7px 0; border-bottom:1px solid rgba(48,44,36,.3); }
  .load-bar-row:last-child { border-bottom:none; }
  .load-bar-name { font-size:12.5px; color:var(--chalk); min-width:110px; font-weight:600; }
  .load-bar-track { flex:1; height:7px; background:var(--gravel); border-radius:4px; overflow:hidden; }
  .load-bar-fill  { height:100%; border-radius:4px; }
  .load-bar-val   { font-family:var(--mono); font-size:11px; min-width:70px; text-align:right; }

  ::-webkit-scrollbar { width:5px; }
  ::-webkit-scrollbar-track { background:transparent; }
  ::-webkit-scrollbar-thumb { background:var(--gravel); border-radius:3px; }

  @media (max-width:1100px) { .kpi-row { grid-template-columns:repeat(3,1fr); } }
`;

// -- Smart Assign view -----------------------------------------
function SmartAssignView() {
  const [selectedWO,    setSelectedWO]    = useState(gw_scheduling_WORK_ORDERS[0]);
  const [analyzing,     setAnalyzing]     = useState(false);
  const [candidates,    setCandidates]    = useState(null);
  const [assignments,   setAssignments]   = useState({});
  const [aiInsight,     setAiInsight]     = useState(null);

  const AI_INSIGHTS = {
    "WO-2025-0311": "Derek Torres is the optimal assignment: he's the customer's preferred technician, holds all required certifications, and is only 4.2 miles away. He has 8 hours of capacity remaining this week with no OT risk. Assigning him maintains the customer relationship Sandra Morales has with Apex MEP.",
    "WO-2025-0312": "Luis Ramirez is the top candidate with a full skill and cert match for water heater replacement. He's available now in Central Phoenix and 6.8 miles from the site. Tony Reyes also qualifies but is at max hours today — avoid to prevent overtime liability.",
    "WO-2025-0313": "Sarah Kim is the clear choice: AZ electrical license, prior work for this customer, and she's lightly loaded this week (28h/40h). Paul Tremblay has requested her before. James Cooper lacks the required electrical certification.",
    "WO-2025-0314": "Marcus Webb is ideal — lightly loaded (24h this week), zone-matched to North Scottsdale, holds EPA 608. This flexible PM window gives scheduling wiggle room. Consider pairing with WO-2025-0311 on Derek's route to avoid a separate dispatch to the same area.",
    "WO-2025-0315": "Only Luis Ramirez holds the Backflow Certification plus AZ Plumbing License required for this job. He's the only qualified candidate available today. Note: Tony Reyes has the cert but is fully booked.",
    "WO-2025-0316": "Sarah Kim handles EV charger installs with confidence — she's done 14 this year. This Chandler location is slightly outside her usual zone but manageable. Given her afternoon slot availability after WO-2025-0313, the timing works well.",
  };

  function runAnalysis() {
    setAnalyzing(true);
    setCandidates(null);
    setAiInsight(null);
    setTimeout(() => {
      const ranked = rankCandidates(selectedWO);
      setCandidates(ranked);
      setAiInsight(AI_INSIGHTS[selectedWO.id] || "Analysis complete. Top candidate ranked by skill match, availability, and workload balance.");
      setAnalyzing(false);
    }, 1200);
  }

  function assign(techId) {
    setAssignments(prev => ({ ...prev, [selectedWO.id]: techId }));
  }

  const priorityColor = { high:"var(--red-l)", normal:"var(--amber-l)", low:"var(--stone)" };
  const priorityBadge = { high:"b-red", normal:"b-amber", low:"b-stone" };

  return (
    <div style={{ display:"grid", gridTemplateColumns:"1fr 1fr", gap:16, height:"calc(100vh - 130px)", overflow:"hidden" }}>
      {/* Left: WO list */}
      <div style={{ overflow:"auto", paddingRight:4 }}>
        <div style={{ fontSize:11, fontWeight:700, letterSpacing:".08em", textTransform:"uppercase", color:"var(--stone)", marginBottom:10 }}>
          UNASSIGNED WORK ORDERS — {gw_scheduling_WORK_ORDERS.length} jobs · {new Date("2025-02-20").toLocaleDateString("en-US",{weekday:"long",month:"long",day:"numeric"})}
        </div>
        {gw_scheduling_WORK_ORDERS.map((wo, i) => {
          const assigned = assignments[wo.id];
          const assignedTech = assigned ? gw_scheduling_TECHS.find(t => t.id === assigned) : null;
          return (
 <div key={wo.id} className={"wo-card"+(selectedWO?.id===wo.id?" selected":"")} style={{ animationDelay:`${i*.05}s` }} onClick={() => { setSelectedWO(wo); setCandidates(null); setAiInsight(null); }}>
              <div className="wo-id">{wo.id}</div>
              <div className="wo-type">{wo.type}</div>
              <div className="wo-customer">{wo.customer}</div>
              <div className="wo-addr">📍 {wo.address}</div>
              <div className="wo-meta">
                <span className={"badge "+(priorityBadge[wo.priority])}>{wo.priority}</span>
                <span style={{ fontFamily:"var(--mono)", fontSize:10, color:"var(--stone)" }}>
                  ⏱ {wo.estimatedHours}h
                </span>
                <span style={{ fontFamily:"var(--mono)", fontSize:10, color:"var(--stone)" }}>
                  🕐 {wo.window}
                </span>
                {assignedTech && (
                  <span className="badge b-green">✓ {assignedTech.name}</span>
                )}
                {wo.preferredTech && !assignedTech && (
                  <span className="badge b-teal">⭐ Pref: {gw_scheduling_TECHS.find(t=>t.id===wo.preferredTech)?.name}</span>
                )}
              </div>
            </div>
          );
        })}
      </div>

      {/* Right: Analysis panel */}
      <div style={{ overflow:"auto" }}>
        {selectedWO ? (
          <>
            {/* WO detail header */}
            <div className="panel" style={{ marginBottom:10 }}>
              <div className="panel-head">
                <span className="ai-tag">🤖 Smart Assign</span>
                <span className="panel-sub">AI-powered candidate ranking</span>
              </div>
              <div className="panel-body">
                <div style={{ fontSize:14, fontWeight:700, color:"var(--chalk)", marginBottom:4 }}>{selectedWO.type}</div>
                <div style={{ fontSize:12, color:"var(--sand)", marginBottom:8 }}>
                  {selectedWO.customer} · {selectedWO.address}
                </div>
                <div style={{ display:"flex", gap:8, flexWrap:"wrap", marginBottom:12 }}>
                  {selectedWO.requiredSkills.map(s => (
                    <span key={s} style={{ fontFamily:"var(--mono)", fontSize:10, background:"var(--blue-b)", color:"var(--blue-l)", border:"1px solid var(--blue)", borderRadius:3, padding:"1px 6px" }}>{s}</span>
                  ))}
                  {selectedWO.requiredCerts.map(c => (
                    <span key={c} style={{ fontFamily:"var(--mono)", fontSize:10, background:"var(--teal-b)", color:"var(--teal-l)", border:"1px solid var(--teal)", borderRadius:3, padding:"1px 6px" }}>🏅 {c}</span>
                  ))}
                </div>
                <button className="btn btn-primary" onClick={runAnalysis} disabled={analyzing}>
                  {analyzing ? <><span className="ai-spin">⚙</span> Analyzing…</> : "🤖 Run AI Analysis"}
                </button>
              </div>
            </div>

            {/* AI insight */}
            {aiInsight && (
              <div style={{ background:"var(--purple-b)", border:"1px solid var(--purple)", borderRadius:7, padding:"12px 14px", marginBottom:10, animation:"fadeIn .3s ease" }}>
                <div style={{ display:"flex", alignItems:"center", gap:8, marginBottom:6 }}>
                  <span className="ai-tag">🤖 AI Insight</span>
                </div>
                <div style={{ fontSize:12.5, color:"var(--bone)", lineHeight:1.65 }}>{aiInsight}</div>
              </div>
            )}

            {/* Candidates */}
            {candidates && (
              <div>
                <div style={{ fontSize:11, fontWeight:700, letterSpacing:".08em", textTransform:"uppercase", color:"var(--stone)", marginBottom:8 }}>
                  RANKED CANDIDATES
                </div>
                {candidates.map((c, i) => {
                  const sc = scoreColor(c.score);
                  const isAssigned = assignments[selectedWO.id] === c.tech.id;
                  return (
                    <div key={c.tech.id} className={"candidate"+(i===0?" rank1":"")} style={{ animationDelay:`${i*.06}s` }}>
                      <div className="cand-header">
                        <div className="cand-avatar" style={{ background:c.tech.color+"28", border:`2px solid ${c.tech.color}`, color:c.tech.color }}>
                          {c.tech.initials}
                        </div>
                        <div>
                          <div className="cand-name">{c.tech.name}</div>
                          <div className="cand-div">{c.tech.div} · {c.tech.zone}</div>
                          <div style={{ fontSize:10.5, color:"var(--stone)", marginTop:1 }}>
                            {c.tech.hoursThisWeek}h this week · {c.travelMins} min drive
                          </div>
                        </div>
                        {i === 0 && <span className="badge b-amber" style={{ marginLeft:"auto", marginRight:8 }}>Top Pick</span>} <div className="score-ring" style={{ background:sc+"22", border:`2px solid ${sc}` }}>
                          <span style={{ color:sc }}>{c.score}</span>
                        </div>
                      </div>
                      <div className="prog" style={{ marginBottom:8 }}>
                        <div className="prog-fill" style={{ width:`${c.score}%`, background:`linear-gradient(90deg,${sc}88,${sc})` }} />
                      </div>
                      <div className="reason-list" style={{ marginBottom:8 }}>
                        {c.reasons.slice(0,4).map((r,ri) => (
                          <div key={ri} className="reason-item">{r}</div>
                        ))}
                      </div>
                      <div style={{ display:"flex", gap:6 }}>
                        {isAssigned ? (
                          <span className="badge b-green">✓ Assigned</span>
                        ) : (
                          <button className="btn btn-green btn-sm" onClick={()=>assign(c.tech.id)}>
                            ✓ Assign {c.tech.name.split(" ")[0]}
                          </button>
                        )}
                        <button className="btn btn-ghost btn-sm">View Schedule</button>
                      </div>
                    </div>
                  );
                })}
              </div>
            )}

            {!candidates && !analyzing && (
              <div style={{ textAlign:"center", padding:"48px 24px", color:"var(--stone)" }}>
                <div style={{ fontSize:32, marginBottom:10 }}>🤖</div>
                <div style={{ fontSize:13, color:"var(--sand)", marginBottom:4 }}>Click Run AI Analysis</div>
                <div style={{ fontSize:11.5 }}>Scores all technicians by skill, cert, location, and load</div>
              </div>
            )}
          </>
        ) : (
          <div style={{ textAlign:"center", padding:"64px 24px", color:"var(--stone)" }}>
            Select a work order to begin
          </div>
        )}
      </div>
    </div>
  );
}

// -- Route Optimizer view --------------------------------------
function RouteOptimizerView() {
  const [selectedTech, setSelectedTech]   = useState(gw_scheduling_TECHS[0]);
  const [optimized,    setOptimized]      = useState(false);
  const [optimizing,   setOptimizing]     = useState(false);

  // Build sample routes per tech (subset of work orders)
  const TECH_ROUTES = {
    "EMP-001": [
      { wo: gw_scheduling_WORK_ORDERS[0], driveMins: 0,  driveFrom:"Depot (N. Scottsdale)"         },
      { wo: gw_scheduling_WORK_ORDERS[3], driveMins:11,  driveFrom:"4821 E Cactus Rd, Scottsdale"  },
    ],
    "EMP-002": [
      { wo: gw_scheduling_WORK_ORDERS[1], driveMins: 0,  driveFrom:"Depot (Central Phoenix)"       },
      { wo: gw_scheduling_WORK_ORDERS[4], driveMins:22,  driveFrom:"3811 N 44th St, Phoenix"       },
    ],
    "EMP-003": [
      { wo: gw_scheduling_WORK_ORDERS[2], driveMins: 0,  driveFrom:"Depot (Tempe/Mesa)"            },
      { wo: gw_scheduling_WORK_ORDERS[5], driveMins:18,  driveFrom:"9020 N Pima Rd, Scottsdale"   },
    ],
  };

  const currentRoute = TECH_ROUTES[selectedTech.id] || [];
  const totalDrive   = currentRoute.reduce((s, r) => s + r.driveMins, 0);
  const totalWork    = currentRoute.reduce((s, r) => s + r.wo.estimatedHours, 0);

  function runOptimize() {
    setOptimizing(true);
    setTimeout(() => { setOptimized(true); setOptimizing(false); }, 900);
  }

  const dotColors = ["var(--amber-l)","var(--blue-l)","var(--teal-l)","var(--purple-l)","var(--green-l)"];

  return (
    <div>
      <div style={{ display:"grid", gridTemplateColumns:"220px 1fr", gap:16 }}>
        {/* Tech selector */}
        <div>
          <div style={{ fontSize:11, fontWeight:700, letterSpacing:".08em", textTransform:"uppercase", color:"var(--stone)", marginBottom:8 }}>SELECT TECH</div>
          {gw_scheduling_TECHS.filter(t => TECH_ROUTES[t.id]).map(tech => (
            <div key={tech.id} onClick={() => { setSelectedTech(tech); setOptimized(false); }} style={{ background: selectedTech.id===tech.id ? "var(--amber-b)" : "var(--clay)", border:`1px solid ${selectedTech.id===tech.id ? "var(--amber)" : "var(--gravel)"}`, borderRadius:7, padding:"10px 12px", marginBottom:8, cursor:"pointer", transition:"all .15s" }}>
              <div style={{ display:"flex", alignItems:"center", gap:8 }}>
 <div style={{ width:30, height:30, borderRadius:"50%", background:tech.color+"28", border:`2px solid ${tech.color}`, display:"flex", alignItems:"center", justifyContent:"center", fontSize:11, fontWeight:700, color:tech.color, fontFamily:"var(--mono)", flexShrink:0 }}>
                  {tech.initials}
                </div>
                <div>
                  <div style={{ fontSize:12.5, fontWeight:700, color:"var(--chalk)" }}>{tech.name}</div>
                  <div style={{ fontSize:10.5, color:"var(--stone)" }}>{tech.div}</div>
                </div>
              </div>
              <div style={{ fontSize:10.5, color:"var(--stone)", marginTop:6 }}>
                {(TECH_ROUTES[tech.id]||[]).length} stops today
              </div>
            </div>
          ))}
        </div>

        {/* Route panel */}
        <div>
          <div className="panel">
            <div className="panel-head">
              <span className="panel-title">📍 Route — {selectedTech.name}</span>
              <span className="panel-sub">{currentRoute.length} stops · {totalWork.toFixed(1)}h work · ~{totalDrive} min drive</span>
            </div>
            <div className="panel-body">
              {/* Summary bar */}
              <div style={{ display:"grid", gridTemplateColumns:"repeat(3,1fr)", gap:10, marginBottom:16 }}>
                {[
                  { label:"Total Stops",    val:currentRoute.length,           color:"var(--chalk)"   },
                  { label:"Drive Time",     val:`~${totalDrive} min`,           color:"var(--amber-l)" },
                  { label:"Billable Hrs",   val:`${totalWork.toFixed(1)}h`,     color:"var(--green-l)" },
                ].map(s => (
                  <div key={s.label} style={{ background:"var(--raise)", borderRadius:6, padding:"10px 12px" }}>
                    <div style={{ fontSize:9.5, color:"var(--stone)", textTransform:"uppercase", letterSpacing:".08em", marginBottom:4 }}>{s.label}</div>
                    <div style={{ fontFamily:"var(--display)", fontSize:22, color:s.color }}>{s.val}</div>
                  </div>
                ))}
              </div>

              {/* Optimize button */}
              <div style={{ marginBottom:16 }}>
                <button className="btn btn-primary" onClick={runOptimize} disabled={optimizing}>
                  {optimizing ? <><span style={{ display:"inline-block", animation:"spin .8s linear infinite" }}>⚙</span> Optimizing…</>
                    : optimized ? "✓ Route Optimized" : "🗺 Optimize Route Order"}
                </button>
                {optimized && (
                  <span style={{ marginLeft:12, fontSize:11.5, color:"var(--green-l)" }}>
                    ↓ Saved ~8 min drive time by reordering stops
                  </span>
                )}
              </div>

              {/* Route stops */}
              <div>
                {currentRoute.map((stop, i) => (
                  <div key={stop.wo.id} className="route-stop">
                    <div className="route-dot" style={{ background:dotColors[i]+"28", border:`2px solid ${dotColors[i]}`, color:dotColors[i] }}>
                      {i + 1}
                    </div>
                    <div className="route-content">
                      <div className="route-wo-id">{stop.wo.id}</div>
                      <div className="route-wo-type">{stop.wo.type}</div>
                      <div style={{ fontSize:12, color:"var(--sand)" }}>{stop.wo.customer}</div>
                      <div className="route-addr">{stop.wo.address}</div>
                      <div className="route-drive">
                        {i === 0
                          ? `🚗 Starting location: ${stop.driveFrom}`
                          : `🚗 +${stop.driveMins} min from previous stop`}
                      </div>
                      <div style={{ display:"flex", gap:6, marginTop:6 }}>
                        <span className={"badge "+(stop.wo.priority === "high" ? "b-red" : stop.wo.priority === "normal" ? "b-amber" : "b-stone")}>
                          {stop.wo.priority}
                        </span>
                        <span style={{ fontFamily:"var(--mono)", fontSize:10, color:"var(--stone)" }}>⏱ {stop.wo.estimatedHours}h · {stop.wo.window}</span>
                      </div>
                    </div>
                  </div>
                ))}
                {currentRoute.length === 0 && (
                  <div style={{ textAlign:"center", padding:"32px", color:"var(--stone)" }}>
                    No stops assigned to this tech today
                  </div>
                )}
              </div>

              {/* Map link stub */}
              <div style={{ background:"var(--raise)", borderRadius:7, padding:"12px 14px", marginTop:8, display:"flex", alignItems:"center", gap:10 }}>
                <span style={{ fontSize:20 }}>🗺</span>
                <div>
                  <div style={{ fontSize:12.5, fontWeight:600, color:"var(--chalk)" }}>Google Maps Route</div>
                  <div style={{ fontSize:11, color:"var(--stone)" }}>Production: opens optimized multi-stop route in Google Maps / Apple Maps</div>
                </div>
                <button className="btn btn-ghost btn-sm" style={{ marginLeft:"auto" }}>Open Maps</button>
              </div>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}

// -- Capacity Planner view -------------------------------------
function CapacityView() {
  const [hoveredDay, setHoveredDay] = useState(null);
  const maxCap = Math.max(...CAPACITY_DATA.filter(d=>!d.isWeekend).map(d=>d.capacity));

  return (
    <div>
      <div className="kpi-row" style={{ gridTemplateColumns:"repeat(4,1fr)" }}>
        {[
          { label:"Avg Utilization",  val:`${Math.round(CAPACITY_DATA.filter(d=>!d.isWeekend).reduce((s,d)=>s+d.utilPct,0)/CAPACITY_DATA.filter(d=>!d.isWeekend).length*100)}%`, sub:"Next 14 workdays", cls:"amber" },
          { label:"Overloaded Days",  val:CAPACITY_DATA.filter(d=>d.utilPct>0.9).length, sub:">90% utilization", cls:"red" },
          { label:"Available Techs",  val:gw_scheduling_TECHS.filter(t=>t.available).length, sub:"Active this period",  cls:"green" },
          { label:"Backlog Hours",    val:`${gw_scheduling_WORK_ORDERS.reduce((s,w)=>s+w.estimatedHours,0).toFixed(0)}h`, sub:"Unassigned today", cls:"blue" },
        ].map((k,i) => (
          <div key={k.label} className={"kpi "+(k.cls)} style={{ animationDelay:`${i*.05}s` }}>
            <div className="kpi-label">{k.label}</div>
            <div className="kpi-val">{k.val}</div>
            <div className="kpi-sub">{k.sub}</div>
          </div>
        ))}
      </div>

      <div className="panel">
        <div className="panel-head">
          <span className="panel-title">14-Day Capacity Forecast</span>
          <span className="panel-sub">Hours booked vs. available</span>
        </div>
        <div className="panel-body">
          <div style={{ display:"flex", gap:12, marginBottom:10, fontSize:11 }}>
            {[
              { color:"var(--green-l)", label:"<70% — Available" },
              { color:"var(--amber-l)", label:"70–90% — Busy" },
              { color:"var(--red-l)",   label:">90% — Near Full" },
            ].map(l => (
              <div key={l.label} style={{ display:"flex", alignItems:"center", gap:5 }}>
                <div style={{ width:10, height:10, borderRadius:2, background:l.color }} />
                <span style={{ color:"var(--sand)" }}>{l.label}</span>
              </div>
            ))}
          </div>
          <div className="cap-bar-wrap">
            {CAPACITY_DATA.map((day, i) => {
              if (day.isWeekend) return (
                <div key={day.date} className="cap-bar-col">
                  <div style={{ flex:1 }} />
                  <div className="cap-bar-label" style={{ color:"var(--gravel)" }}>WE</div>
                </div>
              );
              const barH   = `${(day.booked / maxCap) * 100}%`;
              const color  = day.utilPct > .9 ? "var(--red-l)" : day.utilPct > .7 ? "var(--amber-l)" : "var(--green-l)";
              return (
 <div key={day.date} className="cap-bar-col" onMouseEnter={()=>setHoveredDay(day)}
                  onMouseLeave={()=>setHoveredDay(null)}>
                  <div style={{ flex:1, display:"flex", alignItems:"flex-end" }}>
                    <div className="cap-bar" style={{ height:barH, background:color, opacity:hoveredDay?.date===day.date?1:.75 }} />
                  </div>
                  <div className="cap-bar-label">{day.label.split(",")[0]}</div>
                </div>
              );
            })}
          </div>
          {hoveredDay && !hoveredDay.isWeekend && (
            <div style={{ background:"var(--raise)", borderRadius:6, padding:"8px 12px", marginTop:8, fontSize:12, animation:"fadeIn .12s ease" }}>
              <strong style={{ color:"var(--chalk)" }}>{hoveredDay.label}</strong>
              <span style={{ color:"var(--sand)", marginLeft:12 }}>
                {hoveredDay.booked}h booked / {hoveredDay.capacity}h capacity ({Math.round(hoveredDay.utilPct*100)}% utilized)
              </span>
            </div>
          )}
        </div>
      </div>

      {/* Tech availability table */}
      <div className="panel">
        <div className="panel-head"><span className="panel-title">Tech Availability Overview</span></div>
        <table style={{ width:"100%", borderCollapse:"collapse" }}>
          <thead>
            <tr>
              <th style={{ padding:"7px 14px", textAlign:"left", fontSize:10, fontWeight:700, letterSpacing:".08em", textTransform:"uppercase", color:"var(--stone)", borderBottom:"1px solid var(--gravel)" }}>Tech</th>
              <th style={{ padding:"7px 14px", textAlign:"left", fontSize:10, fontWeight:700, letterSpacing:".08em", textTransform:"uppercase", color:"var(--stone)", borderBottom:"1px solid var(--gravel)" }}>Division</th>
              <th style={{ padding:"7px 14px", textAlign:"left", fontSize:10, fontWeight:700, letterSpacing:".08em", textTransform:"uppercase", color:"var(--stone)", borderBottom:"1px solid var(--gravel)" }}>Status</th>
              <th style={{ padding:"7px 14px", textAlign:"left", fontSize:10, fontWeight:700, letterSpacing:".08em", textTransform:"uppercase", color:"var(--stone)", borderBottom:"1px solid var(--gravel)" }}>Hours This Week</th>
              <th style={{ padding:"7px 14px", textAlign:"left", fontSize:10, fontWeight:700, letterSpacing:".08em", textTransform:"uppercase", color:"var(--stone)", borderBottom:"1px solid var(--gravel)" }}>Remaining</th>
              <th style={{ padding:"7px 14px", textAlign:"left", fontSize:10, fontWeight:700, letterSpacing:".08em", textTransform:"uppercase", color:"var(--stone)", borderBottom:"1px solid var(--gravel)" }}>OT</th>
            </tr>
          </thead>
          <tbody>
            {gw_scheduling_TECHS.map(tech => {
              const remaining = tech.maxHours - tech.hoursThisWeek;
              const loadColor = remaining < 4 ? "var(--red-l)" : remaining < 10 ? "var(--amber-l)" : "var(--green-l)";
              return (
                <tr key={tech.id} style={{ borderBottom:"1px solid rgba(48,44,36,.3)" }}>
                  <td style={{ padding:"10px 14px" }}>
                    <div style={{ display:"flex", alignItems:"center", gap:8 }}>
                      <div style={{ width:28, height:28, borderRadius:"50%", background:tech.color+"28", border:`1.5px solid ${tech.color}`, display:"flex", alignItems:"center", justifyContent:"center", fontSize:10, fontWeight:700, color:tech.color, fontFamily:"var(--mono)" }}>
                        {tech.initials}
                      </div>
                      <span style={{ fontSize:12.5, fontWeight:600, color:"var(--chalk)" }}>{tech.name}</span>
                    </div>
                  </td>
                  <td style={{ padding:"10px 14px" }}>
                    <span style={{ fontSize:12, color:"var(--sand)" }}>{tech.div}</span>
                  </td>
                  <td style={{ padding:"10px 14px" }}>
                    <span className={"badge "+(tech.available?"b-green":"b-red")}>
                      {tech.available ? "Available" : "Unavailable"}
                    </span>
                  </td>
                  <td style={{ padding:"10px 14px" }}>
                    <div style={{ display:"flex", alignItems:"center", gap:8 }}>
                      <div className="prog" style={{ width:80 }}>
                        <div className="prog-fill" style={{ width:`${(tech.hoursThisWeek/tech.maxHours)*100}%`, background:loadColor }} />
                      </div>
                      <span style={{ fontFamily:"var(--mono)", fontSize:11, color:loadColor }}>{tech.hoursThisWeek}h</span>
                    </div>
                  </td>
                  <td style={{ padding:"10px 14px" }}>
                    <span style={{ fontFamily:"var(--mono)", fontSize:12, color:loadColor }}>{remaining}h left</span>
                  </td>
                  <td style={{ padding:"10px 14px" }}>
                    <span className={"badge "+(tech.otApproved?"b-amber":"b-stone")}>
                      {tech.otApproved ? "Approved" : "Not Approved"}
                    </span>
                  </td>
                </tr>
              );
            })}
          </tbody>
        </table>
      </div>
    </div>
  );
}

// -- Skill Matrix view -----------------------------------------
function SkillMatrixView() {
  const DIV_SKILLS = {
    HVAC:       ALL_SKILLS.slice(0, 7),
    Plumbing:   ALL_SKILLS.slice(7, 13),
    Electrical: ALL_SKILLS.slice(13),
  };

  return (
    <div>
      {Object.entries(DIV_SKILLS).map(([div, skills]) => (
        <div key={div} className="panel">
          <div className="panel-head">
            <span className="panel-title">{div} — Skill Coverage</span>
            <span className="panel-sub">{skills.length} skills · {gw_scheduling_TECHS.filter(t=>t.div===div||t.div==="Multi-Trade").length} techs</span>
          </div>
          <div style={{ overflowX:"auto" }}>
            <table className="skill-matrix-table">
              <thead>
                <tr>
                  <th style={{ minWidth:130 }}>Technician</th>
                  {skills.map(s => <th key={s} style={{ minWidth:90, textAlign:"center" }}>{s}</th>)}
                </tr>
              </thead>
              <tbody>
                {gw_scheduling_TECHS.map(tech => (
                  <tr key={tech.id}>
                    <td>
                      <div style={{ display:"flex", alignItems:"center", gap:7 }}>
                        <div style={{ width:24, height:24, borderRadius:"50%", background:tech.color+"28", border:`1.5px solid ${tech.color}`, display:"flex", alignItems:"center", justifyContent:"center", fontSize:9, fontWeight:700, color:tech.color, fontFamily:"var(--mono)", flexShrink:0 }}>
                          {tech.initials}
                        </div>
                        <span style={{ fontSize:12, color:"var(--chalk)", fontWeight:600 }}>{tech.name}</span>
                      </div>
                    </td>
                    {skills.map(skill => {
                      const has = tech.skills.includes(skill);
                      return (
                        <td key={skill} style={{ textAlign:"center" }}>
                          <div className={"skill-check "+(has?"yes":"no")}>
                            {has ? "✓" : "·"}
                          </div>
                        </td>
                      );
                    })}
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      ))}
    </div>
  );
}

// -- Load Balancing view ---------------------------------------
function LoadBalancingView() {
  const [reassigning, setReassigning] = useState(null);

  const overloaded   = gw_scheduling_TECHS.filter(t => t.hoursThisWeek / t.maxHours > 0.85);
  const underloaded  = gw_scheduling_TECHS.filter(t => t.hoursThisWeek / t.maxHours < 0.65 && t.available);

  return (
    <div>
      <div style={{ display:"grid", gridTemplateColumns:"1fr 1fr", gap:16, marginBottom:16 }}>
        {/* Overloaded */}
        <div className="panel">
          <div className="panel-head">
            <span className="panel-title" style={{ color:"var(--red-l)" }}>⚠ Near Capacity</span>
            <span className="panel-sub">{overloaded.length} techs</span>
          </div>
          <div className="panel-body">
            {overloaded.map(tech => {
              const util = tech.hoursThisWeek / tech.maxHours;
              return (
                <div key={tech.id} className="load-bar-row">
                  <span className="load-bar-name">{tech.name}</span>
                  <div className="load-bar-track">
                    <div className="load-bar-fill" style={{ width:`${util*100}%`, background:"var(--red-l)" }} />
                  </div>
                  <span className="load-bar-val" style={{ color:"var(--red-l)" }}>{tech.hoursThisWeek}/{tech.maxHours}h</span>
                </div>
              );
            })}
            {overloaded.length === 0 && <div style={{ color:"var(--stone)", fontSize:12 }}>No techs near capacity 🎉</div>}
          </div>
        </div>

        {/* Underloaded */}
        <div className="panel">
          <div className="panel-head">
            <span className="panel-title" style={{ color:"var(--green-l)" }}>✅ Has Capacity</span>
            <span className="panel-sub">{underloaded.length} techs</span>
          </div>
          <div className="panel-body">
            {underloaded.map(tech => {
              const util      = tech.hoursThisWeek / tech.maxHours;
              const remaining = tech.maxHours - tech.hoursThisWeek;
              return (
                <div key={tech.id} className="load-bar-row">
                  <span className="load-bar-name">{tech.name}</span>
                  <div className="load-bar-track">
                    <div className="load-bar-fill" style={{ width:`${util*100}%`, background:"var(--green-l)" }} />
                  </div>
                  <span className="load-bar-val" style={{ color:"var(--green-l)" }}>{remaining}h free</span>
                </div>
              );
            })}
          </div>
        </div>
      </div>

      {/* Redistribution suggestions */}
      <div className="panel">
        <div className="panel-head">
          <span className="ai-tag">🤖 AI Suggestions</span>
          <span className="panel-sub">Rebalancing recommendations</span>
        </div>
        <div className="panel-body">
          {[
            { from:"Tony Reyes (40h)", to:"Luis Ramirez (38h)", wo:"WO-2025-0315", reason:"Both plumbers with Backflow cert. Luis has 2h remaining — borderline but works with OT approval." },
            { from:null,               to:"Marcus Webb (24h)",  wo:"WO-2025-0314", reason:"PM tune-up is flexible and Marcus is lightly loaded. Frees Derek Torres for the higher-priority AC repair." },
          ].map((s, i) => (
            <div key={i} style={{ background:"var(--raise)", borderRadius:7, padding:"12px 14px", marginBottom:10 }}>
              <div style={{ display:"flex", gap:10, marginBottom:6 }}>
                <span className="badge b-teal">WO {s.wo}</span>
                {s.from && <span style={{ fontSize:12, color:"var(--sand)" }}>Move from {s.from} → {s.to}</span>}
                {!s.from && <span style={{ fontSize:12, color:"var(--sand)" }}>Assign to {s.to}</span>}
              </div>
              <div style={{ fontSize:12.5, color:"var(--bone)", lineHeight:1.6 }}>{s.reason}</div>
              <div style={{ display:"flex", gap:8, marginTop:10 }}>
                <button className="btn btn-green btn-sm">Apply Suggestion</button>
                <button className="btn btn-ghost btn-sm">Dismiss</button>
              </div>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
}

// -- Root component --------------------------------------------
function GroundworkSchedulingOptimizer() {
  const [activeView, setActiveView] = useState("smart");

  const NAV = [
    { id:"smart",    icon:"🤖", label:"Smart Assign"      },
    { id:"route",    icon:"🗺", label:"Route Optimizer"   },
    { id:"capacity", icon:"📅", label:"Capacity Planner"  },
    { id:"skills",   icon:"🏅", label:"Skill Matrix"      },
    { id:"load",     icon:"⚖",  label:"Load Balancing"    },
  ];

  const TITLES = {
    smart:"Smart Assign", route:"Route Optimizer",
    capacity:"Capacity Planner", skills:"Skill Matrix", load:"Load Balancing",
  };

  const unassigned = gw_scheduling_WORK_ORDERS.length;

  return (
    <>
      <style>{css_gw_scheduling}</style>
      <div className="so-root">
        <div className="so-sidebar">
          <div className="so-logo">GROUNDWORK<span>Scheduling Optimizer</span></div>
          <nav className="so-nav">
            {NAV.map(n => (
 <div key={n.id} className={"so-nav-item"+(activeView===n.id?" active":"")} onClick={() => setActiveView(n.id)}>
                <span style={{ fontSize:15 }}>{n.icon}</span>
                <span>{n.label}</span>
                {n.id === "smart" && unassigned > 0 && (
                  <span style={{ marginLeft:"auto", background:"var(--amber)", color:"#fff", fontSize:9, fontWeight:700, padding:"1px 5px", borderRadius:8, fontFamily:"var(--mono)" }}>
                    {unassigned}
                  </span>
                )}
              </div>
            ))}
          </nav>
          <div style={{ padding:"10px 14px", borderTop:"1px solid var(--gravel)" }}>
            <div style={{ display:"flex", alignItems:"center", gap:6, marginBottom:4 }}>
              <span className="ai-tag" style={{ fontSize:9 }}>🤖 AI Powered</span>
            </div>
            <div style={{ fontSize:10.5, color:"var(--stone)", lineHeight:1.5 }}>
              Scoring engine uses skill match, location, load, certs, and customer history
            </div>
          </div>
        </div>

        <div className="so-main">
          <div className="so-topbar">
            <div className="so-title">{TITLES[activeView]}</div>
            <div style={{ marginLeft:"auto", display:"flex", gap:8, alignItems:"center" }}>
              <span style={{ fontSize:11.5, color:"var(--stone)" }}>
                {new Date("2025-02-20").toLocaleDateString("en-US",{weekday:"short",month:"short",day:"numeric",year:"numeric"})}
              </span>
              <button className="btn btn-ghost btn-sm">🔄 Refresh</button>
            </div>
          </div>
          <div className="so-body">
            {activeView === "smart"    && <SmartAssignView />}
            {activeView === "route"    && <RouteOptimizerView />}
            {activeView === "capacity" && <CapacityView />}
            {activeView === "skills"   && <SkillMatrixView />}
            {activeView === "load"     && <LoadBalancingView />}
          </div>
        </div>
      </div>
    </>
  );
}


// -- GROUNDWORK-SOV-MANAGEMENT --------------------------------------
const css_gw_sov_management = `
  @import url('https://fonts.googleapis.com/css2?family=Bebas+Neue&family=IBM+Plex+Mono:wght@400;600&family=IBM+Plex+Sans:wght@300;400;500;600&display=swap');
  :root {
    --bg:#0B0C0E; --surf:#111316; --surf2:#181B1F; --surf3:#1E2126;
    --bdr:#2A2D33; --bdr2:#353840;
    --sl:#4A9EFF; --sl-dim:rgba(74,158,255,.12);
    --tl:#2DD4BF; --tl-dim:rgba(45,212,191,.12);
    --gn:#22C55E; --gn-dim:rgba(34,197,94,.12);
    --gd:#F59E0B; --gd-dim:rgba(245,158,11,.12);
    --rd:#EF4444; --rd-dim:rgba(239,68,68,.12);
    --pu:#A855F7; --pu-dim:rgba(168,85,247,.12);
    --or:#F97316; --or-dim:rgba(249,115,22,.12);
    --pk:#EC4899; --pk-dim:rgba(236,72,153,.12);
    --tx:#F1F3F5; --tx2:#9CA3AF; --tx3:#6B7280;
    --bebas:'Bebas Neue',sans-serif;
    --mono:'IBM Plex Mono',monospace;
    --sans:'IBM Plex Sans',sans-serif;
  }
  *{box-sizing:border-box;margin:0;padding:0}
  body{background:var(--bg);color:var(--tx);font-family:var(--sans);font-size:13px}
  .shell{display:flex;height:100vh;overflow:hidden}
  .sov-sb{width:220px;background:var(--surf);border-right:1px solid var(--bdr);display:flex;flex-direction:column;flex-shrink:0}
  .sb-top{padding:20px 16px 16px;border-bottom:1px solid var(--bdr);background:linear-gradient(135deg,var(--pk-dim),transparent)}
  .sb-logo{font-family:var(--bebas);font-size:22px;letter-spacing:1px;color:var(--tx)}
  .sb-sub{font-size:10px;color:var(--pk);text-transform:uppercase;letter-spacing:1.5px;margin-top:2px}
  .sb-nav{padding:12px 8px;flex:1;overflow-y:auto}
  .sb-item{display:flex;align-items:center;gap:10px;padding:8px 10px;border-radius:6px;cursor:pointer;color:var(--tx2);font-size:12px;font-weight:500;transition:all .15s;margin-bottom:2px}
  .sb-item:hover{background:var(--surf2);color:var(--tx)}
  .sb-item.active{background:var(--pk-dim);color:var(--pk);border:1px solid rgba(236,72,153,.25)}
  .sb-dot{width:7px;height:7px;border-radius:50%;background:var(--bdr2);flex-shrink:0}
  .sb-item.active .sb-dot{background:var(--pk)}
  .main{flex:1;display:flex;flex-direction:column;overflow:hidden}
  .topbar{height:50px;background:var(--surf);border-bottom:1px solid var(--bdr);display:flex;align-items:center;padding:0 24px;gap:16px;flex-shrink:0}
  .topbar-title{font-family:var(--bebas);font-size:20px;letter-spacing:1px;color:var(--tx);flex:1}
  .badge{display:inline-flex;align-items:center;padding:3px 8px;border-radius:4px;font-size:10px;font-weight:600;text-transform:uppercase;letter-spacing:.8px}
  .badge-pk{background:var(--pk-dim);color:var(--pk);border:1px solid rgba(236,72,153,.3)}
  .badge-gn{background:var(--gn-dim);color:var(--gn);border:1px solid rgba(34,197,94,.3)}
  .badge-rd{background:var(--rd-dim);color:var(--rd);border:1px solid rgba(239,68,68,.3)}
  .badge-gd{background:var(--gd-dim);color:var(--gd);border:1px solid rgba(245,158,11,.3)}
  .badge-sl{background:var(--sl-dim);color:var(--sl);border:1px solid rgba(74,158,255,.3)}
  .badge-pu{background:var(--pu-dim);color:var(--pu);border:1px solid rgba(168,85,247,.3)}
  .badge-or{background:var(--or-dim);color:var(--or);border:1px solid rgba(249,115,22,.3)}
  .content{flex:1;overflow-y:auto;padding:24px}
  .tabs{display:flex;gap:4px;margin-bottom:20px;background:var(--surf);padding:4px;border-radius:8px;border:1px solid var(--bdr);width:fit-content}
  .tab{padding:7px 16px;border-radius:6px;cursor:pointer;font-size:12px;font-weight:500;color:var(--tx2);transition:all .15s;white-space:nowrap}
  .tab.active{background:var(--pk-dim);color:var(--pk);border:1px solid rgba(236,72,153,.25)}
  .tab:hover:not(.active){background:var(--surf2);color:var(--tx)}
  .kpi-row{display:grid;grid-template-columns:repeat(4,1fr);gap:12px;margin-bottom:20px}
  .kpi{background:var(--surf);border:1px solid var(--bdr);border-radius:8px;padding:16px}
  .kpi-label{font-size:10px;color:var(--tx3);text-transform:uppercase;letter-spacing:1px;margin-bottom:6px}
  .kpi-val{font-family:var(--mono);font-size:22px;font-weight:600;color:var(--tx)}
  .kpi-sub{font-size:10px;color:var(--tx3);margin-top:4px}
  .kpi-pk .kpi-val{color:var(--pk)}
  .kpi-gn .kpi-val{color:var(--gn)}
  .kpi-gd .kpi-val{color:var(--gd)}
  .kpi-sl .kpi-val{color:var(--sl)}
  .panel{background:var(--surf);border:1px solid var(--bdr);border-radius:8px;margin-bottom:16px}
  .panel-hd{padding:14px 16px;border-bottom:1px solid var(--bdr);display:flex;align-items:center;justify-content:space-between;flex-wrap:wrap;gap:8px}
  .panel-title{font-family:var(--bebas);font-size:16px;letter-spacing:.8px;color:var(--tx)}
  .panel-body{padding:16px}
  .tbl{width:100%;border-collapse:collapse}
  .tbl th{font-size:10px;text-transform:uppercase;letter-spacing:1px;color:var(--tx3);padding:8px 12px;border-bottom:1px solid var(--bdr);text-align:left;font-weight:600}
  .tbl td{padding:10px 12px;border-bottom:1px solid var(--bdr);font-size:12px;color:var(--tx2)}
  .tbl tr:last-child td{border-bottom:none}
  .tbl tr:hover td{background:var(--surf2);color:var(--tx)}
  .tbl td.mono{font-family:var(--mono);font-size:11px}
  .tbl td.name{color:var(--tx);font-weight:500}
  .tbl tfoot td{border-top:2px solid var(--bdr2);font-weight:700;color:var(--tx);font-family:var(--mono);font-size:12px;padding:10px 12px}
  .two-col{display:grid;grid-template-columns:1fr 1fr;gap:16px}
  .three-col{display:grid;grid-template-columns:repeat(3,1fr);gap:16px}
  .version-pill{display:inline-flex;align-items:center;gap:6px;padding:4px 10px;border-radius:20px;font-size:11px;font-weight:600;cursor:pointer;transition:all .15s;border:1px solid transparent}
  .version-pill.orig{background:var(--sl-dim);color:var(--sl);border-color:rgba(74,158,255,.3)}
  .version-pill.co{background:var(--gd-dim);color:var(--gd);border-color:rgba(245,158,11,.3)}
  .version-pill.curr{background:var(--pk-dim);color:var(--pk);border-color:rgba(236,72,153,.3)}
  .version-pill:not(.active){opacity:.55}
  .version-pill.active{opacity:1;box-shadow:0 0 0 2px currentColor}
  .co-row{background:var(--surf2);border:1px solid var(--bdr);border-radius:6px;padding:12px 14px;margin-bottom:8px;display:flex;align-items:center;gap:12px}
  .co-num{font-family:var(--bebas);font-size:18px;color:var(--gd);width:60px;flex-shrink:0}
  .co-info{flex:1}
  .co-name{font-size:12px;font-weight:600;color:var(--tx);margin-bottom:3px}
  .co-meta{font-size:11px;color:var(--tx3)}
  .timeline{position:relative;padding-left:24px}
  .tl-line{position:absolute;left:7px;top:0;bottom:0;width:2px;background:var(--bdr)}
  .tl-item{position:relative;margin-bottom:16px}
  .tl-dot{position:absolute;left:-20px;top:4px;width:10px;height:10px;border-radius:50%;border:2px solid var(--bg)}
  .tl-content{background:var(--surf2);border:1px solid var(--bdr);border-radius:6px;padding:10px 12px}
  .tl-title{font-size:12px;font-weight:600;color:var(--tx);margin-bottom:3px}
  .tl-meta{font-size:11px;color:var(--tx3)}
  .select{background:var(--surf2);border:1px solid var(--bdr);color:var(--tx);padding:6px 10px;border-radius:5px;font-size:12px;font-family:var(--sans);cursor:pointer}
  .btn{padding:7px 14px;border-radius:5px;font-size:12px;font-weight:600;cursor:pointer;border:none;transition:all .15s;font-family:var(--sans)}
  .btn-pk{background:var(--pk);color:#fff}
  .btn-pk:hover{filter:brightness(1.1)}
  .btn-ghost{background:transparent;border:1px solid var(--bdr);color:var(--tx2)}
  .btn-ghost:hover{border-color:var(--pk);color:var(--pk)}
  .progress-row{display:flex;align-items:center;gap:10px;margin-bottom:10px}
  .progress-label{font-size:11px;color:var(--tx2);flex:1;min-width:0;white-space:nowrap;overflow:hidden;text-overflow:ellipsis}
  .progress-track{width:160px;height:8px;background:var(--surf3);border-radius:4px;overflow:hidden;flex-shrink:0}
  .progress-fill{height:100%;border-radius:4px;transition:width .4s}
  .diff-added{background:rgba(34,197,94,.06)}
  .diff-changed{background:rgba(245,158,11,.06)}
  .diff-removed{background:rgba(239,68,68,.06)}
`;

const PROJECTS_LIST = [
  { id:"J-2401", name:"Desert Ridge Medical – Mech" },
  { id:"J-2402", name:"Tempe Office Park – Elec" },
  { id:"J-2403", name:"Scottsdale HVAC Retrofit" },
];

const SOV = {
  items: [
    { id:"01", desc:"Mechanical Piping — Rough-In", orig:420000, co_deltas:[0,0,18000,0], billed:380000 },
    { id:"02", desc:"HVAC Equipment Procurement", orig:680000, co_deltas:[0,42000,0,0], billed:722000 },
    { id:"03", desc:"Air Handling Units — Install", orig:380000, co_deltas:[85000,0,0,0], billed:210000 },
    { id:"04", desc:"Controls & BAS Integration", orig:290000, co_deltas:[0,0,0,95000], billed:50000 },
    { id:"05", desc:"Plumbing Rough-In", orig:310000, co_deltas:[0,0,0,0], billed:310000 },
    { id:"06", desc:"Medical Gas Systems", orig:420000, co_deltas:[0,0,0,0], billed:280000 },
    { id:"07", desc:"Electrical — Power Distribution", orig:350000, co_deltas:[0,28000,0,0], billed:190000 },
    { id:"08", desc:"Final Testing & Commissioning", orig:0, co_deltas:[0,0,0,80000], billed:0 },
  ],
  change_orders: [
    { id:"CO-001", date:"Oct 14", desc:"OR suite expansion — additional mechanical scope", amount:85000 },
    { id:"CO-002", date:"Nov 02", desc:"HVAC spec upgrade to HEPA filtration systems", amount:70000 },
    { id:"CO-003", date:"Dec 19", desc:"Unforeseen plumbing conflicts — reroute cost", amount:18000 },
    { id:"CO-004", date:"Jan 08", desc:"Additional BAS monitoring points + commissioning line", amount:175000 },
  ],
};

function SOVVersionManagement() {
  const [tab, setTab] = useState("current-sov");
  const [project, setProject] = useState("J-2401");
  const [version, setVersion] = useState("curr");
  const tabs = ["current-sov","change-orders","version-diff","billing-status","history","reports"];
  const tabLabels = { "current-sov":"Current SOV","change-orders":"Change Orders","version-diff":"Version Diff","billing-status":"Billing Status",history:"Audit History",reports:"Reports" };

  const getCurrVal = (item) => item.orig + item.co_deltas.reduce((s,c)=>s+c,0);
  const getVersionVal = (item) => {
    if (version === "orig") return item.orig;
    if (version === "co") return item.orig + item.co_deltas[0] + item.co_deltas[1];
    return getCurrVal(item);
  };

  const totalOrig = SOV.items.reduce((s,i)=>s+i.orig,0);
  const totalCurr = SOV.items.reduce((s,i)=>s+getCurrVal(i),0);
  const totalBilled = SOV.items.reduce((s,i)=>s+i.billed,0);
  const totalCO = SOV.change_orders.reduce((s,c)=>s+c.amount,0);

  return (
    <div className="shell">
      <style>{css_gw_sov_management}</style>
      <aside className="sov-sb">
        <div className="sb-top">
          <div className="sb-logo">Groundwork</div>
          <div className="sb-sub">SOV Management</div>
        </div>
        <nav className="sb-nav">
          {tabs.map(t => (
            <div key={t} className={"sb-item "+(tab===t?"active":"")} onClick={()=>setTab(t)}>
              <div className="sb-dot" />
              {tabLabels[t]}
            </div>
          ))}
        </nav>
      </aside>
      <div className="main">
        <div className="topbar">
          <span className="topbar-title">SOV Version Management</span>
          <select className="select" value={project} onChange={e=>setProject(e.target.value)}>
            {PROJECTS_LIST.map(p=><option key={p.id} value={p.id}>{p.id} — {p.name.split("–")[0].trim()}</option>)}
          </select>
          <span className="badge badge-pk">v5.0 Current</span>
        </div>
        <div className="content">
          <div className="kpi-row">
            <div className="kpi kpi-sl">
              <div className="kpi-label">Original Contract</div>
              <div className="kpi-val">${(totalOrig/1000000).toFixed(3)}M</div>
              <div className="kpi-sub">Baseline v1.0</div>
            </div>
            <div className="kpi kpi-gd">
              <div className="kpi-label">CO Adjustments</div>
              <div className="kpi-val">+${(totalCO/1000).toFixed(0)}K</div>
              <div className="kpi-sub">4 approved COs</div>
            </div>
            <div className="kpi kpi-pk">
              <div className="kpi-label">Current Contract</div>
              <div className="kpi-val">${(totalCurr/1000000).toFixed(3)}M</div>
              <div className="kpi-sub">SOV v5.0</div>
            </div>
            <div className="kpi kpi-gn">
              <div className="kpi-label">Billed to Date</div>
              <div className="kpi-val">{(totalBilled/totalCurr*100).toFixed(1)}%</div>
              <div className="kpi-sub">${(totalBilled/1000000).toFixed(3)}M earned</div>
            </div>
          </div>

          <div className="tabs">
            {tabs.map(t=>(
              <div key={t} className={"tab "+(tab===t?"active":"")} onClick={()=>setTab(t)}>{tabLabels[t]}</div>
            ))}
          </div>

          {tab==="current-sov" && (
            <div className="panel">
              <div className="panel-hd">
                <span className="panel-title">Schedule of Values — {project}</span>
                <div style={{display:"flex",gap:6,alignItems:"center"}}>
                  {[["orig","v1.0 Original","orig"],["co","After CO 1-2","co"],["curr","v5.0 Current","curr"]].map(([v,l,cls])=>(
                    <div key={v} className={"version-pill "+(cls)+" "+(version===v?"active":"")} onClick={()=>setVersion(v)}>{l}</div>
                  ))}
                </div>
              </div>
              <div className="panel-body" style={{padding:0}}>
                <table className="tbl">
                  <thead><tr>
                    <th>Item</th><th>Description</th><th>Value ({version==="orig"?"Original":version==="co"?"After CO 1-2":"Current"})</th><th>Total CO Δ</th><th>Origin</th>
                  </tr></thead>
                  <tbody>
                    {SOV.items.map(item=>{
                      const coDelta = item.co_deltas.reduce((s,c)=>s+c,0);
                      const val = getVersionVal(item);
                      return (
                        <tr key={item.id} className={coDelta>0?"diff-changed":""}>
                          <td className="mono">{item.id}</td>
                          <td className="name">{item.desc}</td>
                          <td className="mono">{val>0?`$${val.toLocaleString()}`:"—"}</td>
                          <td style={{fontFamily:"var(--mono)",fontSize:11,color:coDelta>0?"var(--gn)":coDelta<0?"var(--rd)":"var(--tx3)"}}>
                            {coDelta!==0?`${coDelta>0?"+":""}$${coDelta.toLocaleString()}`:"—"}
                          </td>
                          <td>{item.orig===0?<span className="badge badge-gd">CO Added</span>:<span className="badge badge-sl">Original</span>}</td>
                        </tr>
                      );
                    })}
                  </tbody>
                  <tfoot>
                    <tr>
                      <td colSpan={2}>CONTRACT TOTAL</td>
                      <td>${(version==="orig"?totalOrig:totalCurr).toLocaleString()}</td>
                      <td style={{color:"var(--gn)"}}>+${totalCO.toLocaleString()}</td>
                      <td>4 COs Applied</td>
                    </tr>
                  </tfoot>
                </table>
              </div>
            </div>
          )}

          {tab==="change-orders" && (
            <div className="panel">
              <div className="panel-hd">
                <span className="panel-title">Change Order Log — {project}</span>
                <button className="btn btn-pk">New Change Order</button>
              </div>
              <div className="panel-body">
                {SOV.change_orders.map(co=>(
                  <div key={co.id} className="co-row">
                    <div className="co-num">{co.id}</div>
                    <div className="co-info">
                      <div className="co-name">{co.desc}</div>
                      <div className="co-meta">{co.date}, 2024 — Approved by Owner</div>
                    </div>
                    <span style={{fontFamily:"var(--mono)",fontSize:14,fontWeight:600,color:"var(--gn)"}}>+${co.amount.toLocaleString()}</span>
                    <span className="badge badge-gn" style={{marginLeft:8}}>Approved</span>
                  </div>
                ))}
                <div style={{display:"flex",justifyContent:"space-between",padding:"12px 0 0",borderTop:"1px solid var(--bdr)"}}>
                  <span style={{fontSize:12,color:"var(--tx2)"}}>Total CO Adjustments</span>
                  <span style={{fontFamily:"var(--mono)",fontSize:13,color:"var(--gn)",fontWeight:600}}>+${totalCO.toLocaleString()}</span>
                </div>
              </div>
            </div>
          )}

          {tab==="version-diff" && (
            <div className="panel">
              <div className="panel-hd"><span className="panel-title">Version Diff — v1.0 Original vs v5.0 Current</span></div>
              <div className="panel-body" style={{padding:0}}>
                <table className="tbl">
                  <thead><tr>
                    <th>Item</th><th>Description</th><th>v1.0 Original</th><th>v5.0 Current</th><th>Net Change</th><th>Δ%</th>
                  </tr></thead>
                  <tbody>
                    {SOV.items.map(item=>{
                      const curr = getCurrVal(item);
                      const change = curr - item.orig;
                      const pct = item.orig>0?(change/item.orig*100).toFixed(1):null;
                      return (
                        <tr key={item.id} className={change>0?"diff-added":change<0?"diff-removed":""}>
                          <td className="mono">{item.id}</td>
                          <td className="name">{item.desc}</td>
                          <td className="mono">{item.orig>0?`$${item.orig.toLocaleString()}`:<span style={{color:"var(--tx3)"}}>—</span>}</td>
                          <td className="mono">{curr>0?`$${curr.toLocaleString()}`:<span style={{color:"var(--tx3)"}}>—</span>}</td>
                          <td style={{fontFamily:"var(--mono)",fontSize:11,color:change>0?"var(--gn)":change<0?"var(--rd)":"var(--tx3)"}}>
                            {change!==0?`${change>0?"+":""}$${change.toLocaleString()}`:"—"}
                          </td>
                          <td style={{fontFamily:"var(--mono)",fontSize:11,color:change>0?"var(--gn)":change<0?"var(--rd)":"var(--tx3)"}}>
                            {pct!=null&&change!==0?`${change>0?"+":""}${pct}%`:"—"}
                          </td>
                        </tr>
                      );
                    })}
                  </tbody>
                  <tfoot>
                    <tr>
                      <td colSpan={2}>TOTAL</td>
                      <td>${totalOrig.toLocaleString()}</td>
                      <td>${totalCurr.toLocaleString()}</td>
                      <td style={{color:"var(--gn)"}}>+${totalCO.toLocaleString()}</td>
                      <td style={{color:"var(--gn)"}}>+{(totalCO/totalOrig*100).toFixed(1)}%</td>
                    </tr>
                  </tfoot>
                </table>
              </div>
            </div>
          )}

          {tab==="billing-status" && (
            <div className="panel">
              <div className="panel-hd"><span className="panel-title">Billing Progress by Line Item</span></div>
              <div className="panel-body">
                {SOV.items.filter(i=>getCurrVal(i)>0).map(item=>{
                  const curr = getCurrVal(item);
                  const pct = Math.min(100,Math.round(item.billed/curr*100));
                  return (
                    <div key={item.id} className="progress-row">
                      <span className="progress-label">{item.id} — {item.desc}</span>
                      <div className="progress-track">
                        <div className="progress-fill" style={{width:`${pct}%`,background:pct>=100?"var(--gn)":pct>50?"var(--pk)":"var(--sl)"}} />
                      </div>
                      <span style={{fontFamily:"var(--mono)",fontSize:11,color:"var(--tx3)",width:42,textAlign:"right"}}>{pct}%</span>
                      <span style={{fontFamily:"var(--mono)",fontSize:11,color:"var(--tx3)",width:140,textAlign:"right"}}>${item.billed.toLocaleString()} / ${curr.toLocaleString()}</span>
                    </div>
                  );
                })}
                <div style={{borderTop:"1px solid var(--bdr)",paddingTop:12,marginTop:4,display:"flex",justifyContent:"space-between"}}>
                  <span style={{fontSize:12,color:"var(--tx2)"}}>Overall Completion</span>
                  <span style={{fontFamily:"var(--mono)",fontSize:13,color:"var(--pk)",fontWeight:600}}>{(totalBilled/totalCurr*100).toFixed(1)}%</span>
                </div>
              </div>
            </div>
          )}

          {tab==="history" && (
            <div className="panel">
              <div className="panel-hd"><span className="panel-title">SOV Version History</span></div>
              <div className="panel-body">
                <div className="timeline">
                  <div className="tl-line" />
                  {[
                    { v:"v5.0", date:"Jan 08, 2025", event:"CO-004 applied — BAS monitoring + commissioning (+$175,000)", color:"var(--pk)" },
                    { v:"v4.0", date:"Dec 19, 2024", event:"CO-003 applied — Plumbing reroute unforeseen (+$18,000)", color:"var(--gd)" },
                    { v:"v3.0", date:"Nov 02, 2024", event:"CO-002 applied — HVAC spec upgrade to HEPA (+$70,000)", color:"var(--gd)" },
                    { v:"v2.0", date:"Oct 14, 2024", event:"CO-001 applied — OR suite expansion (+$85,000)", color:"var(--gd)" },
                    { v:"v1.0", date:"Aug 01, 2024", event:"Original SOV executed — 7 line items, $2,850,000", color:"var(--sl)" },
                  ].map((item,i)=>(
                    <div key={i} className="tl-item">
                      <div className="tl-dot" style={{background:item.color}} />
                      <div className="tl-content">
                        <div style={{display:"flex",justifyContent:"space-between",marginBottom:3}}>
                          <div className="tl-title">{item.event}</div>
                          <span className="badge badge-gn">{item.v}</span>
                        </div>
                        <div className="tl-meta">{item.date} · P. Nair (PM)</div>
                      </div>
                    </div>
                  ))}
                </div>
              </div>
            </div>
          )}

          {tab==="reports" && (
            <div className="three-col">
              {[
                { title:"AIA G702/G703", desc:"Payment application with SOV, % complete, retainage", badge:"badge-pk" },
                { title:"SOV Version Compare", desc:"Side-by-side original vs. current with all CO impacts", badge:"badge-gd" },
                { title:"Change Order Register", desc:"Complete CO log with approvals and amounts", badge:"badge-or" },
                { title:"Billing Projection", desc:"Remaining unearned by line item for next 3 periods", badge:"badge-sl" },
                { title:"Over-Billed Alert", desc:"Line items where billed % exceeds work-in-place %", badge:"badge-rd" },
                { title:"SOV Compliance Check", desc:"Verify SOV total ties to contract including all COs", badge:"badge-gn" },
              ].map(r=>(
                <div key={r.title} className="panel" style={{marginBottom:0}}>
                  <div className="panel-body">
                    <div style={{display:"flex",justifyContent:"space-between",marginBottom:8}}>
                      <span className="panel-title" style={{fontSize:14}}>{r.title}</span>
                      <span className={"badge "+(r.badge)}>SOV</span>
                    </div>
                    <div style={{fontSize:11,color:"var(--tx3)",marginBottom:12,lineHeight:1.5}}>{r.desc}</div>
                    <button className="btn btn-pk" style={{width:"100%"}}>Generate Report</button>
                  </div>
                </div>
              ))}
            </div>
          )}
        </div>
      </div>
    </div>
  );
}


// -- GROUNDWORK-SUBCONTRACTOR --------------------------------------
// -- DESIGN TOKENS & CSS ---------------------------------------
const css_gw_subcontractor = `
  @import url('https://fonts.googleapis.com/css2?family=Bebas+Neue&family=IBM+Plex+Sans:wght@300;400;500;600;700&family=IBM+Plex+Mono:wght@400;500;600&display=swap');
  *,*::before,*::after{box-sizing:border-box;margin:0;padding:0}
  :root{
    --bg:#09090B;--surf:#111114;--raise:#18181C;--card:#1E1E23;
    --bord:#27272D;--bord2:#323238;--mute:#52525B;--dim:#71717A;
    --lite:#A1A1AA;--brite:#D4D4D8;--white:#F4F4F5;
    --sl:#4F7ADB;--sl-d:rgba(79,122,219,.12);--sl-b:rgba(79,122,219,.28);
    --tl:#10A57E;--tl-d:rgba(16,165,126,.12);--tl-b:rgba(16,165,126,.28);
    --gn:#16A34A;--gn-d:rgba(22,163,74,.12);--gn-b:rgba(22,163,74,.28);
    --gd:#D97706;--gd-d:rgba(217,119,6,.12);--gd-b:rgba(217,119,6,.28);
    --rd:#DC2626;--rd-d:rgba(220,38,38,.12);--rd-b:rgba(220,38,38,.28);
    --pu:#7C3AED;--pu-d:rgba(124,58,237,.12);--pu-b:rgba(124,58,237,.28);
    --pk:#BE185D;--pk-d:rgba(190,24,93,.12);--pk-b:rgba(190,24,93,.28);
    --font:'IBM Plex Sans',sans-serif;
    --mono:'IBM Plex Mono',monospace;
    --display:'Bebas Neue',sans-serif;
  }
  html,body,#root{height:100%;background:var(--bg);color:var(--white);font-family:var(--font);font-size:13px}
  @keyframes fi{from{opacity:0;transform:translateY(6px)}to{opacity:1;transform:translateY(0)}}
  @keyframes spin{to{transform:rotate(360deg)}}
  .fade{animation:fi .2s ease}

  .shell{display:flex;height:100vh;overflow:hidden}
  .sub-sb{width:220px;flex-shrink:0;background:var(--surf);border-right:1px solid var(--bord);display:flex;flex-direction:column;overflow-y:auto}
  .main{flex:1;display:flex;flex-direction:column;overflow:hidden}
  .topbar{height:52px;background:var(--surf);border-bottom:1px solid var(--bord);display:flex;align-items:center;padding:0 20px;gap:12px;flex-shrink:0}
  .content{flex:1;overflow-y:auto;padding:20px;display:flex;flex-direction:column;gap:16px}

  .sb-logo{padding:16px 14px 12px;border-bottom:1px solid var(--bord)}
  .sb-section{padding:8px 10px 4px;font-size:9px;font-weight:700;letter-spacing:2px;text-transform:uppercase;color:var(--mute)}
  .sb-item{display:flex;align-items:center;gap:9px;padding:8px 12px;margin:1px 6px;border-radius:7px;cursor:pointer;font-size:12px;color:var(--lite);transition:all .12s;user-select:none}
  .sb-item:hover{background:var(--raise);color:var(--white)}
  .sb-item.on{background:var(--sl-d);color:var(--sl);border:1px solid var(--sl-b)}
  .sb-badge{margin-left:auto;background:var(--rd);color:#fff;border-radius:10px;padding:1px 6px;font-size:9px;font-weight:700}

  .panel{background:var(--surf);border:1px solid var(--bord);border-radius:10px;overflow:hidden}
  .ph{padding:14px 16px;border-bottom:1px solid var(--bord);display:flex;justify-content:space-between;align-items:center;gap:10px;flex-wrap:wrap}
  .pt{font-family:var(--display);letter-spacing:2px;font-size:12px;color:var(--white)}
  .ps{font-size:10px;color:var(--mute);margin-top:2px}

  .krow{display:grid;grid-template-columns:repeat(auto-fit,minmax(150px,1fr));gap:10px}
  .kpi{background:var(--surf);border:1px solid var(--bord);border-radius:10px;padding:14px 16px}
  .kl{font-size:10px;color:var(--mute);margin-bottom:5px;text-transform:uppercase;letter-spacing:.5px}
  .kv{font-family:var(--mono);font-size:20px;font-weight:600;color:var(--white);line-height:1}
  .ks{font-size:9px;color:var(--mute);margin-top:4px}
  .k-sl{border-color:var(--sl-b)}.k-sl .kv{color:var(--sl)}
  .k-tl{border-color:var(--tl-b)}.k-tl .kv{color:var(--tl)}
  .k-gn{border-color:var(--gn-b)}.k-gn .kv{color:var(--gn)}
  .k-gd{border-color:var(--gd-b)}.k-gd .kv{color:var(--gd)}
  .k-rd{border-color:var(--rd-b)}.k-rd .kv{color:var(--rd)}
  .k-pu{border-color:var(--pu-b)}.k-pu .kv{color:var(--pu)}

  .tbl{width:100%;border-collapse:collapse;font-size:12px}
  .tbl th{padding:9px 12px;text-align:left;font-size:9px;font-weight:700;letter-spacing:1.5px;text-transform:uppercase;color:var(--mute);border-bottom:1px solid var(--bord);white-space:nowrap}
  .tbl td{padding:9px 12px;border-bottom:1px solid rgba(255,255,255,.04);vertical-align:middle}
  .tbl tr:last-child td{border-bottom:none}
  .tbl tr:hover td{background:rgba(255,255,255,.02)}
  .mono{font-family:var(--mono);font-size:11px}

  .badge{display:inline-flex;align-items:center;gap:4px;padding:2px 8px;border-radius:20px;font-size:10px;font-weight:600;white-space:nowrap}
  .b-sl{background:var(--sl-d);color:var(--sl);border:1px solid var(--sl-b)}
  .b-tl{background:var(--tl-d);color:var(--tl);border:1px solid var(--tl-b)}
  .b-gn{background:var(--gn-d);color:var(--gn);border:1px solid var(--gn-b)}
  .b-gd{background:var(--gd-d);color:var(--gd);border:1px solid var(--gd-b)}
  .b-rd{background:var(--rd-d);color:var(--rd);border:1px solid var(--rd-b)}
  .b-pu{background:var(--pu-d);color:var(--pu);border:1px solid var(--pu-b)}
  .b-mute{background:rgba(82,82,91,.2);color:var(--lite);border:1px solid var(--bord)}

  .btn{display:inline-flex;align-items:center;gap:6px;padding:7px 14px;border-radius:7px;border:none;font-family:var(--font);font-size:12px;font-weight:500;cursor:pointer;transition:all .12s;white-space:nowrap}
  .btn:disabled{opacity:.4;cursor:not-allowed}
  .btn-primary{background:var(--sl);color:#fff}.btn-primary:hover{background:#5F8AEB}
  .btn-tl{background:var(--tl);color:#fff}.btn-tl:hover{background:#12B88E}
  .btn-gn{background:var(--gn);color:#fff}.btn-gn:hover{background:#18B854}
  .btn-rd{background:var(--rd);color:#fff}.btn-rd:hover{background:#EF3535}
  .btn-ghost{background:transparent;color:var(--lite);border:1px solid var(--bord)}.btn-ghost:hover{border-color:var(--bord2);color:var(--white)}
  .btn-sm{padding:5px 10px;font-size:11px}

  .inp{background:var(--raise);border:1px solid var(--bord);border-radius:7px;color:var(--white);font-family:var(--font);font-size:12px;padding:8px 11px;outline:none;width:100%;transition:border .12s}
  .inp:focus{border-color:var(--sl)}
  .inp-sm{padding:5px 9px;font-size:11px}
  .lbl{font-size:10px;font-weight:600;color:var(--lite);letter-spacing:.5px;margin-bottom:4px;display:block}
  select.inp option{background:var(--raise)}
  textarea.inp{resize:vertical;min-height:72px}

  .g2{display:grid;grid-template-columns:1fr 1fr;gap:14px}
  .g3{display:grid;grid-template-columns:1fr 1fr 1fr;gap:14px}
  .g2a{display:grid;grid-template-columns:2fr 1fr;gap:14px}

  .alert{display:flex;align-items:flex-start;gap:10px;padding:10px 14px;border-radius:8px;font-size:11px;line-height:1.5}
  .a-rd{background:var(--rd-d);border:1px solid var(--rd-b);color:var(--rd)}
  .a-gd{background:var(--gd-d);border:1px solid var(--gd-b);color:var(--gd)}
  .a-gn{background:var(--gn-d);border:1px solid var(--gn-b);color:var(--gn)}
  .a-sl{background:var(--sl-d);border:1px solid var(--sl-b);color:var(--sl)}

  .fc{padding:4px 10px;border-radius:6px;font-size:11px;cursor:pointer;color:var(--mute);border:1px solid transparent;transition:all .12s}
  .fc:hover{color:var(--lite)}
  .fc.on{background:var(--sl-d);color:var(--sl);border-color:var(--sl-b)}

  .overlay{position:fixed;inset:0;background:rgba(0,0,0,.72);display:flex;align-items:center;justify-content:center;z-index:100;padding:20px;overflow-y:auto}
  .modal{background:var(--surf);border:1px solid var(--bord);border-radius:12px;width:min(700px,96vw);animation:fi .18s ease;max-height:90vh;overflow-y:auto}
  .modal-lg{width:min(880px,96vw)}
  .modal-head{padding:16px 20px;border-bottom:1px solid var(--bord);display:flex;justify-content:space-between;align-items:center}

  /* COI status rings */
  .coi-ring{width:10px;height:10px;border-radius:50%;flex-shrink:0}

  /* Progress bar */
  .pbar-wrap{height:6px;background:var(--raise);border-radius:3px;overflow:hidden;flex:1}
  .pbar-fill{height:100%;border-radius:3px;transition:width .3s}

  /* Pay app SOV table */
  .sov-tbl{width:100%;border-collapse:collapse;font-size:11px}
  .sov-tbl th{padding:7px 10px;font-size:9px;font-weight:700;letter-spacing:1px;text-transform:uppercase;color:var(--mute);border-bottom:1px solid var(--bord);text-align:right;white-space:nowrap}
  .sov-tbl th:first-child,.sov-tbl th:nth-child(2){text-align:left}
  .sov-tbl td{padding:7px 10px;border-bottom:1px solid rgba(255,255,255,.03);text-align:right;font-family:var(--mono)}
  .sov-tbl td:first-child,.sov-tbl td:nth-child(2){text-align:left;font-family:var(--font)}
  .sov-tbl tr:hover td{background:rgba(255,255,255,.02)}
  .sov-foot{background:var(--raise);font-weight:700}
  .sov-foot td{border-top:1px solid var(--bord);border-bottom:none;padding:9px 10px}

  /* Lien waiver type pill */
  .lw-type{font-size:9px;font-weight:700;letter-spacing:.8px;text-transform:uppercase;padding:2px 7px;border-radius:4px}
  .lw-cond-prog{background:rgba(79,122,219,.15);color:var(--sl)}
  .lw-uncond-prog{background:rgba(16,165,126,.15);color:var(--tl)}
  .lw-cond-final{background:rgba(217,119,6,.15);color:var(--gd)}
  .lw-uncond-final{background:rgba(22,163,74,.15);color:var(--gn)}

  /* Timeline dots */
  .tl-dot{width:8px;height:8px;border-radius:50%;flex-shrink:0}
  .tl-line{width:1px;flex:1;background:var(--bord);margin:2px auto}
`;

