const gw_subcontractor_dollarc = n => "$" + (n||0).toLocaleString("en-US",{minimumFractionDigits:2,maximumFractionDigits:2});
const $k = n => "$" + Math.round((n||0)/1000) + "k";
const gw_subcontractor_pct = (a,b) => b ? Math.round(a/b*100) : 0;
const gw_subcontractor_daysDiff = (a,b) => {
  const ms = new Date(b+"T12:00:00") - new Date(a+"T12:00:00");
  return Math.round(ms/(1000*60*60*24));
};
const gw_subcontractor_fmtDate = d => d ? new Date(d+"T12:00:00").toLocaleDateString("en-US",{month:"short",day:"numeric",year:"numeric"}) : "—";
const gw_subcontractor_fmtShort = d => d ? new Date(d+"T12:00:00").toLocaleDateString("en-US",{month:"short",day:"numeric"}) : "—";

