// -- MODAL: PAY APP DETAIL -------------------------------------
function PayAppModal({pa, onClose, onApprove}) {
  const sub = gw_subcontractor_SUBS.find(s=>s.id===pa.subId);
  const agr = AGREEMENTS.find(a=>a.id===pa.agreementId);
  const job = gw_subcontractor_JOBS.find(j=>j.id===agr?.jobId);
  const sovLines = SOV_LINES[pa.agreementId] || [];
  const totals = paTotal(pa);
  const cs = coiStatus(pa.subId);
  const canApprove = pa.status==="review" && cs!=="expired";

  // Previous pay apps for this agreement
  const prevApps = PAY_APPS.filter(p=>p.agreementId===pa.agreementId && p.appNum < pa.appNum);
  const prevBilledPerLine = {};
  prevApps.forEach(p => {
    Object.entries(p.billedLines||{}).forEach(([k,v])=>{
      prevBilledPerLine[k] = (prevBilledPerLine[k]||0)+(v||0);
    });
  });

  return (
    <div className="overlay" onClick={e=>e.target===e.currentTarget&&onClose()}>
      <div className="modal modal-lg" style={{maxHeight:"92vh",overflowY:"auto"}}>
        <div className="modal-head">
          <div>
            <div style={{fontFamily:"var(--display)",letterSpacing:2,fontSize:13}}>
              PAY APPLICATION #{pa.appNum} — {sub?.company}
            </div>
            <div style={{fontSize:10,color:"var(--mute)",marginTop:2}}>
              {job?.num} · {job?.name?.slice(0,45)} · Period thru {gw_subcontractor_fmtDate(pa.periodThru)}
            </div>
          </div>
          <div style={{display:"flex",gap:8,alignItems:"center"}}>
            <span className={"badge "+(pa.status==="paid"?"b-gn":pa.status==="approved"?"b-tl":pa.status==="review"?"b-gd":pa.status==="submitted"?"b-sl":"b-mute")}>
              {pa.status==="paid"?"✓ Paid":pa.status==="approved"?"Approved":pa.status==="review"?"Under Review":pa.status==="submitted"?"Submitted":"Draft"}
            </span>
            <button className="btn btn-ghost btn-sm" onClick={onClose}>✕</button>
          </div>
        </div>

        {/* COI block gate */}
        {cs==="expired" && (
          <div className="alert a-rd" style={{margin:"12px 20px 0",borderRadius:8}}>
            <span>⛔</span>
            <span><strong>COI Expired for {sub?.company}.</strong> Cannot approve payment until current certificate of insurance is on file. Contact sub to provide updated COI.</span>
          </div>
        )}
        {cs==="expiring" && (
          <div className="alert a-gd" style={{margin:"12px 20px 0",borderRadius:8}}>
            <span>⚠</span>
            <span>COI for {sub?.company} expires within 30 days. Request renewal before approving future pay apps.</span>
          </div>
        )}

        <div style={{padding:20}}>
          {/* AIA G702-style header */}
          <div style={{background:"var(--raise)",border:"1px solid var(--bord)",borderRadius:8,padding:"12px 16px",marginBottom:16,display:"grid",gridTemplateColumns:"repeat(auto-fit,minmax(140px,1fr))",gap:10}}>
            {[
              {l:"Contract Value",   v:gw_subcontractor_dollarc(agrTotal(agr||{})),  color:"var(--white)"},
              {l:"Prev. Billed",     v:gw_subcontractor_dollarc(totals.prevPaid),    color:"var(--mute)"},
              {l:"This Application", v:gw_subcontractor_dollarc(totals.thisBilled),  color:"var(--sl)"},
              {l:"Stored Materials", v:gw_subcontractor_dollarc(pa.storedMaterials), color:"var(--white)"},
              {l:"Total Billed",     v:gw_subcontractor_dollarc(totals.billed),      color:"var(--white)"},
              {l:"Retention ({gw_subcontractor_pct}%)".replace("{gw_subcontractor_pct}",pa.retentionPct), v:"("+gw_subcontractor_dollarc(totals.retention)+")", color:"var(--gd)"},
              {l:"Net Due This App", v:gw_subcontractor_dollarc(totals.net - totals.prevPaid*(1-pa.retentionPct/100)), color:"var(--tl)"},
            ].map(item=>(
              <div key={item.l}>
                <div style={{fontSize:9,color:"var(--mute)",marginBottom:3,textTransform:"uppercase",letterSpacing:.5}}>{item.l}</div>
                <div className="mono" style={{fontSize:13,fontWeight:700,color:item.color}}>{item.v}</div>
              </div>
            ))}
          </div>

          {/* Schedule of Values */}
          <div className="panel" style={{marginBottom:16}}>
            <div className="ph"><div className="pt">SCHEDULE OF VALUES</div><div className="ps">AIA G702 / G703 Format</div></div>
            <table className="sov-tbl">
              <thead>
                <tr>
                  <th style={{textAlign:"left",paddingLeft:16,width:"30%"}}>Item</th>
                  <th>Scheduled Value</th>
                  <th>Prev. Billed</th>
                  <th>This Period</th>
                  <th>Stored Matl</th>
                  <th>Total Billed</th>
                  <th>% Comp</th>
                  <th>Balance</th>
                </tr>
              </thead>
              <tbody>
                {sovLines.map(line=>{
                  const prev = prevBilledPerLine[line.id]||0;
                  const thisPeriod = pa.billedLines?.[line.id]||0;
                  const total = prev + thisPeriod;
                  const balance = line.scheduled - total;
                  const pctComp = gw_subcontractor_pct(total, line.scheduled);
                  return (
                    <tr key={line.id}>
                      <td style={{textAlign:"left",paddingLeft:16,color:"var(--lite)"}}>{line.desc}</td>
                      <td>{gw_subcontractor_dollarc(line.scheduled)}</td>
                      <td style={{color:"var(--mute)"}}>{prev>0?gw_subcontractor_dollarc(prev):"—"}</td>
                      <td style={{color:thisPeriod>0?"var(--sl)":"var(--mute)",fontWeight:thisPeriod>0?600:400}}>{thisPeriod>0?gw_subcontractor_dollarc(thisPeriod):"—"}</td>
                      <td style={{color:"var(--mute)"}}>—</td>
                      <td style={{fontWeight:total>0?600:400}}>{total>0?gw_subcontractor_dollarc(total):"—"}</td>
                      <td>
                        <div style={{display:"flex",alignItems:"center",gap:6,minWidth:80}}>
                          <div className="pbar-wrap" style={{height:4}}>
                            <div className="pbar-fill" style={{width:pctComp+"%",background:pctComp===100?"var(--gn)":"var(--sl)"}}/>
                          </div>
                          <span style={{fontSize:10,color:"var(--mute)",minWidth:28}}>{pctComp}%</span>
                        </div>
                      </td>
                      <td style={{color:balance===0?"var(--gn)":balance<0?"var(--rd)":"var(--lite)"}}>{gw_subcontractor_dollarc(balance)}</td>
                    </tr>
                  );
                })}
              </tbody>
              <tfoot>
                <tr className="sov-foot">
                  <td style={{textAlign:"left",paddingLeft:16,fontFamily:"var(--display)",letterSpacing:1,fontSize:11}}>TOTALS</td>
                  <td>{gw_subcontractor_dollarc(sovLines.reduce((s,l)=>s+l.scheduled,0))}</td>
                  <td style={{color:"var(--mute)"}}>{gw_subcontractor_dollarc(totals.prevPaid)}</td>
                  <td style={{color:"var(--sl)"}}>{gw_subcontractor_dollarc(totals.thisBilled)}</td>
                  <td>{gw_subcontractor_dollarc(pa.storedMaterials)}</td>
                  <td>{gw_subcontractor_dollarc(totals.billed)}</td>
                  <td><span className="mono">{gw_subcontractor_pct(totals.billed, sovLines.reduce((s,l)=>s+l.scheduled,0))}%</span></td>
                  <td>{gw_subcontractor_dollarc(sovLines.reduce((s,l)=>s+l.scheduled,0)-totals.billed)}</td>
                </tr>
              </tfoot>
            </table>
          </div>

          {/* GL Entry preview */}
          <div className="panel" style={{marginBottom:16}}>
            <div className="ph"><div className="pt">GL POSTING — ON APPROVAL</div><div className="ps">Accrual entries to post on approval</div></div>
            <table className="tbl" style={{fontSize:11}}>
              <thead><tr><th>Account</th><th>Description</th><th>Debit</th><th>Credit</th></tr></thead>
              <tbody>
                <tr>
                  <td className="mono">5050</td>
                  <td>Subcontractor Cost — {sub?.company}</td>
                  <td className="mono" style={{color:"var(--rd)"}}>{gw_subcontractor_dollarc(totals.thisBilled)}</td>
                  <td/>
                </tr>
                <tr>
                  <td className="mono">2010</td>
                  <td>Accounts Payable — {sub?.company}</td>
                  <td/>
                  <td className="mono" style={{color:"var(--gn)"}}>{gw_subcontractor_dollarc(totals.thisBilled - Math.round(totals.thisBilled*(pa.retentionPct/100)))}</td>
                </tr>
                <tr>
                  <td className="mono">2050</td>
                  <td>Retention Payable — {agr?.id}</td>
                  <td/>
                  <td className="mono" style={{color:"var(--gd)"}}>{gw_subcontractor_dollarc(Math.round(totals.thisBilled*(pa.retentionPct/100)))}</td>
                </tr>
              </tbody>
              <tfoot>
                <tr style={{background:"var(--raise)"}}>
                  <td colSpan={2} style={{fontFamily:"var(--display)",letterSpacing:1,fontSize:10,padding:"8px 12px"}}>TOTALS</td>
                  <td className="mono" style={{fontWeight:700,padding:"8px 12px"}}>{gw_subcontractor_dollarc(totals.thisBilled)}</td>
                  <td className="mono" style={{fontWeight:700,padding:"8px 12px"}}>{gw_subcontractor_dollarc(totals.thisBilled)}</td>
                </tr>
              </tfoot>
            </table>
          </div>

          {/* Actions */}
          <div style={{display:"flex",gap:10,justifyContent:"flex-end"}}>
            <button className="btn btn-ghost" onClick={onClose}>Close</button>
            {canApprove && (
              <button className="btn btn-gn" onClick={()=>{onApprove(pa.id);onClose();}}>
                ✓ Approve Pay App — Post GL
              </button>
            )}
            {pa.status==="approved" && !pa.paidDate && (
              <button className="btn btn-tl">Mark as Paid</button>
            )}
          </div>
        </div>
      </div>
    </div>
  );
}

// -- MODAL: ADD/EDIT SUB ---------------------------------------
function AddSubModal({onClose, onSave}) {
  const [form, setForm] = useState({
    company:"", trade:"HVAC", contact:"", phone:"", email:"",
    address:"", license:"", licenseType:"", licenseExp:"",
    dirReg:"", notes:""
  });
  const f = (k,v) => setForm(p=>({...p,[k]:v}));

  return (
    <div className="overlay" onClick={e=>e.target===e.currentTarget&&onClose()}>
      <div className="modal">
        <div className="modal-head">
          <div><div style={{fontFamily:"var(--display)",letterSpacing:2}}>ADD SUBCONTRACTOR</div></div>
          <button className="btn btn-ghost btn-sm" onClick={onClose}>✕</button>
        </div>
        <div style={{padding:20,display:"flex",flexDirection:"column",gap:14}}>
          <div className="g2">
            <div><label className="lbl">Company Name *</label><input className="inp" value={form.company} onChange={e=>f("company",e.target.value)} placeholder="ABC Electrical Inc"/></div>
            <div><label className="lbl">Trade</label>
              <select className="inp" value={form.trade} onChange={e=>f("trade",e.target.value)}>
                {["HVAC","Plumbing","Electrical","Drywall","Fire Sprinklers","Insulation","Sheet Metal","Concrete Cutting","Painting","Flooring","Roofing","Other"].map(t=><option key={t}>{t}</option>)}
              </select>
            </div>
          </div>
          <div className="g2">
            <div><label className="lbl">Primary Contact</label><input className="inp" value={form.contact} onChange={e=>f("contact",e.target.value)} placeholder="Jane Smith"/></div>
            <div><label className="lbl">Phone</label><input className="inp" value={form.phone} onChange={e=>f("phone",e.target.value)} placeholder="(602) 555-0000"/></div>
          </div>
          <div><label className="lbl">Email</label><input className="inp" value={form.email} onChange={e=>f("email",e.target.value)} placeholder="contact@company.com"/></div>
          <div><label className="lbl">Address</label><input className="inp" value={form.address} onChange={e=>f("address",e.target.value)} placeholder="1234 Main St, Phoenix AZ 85001"/></div>
          <div className="g2">
            <div><label className="lbl">ROC License #</label><input className="inp" value={form.license} onChange={e=>f("license",e.target.value)} placeholder="ROC-000000"/></div>
            <div><label className="lbl">License Type</label><input className="inp" value={form.licenseType} onChange={e=>f("licenseType",e.target.value)} placeholder="C-11 Electrical"/></div>
          </div>
          <div className="g2">
            <div><label className="lbl">License Expiration</label><input className="inp" type="date" value={form.licenseExp} onChange={e=>f("licenseExp",e.target.value)}/></div>
            <div><label className="lbl">DIR Registration</label><input className="inp" value={form.dirReg} onChange={e=>f("dirReg",e.target.value)} placeholder="DIR-2024-0000000"/></div>
          </div>
          <div><label className="lbl">Notes</label><textarea className="inp" value={form.notes} onChange={e=>f("notes",e.target.value)} placeholder="Any relevant notes..."/></div>
          <div style={{display:"flex",gap:8,justifyContent:"flex-end"}}>
            <button className="btn btn-ghost" onClick={onClose}>Cancel</button>
            <button className="btn btn-primary" onClick={()=>{onSave(form);onClose();}} disabled={!form.company}>Add Subcontractor</button>
          </div>
        </div>
      </div>
    </div>
  );
}

// -- TAB: DASHBOARD --------------------------------------------
function DashboardTab_Sub({onNav}) {
  const totalContractValue = AGREEMENTS.reduce((s,a)=>s+agrTotal(a),0);
  const totalBilled = AGREEMENTS.reduce((s,a)=>s+agrBilled(a.id),0);
  const openPayApps = PAY_APPS.filter(p=>["submitted","review"].includes(p.status));
  const openPayAppTotal = openPayApps.reduce((s,p)=>s+paTotal(p).thisBilled,0);
  const expiredCOIs = COI_RECORDS.filter(c=>gw_subcontractor_daysDiff(gw_subcontractor_TODAY,c.expires)<0);
  const expiringCOIs= COI_RECORDS.filter(c=>{const d=gw_subcontractor_daysDiff(gw_subcontractor_TODAY,c.expires);return d>=0&&d<=30;});
  const pendingWaivers=LIEN_WAIVERS.filter(w=>w.status==="issued"&&!w.received);
  const unexecutedAgrs=AGREEMENTS.filter(a=>a.status!=="executed");

  return (
    <div className="fade" style={{display:"flex",flexDirection:"column",gap:16}}>

      {/* Alerts */}
      {expiredCOIs.length > 0 && (
        <div className="alert a-rd">
          <span>⛔</span>
          <span>
            <strong>{expiredCOIs.length} expired COI{expiredCOIs.length>1?"s":""} on file.</strong>{" "}
            {[...new Set(expiredCOIs.map(c=>subName(c.subId)))].join(", ")} — payment approval blocked until renewed.{" "}
            <span style={{cursor:"pointer",textDecoration:"underline"}} onClick={()=>onNav("coi")}>View COI Tracker →</span>
          </span>
        </div>
      )}
      {expiringCOIs.length > 0 && (
        <div className="alert a-gd">
          <span>⚠</span>
          <span>
            <strong>{expiringCOIs.length} COI{expiringCOIs.length>1?"s":""} expiring within 30 days.</strong>{" "}
            {[...new Set(expiringCOIs.map(c=>subName(c.subId)))].join(", ")} — request renewals now.
          </span>
        </div>
      )}
      {unexecutedAgrs.length > 0 && (
        <div className="alert a-sl">
          <span>📋</span>
          <span>
            <strong>{unexecutedAgrs.length} subcontract{unexecutedAgrs.length>1?"s":""} awaiting execution.</strong>{" "}
            {unexecutedAgrs.map(a=>a.id).join(", ")} — follow up for signatures.
          </span>
        </div>
      )}

      {/* KPIs */}
      <div className="krow">
        {[
          {l:"Active Subs",       v:gw_subcontractor_SUBS.filter(s=>s.status==="active").length,       s:"on "+gw_subcontractor_JOBS.length+" projects", c:"k-sl"},
          {l:"Total Sub Value",   v:$k(totalContractValue),  s:"across "+AGREEMENTS.length+" agreements", c:"k-tl"},
          {l:"Billed to Date",    v:$k(totalBilled),         s:gw_subcontractor_pct(totalBilled,totalContractValue)+"% of contract value", c:"k-gn"},
          {l:"Open Pay Apps",     v:openPayApps.length,      s:$k(openPayAppTotal)+" pending approval", c:"k-gd"},
          {l:"COI Issues",        v:expiredCOIs.length+expiringCOIs.length, s:expiredCOIs.length+" expired · "+expiringCOIs.length+" expiring", c:expiredCOIs.length>0?"k-rd":"k-gd"},
          {l:"Waivers Pending",   v:pendingWaivers.length,   s:"awaiting return from subs", c:"k-pu"},
        ].map(k=>(
          <div key={k.l} className={"kpi "+(k.c)}>
            <div className="kl">{k.l}</div>
            <div className="kv">{k.v}</div>
            <div className="ks">{k.s}</div>
          </div>
        ))}
      </div>

      <div className="g2a" style={{alignItems:"start"}}>
        {/* Open Pay Applications */}
        <div className="panel">
          <div className="ph">
            <div><div className="pt">OPEN PAY APPLICATIONS</div><div className="ps">Submitted + under review</div></div>
            <button className="btn btn-ghost btn-sm" onClick={()=>onNav("payapps")}>View All</button>
          </div>
          {openPayApps.length===0 && <div style={{padding:20,textAlign:"center",color:"var(--mute)",fontSize:12}}>No open pay applications</div>}
          {openPayApps.map(pa=>{
            const totals = paTotal(pa);
            const sub = gw_subcontractor_SUBS.find(s=>s.id===pa.subId);
            const agr = AGREEMENTS.find(a=>a.id===pa.agreementId);
            const cs = coiStatus(pa.subId);
            return (
              <div key={pa.id} style={{padding:"12px 16px",borderBottom:"1px solid var(--bord)",display:"flex",justifyContent:"space-between",alignItems:"center",gap:10}}>
                <div style={{flex:1,minWidth:0}}>
                  <div style={{fontWeight:600,fontSize:12}}>{sub?.company}</div>
                  <div style={{fontSize:10,color:"var(--mute)",marginTop:1}}>{jobNum(agr?.jobId)} · App #{pa.appNum} · Period thru {gw_subcontractor_fmtShort(pa.periodThru)}</div>
                </div>
                <div style={{display:"flex",gap:8,alignItems:"center",flexShrink:0}}>
                  {cs==="expired" && <span style={{fontSize:9,color:"var(--rd)"}}>⛔ COI</span>}
                  <span className="mono" style={{fontWeight:700,color:"var(--tl)"}}>{gw_subcontractor_dollarc(totals.thisBilled)}</span>
                  <span className={"badge "+(pa.status==="review"?"b-gd":"b-sl")} style={{fontSize:9}}>
                    {pa.status==="review"?"Review":"Submitted"}
                  </span>
                </div>
              </div>
            );
          })}
        </div>

        {/* COI snapshot */}
        <div className="panel">
          <div className="ph">
            <div><div className="pt">COI STATUS</div><div className="ps">All active subcontractors</div></div>
            <button className="btn btn-ghost btn-sm" onClick={()=>onNav("coi")}>Manage</button>
          </div>
          {gw_subcontractor_SUBS.filter(s=>s.status==="active").map(sub=>{
            const cs = coiStatus(sub.id);
            const cois = COI_RECORDS.filter(c=>c.subId===sub.id);
            const earliest = cois.reduce((min,c)=>{
              const d=gw_subcontractor_daysDiff(gw_subcontractor_TODAY,c.expires);
              return d<min?d:min;
            }, Infinity);
            return (
              <div key={sub.id} style={{padding:"10px 16px",borderBottom:"1px solid var(--bord)",display:"flex",alignItems:"center",gap:10}}>
                <div className="coi-ring" style={{background:coiColor(cs)}}/>
                <div style={{flex:1}}>
                  <div style={{fontSize:12,fontWeight:500}}>{sub.company}</div>
                  <div style={{fontSize:10,color:"var(--mute)"}}>{sub.trade}</div>
                </div>
                <div style={{fontSize:10,color:cs==="expired"?"var(--rd)":cs==="expiring"?"var(--gd)":"var(--mute)"}}>
                  {cs==="expired" ? "Expired" : earliest===Infinity ? "—" : earliest<=30 ? earliest+"d left" : gw_subcontractor_fmtShort(cois.reduce((m,c)=>c.expires<m?c.expires:m,"9999"))}
                </div>
              </div>
            );
          })}
        </div>
      </div>

      {/* Agreements by Job */}
      <div className="panel">
        <div className="ph"><div className="pt">ACTIVE AGREEMENTS BY PROJECT</div><div className="ps">Contract value, billed %, execution status</div></div>
        <table className="tbl">
          <thead>
            <tr><th>Agreement</th><th>Subcontractor</th><th>Project</th><th>Scope</th><th>Contract Value</th><th>Billed</th><th>% Complete</th><th>Status</th></tr>
          </thead>
          <tbody>
            {AGREEMENTS.map(agr=>{
              const total = agrTotal(agr);
              const billed = agrBilled(agr.id);
              const pctComp = gw_subcontractor_pct(billed, total);
              const sub = gw_subcontractor_SUBS.find(s=>s.id===agr.subId);
              return (
                <tr key={agr.id}>
                  <td className="mono" style={{color:"var(--sl)",fontSize:10}}>{agr.id}</td>
                  <td>
                    <div style={{fontWeight:600,fontSize:11}}>{sub?.company}</div>
                    <div style={{fontSize:9,color:"var(--mute)"}}>{sub?.trade}</div>
                  </td>
                  <td style={{fontSize:11}}>{jobNum(agr.jobId)}</td>
                  <td style={{fontSize:10,color:"var(--lite)",maxWidth:200}}>{agr.scopeDesc.slice(0,50)}…</td>
                  <td className="mono" style={{color:"var(--white)",fontWeight:600}}>{gw_subcontractor_dollarc(total)}</td>
                  <td>
                    <div style={{display:"flex",alignItems:"center",gap:8,minWidth:120}}>
                      <div className="pbar-wrap"><div className="pbar-fill" style={{width:pctComp+"%",background:pctComp>80?"var(--gn)":"var(--sl)"}}/></div>
                      <span className="mono" style={{fontSize:10,color:"var(--mute)",minWidth:30}}>{pctComp}%</span>
                    </div>
                  </td>
                  <td className="mono" style={{color:"var(--tl)"}}>{gw_subcontractor_dollarc(billed)}</td>
                  <td>
                    <span className={"badge "+(agr.status==="executed"?"b-gn":agr.status==="sent"?"b-gd":"b-mute")}>
                      {agr.status==="executed"?"✓ Executed":agr.status==="sent"?"Awaiting Sig.":"Draft"}
                    </span>
                  </td>
                </tr>
              );
            })}
          </tbody>
        </table>
      </div>
    </div>
  );
}

// -- TAB: SUBCONTRACTORS ---------------------------------------
function SubsTab({onViewSub, onAddSub}) {
  const [filter, setFilter] = useState("all");
  const [search, setSearch] = useState("");

  const filtered = gw_subcontractor_SUBS.filter(s=>{
    if (filter==="active" && s.status!=="active") return false;
    if (filter==="issues") {
      const hasIssue = coiStatus(s.id)!=="ok" || !s.w9OnFile || gw_subcontractor_daysDiff(gw_subcontractor_TODAY,s.licenseExp)<60;
      if (!hasIssue) return false;
    }
    if (search && !s.company.toLowerCase().includes(search.toLowerCase()) && !s.trade.toLowerCase().includes(search.toLowerCase())) return false;
    return true;
  });

  return (
    <div className="fade" style={{display:"flex",flexDirection:"column",gap:16}}>
      <div className="panel">
        <div className="ph">
          <div><div className="pt">SUBCONTRACTOR ROSTER</div><div className="ps">{gw_subcontractor_SUBS.filter(s=>s.status==="active").length} active · {gw_subcontractor_SUBS.length} total</div></div>
          <div style={{display:"flex",gap:8,alignItems:"center"}}>
            <input className="inp inp-sm" placeholder="Search…" value={search} onChange={e=>setSearch(e.target.value)} style={{width:160}}/>
            {[["all","All"],["active","Active"],["issues","Issues"]].map(([v,l])=>(
              <div key={v} className={"fc "+(filter===v?"on":"")} onClick={()=>setFilter(v)}>{l}</div>
            ))}
            <button className="btn btn-primary btn-sm" onClick={onAddSub}>+ Add Sub</button>
          </div>
        </div>
        <table className="tbl">
          <thead>
            <tr><th>Company</th><th>Trade</th><th>Contact</th><th>License</th><th>Lic. Expires</th><th>DIR Reg</th><th>W-9</th><th>COI</th><th>Status</th><th></th></tr>
          </thead>
          <tbody>
            {filtered.map(sub=>{
              const cs = coiStatus(sub.id);
              const licDays = gw_subcontractor_daysDiff(gw_subcontractor_TODAY,sub.licenseExp);
              const licExpired = licDays < 0;
              const licExpiring = !licExpired && licDays < 60;
              return (
                <tr key={sub.id} style={{cursor:"pointer"}} onClick={()=>onViewSub(sub)}>
                  <td>
                    <div style={{fontWeight:600,fontSize:12}}>{sub.company}</div>
                    <div style={{fontSize:9,color:"var(--mute)",marginTop:1}}>{sub.id}</div>
                  </td>
                  <td><span className="badge b-sl" style={{fontSize:9}}>{sub.trade}</span></td>
                  <td>
                    <div style={{fontSize:11}}>{sub.contact}</div>
                    <div style={{fontSize:10,color:"var(--mute)"}}>{sub.phone}</div>
                  </td>
                  <td>
                    <div className="mono" style={{fontSize:10}}>{sub.license}</div>
                    <div style={{fontSize:9,color:"var(--mute)"}}>{sub.licenseType}</div>
                  </td>
                  <td style={{color:licExpired?"var(--rd)":licExpiring?"var(--gd)":"var(--lite)",fontSize:11,fontWeight:licExpired||licExpiring?600:400}}>
                    {gw_subcontractor_fmtShort(sub.licenseExp)}
                    {licExpired && <span style={{fontSize:9,display:"block"}}>EXPIRED</span>}
                    {licExpiring && <span style={{fontSize:9,display:"block"}}>{licDays}d left</span>}
                  </td>
                  <td className="mono" style={{fontSize:10,color:"var(--mute)"}}>{sub.dirReg}</td>
                  <td>
                    {sub.w9OnFile
                      ? <span className="badge b-gn" style={{fontSize:9}}>✓ On File</span>
                      : <span className="badge b-rd" style={{fontSize:9}}>Missing</span>}
                  </td>
                  <td>
                    <div style={{display:"flex",alignItems:"center",gap:5}}>
                      <div className="coi-ring" style={{background:coiColor(cs)}}/>
                      <span className={"badge "+(coiBadge(cs))} style={{fontSize:9}}>
                        {cs==="ok"?"Current":cs==="expiring"?"Expiring":"Expired"}
                      </span>
                    </div>
                  </td>
                  <td>
                    <span className={"badge "+(sub.status==="active"?"b-gn":"b-mute")} style={{fontSize:9}}>
                      {sub.status==="active"?"Active":"Inactive"}
                    </span>
                  </td>
                  <td style={{textAlign:"right"}} onClick={e=>e.stopPropagation()}>
                    <button className="btn btn-ghost btn-sm" onClick={()=>onViewSub(sub)}>View</button>
                  </td>
                </tr>
              );
            })}
          </tbody>
        </table>
      </div>
    </div>
  );
}

// -- TAB: PAY APPLICATIONS -------------------------------------
function PayAppsTab({onViewPA, onApprove}) {
  const [filter, setFilter] = useState("all");
  const [paList, setPaList] = useState(PAY_APPS);

  const filtered = paList.filter(pa=>{
    if (filter==="open") return ["submitted","review"].includes(pa.status);
    if (filter==="approved") return pa.status==="approved";
    if (filter==="paid") return pa.status==="paid";
    return true;
  });

  const openTotal = paList.filter(p=>["submitted","review"].includes(p.status))
    .reduce((s,p)=>s+paTotal(p).thisBilled,0);

  return (
    <div className="fade" style={{display:"flex",flexDirection:"column",gap:16}}>
      <div className="krow" style={{gridTemplateColumns:"repeat(4,1fr)"}}>
        {[
          {l:"Submitted",  v:paList.filter(p=>p.status==="submitted").length, c:"k-sl"},
          {l:"Under Review",v:paList.filter(p=>p.status==="review").length,  c:"k-gd"},
          {l:"Approved",   v:paList.filter(p=>p.status==="approved").length, c:"k-tl"},
          {l:"Paid",       v:paList.filter(p=>p.status==="paid").length,     c:"k-gn"},
        ].map(k=>(
          <div key={k.l} className={"kpi "+(k.c)}>
            <div className="kl">{k.l}</div>
            <div className="kv">{k.v}</div>
          </div>
        ))}
      </div>

      <div className="panel">
        <div className="ph">
          <div>
            <div className="pt">PAY APPLICATIONS</div>
            <div className="ps">{gw_subcontractor_dollarc(openTotal)} pending approval across {paList.filter(p=>["submitted","review"].includes(p.status)).length} open apps</div>
          </div>
          <div style={{display:"flex",gap:6}}>
            {[["all","All"],["open","Open"],["approved","Approved"],["paid","Paid"]].map(([v,l])=>(
              <div key={v} className={"fc "+(filter===v?"on":"")} onClick={()=>setFilter(v)}>{l}</div>
            ))}
          </div>
        </div>
        <table className="tbl">
          <thead>
            <tr><th>App #</th><th>Subcontractor</th><th>Project</th><th>Period Thru</th><th>Submitted</th><th>This App</th><th>Retention</th><th>Net Due</th><th>COI</th><th>Status</th><th></th></tr>
          </thead>
          <tbody>
            {filtered.map(pa=>{
              const sub = gw_subcontractor_SUBS.find(s=>s.id===pa.subId);
              const agr = AGREEMENTS.find(a=>a.id===pa.agreementId);
              const totals = paTotal(pa);
              const cs = coiStatus(pa.subId);
              return (
                <tr key={pa.id} style={{cursor:"pointer"}} onClick={()=>onViewPA(pa)}>
                  <td className="mono" style={{color:"var(--sl)",fontWeight:700}}>#{pa.appNum}</td>
                  <td>
                    <div style={{fontWeight:600,fontSize:11}}>{sub?.company}</div>
                    <div style={{fontSize:9,color:"var(--mute)"}}>{pa.id}</div>
                  </td>
                  <td style={{fontSize:11}}>{jobNum(agr?.jobId)}</td>
                  <td style={{fontSize:11}}>{gw_subcontractor_fmtShort(pa.periodThru)}</td>
                  <td style={{fontSize:11,color:"var(--mute)"}}>{gw_subcontractor_fmtShort(pa.submitted)}</td>
                  <td className="mono" style={{color:"var(--white)",fontWeight:600}}>{gw_subcontractor_dollarc(totals.thisBilled)}</td>
                  <td className="mono" style={{color:"var(--gd)"}}>({gw_subcontractor_dollarc(totals.retention)})</td>
                  <td className="mono" style={{color:"var(--tl)",fontWeight:700}}>
                    {gw_subcontractor_dollarc(totals.net - totals.prevPaid*(1-(pa.retentionPct/100)))}
                  </td>
                  <td>
                    <div style={{display:"flex",alignItems:"center",gap:4}}>
                      <div className="coi-ring" style={{background:coiColor(cs),width:7,height:7}}/>
                      <span style={{fontSize:9,color:coiColor(cs)}}>{cs==="ok"?"OK":cs==="expiring"?"EXP SOON":"EXPIRED"}</span>
                    </div>
                  </td>
                  <td>
                    <span className={"badge "+(pa.status==="paid"?"b-gn":pa.status==="approved"?"b-tl":pa.status==="review"?"b-gd":pa.status==="submitted"?"b-sl":"b-mute")} style={{fontSize:9}}>
                      {pa.status==="paid"?"✓ Paid":pa.status==="approved"?"Approved":pa.status==="review"?"Review":pa.status==="submitted"?"Submitted":"Draft"}
                    </span>
                  </td>
                  <td style={{textAlign:"right"}} onClick={e=>e.stopPropagation()}>
                    <button className="btn btn-ghost btn-sm" onClick={()=>onViewPA(pa)}>
                      {["review","submitted"].includes(pa.status)?"Review":"View"}
                    </button>
                  </td>
                </tr>
              );
            })}
          </tbody>
        </table>
      </div>
    </div>
  );
}

// -- TAB: COI TRACKER -----------------------------------------
function COITab() {
  const [sub, setSub] = useState("all");
  const [type, setType] = useState("all");

  const filtered = COI_RECORDS.filter(c=>{
    if (sub!=="all" && c.subId!==sub) return false;
    if (type!=="all" && c.type!==type) return false;
    return true;
  });

  const byType = ["GL","WC","Auto","Umbrella"];
  const expiredCount = COI_RECORDS.filter(c=>gw_subcontractor_daysDiff(gw_subcontractor_TODAY,c.expires)<0).length;
  const expiringCount= COI_RECORDS.filter(c=>{const d=gw_subcontractor_daysDiff(gw_subcontractor_TODAY,c.expires);return d>=0&&d<=30;}).length;

  return (
    <div className="fade" style={{display:"flex",flexDirection:"column",gap:16}}>

      {/* Per-sub COI matrix */}
      <div className="panel">
        <div className="ph">
          <div><div className="pt">COI COVERAGE MATRIX</div><div className="ps">Required: GL · WC · Auto · Umbrella</div></div>
          <div style={{display:"flex",gap:6,fontSize:10,alignItems:"center"}}>
            <div style={{display:"flex",alignItems:"center",gap:4}}><div style={{width:8,height:8,borderRadius:"50%",background:"var(--gn)"}}/>Current</div>
            <div style={{display:"flex",alignItems:"center",gap:4}}><div style={{width:8,height:8,borderRadius:"50%",background:"var(--gd)"}}/>Expiring &lt;30d</div>
            <div style={{display:"flex",alignItems:"center",gap:4}}><div style={{width:8,height:8,borderRadius:"50%",background:"var(--rd)"}}/>Expired</div>
            <div style={{display:"flex",alignItems:"center",gap:4}}><div style={{width:8,height:8,borderRadius:"50%",background:"var(--mute)"}}/>Not on File</div>
          </div>
        </div>
        <table className="tbl">
          <thead>
            <tr>
              <th>Subcontractor</th>
              {byType.map(t=><th key={t} style={{textAlign:"center"}}>{t}</th>)}
              <th>Next Expiry</th>
              <th>Overall</th>
            </tr>
          </thead>
          <tbody>
            {gw_subcontractor_SUBS.filter(s=>s.status==="active").map(s=>{
              const subCOIs = COI_RECORDS.filter(c=>c.subId===s.id);
              const cs = coiStatus(s.id);
              const nextExpiry = subCOIs.reduce((m,c)=>c.expires<m?c.expires:m,"9999-12-31");
              const daysToNext = gw_subcontractor_daysDiff(gw_subcontractor_TODAY, nextExpiry);
              return (
                <tr key={s.id}>
                  <td>
                    <div style={{fontWeight:600,fontSize:12}}>{s.company}</div>
                    <div style={{fontSize:9,color:"var(--mute)"}}>{s.trade}</div>
                  </td>
                  {byType.map(t=>{
                    const coi = subCOIs.find(c=>c.type===t);
                    if (!coi) return <td key={t} style={{textAlign:"center"}}><div style={{width:10,height:10,borderRadius:"50%",background:"var(--mute)",margin:"0 auto"}}/></td>;
                    const d = gw_subcontractor_daysDiff(gw_subcontractor_TODAY,coi.expires);
                    const color = d<0?"var(--rd)":d<=30?"var(--gd)":"var(--gn)";
                    return (
                      <td key={t} style={{textAlign:"center"}}>
                        <div style={{display:"flex",flexDirection:"column",alignItems:"center",gap:2}}>
                          <div style={{width:10,height:10,borderRadius:"50%",background:color}}/>
                          <span style={{fontSize:8,color:d<0?"var(--rd)":d<=30?"var(--gd)":"var(--mute)"}}>
                            {d<0?"Exp":d<=30?d+"d":gw_subcontractor_fmtShort(coi.expires).split(" ").slice(0,2).join(" ")}
                          </span>
                        </div>
                      </td>
                    );
                  })}
                  <td style={{fontSize:11,color:daysToNext<0?"var(--rd)":daysToNext<=30?"var(--gd)":"var(--mute)"}}>
                    {daysToNext<0 ? "Expired" : daysToNext+"d — "+gw_subcontractor_fmtShort(nextExpiry)}
                  </td>
                  <td>
                    <span className={"badge "+(coiBadge(cs))}>{cs==="ok"?"✓ OK":cs==="expiring"?"Expiring":"⛔ Expired"}</span>
                  </td>
                </tr>
              );
            })}
          </tbody>
        </table>
      </div>

      {/* Full COI list */}
      <div className="panel">
        <div className="ph">
          <div><div className="pt">ALL CERTIFICATES</div><div className="ps">{expiredCount} expired · {expiringCount} expiring soon</div></div>
          <div style={{display:"flex",gap:6}}>
            <select className="inp inp-sm" value={sub} onChange={e=>setSub(e.target.value)} style={{width:180}}>
              <option value="all">All Subs</option>
              {gw_subcontractor_SUBS.map(s=><option key={s.id} value={s.id}>{s.company}</option>)}
            </select>
            <select className="inp inp-sm" value={type} onChange={e=>setType(e.target.value)} style={{width:120}}>
              <option value="all">All Types</option>
              {byType.map(t=><option key={t}>{t}</option>)}
            </select>
          </div>
        </div>
        <table className="tbl">
          <thead>
            <tr><th>Sub</th><th>Type</th><th>Carrier</th><th>Policy #</th><th>Limit</th><th>Effective</th><th>Expires</th><th>Days Left</th><th>Addl Ins</th><th>Waiver Subro</th><th>Status</th></tr>
          </thead>
          <tbody>
            {filtered.map(c=>{
              const d = gw_subcontractor_daysDiff(gw_subcontractor_TODAY, c.expires);
              const expired = d < 0;
              const expiring = !expired && d<=30;
              return (
                <tr key={c.id}>
                  <td style={{fontSize:11,fontWeight:500}}>{subName(c.subId)}</td>
                  <td><span className="badge b-sl" style={{fontSize:9}}>{c.type}</span></td>
                  <td style={{fontSize:11,color:"var(--lite)"}}>{c.carrier}</td>
                  <td className="mono" style={{fontSize:10}}>{c.policy}</td>
                  <td className="mono">{gw_subcontractor_dollarc(c.limit)}</td>
                  <td style={{fontSize:11}}>{gw_subcontractor_fmtShort(c.effective)}</td>
                  <td style={{fontSize:11,color:expired?"var(--rd)":expiring?"var(--gd)":"var(--white)",fontWeight:expired||expiring?600:400}}>
                    {gw_subcontractor_fmtShort(c.expires)}
                  </td>
                  <td>
                    <span className="mono" style={{fontSize:11,color:expired?"var(--rd)":expiring?"var(--gd)":"var(--mute)",fontWeight:expired||expiring?700:400}}>
                      {expired ? Math.abs(d)+"d ago" : d+"d"}
                    </span>
                  </td>
                  <td>{c.addlInsured?<span style={{color:"var(--gn)",fontSize:11}}>✓</span>:<span style={{color:"var(--mute)",fontSize:11}}>—</span>}</td>
                  <td>{c.waiverSubro?<span style={{color:"var(--tl)",fontSize:11}}>✓</span>:<span style={{color:"var(--mute)",fontSize:11}}>—</span>}</td>
                  <td>
                    <span className={"badge "+(expired?"b-rd":expiring?"b-gd":"b-gn")} style={{fontSize:9}}>
                      {expired?"Expired":expiring?"Expiring Soon":"Current"}
                    </span>
                  </td>
                </tr>
              );
            })}
          </tbody>
        </table>
      </div>
    </div>
  );
}

// -- TAB: LIEN WAIVERS -----------------------------------------
function LienWaiversTab() {
  const [filter, setFilter] = useState("all");
  const [waivers, setWaivers] = useState(LIEN_WAIVERS);

  const markReceived = (id) => {
    setWaivers(prev=>prev.map(w=>w.id===id?{...w,status:"received",received:gw_subcontractor_TODAY}:w));
  };

  const issueWaiver = (id) => {
    setWaivers(prev=>prev.map(w=>w.id===id?{...w,status:"issued",issued:gw_subcontractor_TODAY}:w));
  };

  const filtered = waivers.filter(w=>{
    if (filter==="pending") return w.status==="pending";
    if (filter==="issued")  return w.status==="issued";
    if (filter==="received")return w.status==="received";
    return true;
  });

  const pendingCount  = waivers.filter(w=>w.status==="pending").length;
  const issuedCount   = waivers.filter(w=>w.status==="issued"&&!w.received).length;
  const receivedCount = waivers.filter(w=>w.status==="received").length;
  const totalWaived   = waivers.filter(w=>w.status==="received").reduce((s,w)=>s+w.amount,0);

  return (
    <div className="fade" style={{display:"flex",flexDirection:"column",gap:16}}>

      <div className="krow" style={{gridTemplateColumns:"repeat(4,1fr)"}}>
        {[
          {l:"Awaiting Approval",  v:pendingCount,  s:"issue after pay app approved",c:"k-mute"},
          {l:"Issued to Sub",      v:issuedCount,   s:"sent, not yet returned",       c:"k-gd"},
          {l:"Received / Cleared", v:receivedCount, s:"waiver in hand",               c:"k-gn"},
          {l:"Total Waived",       v:$k(totalWaived),s:"cleared to date",             c:"k-tl"},
        ].map(k=>(
          <div key={k.l} className={"kpi "+(k.c||"")} style={{borderColor:k.c?"":"var(--bord)"}}>
            <div className="kl">{k.l}</div>
            <div className="kv">{k.v}</div>
            <div className="ks">{k.s}</div>
          </div>
        ))}
      </div>

      <div className="panel">
        <div className="ph">
          <div><div className="pt">LIEN WAIVER LOG</div><div className="ps">Conditional + unconditional · Progress + final</div></div>
          <div style={{display:"flex",gap:6}}>
            {[["all","All"],["pending","Pending"],["issued","Issued"],["received","Received"]].map(([v,l])=>(
              <div key={v} className={"fc "+(filter===v?"on":"")} onClick={()=>setFilter(v)}>{l}</div>
            ))}
            <button className="btn btn-primary btn-sm">+ New Waiver</button>
          </div>
        </div>

        <table className="tbl">
          <thead>
            <tr><th>ID</th><th>Subcontractor</th><th>Project</th><th>Type</th><th>Period Thru</th><th>Amount</th><th>Issued</th><th>Received</th><th>Status</th><th></th></tr>
          </thead>
          <tbody>
            {filtered.map(w=>(
              <tr key={w.id}>
                <td className="mono" style={{color:"var(--sl)",fontSize:10}}>{w.id}</td>
                <td style={{fontSize:11,fontWeight:500}}>{subName(w.subId)}</td>
                <td style={{fontSize:11}}>{jobNum(w.jobId)}</td>
                <td>
                  <span className={"lw-type lw-"+(w.type)}>
                    {w.type==="cond-progress"?"Cond. Progress":w.type==="uncond-progress"?"Uncond. Progress":w.type==="cond-final"?"Cond. Final":"Uncond. Final"}
                  </span>
                </td>
                <td style={{fontSize:11}}>{gw_subcontractor_fmtShort(w.periodThru)}</td>
                <td className="mono" style={{color:"var(--tl)",fontWeight:600}}>{gw_subcontractor_dollarc(w.amount)}</td>
                <td style={{fontSize:11,color:w.issued?"var(--white)":"var(--mute)"}}>{gw_subcontractor_fmtShort(w.issued)||"—"}</td>
                <td style={{fontSize:11,color:w.received?"var(--gn)":"var(--mute)"}}>{gw_subcontractor_fmtShort(w.received)||"—"}</td>
                <td>
                  <span className={"badge "+(w.status==="received"?"b-gn":w.status==="issued"?"b-sl":"b-mute")}>
                    {w.status==="received"?"✓ Received":w.status==="issued"?"Issued":"Pending"}
                  </span>
                </td>
                <td style={{textAlign:"right"}}>
                  {w.status==="pending" && (
                    <button className="btn btn-ghost btn-sm" onClick={()=>issueWaiver(w.id)}>Issue</button>
                  )}
                  {w.status==="issued" && !w.received && (
                    <button className="btn btn-tl btn-sm" onClick={()=>markReceived(w.id)}>✓ Mark Received</button>
                  )}
                  {w.status==="received" && (
                    <span style={{fontSize:10,color:"var(--gn)"}}>✓ Cleared</span>
                  )}
                </td>
              </tr>
            ))}
          </tbody>
        </table>

        {/* Workflow explainer */}
        <div style={{padding:"14px 16px",borderTop:"1px solid var(--bord)",display:"flex",gap:20,alignItems:"center",flexWrap:"wrap"}}>
          <div style={{fontSize:10,fontWeight:700,color:"var(--mute)",letterSpacing:1,textTransform:"uppercase"}}>Workflow</div>
          {[
            {step:"1",label:"Pay App Approved",color:"var(--sl)"},
            {step:"2",label:"Issue Waiver to Sub",color:"var(--gd)"},
            {step:"3",label:"Sub Signs + Returns",color:"var(--pu)"},
            {step:"4",label:"Mark Received → Release Payment",color:"var(--gn)"},
          ].map((s,i)=>(
            <div key={s.step} style={{display:"flex",alignItems:"center",gap:6}}>
              {i>0&&<span style={{color:"var(--mute)",fontSize:12}}>→</span>}
              <div style={{width:18,height:18,borderRadius:"50%",background:s.color+"22",border:"1px solid "+s.color+"66",display:"flex",alignItems:"center",justifyContent:"center",fontSize:9,fontWeight:700,color:s.color}}>{s.step}</div>
              <span style={{fontSize:10,color:"var(--lite)"}}>{s.label}</span>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
}

// -- TAB: COMPLIANCE -------------------------------------------
function ComplianceTab_Sub() {
  const issues = [];

  gw_subcontractor_SUBS.filter(s=>s.status==="active").forEach(sub=>{
    const licDays = gw_subcontractor_daysDiff(gw_subcontractor_TODAY, sub.licenseExp);
    if (licDays < 0) issues.push({subId:sub.id,type:"error",category:"License",msg:"ROC License EXPIRED "+Math.abs(licDays)+"d ago"});
    else if (licDays < 90) issues.push({subId:sub.id,type:"warn",category:"License",msg:"ROC License expires in "+licDays+" days"});
    if (!sub.w9OnFile) issues.push({subId:sub.id,type:"error",category:"Tax",msg:"W-9 not on file — required before payment"});
    if (!sub.dirReg) issues.push({subId:sub.id,type:"error",category:"DIR",msg:"No DIR Registration on file"});
    const coiIssues = COI_RECORDS.filter(c=>c.subId===sub.id && gw_subcontractor_daysDiff(gw_subcontractor_TODAY,c.expires)<0);
    coiIssues.forEach(c=>issues.push({subId:sub.id,type:"error",category:"Insurance",msg:c.type+" COI expired "+Math.abs(gw_subcontractor_daysDiff(gw_subcontractor_TODAY,c.expires))+"d ago"}));
    const coiExpiring = COI_RECORDS.filter(c=>c.subId===sub.id&&gw_subcontractor_daysDiff(gw_subcontractor_TODAY,c.expires)>=0&&gw_subcontractor_daysDiff(gw_subcontractor_TODAY,c.expires)<=30);
    coiExpiring.forEach(c=>issues.push({subId:sub.id,type:"warn",category:"Insurance",msg:c.type+" COI expires in "+gw_subcontractor_daysDiff(gw_subcontractor_TODAY,c.expires)+" days"}));
    const noAddlIns = COI_RECORDS.filter(c=>c.subId===sub.id&&c.type==="GL"&&!c.addlInsured);
    noAddlIns.forEach(()=>issues.push({subId:sub.id,type:"warn",category:"Insurance",msg:"GL COI — Additional Insured endorsement not confirmed"}));
    const unexec = AGREEMENTS.filter(a=>a.subId===sub.id&&a.status!=="executed");
    unexec.forEach(a=>issues.push({subId:sub.id,type:"warn",category:"Contract",msg:"Agreement "+a.id+" not yet executed"}));
    const pendingCOs = AGREEMENTS.filter(a=>a.subId===sub.id)
      .flatMap(a=>a.changeOrders||[]).filter(c=>c.status==="pending");
    pendingCOs.forEach(c=>issues.push({subId:sub.id,type:"info",category:"Change Order",msg:"CO "+c.id+": "+c.desc.slice(0,40)+" awaiting approval"}));
  });

  const errors = issues.filter(i=>i.type==="error");
  const warns  = issues.filter(i=>i.type==="warn");
  const infos  = issues.filter(i=>i.type==="info");

  const scoreMap = {};
  gw_subcontractor_SUBS.filter(s=>s.status==="active").forEach(sub=>{
    const subIssues = issues.filter(i=>i.subId===sub.id);
    const errs = subIssues.filter(i=>i.type==="error").length;
    const wrns = subIssues.filter(i=>i.type==="warn").length;
    const score = Math.max(0,100 - errs*25 - wrns*10);
    scoreMap[sub.id] = {score, errs, wrns};
  });

  return (
    <div className="fade" style={{display:"flex",flexDirection:"column",gap:16}}>
      <div className="krow" style={{gridTemplateColumns:"repeat(3,1fr)"}}>
        {[
          {l:"Compliance Errors",   v:errors.length, s:"block payment/work",    c:"k-rd"},
          {l:"Warnings",            v:warns.length,  s:"action recommended",    c:"k-gd"},
          {l:"Change Orders Open",  v:infos.length,  s:"pending approval",      c:"k-sl"},
        ].map(k=>(
          <div key={k.l} className={"kpi "+(k.c)}>
            <div className="kl">{k.l}</div>
            <div className="kv">{k.v}</div>
            <div className="ks">{k.s}</div>
          </div>
        ))}
      </div>

      {/* Compliance scorecard */}
      <div className="panel">
        <div className="ph"><div className="pt">SUB COMPLIANCE SCORECARD</div><div className="ps">License · Insurance · Contract · Tax</div></div>
        <table className="tbl">
          <thead>
            <tr><th>Subcontractor</th><th>Trade</th><th>Score</th><th>Errors</th><th>Warnings</th><th>License</th><th>COI</th><th>W-9</th><th>Agreement</th></tr>
          </thead>
          <tbody>
            {gw_subcontractor_SUBS.filter(s=>s.status==="active").map(sub=>{
              const sc = scoreMap[sub.id];
              const licOK = gw_subcontractor_daysDiff(gw_subcontractor_TODAY,sub.licenseExp)>=0;
              const cs = coiStatus(sub.id);
              const hasExecAgr = AGREEMENTS.some(a=>a.subId===sub.id&&a.status==="executed");
              return (
                <tr key={sub.id}>
                  <td style={{fontWeight:600,fontSize:12}}>{sub.company}</td>
                  <td><span className="badge b-sl" style={{fontSize:9}}>{sub.trade}</span></td>
                  <td>
                    <div style={{display:"flex",alignItems:"center",gap:8}}>
                      <div className="pbar-wrap" style={{width:60}}>
                        <div className="pbar-fill" style={{width:sc.score+"%",background:sc.score>=80?"var(--gn)":sc.score>=60?"var(--gd)":"var(--rd)"}}/>
                      </div>
                      <span className="mono" style={{fontSize:12,fontWeight:700,color:sc.score>=80?"var(--gn)":sc.score>=60?"var(--gd)":"var(--rd)"}}>{sc.score}</span>
                    </div>
                  </td>
                  <td>{sc.errs>0?<span className="badge b-rd" style={{fontSize:9}}>{sc.errs} Error{sc.errs>1?"s":""}</span>:<span style={{color:"var(--gn)",fontSize:11}}>✓</span>}</td>
                  <td>{sc.wrns>0?<span className="badge b-gd" style={{fontSize:9}}>{sc.wrns} Warn{sc.wrns>1?"s":""}</span>:<span style={{color:"var(--gn)",fontSize:11}}>✓</span>}</td>
                  <td>{licOK?<span style={{color:"var(--gn)",fontSize:11}}>✓ Valid</span>:<span style={{color:"var(--rd)",fontSize:11}}>⛔ Expired</span>}</td>
                  <td><span style={{color:coiColor(cs),fontSize:11}}>{cs==="ok"?"✓ Current":cs==="expiring"?"⚠ Expiring":"⛔ Expired"}</span></td>
                  <td>{sub.w9OnFile?<span style={{color:"var(--gn)",fontSize:11}}>✓ On File</span>:<span style={{color:"var(--rd)",fontSize:11}}>✗ Missing</span>}</td>
                  <td>{hasExecAgr?<span style={{color:"var(--gn)",fontSize:11}}>✓ Executed</span>:<span style={{color:"var(--gd)",fontSize:11}}>⚠ Pending</span>}</td>
                </tr>
              );
            })}
          </tbody>
        </table>
      </div>

      {/* Issue log */}
      <div className="panel">
        <div className="ph"><div className="pt">ISSUE LOG</div><div className="ps">All open compliance items</div></div>
        <table className="tbl">
          <thead><tr><th>Severity</th><th>Sub</th><th>Category</th><th>Issue</th></tr></thead>
          <tbody>
            {issues.map((issue,i)=>(
              <tr key={i}>
                <td>
                  <span className={"badge "+(issue.type==="error"?"b-rd":issue.type==="warn"?"b-gd":"b-sl")} style={{fontSize:9}}>
                    {issue.type==="error"?"⛔ Error":issue.type==="warn"?"⚠ Warning":"ℹ Info"}
                  </span>
                </td>
                <td style={{fontSize:11,fontWeight:500}}>{subName(issue.subId)}</td>
                <td><span className="badge b-mute" style={{fontSize:9}}>{issue.category}</span></td>
                <td style={{fontSize:11,color:"var(--lite)"}}>{issue.msg}</td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
}

// -- MAIN COMPONENT --------------------------------------------
function GroundworkSubcontractor() {
  const [tab, setTab]           = useState("dashboard");
  const [showSub, setShowSub]   = useState(null);
  const [showPA, setShowPA]     = useState(null);
  const [showAddSub, setShowAddSub] = useState(false);
  const [payApps, setPayApps]   = useState(PAY_APPS);

  const expiredCOICount = COI_RECORDS.filter(c=>gw_subcontractor_daysDiff(gw_subcontractor_TODAY,c.expires)<0).length;
  const openPACount     = PAY_APPS.filter(p=>["submitted","review"].includes(p.status)).length;

  const handleApprove = (paId) => {
    setPayApps(prev=>prev.map(p=>p.id===paId?{...p,status:"approved",approvedDate:gw_subcontractor_TODAY}:p));
  };

  const navItems = [
    {section:"Overview",items:[
      {id:"dashboard",  icon:"📊", label:"Dashboard"},
    ]},
    {section:"Subcontractors",items:[
      {id:"subs",       icon:"🏗",  label:"Subcontractors"},
      {id:"payapps",    icon:"💳", label:"Pay Applications", badge:openPACount},
      {id:"coi",        icon:"🛡",  label:"COI Tracker",      badge:expiredCOICount||undefined},
      {id:"waivers",    icon:"📝", label:"Lien Waivers"},
    ]},
    {section:"Compliance",items:[
      {id:"compliance", icon:"✅", label:"Compliance"},
    ]},
  ];

  return (
    <>
      <style>{css_gw_subcontractor}</style>
      <div className="shell">
        {/* Sidebar */}
        <div className="sub-sb">
          <div className="sb-logo">
            <div style={{fontFamily:"var(--display)",letterSpacing:3,fontSize:16,color:"var(--white)"}}>GROUNDWORK</div>
            <div style={{fontSize:9,color:"var(--pu)",marginTop:1,letterSpacing:1.5,fontWeight:600}}>SUBCONTRACTOR MGMT</div>
          </div>

          {navItems.map(({section,items})=>(
            <div key={section}>
              <div className="sb-section">{section}</div>
              {items.map(item=>(
                <div key={item.id} className={"sb-item "+(tab===item.id?"on":"")} onClick={()=>setTab(item.id)}>
                  <span style={{fontSize:14}}>{item.icon}</span>
                  <span style={{flex:1}}>{item.label}</span>
                  {item.badge>0 && <span className="sb-badge">{item.badge}</span>}
                </div>
              ))}
            </div>
          ))}

          {/* Summary at bottom */}
          <div style={{marginTop:"auto",padding:"12px 14px",borderTop:"1px solid var(--bord)"}}>
            <div style={{fontSize:10,color:"var(--mute)",marginBottom:6}}>SUB SUMMARY</div>
            {[
              {l:"Active Subs",    v:gw_subcontractor_SUBS.filter(s=>s.status==="active").length},
              {l:"Open Agreements",v:AGREEMENTS.filter(a=>a.status==="executed").length},
              {l:"Total Sub Value",v:$k(AGREEMENTS.reduce((s,a)=>s+agrTotal(a),0))},
            ].map(({l,v})=>(
              <div key={l} style={{display:"flex",justifyContent:"space-between",fontSize:10,padding:"3px 0"}}>
                <span style={{color:"var(--mute)"}}>{l}</span>
                <span style={{color:"var(--white)",fontFamily:"var(--mono)"}}>{v}</span>
              </div>
            ))}
          </div>
        </div>

        {/* Main */}
        <div className="main">
          {/* Topbar */}
          <div className="topbar">
            <div style={{fontFamily:"var(--display)",fontSize:13,letterSpacing:2,color:"var(--white)"}}>
              {tab==="dashboard"?"DASHBOARD":tab==="subs"?"SUBCONTRACTORS":tab==="payapps"?"PAY APPLICATIONS":tab==="coi"?"COI TRACKER":tab==="waivers"?"LIEN WAIVERS":"COMPLIANCE"}
            </div>
            <div style={{marginLeft:"auto",display:"flex",gap:8,alignItems:"center"}}>
              {expiredCOICount>0 && (
 <div style={{display:"flex",gap:5,alignItems:"center",padding:"4px 10px",background:"var(--rd-d)",border:"1px solid var(--rd-b)",borderRadius:6,fontSize:11,color:"var(--rd)",cursor:"pointer"}} onClick={()=>setTab("coi")}>
                  ⛔ {expiredCOICount} expired COI{expiredCOICount>1?"s":""}
                </div>
              )}
              <div style={{fontSize:11,color:"var(--mute)"}}>{gw_subcontractor_COMPANY.name}</div>
            </div>
          </div>

          {/* Content */}
          <div className="content">
            {tab==="dashboard"  && <DashboardTab_Sub onNav={setTab}/>}
            {tab==="subs"       && <SubsTab onViewSub={setShowSub} onAddSub={()=>setShowAddSub(true)}/>}
            {tab==="payapps"    && <PayAppsTab onViewPA={setShowPA} onApprove={handleApprove}/>}
            {tab==="coi"        && <COITab/>}
            {tab==="waivers"    && <LienWaiversTab/>}
            {tab==="compliance" && <ComplianceTab_Sub/>}
          </div>
        </div>
      </div>

      {/* Modals */}
      {showSub    && <SubDetailModal sub={showSub} onClose={()=>setShowSub(null)}/>}
      {showPA     && <PayAppModal pa={showPA} onClose={()=>setShowPA(null)} onApprove={handleApprove}/>}
      {showAddSub && <AddSubModal onClose={()=>setShowAddSub(false)} onSave={()=>{}}/>}
    </>
  );
}


