function ratioStatus(r) {
  if (r.thresholdVal == null) return "info";
  const ok = r.higher ? (r.isPct ? r.value >= r.thresholdVal : (r.isDollar ? r.value >= r.thresholdVal : r.value >= r.thresholdVal)) : r.value <= r.thresholdVal;
  if (ok) return "good";
  const near = r.higher ? r.value >= r.thresholdVal * 0.85 : r.value <= r.thresholdVal * 1.15;
  return near ? "warn" : "bad";
}

// Gauge SVG component
function CapacityGauge({ used, total }) {
  const pct = Math.min(used / total, 1);
  const r = 70, cx = 100, cy = 90;
  const arcLen = Math.PI * r;
  const usedLen = pct * arcLen;
  const freeLen = arcLen - usedLen;
  const color = pct < 0.7 ? "var(--gn)" : pct < 0.85 ? "var(--gd)" : "var(--rd)";
  return (
    <svg viewBox="0 0 200 110" style={{ width: "100%", maxWidth: 220, display: "block", margin: "0 auto" }}>
      {/* Track */}
      <path d={"M "+(cx - r)+" "+(cy)+" A "+(r)+" "+(r)+" 0 0 1 "+(cx + r)+" "+(cy)} fill="none" stroke="var(--raise)" strokeWidth="14" strokeLinecap="round" />
      {/* Used */}
 <path d={"M "+(cx - r)+" "+(cy)+" A "+(r)+" "+(r)+" 0 0 1 "+(cx + r)+" "+(cy)} fill="none" stroke={color} strokeWidth="14" strokeLinecap="round" strokeDasharray={(usedLen)+" "+(freeLen)} style={{ transition: "stroke-dasharray .6s" }} />
      {/* Center text */}
      <text x={cx} y={cy - 12} textAnchor="middle" fill="var(--white)" fontFamily="IBM Plex Mono" fontSize="22" fontWeight="500">{(pct*100).toFixed(0)}%</text>
      <text x={cx} y={cy + 6} textAnchor="middle" fill="var(--mute)" fontFamily="IBM Plex Sans" fontSize="9" letterSpacing="2">UTILIZED</text>
      {/* Labels */}
      <text x={cx - r} y={cy + 18} textAnchor="middle" fill="var(--mute)" fontFamily="IBM Plex Mono" fontSize="8">$0</text>
      <text x={cx + r} y={cy + 18} textAnchor="middle" fill="var(--mute)" fontFamily="IBM Plex Mono" fontSize="8">{gw_surety_fmtM(total)}</text>
    </svg>
  );
}

// Backlog trend chart
function BacklogChart({ data }) {
  const max = Math.max(...data.map(d => d.value)) * 1.1;
  const w = 300, h = 80, pad = { l: 10, r: 10, t: 8, b: 24 };
  const xScale = i => pad.l + (i / (data.length - 1)) * (w - pad.l - pad.r);
  const yScale = v => h - pad.b - (v / max) * (h - pad.t - pad.b);
  const pathD = data.map((d, i) => `${i === 0 ? "M" : "L"} ${xScale(i)} ${yScale(d.value)}`).join(" ");
  const areaD = pathD + ` L ${xScale(data.length-1)} ${h - pad.b} L ${xScale(0)} ${h - pad.b} Z`;

  return (
    <svg viewBox={"0 0 "+(w)+" "+(h)} style={{ width: "100%", height: 80 }}>
      <defs>
        <linearGradient id="blg" x1="0" y1="0" x2="0" y2="1">
          <stop offset="0%" stopColor="var(--sl)" stopOpacity=".25" />
          <stop offset="100%" stopColor="var(--sl)" stopOpacity="0" />
        </linearGradient>
      </defs>
      {[0.25, 0.5, 0.75].map(r => (
        <line key={r} x1={pad.l} y1={yScale(max * r)} x2={w - pad.r} y2={yScale(max * r)} stroke="rgba(255,255,255,.03)" />
      ))}
      <path d={areaD} fill="url(#blg)" />
      <path d={pathD} fill="none" stroke="var(--sl)" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" />
      {data.map((d, i) => (
        <g key={i}>
          <circle cx={xScale(i)} cy={yScale(d.value)} r="3" fill="var(--sl)" />
          <text x={xScale(i)} y={h - 6} textAnchor="middle" fill="var(--mute)" fontSize="8" fontFamily="IBM Plex Sans">{d.month}</text>
        </g>
      ))}
    </svg>
  );
}

