// -- MODULE FRAME CSS OVERRIDES ----------------------------------
// These overrides are injected per-module to:
// 1. Neutralize height:100vh so modules fill the shell frame
// 2. Hide module's own sidebar (shell handles navigation)
// 3. Make the module's main content area fill full width
const MODULE_OVERRIDES = {
  // root_class, sidebar_class
  'app':          { root: '.app',          sidebar: '.sb',          main: '.main' },
  'shell':        { root: '.shell',        sidebar: '.sidebar',     main: '.main' },
  'gl-root':      { root: '.gl-root',      sidebar: '.gl-sidebar',  main: '.gl-main' },
  'crm-root':     { root: '.crm-root',     sidebar: '.crm-sidebar', main: '.crm-main' },
  'bi-root':      { root: '.bi-root',      sidebar: '.bi-sidebar',  main: '.bi-main' },
  'dm-root':      { root: '.dm-root',      sidebar: '.dm-sidebar',  main: '.dm-main' },
  'est-root':     { root: '.est-root',     sidebar: '.est-sidebar', main: '.est-main' },
  'so-root':      { root: '.so-root',      sidebar: '.so-sidebar',  main: '.so-main' },
  'root':         { root: '.root',         sidebar: '.sidebar',     main: '.main' },
  'portal-root':  { root: '.portal-root',  sidebar: null,           main: null },
  'phone-shell':  { root: '.phone-shell',  sidebar: null,           main: null },
};

function buildModuleOverrideCSS(rootClass, sidebarClass, mainClass) {
  const scoped = (sel) => `.gw-frame ${sel}`;
  return `
    /* Height override: neutralize 100vh → fill frame */
    ${scoped(rootClass)} { height: 100% !important; min-height: 100% !important; }
    /* Hide module's own sidebar — shell handles navigation */
    ${sidebarClass ? `${scoped(sidebarClass)} { display: none !important; }` : ''}
    /* Main content fills full width */
    ${mainClass ? `${scoped(mainClass)} { flex: 1 !important; min-width: 0 !important; }` : ''}
    /* Prevent body-level background override from leaking */
    .gw-frame body { background: transparent !important; }
  `;
}

// -- MODULE WRAPPER COMPONENT ----------------------------------
function ModuleFrame({ rootClass, sidebarClass, mainClass, children }) {
  const overrideCSS = buildModuleOverrideCSS(rootClass, sidebarClass, mainClass);
  return (
    <div className="gw-frame" style={{ flex: 1, overflow: 'hidden', display: 'flex', flexDirection: 'column', height: '100%' }}>
      <style>{overrideCSS}</style>
      {children}
    </div>
  );
}

