// -- SHELL CSS -------------------------------------------------
const SHELL_CSS = `
  @import url('https://fonts.googleapis.com/css2?family=Bebas+Neue&family=IBM+Plex+Sans:wght@300;400;500;600;700&family=IBM+Plex+Mono:wght@400;500;600&display=swap');

  *, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }

  :root {
    --gw-bg:       #0B0C0E;
    --gw-bg2:      #111318;
    --gw-bg3:      #181B22;
    --gw-border:   #222530;
    --gw-border2:  #2D3145;
    --gw-text:     #E8EAF0;
    --gw-text2:    #8B90A0;
    --gw-text3:    #555B6E;
    --gw-accent:   #FF5C35;
    --gw-accent2:  #FF8C6B;
    --gw-font:     'IBM Plex Sans', sans-serif;
    --gw-mono:     'IBM Plex Mono', monospace;
    --gw-display:  'Bebas Neue', cursive;
    --gw-r:        8px;
    --gw-r2:       12px;
    --gw-r3:       16px;
    --gw-shadow:   0 2px 16px rgba(0,0,0,0.5);
    --gw-shadow2:  0 8px 40px rgba(0,0,0,0.7);
  }

  html, body, #root { height: 100%; background: var(--gw-bg); }

  .gw-shell {
    display: flex; height: 100vh;
    background: var(--gw-bg);
    color: var(--gw-text);
    font-family: var(--gw-font);
    overflow: hidden;
  }

  /* SIDEBAR */
  .gw-sidebar {
    width: 256px; min-width: 256px;
    background: var(--gw-bg2);
    border-right: 1px solid var(--gw-border);
    display: flex; flex-direction: column;
    overflow: hidden;
    transition: width 0.2s ease, min-width 0.2s ease;
    position: relative; z-index: 10; flex-shrink: 0;
  }
  .gw-sidebar.collapsed { width: 62px; min-width: 62px; }

  .gw-logo {
    padding: 18px 14px 14px;
    border-bottom: 1px solid var(--gw-border);
    display: flex; align-items: center; gap: 10px; flex-shrink: 0;
  }
  .gw-logo-gem {
    width: 30px; height: 30px; background: var(--gw-accent);
    border-radius: 6px; display: flex; align-items: center; justify-content: center;
    flex-shrink: 0; box-shadow: 0 0 18px rgba(255,92,53,0.35);
  }
  .gw-logo-wordmark { font-family: var(--gw-display); font-size: 20px; letter-spacing: 2px; color: var(--gw-text); white-space: nowrap; }
  .gw-logo-sub { font-size: 8px; font-weight: 700; letter-spacing: 2px; color: var(--gw-text3); text-transform: uppercase; font-family: var(--gw-mono); }

  .gw-collapse-btn {
    position: absolute; top: 20px; right: -11px;
    width: 22px; height: 22px; background: var(--gw-bg3);
    border: 1px solid var(--gw-border2); border-radius: 50%; cursor: pointer;
    display: flex; align-items: center; justify-content: center;
    color: var(--gw-text2); font-size: 10px; z-index: 20; transition: all 0.15s;
  }
  .gw-collapse-btn:hover { background: var(--gw-border2); color: var(--gw-text); }

  .gw-nav { flex: 1; overflow-y: auto; padding: 6px 0; scrollbar-width: thin; scrollbar-color: var(--gw-border2) transparent; }
  .gw-nav::-webkit-scrollbar { width: 3px; }
  .gw-nav::-webkit-scrollbar-thumb { background: var(--gw-border2); border-radius: 2px; }

  .gw-nav-section { padding: 14px 14px 3px; }
  .gw-nav-label { font-size: 9px; font-weight: 700; letter-spacing: 1.5px; color: var(--gw-text3); text-transform: uppercase; font-family: var(--gw-mono); }
  .gw-sidebar.collapsed .gw-nav-label, .gw-sidebar.collapsed .gw-nav-section { display: none; }

  .gw-nav-item {
    display: flex; align-items: center; gap: 9px;
    padding: 8px 14px; cursor: pointer; margin: 1px 7px; border-radius: var(--gw-r);
    transition: all 0.1s; position: relative;
  }
  .gw-nav-item:hover { background: var(--gw-bg3); }
  .gw-nav-item.active { background: rgba(255,92,53,0.1); }
  .gw-nav-item.active::before {
    content: ''; position: absolute; left: 7px; top: 6px; bottom: 6px;
    width: 3px; background: var(--gw-accent); border-radius: 0 2px 2px 0;
  }
  .gw-sidebar.collapsed .gw-nav-item { padding: 9px; justify-content: center; }
  .gw-sidebar.collapsed .gw-nav-item::before { display: none; }

  .gw-nav-icon {
    width: 28px; height: 28px; border-radius: 6px;
    display: flex; align-items: center; justify-content: center;
    font-size: 14px; flex-shrink: 0; transition: transform 0.1s;
  }
  .gw-nav-item:hover .gw-nav-icon { transform: scale(1.06); }

  .gw-nav-info { overflow: hidden; flex: 1; }
  .gw-nav-title { font-size: 12.5px; font-weight: 500; color: var(--gw-text); white-space: nowrap; overflow: hidden; text-overflow: ellipsis; }
  .gw-nav-item.active .gw-nav-title { color: var(--gw-accent2); }
  .gw-nav-sub { font-size: 10px; color: var(--gw-text3); white-space: nowrap; overflow: hidden; text-overflow: ellipsis; margin-top: 1px; }
  .gw-sidebar.collapsed .gw-nav-info { display: none; }

  .gw-nav-badge {
    margin-left: auto; font-size: 9px; font-family: var(--gw-mono);
    font-weight: 600; padding: 2px 5px; border-radius: 4px; flex-shrink: 0; white-space: nowrap;
  }
  .gw-sidebar.collapsed .gw-nav-badge { display: none; }

  .gw-sidebar-footer {
    border-top: 1px solid var(--gw-border); padding: 11px;
    display: flex; align-items: center; gap: 9px; flex-shrink: 0;
  }
  .gw-user-avatar {
    width: 30px; height: 30px; border-radius: 50%;
    background: linear-gradient(135deg, #3D7FFF, #9B6EFF);
    display: flex; align-items: center; justify-content: center;
    font-size: 11px; font-weight: 700; color: white; flex-shrink: 0;
  }
  .gw-user-name { font-size: 12px; font-weight: 600; color: var(--gw-text); }
  .gw-user-role { font-size: 10px; color: var(--gw-text3); }
  .gw-sidebar.collapsed .gw-sidebar-footer { justify-content: center; }
  .gw-sidebar.collapsed .gw-user-info { display: none; }

  /* MAIN */
  .gw-main { flex: 1; display: flex; flex-direction: column; overflow: hidden; min-width: 0; }

  /* TOPBAR */
  .gw-topbar {
    height: 52px; background: var(--gw-bg2); border-bottom: 1px solid var(--gw-border);
    display: flex; align-items: center; padding: 0 20px; gap: 14px; flex-shrink: 0;
  }
  .gw-breadcrumb { display: flex; align-items: center; gap: 6px; font-size: 12.5px; }
  .gw-bc-parent { color: var(--gw-text3); }
  .gw-bc-sep { color: var(--gw-text3); font-size: 10px; }
  .gw-bc-current { color: var(--gw-text); font-weight: 600; }
  .gw-topbar-right { margin-left: auto; display: flex; align-items: center; gap: 8px; }
  .gw-topbar-btn {
    width: 32px; height: 32px; border-radius: var(--gw-r);
    background: var(--gw-bg3); border: 1px solid var(--gw-border);
    cursor: pointer; display: flex; align-items: center; justify-content: center;
    color: var(--gw-text2); font-size: 14px; transition: all 0.1s;
  }
  .gw-topbar-btn:hover { background: var(--gw-border); color: var(--gw-text); }
  .gw-company-chip {
    font-size: 11px; font-weight: 600; color: var(--gw-text2);
    padding: 5px 10px; background: var(--gw-bg3); border: 1px solid var(--gw-border);
    border-radius: var(--gw-r); font-family: var(--gw-mono); letter-spacing: 0.5px;
  }

  /* SUBNAV */
  .gw-subnav {
    background: var(--gw-bg2); border-bottom: 1px solid var(--gw-border);
    padding: 0 20px; display: flex; gap: 0; flex-shrink: 0;
    overflow-x: auto; scrollbar-width: none;
  }
  .gw-subnav::-webkit-scrollbar { display: none; }
  .gw-subnav-tab {
    display: flex; align-items: center; gap: 6px;
    padding: 10px 13px 9px; cursor: pointer; font-size: 12px; font-weight: 500;
    color: var(--gw-text2); border-bottom: 2px solid transparent;
    transition: all 0.1s; white-space: nowrap; position: relative; bottom: -1px;
  }
  .gw-subnav-tab:hover { color: var(--gw-text); }
  .gw-subnav-tab.active { color: var(--gw-text); border-bottom-color: var(--gw-accent); }
  .gw-subnav-tab-icon { font-size: 13px; opacity: 0.7; }
  .gw-subnav-tab.active .gw-subnav-tab-icon { opacity: 1; }

  /* CONTENT */
  .gw-content {
    flex: 1; overflow: hidden; display: flex; flex-direction: column;
    background: var(--gw-bg); position: relative;
  }

  /* MODULE FRAME — critical isolation container */
  .gw-frame {
    flex: 1; overflow: hidden; display: flex; flex-direction: column;
    position: relative; height: 100%;
  }

  /* COMMAND PALETTE */
  .gw-overlay {
    position: fixed; inset: 0; background: rgba(0,0,0,0.72);
    z-index: 9999; display: flex; align-items: flex-start; justify-content: center;
    padding-top: 14vh; backdrop-filter: blur(4px);
    animation: gw-fade 0.1s ease;
  }
  @keyframes gw-fade { from { opacity: 0; } to { opacity: 1; } }

  .gw-palette {
    width: 540px; background: var(--gw-bg2); border: 1px solid var(--gw-border2);
    border-radius: var(--gw-r3); box-shadow: var(--gw-shadow2); overflow: hidden;
    animation: gw-slide 0.15s ease;
  }
  @keyframes gw-slide { from { transform: translateY(-10px); opacity: 0; } to { transform: translateY(0); opacity: 1; } }

  .gw-palette-input {
    width: 100%; padding: 14px 18px; background: transparent;
    border: none; border-bottom: 1px solid var(--gw-border);
    color: var(--gw-text); font-family: var(--gw-font); font-size: 14px; outline: none;
  }
  .gw-palette-input::placeholder { color: var(--gw-text3); }

  .gw-palette-results { max-height: 340px; overflow-y: auto; padding: 5px; }
  .gw-palette-item {
    display: flex; align-items: center; gap: 9px;
    padding: 9px 11px; border-radius: var(--gw-r); cursor: pointer; transition: background 0.08s;
  }
  .gw-palette-item:hover, .gw-palette-item.focused { background: var(--gw-bg3); }
  .gw-palette-icon { width: 28px; height: 28px; border-radius: 6px; display: flex; align-items: center; justify-content: center; font-size: 13px; flex-shrink: 0; }
  .gw-palette-title { font-size: 12.5px; font-weight: 500; color: var(--gw-text); }
  .gw-palette-parent { font-size: 10px; color: var(--gw-text3); margin-top: 1px; }

  .gw-palette-footer {
    padding: 9px 15px; border-top: 1px solid var(--gw-border);
    display: flex; align-items: center; gap: 14px; font-size: 10px; color: var(--gw-text3); font-family: var(--gw-mono);
  }
  .gw-palette-footer kbd {
    background: var(--gw-bg3); border: 1px solid var(--gw-border2);
    border-radius: 3px; padding: 1px 5px; font-family: var(--gw-mono); font-size: 10px;
  }

  /* TOOLTIP */
  .gw-ttip {
    position: fixed; background: var(--gw-bg3); border: 1px solid var(--gw-border2);
    border-radius: 6px; padding: 5px 9px; font-size: 11px; font-weight: 500; color: var(--gw-text);
    white-space: nowrap; pointer-events: none; z-index: 99999; box-shadow: var(--gw-shadow);
    transition: opacity 0.1s; font-family: var(--gw-font);
  }
`;

// -- MAIN SHELL COMPONENT --------------------------------------
export default function GroundworkERP() {
  const [activeModule, setActiveModule] = useState('projects');
  const [activeTab, setActiveTab]       = useState('jobcost');
  const [collapsed, setCollapsed]       = useState(false);
  const [showPalette, setShowPalette]   = useState(false);
  const [query, setQuery]               = useState('');
  const [focus, setFocus]               = useState(0);
  const [tooltip, setTooltip]           = useState({ show: false, text: '', x: 0, y: 0 });
  const paletteInputRef = useRef(null);

  const module = MEGA_MODULES.find(m => m.id === activeModule);
  const tab    = module?.tabs.find(t => t.id === activeTab);

  const navigate = useCallback((moduleId, tabId) => {
    setActiveModule(moduleId);
    setActiveTab(tabId);
    setShowPalette(false);
    setQuery('');
  }, []);

  const selectModule = useCallback((id) => {
    const m = MEGA_MODULES.find(x => x.id === id);
    if (!m) return;
    setActiveModule(id);
    setActiveTab(m.tabs[0].id);
  }, []);

  const filteredItems = query
    ? ALL_ITEMS.filter(i =>
        i.label.toLowerCase().includes(query.toLowerCase()) ||
        i.moduleLabel.toLowerCase().includes(query.toLowerCase())
      )
    : ALL_ITEMS;

  // Keyboard: ⌘K / Ctrl+K → palette; Escape → close
  useEffect(() => {
    const handler = (e) => {
      if ((e.metaKey || e.ctrlKey) && e.key === 'k') { e.preventDefault(); setShowPalette(v => !v); setQuery(''); setFocus(0); }
      if (e.key === 'Escape') setShowPalette(false);
    };
    window.addEventListener('keydown', handler);
    return () => window.removeEventListener('keydown', handler);
  }, []);

  // Palette arrow navigation
  useEffect(() => {
    if (!showPalette) return;
    const handler = (e) => {
      if (e.key === 'ArrowDown') { e.preventDefault(); setFocus(v => Math.min(v + 1, filteredItems.length - 1)); }
      if (e.key === 'ArrowUp')   { e.preventDefault(); setFocus(v => Math.max(v - 1, 0)); }
      if (e.key === 'Enter') { const item = filteredItems[focus]; if (item) navigate(item.moduleId, item.tabId); }
    };
    window.addEventListener('keydown', handler);
    return () => window.removeEventListener('keydown', handler);
  }, [showPalette, focus, filteredItems, navigate]);

  useEffect(() => {
    if (showPalette) setTimeout(() => paletteInputRef.current?.focus(), 30);
  }, [showPalette]);

  const showTip = (text, e) => {
    if (!collapsed) return;
    const r = e.currentTarget.getBoundingClientRect();
    setTooltip({ show: true, text, x: r.right + 10, y: r.top + r.height / 2 - 13 });
  };
  const hideTip = () => setTooltip(t => ({ ...t, show: false }));

  const ActiveComponent = tab?.Component;

  return (
    <>
      <style>{SHELL_CSS}</style>

      {/* Tooltip */}
      {tooltip.show && (
        <div className="gw-ttip" style={{ left: tooltip.x, top: tooltip.y }}>
          {tooltip.text}
        </div>
      )}

      {/* Command Palette */}
      {showPalette && (
        <div className="gw-overlay" onClick={() => setShowPalette(false)}>
          <div className="gw-palette" onClick={e => e.stopPropagation()}>
 <input ref={paletteInputRef} className="gw-palette-input" placeholder="Search modules, tools, reports…" value={query} onChange={e => { setQuery(e.target.value); setFocus(0); }}
            />
            <div className="gw-palette-results">
              {filteredItems.length === 0 && (
                <div style={{ padding: 20, textAlign: 'center', color: 'var(--gw-text3)', fontSize: 12 }}>
                  No results for "{query}"
                </div>
              )}
              {filteredItems.map((item, i) => (
 <div key={(item.moduleId)+"-"+(item.tabId)} className={"gw-palette-item"+(i === focus ? ' focused' : '')} onClick={() => navigate(item.moduleId, item.tabId)}
                  onMouseEnter={() => setFocus(i)}
                >
                  <div className="gw-palette-icon" style={{ background: `${item.moduleColor}20` }}>
                    {item.icon}
                  </div>
                  <div>
                    <div className="gw-palette-title">{item.label}</div>
                    <div className="gw-palette-parent">{item.moduleIcon} {item.moduleLabel}</div>
                  </div>
                </div>
              ))}
            </div>
            <div className="gw-palette-footer">
              <span><kbd>↑↓</kbd> navigate</span>
              <span><kbd>↵</kbd> open</span>
              <span><kbd>esc</kbd> close</span>
              <span style={{ marginLeft: 'auto' }}>{filteredItems.length} of {ALL_ITEMS.length} modules</span>
            </div>
          </div>
        </div>
      )}

      <div className="gw-shell">

        {/* -- SIDEBAR -- */}
        <aside className={"gw-sidebar"+(collapsed ? ' collapsed' : '')}>
          <button className="gw-collapse-btn" onClick={() => setCollapsed(v => !v)}>
            {collapsed ? '›' : '‹'}
          </button>

          {/* Logo */}
          <div className="gw-logo">
            <div className="gw-logo-gem">
              <svg width="16" height="16" viewBox="0 0 24 24" fill="none">
                <path d="M12 2L2 7l10 5 10-5-10-5z" fill="#0B0C0E"/>
                <path d="M2 17l10 5 10-5M2 12l10 5 10-5" stroke="#0B0C0E" strokeWidth="2.2" strokeLinecap="round"/>
              </svg>
            </div>
            {!collapsed && (
              <div>
                <div className="gw-logo-wordmark">GROUNDWORK</div>
                <div className="gw-logo-sub">MEP Construction ERP</div>
              </div>
            )}
          </div>

          {/* Module Nav */}
          <nav className="gw-nav">
            {!collapsed && <div className="gw-nav-section"><div className="gw-nav-label">Modules</div></div>}

            {MEGA_MODULES.map(m => (
 <div key={m.id} className={"gw-nav-item"+(activeModule === m.id ? ' active' : '')} onClick={() => selectModule(m.id)}
                onMouseEnter={e => showTip(m.label, e)}
                onMouseLeave={hideTip}
              >
                <div className="gw-nav-icon" style={{ background: `${m.color}18` }}>{m.icon}</div>
                {!collapsed && (
                  <>
                    <div className="gw-nav-info">
                      <div className="gw-nav-title">{m.label}</div>
                      <div className="gw-nav-sub">{m.subtitle}</div>
                    </div>
                    {m.badge && (
                      <div className="gw-nav-badge" style={{ background: `${m.color}20`, color: m.color }}>
                        {m.badge}
                      </div>
                    )}
                  </>
                )}
              </div>
            ))}

            {!collapsed && <div className="gw-nav-section" style={{ marginTop: 6 }}><div className="gw-nav-label">Quick Access</div></div>}

            <div className="gw-nav-item" onClick={() => setShowPalette(true)} onMouseEnter={e => showTip('Search ⌘K', e)} onMouseLeave={hideTip}>
              <div className="gw-nav-icon" style={{ background: 'rgba(255,255,255,0.05)' }}>🔍</div>
              {!collapsed && <div className="gw-nav-info"><div className="gw-nav-title">Search</div><div className="gw-nav-sub">⌘K anywhere</div></div>}
            </div>
            <div className="gw-nav-item" onMouseEnter={e => showTip('Settings', e)} onMouseLeave={hideTip}>
              <div className="gw-nav-icon" style={{ background: 'rgba(255,255,255,0.05)' }}>⚙️</div>
              {!collapsed && <div className="gw-nav-info"><div className="gw-nav-title">Settings</div><div className="gw-nav-sub">Company configuration</div></div>}
            </div>
          </nav>

          {/* Footer */}
          <div className="gw-sidebar-footer">
            <div className="gw-user-avatar">TW</div>
            {!collapsed && (
              <div className="gw-user-info">
                <div className="gw-user-name">Tyler W.</div>
                <div className="gw-user-role">System Administrator</div>
              </div>
            )}
          </div>
        </aside>

        {/* -- MAIN -- */}
        <div className="gw-main">

          {/* Top bar */}
          <header className="gw-topbar">
            <div className="gw-breadcrumb">
              <span className="gw-bc-parent">{module?.icon} {module?.label}</span>
              <span className="gw-bc-sep">›</span>
              <span className="gw-bc-current">{tab?.label}</span>
            </div>
            <div className="gw-topbar-right">
              <div className="gw-company-chip">ACME MEP CONTRACTORS</div>
              <button className="gw-topbar-btn" onClick={() => setShowPalette(true)} title="Search ⌘K">🔍</button>
              <button className="gw-topbar-btn" title="Notifications">🔔</button>
              <button className="gw-topbar-btn" title="Help">❓</button>
            </div>
          </header>

          {/* Sub-nav tabs */}
          <nav className="gw-subnav">
            {module?.tabs.map(t => (
 <div key={t.id} className={"gw-subnav-tab"+(activeTab === t.id ? ' active' : '')} onClick={() => setActiveTab(t.id)}
              >
                <span className="gw-subnav-tab-icon">{t.icon}</span>
                {t.label}
              </div>
            ))}
          </nav>

          {/* Content — active module rendered here */}
          <div className="gw-content">
            {ActiveComponent && tab && (
 <ModuleFrame key={(activeModule)+"-"+(activeTab)} rootClass={"."+(tab.rootClass)} sidebarClass={tab.sidebarClass} mainClass={tab.mainClass} >
                <ActiveComponent />
              </ModuleFrame>
            )}
          </div>

        </div>
      </div>
    </>
  );
}